window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-008.json"] = [{"name":"三趾滨鹬","english_name":"Sanderling","scientific_name":"Calidris alba","overview":"三趾滨鹬（英文名：Sanderling，学名：Calidris alba），是鸻形目丘鹬科滨鹬属的鸟类。以其独特的‘自行车’步态在沙滩上疾走而闻名。繁殖季节，其上体呈现锈褐色，与深红的颈部形成对比。秋季，成鸟和幼鸟上体黑白斑驳。冬季则整体显得苍白，上体灰白，下体纯白。该物种繁殖于北极高纬度的苔原湿地，迁徙至全球各地的海岸线过冬，除南极洲外，几乎遍布各大洲。","appearance":"体型略小，长约18至20厘米，体重40至100克。特征为无后趾，腿脚均为黑色。喙黑色，短直而粗壮。繁殖季节，头颈及上体变为砂褐色，密布暗淡和浅色斑点，与白色的下体形成鲜明对比。非繁殖季节，头部、颈部、上体灰白，下体纯白，肩部有明显的暗色斑块。幼鸟上体斑驳黑白色，头顶亦深暗并带黑色条纹，胸侧有温暖的淡褐色斑块，点缀或斑驳着精细的黑色标记。","habits":"三趾滨鹬偏好滨海沙滩，极少涉足泥地。在落潮时，它们常成群结队地在水边奔跑，迅速探查并捕食海潮冲刷出来的小型无脊椎动物。繁殖季节，它们在北极苔原湿地筑巢，主要以昆虫和部分植物为食。非繁殖季节，则在世界各地的海滩、沙洲、泥滩和湖泊河流岸边觅食。","breeding":"春季，三趾滨鹬会以群聚方式到达北极附近，在那里，它们会在地面凹坑中产下3至4颗蛋。雌雄双方都会参与孵卵、育雏。在繁殖地，它们主要以昆虫和一些植物材料为食。","identification":"三趾滨鹬与其它小型滨鸟区分的关键在于其缺乏后趾，以及独特的黑白肩部斑块。与红颈滨鹬区别在于，后者喉部和胸部无暗色标记，且体型更为娇小。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美、欧洲和亚洲的北极高纬度苔原湿地。非繁殖季节广泛分布于温带到热带的全球海滨沙滩，包括英国、非洲、马达加斯加、中东、东南亚、澳大利亚、日本南部及加拿大东南部、加勒比海至火地岛，以及波利尼西亚东部岛屿。"},{"name":"黑腹滨鹬","english_name":"Dunlin","scientific_name":"Calidris alpina","overview":"黑腹滨鹬（英文名：Dunlin，学名：Calidris alpina），是鸻形目丘鹬科滨鹬属的鸟类。一种广泛分布于北极和亚北极地区的中小型涉禽。繁殖期的黑腹滨鹬背部亮赤色，腹部黑色，因而曾被称为红背滨鹬。在迁徙季节和冬季以灰色为主，形成数千乃至数万只的大群。繁殖地横跨北极苔原，从阿拉斯加西南部至加拿大詹姆斯湾，冬季则主要栖息于美国太平洋和大西洋海岸的大型河口，部分个体在中国东部沿海越冬。","appearance":"黑腹滨鹬体型略大于其他滨鹬，喙长且略向下弯曲。繁殖期个体背部呈红褐色，腹部黑色，非常显眼。非繁殖期则上体灰褐色，腹部白色。幼鸟背部带有斑驳的棕色图案，腹部有黑色斑点。成鸟翼展可达33-40厘米，喙和腿均为黑色，飞行时可见明显的白色翼带。","call":"发出响亮且略带嗡嗡声的“dzeer！”叫声。","habits":"黑腹滨鹬栖息于北极和亚北极地区的湿地和潮间带，全年可见其身影。它们以蛤蜊、蠕虫、昆虫幼虫和浮游生物为食，反映出其对沿海环境的依赖。冬季时，部分群体会向内陆移动，如加州中央谷地和墨西哥湾沿岸州份。","breeding":"繁殖期在5月至8月，黑腹滨鹬在苔原沼泽或湖泊岸边的苔藓地和草丛中筑巢，通常每窝产卵4枚，孵化期约21-22天。雏鸟出生后不久就能行走，约25天后能飞翔。雌雄共同承担孵化任务。","identification":"与弯嘴滨鹬相比，黑腹滨鹬腰部颜色更深，腿更短，胸部颜色更暗。与阔嘴鹬相区别，黑腹滨鹬腿较粗，头部色彩单调，仅有一道眉纹。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美洲北部、欧洲北部、亚洲北部的湿苔原地带，越冬于北美洲东西海岸、非洲北部、中东、南亚、东亚沿海及日本等地。","other":"黑腹滨鹬在全球范围内分布广泛，尽管某些亚种数量似乎有所下降，但总体上种群数量庞大。"},{"name":"岩滨鹬","english_name":"Rock Sandpiper","scientific_name":"Calidris ptilocnemis","overview":"岩滨鹬（英文名：Rock Sandpiper，学名：Calidris ptilocnemis），是鸻形目丘鹬科滨鹬属的鸟类。分布于西伯利亚东北部、阿拉斯加及阿留申群岛繁殖，越冬于美国西部沿海。具有独特的黑色腹部斑点，尤其是普里比洛夫群岛的亚种表现得更为明显。","appearance":"岩滨鹬拥有短而黄色的腿，中等长度的薄而暗色的喙。繁殖季节，背部呈暗色带有轻微的紫红色光泽，腹部主要为白色。胸部有灰色斑点，臀部为黑色。普里比洛夫群岛亚种有明显的黑色腹部斑块。非繁殖季节，上体颜色较淡，带有灰色斑点。幼鸟背部羽毛边缘呈肉桂色，胸部有褐色斑点。","habits":"岩滨鹬冬季栖息于沿海裸岩，较少出现在沙滩上。它们喜欢群居，常与翻石鹬和其他涉禽混群。其食性与生活习性尚未完全清楚。繁殖于苔原地区，偏好干燥且植被稀少的环境。","breeding":"繁殖期在6月至7月间，岩滨鹬在岩石海岸地区的苔藓地上筑巢，巢穴位于凹坑内，直径约7-8厘米，深度约5厘米。每窝产卵3-4枚，卵的大小约为35-43x24-28毫米，雌雄鸟轮流孵化，孵化期大约为20天。","identification":"岩滨鹬与紫滨鹬极为相似，但分布范围不同，没有重叠。岩滨鹬在繁殖季节有不规则的黑色腹部斑点，而非均匀的条纹状。非繁殖季节，岩滨鹬的胸部斑点更不明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于远北太平洋的极北亚北极至亚寒带苔原：从俄罗斯的楚科茨半岛东部到堪察加半岛南部，以及指挥官群岛和可能的北千岛群岛，阿留申群岛和白令海岛屿，以及阿拉斯加的苏厄德半岛到阿拉斯加湾岛屿。越冬于北海道（日本北部，太平洋西部北部，罕见）至美国加利福尼亚州中部的岩石亚北极至温带海洋海岸线。"},{"name":"紫滨鹬","english_name":"Purple Sandpiper","scientific_name":"Calidris maritima","overview":"紫滨鹬（英文名：Purple Sandpiper，学名：Calidris maritima），是鸻形目丘鹬科滨鹬属的鸟类。广泛分布于北极和亚北极区域的海岸线。其繁殖地遍布加拿大北部岛屿、格陵兰、冰岛、斯瓦尔巴群岛、挪威北部、瑞典、芬兰、俄罗斯西北部直至西伯利亚泰米尔半岛。冬季迁徙至大西洋两岸的岩石海岸，南至美国南卡罗来纳州和欧洲伊比利亚半岛北部。紫滨鹬的体型略胖，身长20-22厘米，翼展42-46厘米，体重介于50-105克之间，具有独特的黄色基部喙和腿，背部暗灰色带有紫色光泽，腹部白色，胸腹部点缀着灰色斑点。","appearance":"紫滨鹬体型紧凑，喙和腿长度适中，翅膀窄而尾巴相对较短。繁殖季节，其上体呈现复杂的‘枯草’图案，由淡褐色、浅黄色和黑色区域构成；非繁殖季节则以深石板灰为主，隐约可见紫色光泽，尤其是在良好的光照条件下。下体白色或淡黄色，秋季羽色较春季更为浅淡。雌雄差异不大，但在喙长上雌鸟略占优势。成鸟在繁殖季节背部和肩羽边缘带红棕色，非繁殖季全身呈现丰富的石板灰色调。幼鸟上体羽毛边缘呈淡色，赋予鳞片状外观。","call":"紫滨鹬的叫声描述在现有资料中未提及。","habits":"紫滨鹬主要栖息于多雾的北极高地，包括北美东部和北欧的海岸线。它们偏好岩石海岸，常在潮间带活动，低潮时觅食水生无脊椎动物。迁徙期间，也会在岸边的海藻堆中觅食。冬季，它们群居于大西洋沿岸的岩石地带。","breeding":"紫滨鹬可在一年龄时开始繁殖。雄鸟会在地面挖掘多个巢穴，雌鸟选择其中一个并产下3到4枚橄榄色带有棕色斑点的蛋，大小约为37毫米×26毫米。雄鸟承担主要的孵卵责任，孵化期大约为21-22天。雏鸟覆盖着密集的绒毛，能够自我喂食。已知欧洲记录中最长寿的紫滨鹬达到20岁零9个月。","identification":"紫滨鹬与岩滨鹬关系密切，但两者在羽毛颜色、斑纹和叫声上有明显区别。紫滨鹬的上体更暗，缺乏岩滨鹬的黑色胸部和腹部斑块，且拥有更窄的白色翼纹。在基本羽衣中，紫滨鹬上体更深色，下体的斑点模式更加模糊和平淡。此外，紫滨鹬的腿和喙基部颜色更偏向橙色，而非岩滨鹬的黄绿色或橄榄色。","protection":"IUCN：LC（无危）","distribution":"繁殖区：横跨北大西洋和北极洋的高至低海拔北极地带，包括格陵兰（除东北部）、冰岛、扬马延岛、贝尔岛、斯瓦尔巴群岛、挪威北部、斯堪的纳维亚半岛、远西北俄罗斯、弗兰格尔岛和新地岛（俄西北西伯利亚）、北地群岛和泰米尔半岛（北西伯利亚）。非繁殖区：沿大西洋岩石海岸，从拉布拉多和圣劳伦斯湾（加拿大东南部）至美国北卡罗来纳州（西大西洋）。","other":"紫滨鹬是晚迁徙的鸟类，冬季选择无冰的岩石海岸栖息。它们在迁徙和冬季时形成小群体，经常与红翻石鸟混群。"},{"name":"黑腰滨鹬","english_name":"Baird's Sandpiper","scientific_name":"Calidris bairdii","overview":"黑腰滨鹬（英文名：Baird's Sandpiper，学名：Calidris bairdii），是鸻形目丘鹬科滨鹬属的小型鹬类。其名称源于19世纪自然学家Spencer Fullerton Baird，他曾任史密森学会助理秘书。黑腰滨鹬拥有独特的黑色腰部斑块，头部和胸部呈淡棕色并带有深色条纹，冬季时整体变为较浅的棕灰色。在北极苔原地带繁殖，从东西伯利亚到格陵兰西部均有分布，冬季则迁徙至南美洲。","appearance":"黑腰滨鹬体型较小，长约14-18厘米，胸部宽阔，拥有短而略下垂的全黑色喙，腿短，体态水平，翅膀长，超过尾尖，赋予其瘦长外观。成鸟夏季羽毛上部呈黑褐色，背部宽大鳞片状花纹，边缘泛着淡黄褐色，使背部呈现银色底色上的黑色斑点。胸部灰黄褐色，均匀分布深褐色条纹，侧面尤为明显。冬季羽毛颜色较为暗淡，鳞片状花纹更加明显。幼鸟羽毛色调偏灰，背部和翼覆羽的\"鳞片\"更窄且边缘更白。","habits":"黑腰滨鹬栖息于干燥的海滩边缘及内陆湿地，偏好低植被覆盖的干燥地带。它们在泥滩上轻松觅食，通过视觉寻找食物，主要以昆虫为食，偶尔也会吃小甲壳类动物。在繁殖季节，它们会进行长途迁徙，从北极繁殖地直飞南美洲。","breeding":"黑腰滨鹬在高纬度的北极苔原上筑巢，通常选择干燥地点，带有低矮植被。它们具有极高的繁殖投资，雌鸟能在抵达北极后短短四天内产出相当于自身体重120%的卵，几乎不依赖储存脂肪。繁殖行为研究有限，已知信息来自少数关键研究。","identification":"与白腰滨鹬相似，但黑腰滨鹬身材更为修长，喙直且全黑，尾部黑色斑块是主要识别特征。冬季羽毛的淡黄色胸部也是区分于其他类似滨鸟的关键。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美和东西伯利亚的高北极苔原地带，包括阿拉斯加北部、加拿大北部、北极岛屿，直至格陵兰西北部。冬季迁徙至南美洲南部，分布于秘鲁南部至智利和阿根廷中部及南部。"},{"name":"小滨鹬","english_name":"Little Stint","scientific_name":"Calidris minuta","overview":"小滨鹬（英文名：Little Stint，学名：Calidris minuta），是鸻形目丘鹬科滨鹬属的体型微小的滨鹬，分布广泛，覆盖欧洲、非洲和亚洲的广大区域。其显著特征包括细长的黑腿和尖端细腻的喙。繁殖期的成鸟头部、颈部两侧和上体常带有鲜艳的锈橙色，尤其在夏季中期到晚期最为明亮。在北美洲极为罕见，偶尔漂泊至此。小滨鹬善于混迹于淡水和咸淡水湿地，有时局部成群，更多时候则单独活动。","appearance":"小滨鹬身长12-14厘米，体重17-44克，翼展28-31厘米。繁殖期的个体头部、颈部和胸部呈亮锈橙色，腿黑色。亚成鸟上体有整齐的花纹，背部通常有细白色条纹。非繁殖期的成鸟较为朴素，上体淡灰褐色，点缀深色斑点，边缘浅色；头顶灰色，有深色条纹；眼纹和颈部两侧暗淡灰色；脸和下体白色。雏鸟上体的覆羽、三级飞羽和翼覆羽有深棕色中心，边缘赤褐色和白色；背部有明显的白色“V”形标记。","call":"在繁殖地，飞行中的展示叫声是一连串快速的高音颤音，‘tree-tree-tree-tree-tree…’。常见叫声为短促的‘tip’声。","habits":"小滨鹬栖息于北极苔原的干燥地面，偏好靠近沼泽或盐沼的矮柳丛生地带，避开年降水量超过250毫米的地区。迁徙期间，它们出现在内陆小水域、河岸或沿海泥滩和海岸。冬季主要在沿海地区的河口泥滩、封闭的泻湖、潮汐溪流活动，同时也出现在内陆淡水环境，如沼泽中的开放水池、稻田和湖泊。","breeding":"小滨鹬在6月底至7月初产卵，一夫一妻制、多配偶制或一妻多夫制。巢筑于地面，可能裸露或被植被遮盖，内衬树叶和草屑。每窝产卵4枚，有时3枚，孵化期20-21天，由双亲共同孵化，但在多配偶制下仅由一方孵化。雏鸟橙色至棕红色，背部有黑色条带和密集的白色或浅色绒羽尖，下体白色；由一位家长照顾；离巢后不久开始向南迁徙。","identification":"小滨鹬与红颈滨鹬区别在于：（1）脚长，比红颈滨鹬更为夸张；（2）嘴型，较红颈滨鹬略长而尖。主要识别特征包括断开的眉斑、覆羽和三级飞羽的赤褐色边缘及清晰的黑色中央、颈侧粗糙痕迹以及背上显眼的白色‘吊带’。","protection":"IUCN：LC（无危）","distribution":"繁殖于北欧至西伯利亚北部，包括远北欧、白海沿岸、新地岛南部、俄罗斯北部至新西伯利亚群岛。越冬于地中海和非洲、阿拉伯半岛、波斯湾东至印度次大陆和缅甸，少量个体在英国东南部和马达加斯加出现。","other":"小滨鹬是《非洲-欧亚迁徙水鸟保护协定》（AEWA）所涵盖的物种之一。"},{"name":"美洲小滨鹬","english_name":"Least Sandpiper","scientific_name":"Calidris minutilla","overview":"美洲小滨鹬（英文名：Least Sandpiper，学名：Calidris minutilla），是鸻形目丘鹬科滨鹬属的鸟类。是最小的滨鹬之一，分布广泛，从阿拉斯加和加拿大北部的湿地到美国南部、中美洲、加勒比海乃至南美洲北部的沿海滩涂和内陆湿地均有其踪迹。繁殖季节时，偏好北极苔原和北方森林带的湿地环境。","appearance":"体型微小，长度约13至15厘米，体重19至30克。颈部短，喙细而短，腿色通常为黄绿色，翼展为同类中最小，仅略超出尾部。成鸟和幼鸟全身呈现褐色调，幼鸟背部带有锈色斑点，上体边缘呈淡棕色至肉桂色或锈色，下体白色，胸腹部有暗色条纹。喙黑色，尖端稍弯，腿色有时会被泥浆遮掩。","call":"发出高音调、滚动式的‘greeep！’叫声。","habits":"栖息于湿地、海岸线和内陆水域边缘的泥泞地带。繁殖季节在北极苔原和北方森林带的湿地筑巢。以小群活动为主，不形成大型密集群落。冬季迁徙路线横跨北美，东部种群可能进行不间断的跨洋迁徙，西部种群则通过北美内陆向墨西哥湾和中美洲迁徙。偏好干燥的泥滩或沼泽地的小水洼边缘。","breeding":"一夫一妻制，每年繁殖一次，筑巢于地面近水处，巢由草和苔藓构成。每窝产卵四枚，双亲共同孵化。雌鸟在幼鸟离巢前离开，有时甚至在卵孵化前就离开。幼鸟出生两周内即可独立觅食和飞行。","identification":"与长趾滨鹬相似，但体型更紧凑，颈更短，脚趾较短，颜色较为暗淡，翼上有明显翼纹。与其它小型滨鸟的区别在于其整体偏棕色、体型较小、腿较短、喙较短和腿色黄绿。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美低北极和亚北极地区的近北极苔原和泰加湿地区域，包括阿拉斯加、加拿大北部直至詹姆斯湾、昂加瓦半岛、拉布拉多和新斯科舍省。非繁殖期分布于美国南部、加勒比海、墨西哥至南美洲北部的亚热带至热带沿海泥滩和内陆湿地。","other":"在迁徙过程中，常与其他滨鸟混群，但倾向于在较干燥的环境中觅食。"},{"name":"白腰滨鹬","english_name":"White-rumped Sandpiper","scientific_name":"Calidris fuscicollis","overview":"白腰滨鹬（英文名：White-rumped Sandpiper，学名：Calidris fuscicollis），是鸻形目丘鹬科滨鹬属的鸟类。别称源自明显的白色尾上覆羽。体长约17厘米，上背具棕色鳞状纹，头顶具棕色条纹，下体白色，胸及两胁具箭头形粗纵纹。繁殖于加拿大北极地带，迁徙至南美最南端，是世界上最长距离迁徙的鸟类之一。","appearance":"体小，约17厘米长，上体呈灰褐色，背部具棕色鳞状纹，头部有棕色条纹。冬季时，棕色斑纹消失，下体几乎全为灰褐色，仅上胸部略带灰色。下体白色，胸及两侧有箭头形粗纵纹。飞行时可见全白色的尾上覆羽，腰部为灰色。喙短而略向下弯曲。雌雄外观相似，但雄鸟的喉咙更大。幼鸟与成鸟类似，但背部有更亮的赤褐色边缘。","call":"发出重复的‘pip, pip, pip…’声，以及独特的金属质感‘tzeep’音，如同两块鹅卵石相互摩擦。","habits":"栖息于沿海及内陆湿地，常与其他涉禽混群。偏好湿草甸、泥滩、沙滩、泛滥的田野以及湖泊和池塘岸边。迁徙时，利用湿地、农田和潮间带资源。在泥滩上，通过浅水和泥地探查寻找食物，有时直接从表面取食。在苔原，需在苔藓和其他植被中深挖。","breeding":"繁殖期在夏季，雌鸟在高苔原地带筑杯状巢，用苔藓、叶子和地衣装饰。雌鸟单独孵化4枚橄榄绿至绿色的蛋，平均孵化期约为22天。幼鸟孵化后一天左右便能离巢，由母鸟照顾，但需自行觅食。首次飞行在约16至17天后。","identification":"与白腰滨鹬最相似的是黑腰滨鹬，但白腰滨鹬更灰暗，翼尖更长，飞行时可见白色尾上覆羽，这是其最显著的识别特征。","protection":"IUCN：VU（易危）","distribution":"繁殖于北美高至低北极湿润苔原地带，包括阿拉斯加北坡、加拿大北部海岸至哈德逊湾西北部、班克斯岛至德文岛和巴芬岛（加拿大东北部）。非繁殖期分布于南美洲南部，包括智利南部、巴西东南部，西北至阿根廷东南部，以及福克兰群岛。","other":"白腰滨鹬是极端的长距离迁徙者，能够不间断飞行长达60小时，跨越4,000公里的距离。"},{"name":"黄胸滨鹬","english_name":"Buff-breasted Sandpiper","scientific_name":"Calidris subruficollis","overview":"黄胸滨鹬（英文名：Buff-breasted Sandpiper，学名：Calidris subruficollis），是鸻形目丘鹬科滨鹬属的鸟类。小型的滨鹬。优雅的黄褐色外观，和平的外表，拥有大眼睛和平面的脸庞。偏好干燥的上地环境而非典型的湿地，展现出与人类主导景观的兼容性，同时可能面临农业化学品的风险。繁殖于北极冻土带，从加拿大中部至德文岛，迁徙途经北美中央地带，冬季栖息于南美的阿根廷、乌拉圭及巴西。","appearance":"这是一种中等体型（18-20厘米长），类似环颈鹬的岸鸟。脸部和下体强烈呈现黄褐色；小头配以短而暗的鸽子般的喙；腿为鲜亮的黄赭色。飞行时，上翼呈黄褐色，腋下羽毛闪着耀眼的白色，与黄褐色的侧腹和腹部形成对比，下翼初级飞羽的末端有黑色条纹。雄鸟和雌鸟的羽毛相似，仅在大小和外侧初级飞羽（P10）的暗斑数量上有细微差异；幼鸟具有精细的斑点。","habits":"栖息于高纬度的北极冻土带，偏好干燥的草原环境，如耕地、牧场和高尔夫球场，而非水边。非繁殖季节常见于南美亚热带的草地。迁徙期间，可见于北美的中央地带，较为少见于海岸。它们以视觉搜寻食物，主要摄食昆虫和其他无脊椎动物。","breeding":"在开阔的北极冻土带地面筑巢，一次产四枚蛋。雄鸟有独特的展示行为，包括举起翅膀展示白色的下部，这一行为在迁徙期间也会出现，即使周围没有其他黄胸滨鹬。","identification":"与黑腰滨鹬相比，具有更长的黄色腿和更加均匀的黄褐色体色，延伸至腹部。比高原鹬小，颈部和尾巴较短，没有深色面部、颈部和侧面标记。与白腰滨鹬相似，但在飞行中下翼的白色更为明显。","protection":"IUCN：VU（易危）","distribution":"繁殖于北极圈内的干燥海岸冻土带，包括远东北亚和北美北部。冬季迁徙至南美洲南部，主要分布在巴西东南部、乌拉圭和阿根廷北部、中部。全球范围内容易迷路。"},{"name":"斑胸滨鹬","english_name":"Pectoral Sandpiper","scientific_name":"Calidris melanotos","overview":"斑胸滨鹬（英文名：Pectoral Sandpiper，学名：Calidris melanotos），是鸻形目丘鹬科滨鹬属的鸟类。繁殖于北美和西伯利亚的北极湿地，冬季则迁移至南美洲南部和大洋洲。雄鸟具有可膨胀的喉囊，夏季用于展示飞行。在迁徙过程中途经中央北美洲，最终抵达南美潘帕斯草原过冬，部分个体则选择东南亚、澳大利亚和新西兰。斑胸滨鹬体型健硕，具黄绿色腿脚，喙基部呈淡色，胸部密集条纹与腹部白色形成鲜明对比。","appearance":"斑胸滨鹬为中型滨鹬，体长19-23厘米，翼展37-45厘米。雄鸟体重45-126克，雌鸟31-97克。喙稍弯且暗色，腿部呈黄绿或橄榄色。飞行时可见模糊的白色翼带和黑色臀部及尾羽上覆羽。繁殖季节雄鸟喉咙和胸部明显肿胀，站立时下垂，飞行时有节奏地膨胀。雌雄羽毛相似，但雄鸟体型大25-30%，尤其在繁殖季节更为显著。","call":"斑胸滨鹬的叫声为响亮、刺耳的'churk'或'trrit'。","habits":"栖息于潮湿的草地和沼泽边缘，偏好淡水环境。迁徙期间和冬季常见于各种湿地，包括天然和人工湿地。取食方式为视觉寻找，有时会探查。食物主要包括昆虫、蜘蛛、甲壳类和其他无脊椎动物，偶尔食用种子。","breeding":"繁殖期为6-7月，筑巢于北极冻原的干燥地面或沼泽中的土丘，巢穴藏于草丛或灌木下，较为隐蔽。每窝产卵4枚，卵色淡灰绿或皮黄绿，带褐色斑点，大小约31-39x24-27毫米。雌鸟孵化，孵化期21-23天。雏鸟早熟，孵化后不久即可行走，约21天后能飞翔。","identification":"与尖尾滨鹬相比，斑胸滨鹬体型更大，颈部更长，胸部条纹更密集，腹部与胸部界限分明。雄鸟的喉囊在繁殖季节膨胀，是辨识的一大特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极圈内的湿地，包括西伯利亚东北部楚利奇半岛和北美洲北部北极地带。冬季主要迁徙至南美洲南部，也有少量个体前往澳大利亚、新西兰等地。在中国偶有记录。","other":"斑胸滨鹬的迁徙距离可能超过30,000公里，与极地燕鸥相当。"},{"name":"半蹼滨鹬","english_name":"Semipalmated Sandpiper","scientific_name":"Calidris pusilla","appearance":"体长15-18厘米，体重约18-51.5克，翼展35-37厘米。成鸟具有黑色腿脚和短而粗直的暗色喙。背部呈深灰褐色，腹部白色，头部和颈部略带淡灰褐色。幼鸟上体呈现鳞状图案，颜色通常为灰色，带有某些淡黄色区域，偶尔会显现更明亮的红褐色调。成鸟和幼鸟的腿脚都是黑色的，但在某些情况下可能会显得灰暗或轻微泛绿或泛黄。","habits":"在繁殖季节外，它们常成群出现在泥滩、湿地、河流边缘、污水池和河口地带觅食，偏好小水生和海洋无脊椎动物为食。春季，东部繁殖者沿大西洋路线从南美东北部迁徙至北美东北海岸、美国内陆和加拿大北部的中转站，聚集能量资源完成向亚北极繁殖地的迁徙，准备产卵。秋季，形成椭圆形迁徙路径横跨西半球。","breeding":"半蹼滨鹬在繁殖地为单配偶制，领域性较强，能在短暂的极地夏季中抚养至多四只幼鸟。雌鸟产卵后不久会离开，留下雄鸟独自照料幼鸟，幼鸟自行觅食。","identification":"与西方滨鹬和美洲小滨鹬相似，主要通过体型大小、喙长和分布区域区分。西方滨鹬体型稍大，喙较长，有时尖端略微下弯；美洲小滨鹬颜色更深，呈棕色。幼鸟上体的鳞状图案有助于与其他种类的辨识。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美亚北极和北极苔原，包括加拿大北部、阿拉斯加东部和俄罗斯东北部的楚科奇半岛。冬季迁徙至南美沿海，覆盖从墨西哥特胡安特佩克地峡到智利北部以及加拉帕戈斯群岛，遍及整个加勒比海地区和从尤卡坦半岛北部到巴西东北部的西大西洋沿岸。"},{"name":"西方滨鹬","english_name":"Western Sandpiper","scientific_name":"Calidris mauri","overview":"西方滨鹬（英文名：Western Sandpiper，学名：Calidris mauri），是鸻形目丘鹬科滨鹬属的鸟类。小型滨鹬之一，以其相对较长且下垂的喙著称。繁殖季节，肩部、脸颊和头部顶部呈现丰富的赤褐色调。非繁殖期外观平淡，上体灰白，下体白色。幼鸟脸庞淡色，翼上缘有一条明亮的赤褐色羽毛带。与半蹼滨鹬相似，但后者喙较短，整体颜色更暗淡。冬季识别极为困难，但西方滨鹬头部稍大，前部较重。喙的下垂可能让人联想到黑腹滨鹬，但西方滨鹬体型更小，颜色更淡。繁殖于阿拉斯加高北极苔原。迁徙和冬季，大量群居于美洲沿岸泥滩和海滩。北美西部更为常见；在东海岸罕见。冬季出现在美国，不同于半蹼滨鹬；定期南迁至秘鲁，罕见至智利。","appearance":"小型滨鹬，体长14至17厘米，翼展35至37厘米，体重22至35克。腿黑色，趾间有小蹼。喙黑色，基部深色，尖端稍弯曲且细长，约2.5至3倍于眼后至喙基的距离。翼上有明显的窄白翼带。主翼羽折叠时短，通常仅涉及一到两根紧密排列的主翼羽尖。臀部和尾部中央黑色，外侧尾羽白色。雄鸟繁殖羽头部、背部和肩部略带赤褐色。雌鸟体型更大，喙长不成比例。基本羽和替代羽有明显差异。幼鸟羽色独特。替代羽时，肩部和通常后冠、颈背及后耳羽覆盖有广泛的亮栗色。幼鸟显示不同程度的栗色，至少在披肩羽中心和上肩羽边缘。","habits":"栖息于沿海湾和河口地带。迁徙和非繁殖季节，以海洋无脊椎动物如甲壳类、双壳类和多毛虫为食。在繁殖地，食用昆虫及其幼虫，以及沿苔原池塘和海岸泻湖边缘的水生和海洋无脊椎动物。已知西方滨鹬和其他小型滨鹬也会在潮间带环境中摄食生物膜。","breeding":"繁殖于阿拉斯加和西伯利亚东部的苔原。在地面筑巢，通常位于一些植被下。雄鸟准备多个巢穴，雌鸟选择其一产下四枚卵。双亲共同孵卵并照顾幼鸟，幼鸟自食其力。有时雌鸟会在幼鸟离巢前离开配偶和幼鸟。","identification":"西方滨鹬比美洲小滨鹬颜色更浅，更偏灰色；嘴比弯嘴滨鹬直；比青脚滨鹬的嘴长；色彩比姬滨鹬单调且深沉。","protection":"IUCN：LC（无危）","distribution":"繁殖于西伯利亚东部和阿拉斯加；越冬于墨西哥湾至美国西部沿海，南至秘鲁和加拉帕戈斯群岛（东太平洋），加拿大东南部至佛罗里达州，墨西哥湾，加勒比海岛屿和海岸至圭亚那；内陆从墨西哥中部至哥斯达黎加北部。","other":"西方滨鹬是北美洲最丰富的滨鸟物种之一，估计全球种群数量约为350万只。"},{"name":"半蹼鹬","english_name":"Asian Dowitcher","scientific_name":"Limnodromus semipalmatus","overview":"半蹼鹬（英文名：Asian Dowitcher，学名：Limnodromus semipalmatus），是鸻形目丘鹬科半蹼鹬属的鸟类。少见的大型鹬类，喙长，体型接近斑尾塍鹬。繁殖成鸟下体砖红色，上体深色并呈明显的砖红色调。非繁殖成鸟总体灰褐色，喙色相比繁殖成鸟更暗更棕。分布于沿海滩涂和开阔的沼泽，从西伯利亚到东亚，冬季南迁至东南亚和澳大利亚北部。","appearance":"成鸟体长33–36厘米，体重127–245克，翼展57–59厘米。脸、颈和胸砖红色，下腹和两胁主要白色；上体深色，边缘呈淡棕色和砖红色，有条纹而非斑点。与斑尾塍鹬类相比，喙直而长，通常黑色或褐色，亚成鸟喙基部淡色。腿黑色，区别于长嘴半蹼鹬的黄绿色腿。","call":"在繁殖地，雄鸟发出空洞、轰鸣的咕噜声，无论是在飞行还是地面，形成长串脉冲式“hr’r’r’r’r, hr’r’r’r’r”，以及哀怨的吠叫声“tye chu”和柔和的“kru-ru kru-ru”。在非繁殖地，大部分时间保持沉默，偶尔会发出柔和的“eouw”或猫叫般的“miau”叫声。","habits":"栖息于广阔的淡水湿地，如湖泊岸边或河流三角洲的淹没草地和沼泽地带，以及沿海的潮间带泥滩、泥塘和盐田。迁徙时，出现在东亚沿海、中南半岛沿海、菲律宾、婆罗洲等地。以昆虫幼虫、小鱼、软体动物和多毛纲为食，通过在浅水或湿地上行走并反复探入泥土深处觅食。","breeding":"繁殖期为5月底至6月初，通常在小型群落中繁殖，每窝产2枚蛋，偶尔3枚，孵化期约22天，由双亲共同孵化和抚养。繁殖地点可能因水位变化而有所变动。","identification":"与长嘴半蹼鹬相比，腿黑色，而后者腿黄绿色。与斑尾塍鹬类的双色喙不同，成鸟喙部黑或褐色。亚成鸟上体深色，羽缘宽且金色；下体淡色，呈黄褐色或金色调，并有整齐的深色点状和矢状纹路。","protection":"IUCN：NT（近危）国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"繁殖于西伯利亚中部、东部哈萨克斯坦，可能蒙古北部至阿穆尔地区（远东西伯利亚）和中国东北部。非繁殖期分布于泰国南部沿海、马来半岛、印尼群岛、澳大利亚北部和菲律宾（罕见）。","other":"在严重干旱期间，如蒙古和中国，大量个体出现在繁殖区北部，例如1970年代后期在贝加尔湖塞兰加三角洲有大约6000只繁殖，但到了1990年代初期数量大幅减少。"},{"name":"长嘴半蹼鹬","english_name":"Long-billed Dowitcher","scientific_name":"Limnodromus scolopaceus","overview":"长嘴半蹼鹬（英文名：Long-billed Dowitcher，学名：Limnodromus scolopaceus），是鸻形目丘鹬科半蹼鹬属的鸟类。大型鹬类。喙长，繁殖成鸟下体呈粉橙色，两侧有较细的黑白斑纹，羽毛显较深的赤色纹路和较窄的白色尖端。分布于北极圈低地至亚北极湿草甸，从东北亚到西北美洲，包括俄罗斯远东地区至楚科奇半岛，加拿大北部至努纳武特地区。迁徙和越冬时可见于北美洲温带至亚热带地区，从美国南部、墨西哥至中美洲西北部。","appearance":"长嘴半蹼鹬为中等体型，喙长且直，长度约为头部的两倍。繁殖季节成鸟头顶暗色，下体为鲜明的鲑橙色，两侧有细密的黑白条纹，上体呈混合的棕、黑和淡褐色斑点。非繁殖季成鸟全身灰褐色，腹部较淡，胸部与腹部颜色对比明显。亚成鸟总体灰褐色，翼上覆羽有赤色边缘。喙黑色，基部橄榄绿至黄绿色，脚亦为黄绿色。","call":"叫声为尖锐的‘keek’，有时会连续发出一系列音节。","habits":"长嘴半蹼鹬偏好淡水湿地，如沼泽地和沿海滩涂，尤其在繁殖期选择湿草甸或泥炭沼泽。它们以缝纫机般的动作在浅水中觅食，主要食物包括昆虫幼虫和其他小型水生生物。迁徙期间和冬季，它们出现在多种淡水环境，如湖泊、河流和湿地。","breeding":"长嘴半蹼鹬在北极圈低地至亚北极的湿草甸筑巢，每次产卵四枚，孵化期约20天。雏鸟早熟，出生数小时后即可自行觅食。雄鸟负责照料雏鸟直至它们离巢。","identification":"与短嘴半蹼鹬极为相似，但可通过尖锐的‘keek’叫声、较为驼背的体态、略长的喙和更高的身高加以区分。长嘴半蹼鹬在繁殖羽时下体更显深橙色，而短嘴半蹼鹬下体颜色较浅。此外，长嘴半蹼鹬的背部条纹更宽，而短嘴半蹼鹬的背部条纹更细碎。","protection":"IUCN：NT（近危）","distribution":"繁殖于北极圈低地至亚北极湿草甸，包括俄罗斯远东地区至楚科奇半岛，加拿大北部至努纳武特地区。非繁殖期分布于北美洲温带至亚热带地区，从美国南部、墨西哥至中美洲西北部，包括加利福尼亚南部、佛罗里达州、墨西哥湾沿岸至墨西哥坎佩切州和中美洲太平洋沿岸至哥斯达黎加西北部。","other":"长嘴半蹼鹬在19世纪后期至20世纪初曾因过度猎杀数量下降，但目前种群稳定。它们在繁殖季节有非常生动的求偶展示，雄鸟在空中追逐雌鸟，快速而敏捷地飞行，同时发出响亮的叫声。"},{"name":"短嘴半蹼鹬","english_name":"Short-billed Dowitcher","scientific_name":"Limnodromus griseus","overview":"短嘴半蹼鹬（英文名：Short-billed Dowitcher，学名：Limnodromus griseus），是鸻形目丘鹬科半蹼鹬属的鸟类。北美特有的一种中型长喙涉禽。其体形丰满，羽色随季节和亚种而异，繁殖地跨越北美的苔原湿地至树线附近的沼泽地带。在迁徙和越冬期间，可见于盐沼、海滩和泥滩等生境。","appearance":"短嘴半蹼鹬是一种中等体型的涉禽，体长23至32厘米，翼展46至56厘米，体重介于73至155克之间。成鸟背部呈深褐色，腹部为红色，尾部有黑白相间的条纹。腿为黄色。不同亚种在外观上存在细微差异，如L. g. griseus的腹部颜色较浅，L. g. hendersoni的腹部更红，L. g. caurinus则介于两者之间。冬季羽毛主要为灰色。长喙是其显著特征，长度约为头部的两倍。","call":"其叫声比长嘴半蹼鹬更为柔和，这在识别成鸟的困难情况下尤其有用。","habits":"短嘴半蹼鹬在繁殖季节偏好北美的苔原湿地和沼泽环境，而在迁徙和越冬时则出现在各种湿地，包括盐水沼泽、海滩和泥滩。它们倾向于群居，以缝纫机般的动作快速探头进食，主要食物包括昆虫、软体动物、甲壳类和海洋蠕虫，偶尔也会摄取一些植物物质。","breeding":"它们在地上筑巢，通常靠近水源。巢穴是草丛或苔藓中的浅坑，内部铺垫细草、枝条和叶子。每窝产四枚，有时三枚橄榄色至棕色的蛋。孵化期为21天，由双亲共同承担。刚孵化的绒毛幼鸟很快就会离开巢穴，母鸟可能在孵化后离开，留下雄鸟照顾幼鸟，幼鸟需自行觅食。","identification":"与长嘴半蹼鹬相比，短嘴半蹼鹬的腹部颜色更淡，且斑纹分布较少，尤其是在繁殖季节。此外，叫声也有明显差异，短嘴半蹼鹬的声音更为柔和。","protection":"IUCN：VU（易危）","distribution":"繁殖于北美北部的温带沼泽、苔原和沼泽地带，包括阿拉斯加湾沿岸、加拿大西南部的育空和不列颠哥伦比亚省西北部、艾伯塔省北部至曼尼托巴省西部以及哈德逊湾和詹姆斯湾西南部至拉布拉多西部。迁徙和越冬时分布于美国南部至巴西东北部的沿海泥滩和红树林，范围涵盖东太平洋的北加州至北秘鲁和加拉帕戈斯群岛，以及大西洋的北卡罗来纳州至巴西东北部。","other":"尽管其英文名“dowitcher”源于易洛魁语，但实际的喙长在两个物种间有重叠，仅凭这一特征难以单独区分。"},{"name":"丘鹬","english_name":"Eurasian Woodcock","scientific_name":"Scolopax rusticola","overview":"丘鹬（英文名：Eurasian Woodcock，学名：Scolopax rusticola），是鸻形目丘鹬科丘鹬属的鸟类。广泛分布于欧亚大陆温带和亚北极地区的湿润森林中。这种夜行性森林鸟，昼伏夜出，主要在夜晚飞至开阔地觅食。拥有独特而笨拙的外观，头部和颈部具有明显的斑纹，眼睛位置高，能提供360度视野。","appearance":"成鸟体长33-38厘米，翼展55-65厘米，嘴长6-8厘米，直而灵敏。羽毛呈复杂图案，上部红棕色，下部淡黄色，头上有黑色条纹而非条纹，大眼位于头部侧面，腿色从灰色到粉红色不等。雄鸟比雌鸟大，但野外无法通过视觉分辨性别差异。","call":"雄鸟在春季黄昏进行被称为“roding”的求偶飞行，发出深沉加速的叫声，随后突然发出打喷嚏般的音符。在求偶期间，也可能发出柔和的“chhrr”声或快速的‘bibbibbibbibbib’声。","habits":"栖息于阴暗潮湿的阔叶林和混交林，偏好有丰富植被的林下环境，如荆棘、冬青、金雀花和蕨类植物。在繁殖季节，选择大型未受干扰的林地，有干燥温暖的休息地、湿润的觅食区和开阔的飞行空间。冬季，它们会聚集在富含蚯蚓的永久草地上觅食。","breeding":"繁殖期为5月至7月，雄鸟通过空中求偶飞行吸引雌鸟。在森林边缘或有遮蔽的地点筑巢，每窝产卵4枚，颜色为赭色或暗沙粉红色，带有锈色或暗棕红色斑点。孵化期约23天，由雌鸟独自承担。","identification":"丘鹬与沙锥相比，体型更大，头顶和颈背具斑纹，嘴与头部比例较短。沙锥的嘴长通常是头部长度的2-3倍。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布在欧亚大陆北部，从英国北部至斯堪的纳维亚半岛，东至俄罗斯，南至伊比利亚半岛、亚速尔群岛、马德拉岛和加那利群岛西部。非繁殖区扩展至非洲北部、中东、印度南部、东亚、台湾、朝鲜半岛和日本中部。","other":"气候变化影响着丘鹬的春季迁徙时间，导致迁徙提前。过度狩猎对其欧洲种群构成威胁，尤其是在法国和意大利，年猎杀量高达数百万只，可能影响长期种群稳定性。"},{"name":"琉球丘鹬","english_name":"Amami Woodcock","scientific_name":"Scolopax mira","appearance":"琉球丘鹬体长34-36厘米，体重405-541克，翼展约66厘米。羽毛色泽变异大，可能相当暗淡，也可能比丘鹬更浅。与丘鹬相比，其翅膀更宽，胫骨更长，前额和头顶更平，嘴基更深，眼部周围有粉红色裸露皮肤（并非所有个体都有）。一般而言，颜色较少红棕色，更多橄榄棕色，整体色彩更均匀，翅膀和背羽上的暗色和灰色区域较少。头部的第一条冠纹略窄于第二条，尾部缺乏暗色亚端斑。雌鸟在Amami和Tukuno通常比雄鸟大，但尾巴长度除外。","call":"琉球丘鹬在受到惊吓时会发出类似滨鹬的“jheet”声，有时会发出更像鸭子的“ghett！”声，或是尖锐的“je je”或“vett vet-vett”，以及飞行中的响亮高音“puu”或低音“vuu”。在三月，它也会进行0.5-1公里的环领地飞行，伴随着类似丘鹬的“wart wart wart”声。","habits":"琉球丘鹬栖息于常绿阔叶山林，偏好潮湿阴凉的一级森林环境，尽管次生林也被利用。它可能还会出现在相邻的田野，包括甘蔗种植园，但这可能指的是丘鹬。后者在同一范围内越冬，但通常选择非森林生境。琉球丘鹬是非迁徙性的，但在繁殖后，幼鸟和成鸟会发生分散，怀疑雌鸟会迁移到更远的地方。","breeding":"琉球丘鹬在三月中旬至五月初筑巢。已知的地面展示行为中，单一雄鸟会在单一雌鸟附近展示，翅膀颤动下垂，头部轻轻摇晃，发出强烈的“gu”声和柔和的“ku”声。每窝产2-4枚蛋，颜色从红色到深黄褐色不等，比丘鹬的蛋更大更暗，尺寸约为48.2-50.2毫米×36.8-37.8毫米。","identification":"琉球丘鹬与丘鹬的区别在于翅膀更宽、胫骨更长、前额和头顶更平、嘴基更深，以及眼部周围可能有的粉红色裸露皮肤。颜色上，琉球丘鹬更倾向于橄榄棕色，整体色彩更均匀，翅膀和背羽上的暗色和灰色区域较少。","protection":"IUCN：VU（易危）","distribution":"琉球丘鹬的繁殖区域限于Amami-Oshima、Kakeroma、Tokuno、Okinawa和Tokashiki Island（琉球群岛北部，日本南部）。非繁殖季节，它们可能会向南迁至Okinawa岛（琉球群岛中部，日本南部）。","other":"琉球丘鹬的种群受小印度猫鼬的威胁，这种猫鼬被引入以控制毒蛇，却导致了琉球丘鹬数量的减少。"},{"name":"棕丘鹬","english_name":"Javan Woodcock","scientific_name":"Scolopax saturata","overview":"棕丘鹬（英文名：Javan Woodcock，学名：Scolopax saturata），是鸻形目丘鹬科丘鹬属的小型涉禽，分布于苏门答腊岛山区和爪哇岛西部的湿润山林中。在密林底层筑巢，偏好在苔藓覆盖的蕨类间。其数量正在减少，目前估计成年个体总数介于2500至10000之间，分散于10到50个亚群落中。","appearance":"体型较小，长度约29至31厘米，重量约189至220克。全身暗棕色，饰有密集的花纹，尤其是背部。上腹部有一小块浅色斑。头部呈赤褐色，后冠有黑色横纹，眉线为棕栗色，上体为黑褐色，具深棕色横纹，翼羽深棕色，尾羽黑褐色，末端银灰色。胸部和腹部大部分为棕色，颏部为淡黄色。上腹部的浅色区域明显，将其与同类区分开。翅膀下方全为深色。喙角褐色，尖端或呈黑褐色或石板褐色。眼睛为深褐色，腿和脚为灰色，常带些石板色或蓝灰色。","call":"具有独特的三部分鸣声，开始为低沉的‘grrrr’声，随后是爆炸性的喷嚏声‘chum！’，最后是一连串断续的哼鸣‘do-do-do-dodo-do-do-do’，总持续时间约为8.7秒。鸣声在展示飞行时从树梢发出，而非在飞行中。","habits":"生活在海拔1350至3000米的湿润山地森林中，通常在亚高山草甸的小片森林中发现。似乎不迁徙，夜间觅食，食物主要包括毛虫和蛾蛹。","breeding":"繁殖季节在湿季，大约在2月至4月期间，巢穴由苔藓构成，位于蕨类植物间的轻度灌木丛中，略高于地面。推测产卵数量为两个。其他繁殖细节未知。","identification":"与新几内亚丘鹬相比，其鸣叫声具有三部分结构，存在引子谐音，第三部分重复而无停顿，且三个部分之间无缝连接。","protection":"IUCN：NT（近危）","distribution":"分布在苏门答腊北部和中部山区以及爪哇岛西部。已知在几个保护区中存在，包括爪哇的Gunung Gede Pangrango国家公园和Gunung Gede国家公园，以及苏门答腊的Kerinci-Seblat国家公园。","other":"尽管面临来自伐木和油棕榈种植园的压力，但山地生境相对安全。"},{"name":"新几内亚丘鹬","english_name":"New Guinea Woodcock","scientific_name":"Scolopax rosenbergii","overview":"新几内亚丘鹬（英文名：New Guinea Woodcock，学名：Scolopax rosenbergii），是鸻形目丘鹬科丘鹬属的鸟类。具有深栗色上身和胸部，黑色条纹，白色腹部。体型圆胖，尾巴短，喙长。仅分布于新几内亚的湿润山地森林、邻近灌木丛及高山草甸。最常在林地地面或黄昏时的空中展示飞行中被观察到。","appearance":"体长约30厘米，体重189至220克。外观与曾经同种的棕丘鹬相似，但两者地理分布完全不同。新几内亚丘鹬是该岛上唯一的丘鹬，可能与偶尔访问亚高山沼泽的小鹬混淆，但小鹬体型更小，身体较瘦，翅膀更长更窄，下体颜色更淡，头部和背部有明显的浅色条纹。新几内亚丘鹬的羽色相对较暗，喙较长，有对比明显的羽毛图案，头部顶部和颈背密集条纹，白色下巴、脸颊和颊纹，通常在眼上方有白色斑点，大而深褐色的眼睛位于头部后方，白色腹部，有时后部变为淡黄色，下体有明显的棕色条纹；飞行时展现宽而圆的全黑翅膀；喙呈黑褐色角质，腿为深棕灰色。性别和季节差异，如果存在，以及幼鸟特征尚未描述。","call":"展示飞行时发出深沉的“grrr-grrr-grrr”叫声和细高双音节的“chuwit”声，后者经常听到。","habits":"夜间觅食，黄昏时分出现在潮湿的森林空地觅食，白天在森林地面或苔藓覆盖的树枝上睡觉，以蠕虫、幼虫和其他昆虫为食。在地面遇到时，通常非常温顺，倾向于悄悄离开而不是飞走，但如果飞走，可能会很快再次降落。","breeding":"繁殖习性知之甚少。在巴布亚新几内亚观察到的展示飞行时间为8月至9月，而在西新几内亚，3月中旬收集到了正在孵卵的雌鸟。已知的唯一巢穴位于离地约1.6米的树叶和枝条覆盖的水平枝上。一窝蛋似乎有两个显著标记的蛋，但需更多研究确认。","identification":"与小鹬区分明显，小鹬体型更小，翅膀更长更窄，下体颜色更淡，头部和背部有明显的浅色条纹。","protection":"IUCN：LC（无危）。数量估计未知，但并不罕见，只是难以察觉，因此记录不多；已知分布于Bird's Head（Vogelkop）半岛、中央山脉、Foja山脉和Huon半岛。","distribution":"分布于新几内亚山区，包括Bird's Head（Vogelkop）半岛、中央山脉、Foja山脉和Huon半岛。"},{"name":"菲律宾丘鹬","english_name":"Bukidnon Woodcock","scientific_name":"Scolopax bukidnonensis","overview":"菲律宾丘鹬（英文名：Bukidnon Woodcock，学名：Scolopax bukidnonensis），是鸻形目丘鹬科丘鹬属的鸟类。","appearance":"菲律宾丘鹬上部呈丰富的红棕色，细密地带有黑色条纹和点斑，头顶有宽广的黑色斑纹。下部颜色较淡，呈缓冲色。眼睛位于头部较高位置，且靠后，喙长，尖端灵活，能从土壤中提取蚯蚓和其他无脊椎动物。体长约30至33厘米，重量介于193至310克之间。面部为淡黄色，带有细微的暗色斑点，眼上方有一条醒目的黑色条纹，一直延伸到眼后；额头和前冠部分为浅橄榄棕色，带有暗棕色的羽毛尖端，后冠和颈背为肉桂红棕色，上面有四条黑色横杠；背部、肩羽和小翼羽为暗棕色，点缀着粉红色和肉桂红棕色的斑点，肩羽上有淡黄色的羽轴，外缘有平行的线条，形成背部两条平行的浅色线条；下背部和臀部为橄榄棕色，带有淡黄色的尖端或边缘；上尾覆羽有暗棕色、淡黄色和肉桂红棕色的斑点或条纹；上翼有中等和大型的覆羽以及飞羽为暗棕色，外缘有肉桂红棕色的缺口，内缘有较浅的缺口，图案在中等覆羽上更像条纹；下翼为暗色，飞羽上有淡色缺口，覆羽上有淡黄色的条纹；上尾为暗棕色，带有肉桂红棕色的缺口和两到三条远端的棕橄榄色条纹，尾巴下部有银灰色的末端斑点；下巴为淡黄色，喉咙和胸部为肉桂黄色，密集地带有暗棕色条纹，颈部和胸部两侧有宽大的垂直暗色区域，其余下部为淡黄色，带有暗棕色的条纹，腹部中央的暗色条纹较淡；虹膜为深棕色；喙为灰角质色；腿和脚为灰色。雌雄相似，但雌性外观略显暗淡。幼鸟特征尚未描述。","call":"在飞行展示期间发出响亮且独特的声音，是一种坚硬、金属般的颤音，间歇性地穿插一系列较低音调的哼声。","habits":"生活在海拔900至2760米的山地森林，主要活动于1260至1650米之间。在棉兰老岛的基坦格拉特山，它们栖息在蕨类植物和灌木丛以及有大量开阔地带的小型森林残余中；而在吕宋岛，主要栖息在低矮的苔藓云雾林中，直至山顶。在卡亚延岛，它们被记录在低地环境中。这种鸟主要在夜间活动，白天休息在森林地面，以地下的蚯蚓为食。","breeding":"繁殖资料有限。推测的筑巢时间可能从早期九月开始，五月发现过蛋，九月观察到雏鸟；一月和四月末分别有两个雄性的生殖腺增大，四月末和九月初有两个雌性的卵巢增大；雄鸟在黎明和黄昏时分在森林上空进行飞行展示，可能全年都有这种行为，暗示繁殖季节较长。假定的巢是一个轻微的苔藓凹陷，覆盖了一层死草和活草以及蕨类植物，类似于棕丘鹬的巢。每窝产两个蛋，关于孵化期没有信息；绒毛幼鸟与棕丘鹬最相似，但颈部侧面有一个大白色斑块；关于雏鸟期没有信息。","identification":"与其他丘鹬属鸟类相比，菲律宾丘鹬具有独特的外形特征，如头部的黑色条纹和眼纹，以及背部和翅膀上的特殊条纹和斑点。它的叫声也是区分于其他同类的重要特征。","protection":"IUCN: LC","distribution":"分布于菲律宾的吕宋岛和棉兰老岛的山区。在吕宋岛的四个省份均有记录，包括附近的卡亚延岛和巴布亚恩克拉罗岛，以及棉兰老岛的五个山区。可能广泛分布于菲律宾的湿润山地森林。"},{"name":"苏拉丘鹬","english_name":"Sulawesi Woodcock","scientific_name":"Scolopax celebensis","appearance":"苏拉威西丘鹬为中型或小型涉禽，体长约30至35厘米，翅膀短圆，上体黑色带红棕色斑纹，下体几乎无条纹，呈赭黄色。其外观与丘鹬和琉球丘鹬类似，但上体更暗，下体颜色更亮，几乎无条纹，喙和跗蹠较长且颜色深。性别差异、季节性变化和幼鸟特征尚未详细描述。","habits":"栖息于苏拉威西岛海拔1100至2500米的密集成熟山地森林中，偏好潮湿环境和竹林地带。它在受扰动时会躲藏在茂密的地面覆盖物中，或步行逃离。觅食时，它会在森林地面上的湿润区域活动，甚至在野猪挖掘的水坑中觅食。","identification":"苏拉威西丘鹬与其他丘鹬属物种的区别在于其更暗的上体色彩和更明亮、几乎无条纹的下体。喙和跗蹠的长度和颜色也是辨识要点。","protection":"IUCN：LC（无危）","distribution":"苏拉威西丘鹬仅分布于印尼苏拉威西岛的东北部和中部山区。","other":"苏拉威西丘鹬的系统学历史和确切的保护状态细节有待进一步研究。"},{"name":"摩鹿加丘鹬","english_name":"Moluccan Woodcock","scientific_name":"Scolopax rochussenii","overview":"摩鹿加丘鹬（英文名：Moluccan Woodcock，学名：Scolopax rochussenii），是鸻形目丘鹬科丘鹬属的鸟类。体型较大的森林栖息型鹬科鸟类，仅分布于印尼的奥比岛和可能的巴坎岛。其体长介于32至40厘米之间，拥有独特的黑底黄斑羽色和长而有力的喙，是所有丘鹬中最大的种类。由于栖息地严重破坏，其保育状态被列为易危。","appearance":"摩鹿加丘鹬体形短粗，具有一身隐蔽性极强的羽毛，上体黑色带有大而明亮的橙黄色斑点，下体橙黄色并有轻微的黑色斑驳。喙长而直，颜色深沉，翼展宽广，尾部短小。与同类相比，它更为庞大，色泽更亮，斑点更大更黄。雌雄差异及幼鸟特征尚未详细描述。","call":"在展示飞行中，重复发出独特而短促、湿润的颤音“titilit”，此叫声在晨昏时分最为显著。","habits":"偏好低地和山脚森林的地面，常见于沼泽森林、河流及溪谷旁，既出现在原始森林，也在选择性砍伐的次生林中栖息。主要活动于黄昏和黎明，飞行时体态沉重，尾部短小，双翼宽阔，下翼斑驳明显。食物来源不明，但据当地人推测，其饮食习性可能与印尼其他丘鹬相似。","breeding":"关于繁殖习性的信息缺失，但展示飞行在3月和7月至8月间观察到，具体繁殖细节未知。","identification":"与其他丘鹬相比，摩鹿加丘鹬体型最大，羽色更亮，上体斑点更大更黄。与苏拉威西丘鹬的区别在于体型更大，色彩更鲜明，斑点更大。","protection":"IUCN：VU（易危）","distribution":"严格限于印尼的奥比岛和可能的巴坎岛，主要分布在北摩鹿加群岛的低地和山脚森林。","other":"自1862年首次记录以来，直到2013年才被再次发现，期间仅有八份标本记录，大部分来自奥比岛。"},{"name":"小丘鹬","english_name":"American Woodcock","scientific_name":"Scolopax minor","overview":"小丘鹬（英文名：American Woodcock，学名：Scolopax minor），是鸻形目丘鹬科丘鹬属的鸟类。体型较小的冬候鸟，分布于北美东部森林及边缘地带，自加拿大南部至美国东南部。其最显著的外部特征为锈红色上体，饰以黑色、暗色及灰黄色横斑或横带斑，下体白色，布满暗色横斑。体长25-31厘米，体重介于116-279克之间。","appearance":"小丘鹬拥有圆胖的身躯，色彩斑斓的羽毛，主要为锈红色调，点缀着黑色、暗色及灰黄色的横斑或横带斑。雌雄相似，但雌鸟通常比雄鸟大。头部较大，眼睛位置较高，利于全方位视野。最显著特征为长长的喙，用于地面探查食物。幼鸟出生时体重大约12-14克，喙长14毫米，30天后与成鸟无法区分，第一年夏季时颈部和喙脚呈灰色。","call":"小丘鹬的鸣叫特征独特，包括响亮的鼻音“PEENT！”叫声，以及高空飞行时由外翼羽产生的高音颤鸣和啾啾声。","habits":"小丘鹬偏好栖息于森林、森林边缘、旧田地及湿地草地，主要分布于北美东部。它们是迁徙性鸟类，春季会进行壮观的求偶展示，雄鸟会在黄昏至黎明时分发出“PEENT！”叫声，随后进行复杂的空中表演。小丘鹬主要以蚯蚓为食，也会进食昆虫幼虫、蜗牛、蜘蛛等小型无脊椎动物。","breeding":"小丘鹬实行一雄多雌制，雄鸟在日落后高飞鸣叫吸引雌鸟。巢穴位于灌木根旁的枯枝落叶堆中，每次产卵3-4枚，孵化期为22-24天。雏鸟孵化后，亲鸟会小心守护，若遇危险，亲鸟会携带雏鸟转移至安全地点。","identification":"小丘鹬与美洲沙锥容易混淆，但小丘鹬颜色更浅，图案不那么密集。与欧洲丘鹬相比，小丘鹬体型较小，下体具条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲温带东部森林及边缘地带，从加拿大西南部至马里布省，南至德克萨斯州东南部和佛罗里达州北部。冬季迁徙至得克萨斯州东南部和佛罗里达州南部的林地和田野。","other":"小丘鹬的种群数量自1960年代以来平均每年下降超过1%，主要归咎于栖息地丧失，尤其是森林成熟和城市开发。"},{"name":"查岛沙锥","english_name":"Chatham Snipe","scientific_name":"Coenocorypha pusilla","overview":"查岛沙锥（英文名：Chatham Islands Snipe，学名：Coenocorypha pusilla），是鸻形目丘鹬科亚南极沙锥属的特有种。小型鸻鹬，仅见于新西兰查塔姆群岛的几个岛屿。其自然栖息地为温带森林和草地。","appearance":"查岛沙锥是一种小型、躯体短粗的涉禽，具有斑驳的棕色和黑色羽毛，长喙，下胸和腹部呈淡色。雌雄相似，但雌鸟体型更大，色彩更淡，图案不那么鲜艳。幼鸟的上部标记不那么明显，腿部灰色或橄榄色，喙基部颜色较淡。","call":"雄鸟的主要叫声是响亮的“chup chup”，逐渐升高至一系列二音节的“queeyoo queeyoo”。报警叫声是尖锐的“chep”，经常在夜间听到。夜间可听到独特的飞行展示叫声，名为“hakawai”。","habits":"主要栖息在有大量灌木覆盖和残余森林的地区，如莎草、藤蔓、高草和再生灌木地。夜行性，白天藏匿在密集植被中，夜晚活动于更开阔的生境，包括沿海盐沼。以蚯蚓、虾虎鱼、甲虫和昆虫幼虫为食，通过探查土壤觅食。","breeding":"繁殖期从7月至翌年4月，一雄一雌制。雄鸟进行夜间鼓翼展示飞行和喂食雌鸟。巢建在灌木或草丛下，用树叶填充，通常在莎草中。每窝产2枚蛋，有时3至4枚，孵化期18至20天。雏鸟发育缓慢，由成鸟完全喂养前2至3周，21天后能够飞行，33至47天后独立。","identification":"查岛沙锥是查塔姆群岛唯一现存的鹬类，与非常相似的奥克兰沙锥相比，体型更小，下部颜色更淡，条纹和斑点较少。雌鸟体型较大，颜色更淡，图案不那么鲜艳。","protection":"IUCN：VU（易危）。总数量估计为900至1050对，面临外来哺乳动物和新西兰秧鸡鸟的威胁，导致遗传多样性降低。","distribution":"仅分布于查塔姆群岛南部的Rangatira、Mangere、Little Mangere和Star Keys等岛屿。","other":"查岛沙锥曾广泛分布于查塔姆群岛，但在引入的掠食者影响下，种群被限制在Rangatira岛。1970年后成功地重新引入至Mangere岛。"},{"name":"北岛沙锥","english_name":"North Island Snipe","scientific_name":"Coenocorypha barrierensis","overview":"北岛沙锥（英文名：North Island Snipe，学名：Coenocorypha barrierensis），是鸻形目丘鹬科亚南极沙锥属的鸟类。特有于新西兰。这一物种仅知于单一标本，曾经被认为可能与 南岛沙锥, 斯岛沙锥, 奥克兰沙锥或查岛沙锥同种。近期分子研究建议其应被视为独立物种，形态分析间接支持了这一观点。北岛沙锥为单型种。由于波利尼西亚人抵达新西兰以及随之而来的鼠类引入，该物种在新西兰北岛大陆上灭绝。然而，在至少一个小岛上，即哈拉基湾的小巴里尔岛，该物种曾得以幸存，直到1870年在那里采集到了唯一的现存标本。自此之后，由于家猫的引入，再无记录。","protection":"IUCN：EX（灭绝）","distribution":"北岛沙锥的分布限定在新西兰的北岛，具体包括布朗斯岛北部和巴里尔岛。"},{"name":"南岛沙锥","english_name":"South Island Snipe","scientific_name":"Coenocorypha iredalei","overview":"南岛沙锥（South Island Snipe，学名：Coenocorypha iredalei）属于鸻形目丘鹬科下的亚南极沙锥属。与查岛沙锥关系紧密，历史上常被视作同种，直至近代研究揭示了其独特之处，特别是在胸腹部显著的奶油色与巧克力色条纹，以及上体更为鲜明的窄边奶油色羽缘，和带栗色的尾上覆羽，这些特征使其区别于斯岛沙锥和奥克兰沙锥。该物种现被视为单型种，即不包含亚种分类。","appearance":"南岛沙锥的特征体现在其独特的羽毛色彩和图案，特别是在下体的喉咙和胸部有着大胆的奶油色和巧克力色条纹，中胸转为带有中棕色镶边的红褐色羽毛，再往下到腹部两侧则是明显的奶油色和巧克力色的鳞状斑纹，腹部中央则为清晰的奶油色。上体羽毛边缘有明显的窄边奶油色，整体上背部呈现出更多的栗色调。","habits":"历史分布显示，南岛沙锥曾广泛存在于新西兰的南岛和斯图尔特岛，以及周围的小岛上。然而，随着波利尼西亚人抵达新西兰并引入鼠类，这种鸟在主岛上灭绝，仅在几个小岛上残存至20世纪。","protection":"IUCN：EX（灭绝）。该物种因鼠类入侵导致的栖息地丧失而在多个岛屿上消失，最终记录来自1964年初的大南角岛和普克韦卡岛。","distribution":"分布区域原包括新西兰斯图尔特岛及其周边小岛，如小摩奇岛、大南角岛等。"},{"name":"斯岛沙锥","english_name":"Snares Snipe","scientific_name":"Coenocorypha huegeli","overview":"斯岛沙锥（英文名：Snares Snipe，学名：Coenocorypha huegeli），是鸻形目丘鹬科亚南极沙锥属的鸟类。亦称为斯奈尔斯群岛沙锥或毛利语中的‘tutukiwi’，暗示其外观与行为类似迷你版的几维鸟。主要分布于新西兰南部的斯奈尔斯群岛，包括北东岛和布罗顿岛。","appearance":"斯岛沙锥是一种小型、圆胖的涉禽，体长20-23厘米，体重89-131克，翼展30-35厘米。全身覆盖着暗褐色和黑色的羽毛，腹部具有明显的横纹。上体部分细密条纹，尾羽密集横纹。喙灰黑色，基部深灰色，下颚略带粉红或棕褐色。雄鸟的腿色较浅，呈黄白色至奶油色，而雌鸟的腿则为橄榄灰色。","call":"雄鸟的领地呼唤声由一系列响亮的单音节音符组成，逐渐升高为双音节口哨声，白天常见，黄昏和黎明更为频繁，偶尔夜间也会发出。雌雄双方在巢穴交接或与幼鸟互动时会发出柔和的‘chur chur’或‘churrrr churrrr’喉咙声。","habits":"斯岛沙锥偏好生活在植被茂密的环境中，夜间会进入较为开阔的区域觅食。以土壤中的无脊椎动物为食，如蚯蚓、端足目、蜘蛛和昆虫。最活跃的时间是在清晨和夜晚，白天在草丛、苔藓和蕨类植物间觅食。","breeding":"繁殖期从11月初持续到翌年4月，孵化高峰在2月。95%的个体为一夫一妻制，有时表现为一雄多雌制。巢建在植物残骸中的自然凹陷处或由莎草和禾本科植物叶制成的杯状巢穴中。每窝产卵2枚（极少数3枚），卵色淡棕色，带有灰色、红色、棕色和深棕色斑点，孵化期约22天，由双方轮流孵化。幼鸟出生后由父母喂养约2-3周，30天后能飞行，65天后完全独立。","identification":"斯岛沙锥在其分布范围内独一无二，但与前同种的奥克兰沙锥相比，后者具有更强烈的奶油色和巧克力色条纹，且下体几乎无横纹。幼鸟的颜色比奥克兰沙锥的幼鸟更灰暗。","protection":"IUCN：NT（近危）","distribution":"斯岛沙锥原生分布于新西兰南部的斯奈尔斯群岛，包括北东岛和布罗顿岛。通过人为引入，种群已扩展至Putauhinu岛和Codfish Island/Whenua Hou。","other":"斯岛沙锥面临的主要威胁之一是El Niño事件，如1982-1983年的事件对其繁殖成功率和成鸟死亡率造成了显著影响。"},{"name":"奥克兰沙锥","english_name":"Subantarctic Snipe","scientific_name":"Coenocorypha aucklandica","overview":"奥克兰沙锥（英文名：Subantarctic Snipe，学名：Coenocorypha aucklandica），是鸻形目丘鹬科亚南极沙锥属的鸟类。小型的沙锥，主要分布在新西兰的南极圈岛屿群，包括奥克兰群岛、坎贝尔岛和安蒂波德斯群岛。其体色为棕色与黑色斑驳，具有独特的长而微弯的喙。雌雄体型差异不大，幼鸟与成鸟相似，但黑色标记和条纹较不明显。","appearance":"奥克兰沙锥身长21至24厘米，体重82至129克，翼展30至35厘米。体态紧凑，腿短，喙长且稍向下弯曲。成鸟有明显的黑色和棕色斑点，腹部呈淡黄色，幼鸟的胸部和喉咙上的黑色标记和条纹较为模糊。三个亚种在大小和标记上有细微差别。","call":"雄性奥克兰沙锥的叫声在黎明和黄昏时最为频繁，声音类似'trerk trerk trerk'，有时会升高至'queeyoo queeyoo'。Maori人称其夜间空中飞行展示为'Hakawai'，伴随空气通过展开的尾羽产生的轰鸣声。","habits":"奥克兰沙锥偏好凉温带和南极圈岛屿的环境，如草丛、湿润的林地、草甸和灌木丛，以土壤中的无脊椎动物为食，包括蚯蚓、甲壳类、蜘蛛等。它们在白天倾向于隐蔽在密集植被中，夜晚则更活跃。","breeding":"繁殖季节从8月中旬持续至4月，不同亚种的繁殖时间略有差异。雄鸟通过夜间飞行鸣叫吸引雌鸟，巢建在地面，通常藏在盾蕨或草丛下，每次产卵2枚，孵化由双亲共同承担。","identification":"与可能的迷鸟拉瑟姆沙锥相比，奥克兰沙锥体型较小，翅膀和腿更短。三个亚种在体色和腿的颜色上有差异，其中perseverance亚种在背部颜色上比其他两个亚种更深。","protection":"IUCN：NT（近危）","distribution":"分布于新西兰的南极圈岛屿，包括奥克兰群岛、坎贝尔岛和安蒂波德斯群岛。具体而言，可在斯图尔特岛东南部、奥克兰群岛和坎贝尔岛南部找到。","other":"尽管总体数量稳定，但在新入侵者的威胁下，某些亚种存在迅速灭绝的风险。"},{"name":"姬鹬","english_name":"Jack Snipe","scientific_name":"Lymnocryptes minimus","overview":"姬鹬（英文名：Jack Snipe，学名：Lymnocryptes minimus），是鸻形目丘鹬科姬鹬属的鸟类。小型涉水禽鸟，名字可能源自雄鸟名字Jack，也可能因体型较小而得名。繁殖于北极和温带泰加湿地区域，自北欧至俄罗斯东北部。越冬于大西洋和地中海沿岸欧洲、非洲、印度等地。姬鹬善于隐蔽，难以观察。","appearance":"姬鹬体型小巧，长度约18-25厘米，翼展30-41厘米，体重33-73克。其羽色呈斑驳棕色，腹部较淡。头部有暗色眼纹，背部可见黄色条纹，翅膀尖窄，飞行时可见两条黄背条纹。雌雄羽毛相似，但雄鸟在翼长、头长等特征上显著较大。","call":"姬鹬的展示飞行叫声分为三部分：快速规律的敲击声、类似马蹄疾驰的加速声，以及持续的高音哨声。这些声音具有回声效果。","habits":"姬鹬偏好繁殖于北方沼泽、湿地，如苔藓、芦苇和水生植被丰富的环境。迁徙和冬季时栖息于沙滩、沼泽、水边岛屿和农田。夜行性，白天多隐藏。受到威胁时会伪装不动，直至最后一刻才突然飞离。以蠕虫、昆虫、幼虫和软体动物为食。","breeding":"繁殖期为6月至8月，巢建于溪流附近沼泽地的土丘上，每窝产卵4枚，颜色为鸽灰或橄榄褐，带有锈色斑点。卵尺寸约为35-42x25-30毫米，由雌鸟孵化。","identification":"姬鹬与扇尾沙锥的区别在于更短的喙、无中央冠纹、背部有金色条纹。其独特的上下摆动的运动方式也是辨识要点。","protection":"IUCN：LC（无危）。欧洲估计有50万只，但确切繁殖数量较小。俄罗斯东部尤其罕见，面临湿地丧失和气候变化的威胁。","distribution":"繁殖于北欧至俄罗斯东北部的亚北极至温带泰加湿地区域，越冬于英国、欧洲沿海、非洲北部、中东和印度次大陆。","other":"姬鹬是《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》中的保护物种。"},{"name":"孤沙锥","english_name":"Solitary Snipe","scientific_name":"Gallinago solitaria","overview":"孤沙锥（英文名：Solitary Snipe，学名：Gallinago solitaria），是鸻形目丘鹬科沙锥属的鸟类。体型较大，约29至31厘米长，具有深褐色背部和苍白色脸部与腹部。繁殖于远东北亚的高海拔沼泽和溪流附近，即使在寒冷月份也能在未冻结的水域附近观察到其身影，使其成为该生境中唯一可能越冬的沙锥种类。","appearance":"孤沙锥拥有一个桶状胸部，背部呈深褐色，脸部和腹部为霜白至苍白色。雌雄体型相似，平均长度29-31厘米，体重126-227克，翼展51-56厘米。头部灰白，中央有一条细薄的顶冠纹，有时断断续续，两侧有模糊的暗色顶冠纹，眼周明显黑色，眼眉有时带有条纹。上体部分为独特的姜棕色，且有冷色调的网状花纹，与其它沙锥种整体浅棕色形成鲜明对比。翅膀、三级飞羽和尾巴较长，尾羽显眼的栗色，尾上覆羽和臀部通常颜色统一。喙为黑色，基部灰色，眼睛黑色，腿和脚绿色至黄绿色。与扇尾沙锥相比，孤沙锥颜色更深，脸上的条纹偏白而非皮黄色，体型略大。","call":"在繁殖地，孤沙锥雄鸟在展示飞行时发出独特而低沉的“chok-achocka”声，伴随由外侧尾羽产生的嗡嗡或类似吹奏的声音，这种声音可能比普通沙锥的鼓声更为尖锐。在其他时间，当受到惊吓时，最常见的叫声是较为刺耳的“pench”，与普通沙锥的声音相似，但更加粗糙响亮。","habits":"孤沙锥主要栖息于高山地带，海拔1500至5000米之间，位于树线之上，如河流谷地、草地沼泽和山区泥炭沼泽，通常靠近流水。非繁殖季节，它会下降至较低海拔的类似生境，如山脚下的未冻水域、稻田和沼泽，甚至海岸。飞行相对缓慢而有力，不会像普通沙锥和针尾沙锥那样在空中曲折飞行。以小蜗牛、蠕虫、甲虫、昆虫幼虫和蝇类为食，通过在湿草和泥地里探查来觅食，整个身体在觅食时会上下颤动。","breeding":"孤沙锥在高山上繁殖，筑建碟状干草巢于其繁殖湿地的较干燥区域，巢隐藏在密集的草丛或莎草中。繁殖期间，雄鸟会展开空中展示，包括在空中盘旋，随后进行强力俯冲，期间尾羽产生“鼓声”，这是由尾羽振动造成的。具体繁殖细节如求偶、交配、产卵、孵化和育雏等信息尚需更多研究。","identification":"孤沙锥与针尾沙锥的主要区别在于，孤沙锥的颜色更深，脸上条纹偏白而非皮黄色，体型（29厘米）略大于扇尾沙锥（26厘米）。扇尾沙锥背部两侧有亮黄色的几乎成一直线的粗纵纹。","protection":"IUCN：LC（无危）。该物种被列入俄罗斯红皮书，类别为“研究不足物种”。总体数量似乎较少，仅在西伯利亚南部局部地区较为常见。在日本，少于10,000只孤沙锥越冬；在中国和东南亚地区较为稀少。","distribution":"繁殖区分布于帕拉尔地区，从俄罗斯东部、哈萨克斯坦东部、吉尔吉斯斯坦和蒙古，东至堪察加半岛和中国东北部。非繁殖季节，孤沙锥迁徙至东北伊朗、巴基斯坦、印度北部、孟加拉国、中国东部、韩国、日本、库页岛（俄罗斯远东地区）等地。","other":"孤沙锥已被列入中国国家林业局2000年8月1日发布的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"拉氏沙锥","english_name":"Latham's Snipe","scientific_name":"Gallinago hardwickii","overview":"拉氏沙锥（英文名：Latham's Snipe，学名：Gallinago hardwickii），是鸻形目丘鹬科沙锥属的鸟类。中型迁徙性沙锥，主要特征为长喙，分布于东亚至澳大利亚的迁徙路线，是东亚洲-澳大利西亚迁徙路径上的典型代表。在日本北部繁殖，冬季主要迁徙至澳大利亚东部。","appearance":"拉氏沙锥体长29-33厘米，翼展50-54厘米，体重150-230克。其羽色由黑、棕、淡棕色和白色构成，具有隐蔽性的图案。与Swinhoe's和Pin-tailed沙锥相似，但体型略大。雌雄羽毛相似，但雄鸟稍小且具有一些性别二态性特征。幼鸟翼覆羽边缘淡黄而非红棕色。","call":"在求偶飞行（距离地面30-40米）中，雄鸟会发出独特的\"tsupiyaku tsupiyaku tsupiyaku\"和\"gwo gwo gwo gwo gwo-o-o\"叫声，后者是在鼓翅俯冲时由展开的尾羽产生的声音。此外，还有一种短促、粗糙的\"geh geh\"或\"jek jek\"声。","habits":"栖息于远东地区的温带草原、牧场、新造林和耕作区，以及澳大利亚的各种淡水湿地，包括沼泽、河流边缘、水稻田等。迁徙时可能短暂停留于海滩和其他盐碱地。高度迁徙性，迁徙路线至今仍部分未知。主要以蚯蚓、甲虫、蜘蛛和新鲜种子为食，偶尔也吃软体动物、蜈蚣和等足类动物。","breeding":"繁殖期为5月至6月初，采用独对繁殖。巢筑于干燥草地或灌木下，通常靠近沼泽地。每窝产卵4枚（2-5枚），只有雌鸟孵化，孵化期至少18天。求偶飞行壮观，包括高空飞行和一系列俯冲。","identification":"与大沙锥和针尾沙锥相比，拉氏沙锥体型较大，尾部和翅膀比例较长，形成平滑的后端。飞行时，趾不超出尾尖。尾羽仅18根，不同于大沙锥的20-22根和针尾沙锥的26根。","protection":"IUCN：NT（近危），面临湿地排水和人类活动的影响，特别是在日本和澳大利亚。自1974年以来，日本已停止狩猎。","distribution":"繁殖区位于俄罗斯远东阿穆尔地区南部、库页岛南部、千岛群岛南部，直至日本北部至九州。非繁殖季节主要分布于澳大利亚东部，包括塔斯马尼亚。","other":"历史上，拉氏沙锥曾遭受大量猎杀，尤其是在澳大利亚和日本，但现已受到全面保护。"},{"name":"林沙锥","english_name":"Wood Snipe","scientific_name":"Gallinago nemoricola","appearance":"林沙锥是一种大型、暗色的类似林鹬的沙锥，体长28-32厘米，体重142-198克，翼展46厘米。其上体呈黑色、棕色和白色交织的复杂图案，背部有明显的奶油白色标记，无论在飞行还是静止时都非常醒目。成鸟的腹部有条纹，延伸至腹部，羽色略带变化。头部有一条狭窄的淡色冠纹，上体黑色，边缘呈淡灰褐色。喙基部宽大。幼鸟与成鸟相似，但翅膀上的羽毛边缘更窄，呈现出鳞片状外观。","call":"在展示飞行中，特别是在黎明和黄昏的微光中，雄性林沙锥会发出持续的、粗糙而有节奏的‘chep, chep’声，音节间隔大约为每秒3-4个音符，每次系列可持续4-20秒。领土飞行时，这种叫声听起来更为双音节，但仍保持鼻音且几乎类似蛙鸣。","habits":"林沙锥夏季栖息于海拔1200米至4520米的高山森林地带，最高可达5000米左右，冬季则下移至低山和平原地带。常见于林间河流、水塘岸边及其附近的沼泽和草地。它性格胆小且独行，通常单独活动。飞行缓慢而笨拙，受惊后会突然飞起，飞行方向多变，常作波浪式飞行，飞不远便再次降落。","breeding":"繁殖期为5月至7月，林沙锥在海拔1200-4000米的山地森林中繁殖。它们擅长进行求偶飞行表演。巢筑于河流两岸的草地上，通常位于有蕨类植物覆盖的地面凹坑内，巢内铺有柔软的枯草。每窝产卵4枚，卵呈淡黄色，带有褐色斑点，大小约为38.0×27.O毫米。","identification":"林沙锥与大多数其他沙锥的区别在于其高海拔分布范围和特有的羽色，尤其是与孤独沙锥相比，后者颜色更加灰白，尤其是在脸部和背部。","protection":"IUCN：VU（易危）","distribution":"繁殖区域位于喜马拉雅山脉，从印度的喜马偕尔邦至中国南部，包括尼泊尔、不丹和中国东北部。非繁殖季节，林沙锥会迁至喜马拉雅山脉较低海拔的湿地和森林，偶尔出现在印度半岛和东南亚北部。","other":"林沙锥已被列入中国国家重点保护野生动物名录，保护级别为Ⅱ级（2021年2月5日）。"},{"name":"针尾沙锥","english_name":"Pin-tailed Snipe","scientific_name":"Gallinago stenura","overview":"针尾沙锥（英文名：Pin-tailed Snipe，学名：Gallinago stenura），是鸻形目丘鹬科沙锥属的鸟类。又名: 针尾鹬、中沙锥、针尾水。体型中等，长度约25-27厘米，重量介于84-182克之间，尾部特征明显，具有细长的针状外侧尾羽，仅在尾部展开时可见。栖息于湿地、湿草甸和农田，分布于北极和温带地区的苔原草地至低海拔的亚高山草甸。","appearance":"针尾沙锥的外形与扇尾沙锥和大沙锥相似，但体型略小，尾部更短，脚趾在飞行时伸出尾部更远。成鸟拥有短绿灰色的腿和长长的直立暗色喙，背部有斑驳的棕色，背部中央有奶油色条纹，腹部白色，胸部有淡黄色条纹。翅膀尖端无白色边缘，与扇尾沙锥不同。雌雄外观相似，幼鸟与成鸟相似，但翼覆羽有淡黄色边缘。","call":"被惊飞时会发出类似鸭子的叫声，音调较高且略带鼻音，比扇尾沙锥的叫声更为急促，有时缺乏喉音和滑音。","habits":"栖息于北极和北方湿润地带，包括湿地、湿地草原和矮桦树（Betula nana）覆盖的灌木苔原。冬季迁徙至印度次大陆、马来群岛、东南亚至菲律宾和西小巽他群岛。常见于稻田、潮湿洼地和红树林，偏好稍微干燥的环境。常单独或小群活动，晨昏时分在水边浅水区觅食，日间多隐蔽于草丛。食物以昆虫、昆虫幼虫、甲壳类和软体动物为主，偶尔食用作物种子和草籽。","breeding":"繁殖期为5月至7月，雄鸟进行求偶飞行，飞行时尾羽呈扇形散开并发出特殊声音。巢筑于干燥地面或湿地土丘上，主要由枯草、松针和落叶构成。每窝产卵4枚，卵色为灰白、黄色或绿色，带有大块褐色或赭色斑点。","identification":"与扇尾沙锥和大沙锥相比，体型较小，尾部更短，飞行时脚趾伸出尾部更远。翅膀无白色后缘，腿较细且黄色较少。尾羽数量和形状与扇尾沙锥和大沙锥不同，野外识别困难，需特定条件下方可明确判断。","protection":"IUCN：LC（无危）。在印度次大陆的越冬地数量估计在25,000至1,000,000只之间，东亚和东南亚也有类似数量。俄罗斯繁殖地数量稀少，实际种群规模难以评估。人类活动导致的森林变化，尤其是森林砍伐，使得其数量和分布范围略有增加。","distribution":"繁殖区位于北极苔原至温带亚高山草甸，从西北西伯利亚、东北哈萨克斯坦和北蒙古至楚科奇半岛至鄂霍次克海。非繁殖区跨越阿拉伯半岛南部、东南亚、中国东南部、台湾、朝鲜半岛、琉球群岛。","other":"在适宜的繁殖地密度较高，由于人类活动导致的栖息地变化，其数量和分布范围有所扩大。"},{"name":"大沙锥","english_name":"Swinhoe's Snipe","scientific_name":"Gallinago megala","appearance":"大沙锥是一种中等体型的沙锥，体长27-29厘米，翼展38-50厘米，体重82-164克。其羽毛呈黑色、棕色、淡褐色和白色相间的迷彩图案，初级飞羽略长于三级飞羽，外侧尾羽比针尾沙锥宽，但通常不展开。雄雌外观相似，但雌鸟的喙平均稍长。无明显的季节性变化，幼鸟与成鸟相似，但翼覆羽和三级飞羽边缘微呈白色。","call":"在展示飞行中，大沙锥会发出连续的、急促的‘cheek-cheek-cheek...’或‘kkhryu-kkhryu-kkhryu-kkhryu’声，速率约为每秒4个音节，持续约25秒，随后是持续约5秒的尾部冲刷空气产生的‘ssseeeu’声。当受到惊吓时，它会无声地起飞，很少发出声音。","habits":"大沙锥繁殖季节栖息于针叶林或落叶阔叶林中的河谷、草地和沼泽地带。非繁殖期则栖息于各种类型的浅淡水湿地，包括稻田和污水处理场，这些地方有裸露的泥地或浅水区用于觅食，附近有植被覆盖。它们主要在晚上、黎明和黄昏活动，白天则隐藏在草丛或芦苇丛中。主要食物包括昆虫、昆虫幼虫、环节动物、蚯蚓和甲壳类等小型无脊椎动物。","breeding":"繁殖期为5月至7月。繁殖期间，雄鸟进行空中求偶飞行表演，飞得很高并在高空来回盘旋，然后突然垂直下降，尾羽展开，与空气摩擦产生特殊的声音。巢置于开阔森林的草地、河谷、芦苇沼泽或林间空地，通常为浅坑，内垫枯草和落叶，每窝产卵2-5枚，卵为乳黄色、污白色或淡绿色，带有褐色或赤褐色斑点。","identification":"与针尾沙锥相比，大沙锥的尾部更长，腿更粗且多黄色，飞行时脚伸出较少。与扇尾沙锥相比，大沙锥尾端两侧白色较多，飞行时尾长于脚，翼下缺少白色宽横纹，飞行时翼上无白色后缘。与拉氏沙锥相比，大沙锥初级飞羽长过三级飞羽。","protection":"IUCN：LC（无危）。由于与其他极为相似的物种混淆以及其隐秘的行为，大沙锥的状况不确定，估计总数量在25,000到100,000只之间。在20世纪初，它在中西伯利亚的森林草原和亚泰加地区极其丰富；现在，该物种在当地分布，且在森林草原区域变得稀少，但在亚泰加区域仍然相当多。","distribution":"繁殖区位于中西伯利亚和北蒙古的温带森林边缘湿地。非繁殖期主要分布在东亚南部和东南亚，包括韩国南部、中国东南部、台湾、菲律宾、马来半岛、印度尼西亚群岛、新几内亚、澳大利亚北部、俾斯麦群岛（包括阿德米拉尔蒂群岛）、所罗门群岛、马里亚纳群岛（密克罗尼西亚北部）和帕劳至楚克（特鲁克；密克罗尼西亚西南部、东南部卡罗琳群岛）。","other":"大沙锥的识别问题，尤其是在冬季分布区与针尾沙锥的混淆，阻碍了对其状态的了解。"},{"name":"非洲沙锥","english_name":"African Snipe","scientific_name":"Gallinago nigripennis","overview":"非洲沙锥（英文名：African Snipe，学名：Gallinago nigripennis），是鸻形目丘鹬科沙锥属的鸟类。小型而健壮的涉禽。其分布于东非和南非的高海拔湿地和沼泽地带，高度介于1,700至4,000米之间。非繁殖季节时广泛分散，甚至到达沿海低地。","appearance":"体长30至32厘米，拥有粗壮的身躯和相对短腿，上部、头部和颈部有深棕色条纹和金色边缘，形成背部的线条。腹部白色，两翼覆羽有淡色边缘。喙长、直而强健，呈粉棕色，脚为黄绿色至灰绿色。雌雄相似，幼鸟仅在翼覆羽上有较淡的边缘。","call":"起飞时发出'hleep'声，繁殖时有远距离传播的'kip'叫声。","habits":"栖息于湿润山地泥沼和湿地，主要在黄昏和夜晚活动，以昆虫和蠕虫为食。受惊时会静止不动，利用其伪装融入环境，被惊扰时则快速飞行，飞行路径曲折。","breeding":"繁殖期依赖于热带雨季，主要在南半球的4月至10月间。在较干燥的繁殖地建造碟形巢，隐藏于密集的草丛或芦苇中。每次产卵3至4枚，卵呈长梨形，孵化期22至24天。","identification":"与扇尾沙锥、针尾沙锥和斑腹沙锥相比较，非洲沙锥体型较大，上部颜色更深，翼缘有白色，尾部白色更为显著。","protection":"IUCN：LC（无危）","distribution":"分布于东非、南部非洲和南非的亚热带至热带湿地。","other":"非洲沙锥的空中展示壮观，包含飞行圈旋和俯冲时由特殊尾羽振动产生的鼓声。"},{"name":"马岛沙锥","english_name":"Madagascar Snipe","scientific_name":"Gallinago macrodactyla","overview":"马岛沙锥（英文名：Madagascar Snipe，学名：Gallinago macrodactyla），是鸻形目丘鹬科沙锥属的鸟类。体型紧凑、隐秘、短腿长喙的涉禽，仅在马达加斯加东部湿润地区繁殖，海拔从海平面至约2700米，常见于700米以上。该鸟种为易危物种。","appearance":"马岛沙锥长约29-32厘米，重约216克，体形壮硕，喙长腿短。与非洲沙锥类似，但上体与下体颜色对比不那么鲜明，外侧尾羽呈灰褐色，翼下覆羽边缘灰暗，翼下深色，覆羽边缘橄榄色。成鸟的翼覆羽尖端有冷色调的橄榄棕色斑点。雌雄相似，雌鸟的喙平均比雄鸟长约10%。幼鸟的肩羽和披肩羽毛边缘较窄，颜色更浅的橄榄色。全年无季节性变化。","call":"当受惊飞起时发出粗糙的“trik”叫声。展示鸣唱为一系列加速的“kik”音符。空中展示时发出中到高音调的快速“wikwikwikwikwikwikwik...”声，每秒2-3个音符，每次持续2-4秒，有时声音渐强，伴随低沉的“woo-woo-woo”或“whor-whor-whor”声，可能是由展开的尾羽产生的机械声。受惊时发出尖锐、芦苇般或鼻音的“checka-kep ... kepkep ... kep ... kep ... kep ... kip ... kip”，最后几个音符更高且间隔更宽。","habits":"栖息于草甸和莎草覆盖的沼泽、湿地、高大纸莎草床、水道边缘和稻田（至少废弃或杂草丛生区域），海拔从海平面至约2500米。偏好密集植被和泥泞地带。似乎定居，但在圣玛丽岛可能只是访客。非繁殖季，常以4-8只小群体觅食。主要以昆虫、种子和其他植物物质为食，通过深度探入泥中觅食。","breeding":"繁殖情况知之甚少。据推测在7月至1月间产卵，可能延续至4月，全年繁殖可能性存在。巢建于干燥土堆上，铺少量草或无铺垫，直径约10厘米，曾有一例巢顶有草拱，另一次巢位高于水面60厘米。每窝产卵1-2枚，橄榄棕色至红黄色带深棕色、灰色或红色斑点，尺寸41-50毫米×29.8-34毫米。孵化期未知。雏鸟上体黑色带有肉桂色和浅色斑点，下体主要为浅色带侧翼条纹，头部主要为浅色，有深黑色和深棕色标记。","identification":"与非洲沙锥相比，上体与下体颜色对比不明显，外侧尾羽颜色更偏灰褐色。与扇尾沙锥和其他近亲相比，喙和腿均为深色，翼下覆羽边缘灰暗，翼下深色，覆羽边缘橄榄色。在马达加斯加范围内，其独特的沙锥形状使其与其他滨鸟区别开来。","protection":"IUCN：VU（易危）","distribution":"主要分布在马达加斯加东部湿地区域，从北端的Tsaratanana至南部的Mandena和西部的R Sakay，海拔高度从海平面至约2700米。","other":"总数量估计在1800-7500只之间，且数量被认为正在下降。受到栖息地转变的威胁，尤其是稻田的扩张，狩猎压力也可能是一个重要因素。在19世纪被认为是局部常见的物种。"},{"name":"斑腹沙锥","english_name":"Great Snipe","scientific_name":"Gallinago media","overview":"斑腹沙锥（英文名：Great Snipe，学名：Gallinago media），是鸻形目丘鹬科沙锥属的鸟类。体型稍大、健壮。拥有长而粗的喙，腹部带有明显的条纹，上翼有对比鲜明的图案，下翼呈深色。分布于北欧至西伯利亚一带的湿草地和山地泥炭地。迁徙期间，会在非洲热带地区的湿地停留。","appearance":"斑腹沙锥长约27至29厘米，重140至260克，翼展47至50厘米。体态丰满，比普通沙锥稍大。雄鸟和雌鸟相似，雌鸟平均略大。喙的远端有轻微下垂，上体羽毛在非繁殖季节较为暗淡，幼鸟比成鸟颜色更深，标记较少明显，腹部条纹更密集。","call":"斑腹沙锥一般在非展示区域保持沉默。在求偶展示中，雄鸟的叫声复杂，包括颤音、低沉的连续音、鼓声和呼啸声，每种声音持续约5.5秒。受到惊吓时，会发出低沉的咕噜声。","habits":"斑腹沙锥选择富含地下无脊椎动物和中等灌木覆盖的环境繁殖，常在河流谷地、泛滥平原、草甸、泥炭地、散布着灌木的苔原以及邻近沼泽或泥炭地的较干燥林地。迁徙时，它们出现在湿地、短草或湖边的芦苇丛中，包括稻田，以及山区泥炭地、机场跑道和林区内的道路。","breeding":"斑腹沙锥在5月中旬至7月初产卵，为多配偶制。雌鸟独自筑巢、孵化和照料幼鸟。巢建于地面的浅凹处，填满苔藓或草。每次产卵3至5枚，孵化期22至24天，雏鸟出生后立即独立。","identification":"斑腹沙锥与普通沙锥相比，体型更大，喙更长且厚实，腹部条纹更明显，上翼有独特的图案，下翼深色。雌雄差异不大，主要通过大小区分。","protection":"IUCN：NT（近危）","distribution":"繁殖于北欧至西伯利亚西部的亚北极至温带草甸。冬季迁徙至撒哈拉以南非洲的热带和亚热带湿地。","other":"斑腹沙锥在20世纪经历了大幅减少，尤其是在德国和丹麦，主要由于其繁殖地——泛滥平原和湿地的丧失和退化。"},{"name":"扇尾沙锥","english_name":"Common Snipe","scientific_name":"Gallinago gallinago","overview":"扇尾沙锥（英文名：Common Snipe，学名：Gallinago gallinago），是鸻形目丘鹬科沙锥属的鸟类。直译: 普通沙锥，广泛分布于旧世界北部的中小型涉禽。分布范围北至冰岛、英国北部和芬兰北部，南至葡萄牙北部、法国中部、意大利北部等地。亚洲范围内，延伸至中亚、阿富汗、中东、西伯利亚东部直至库页岛。扇尾沙锥以其独特的长喙和隐蔽的羽色著称，栖息于多种湿地环境。","appearance":"成年扇尾沙锥体长25-27厘米，翼展44-47厘米，体重80-140克。它们具有短而灰绿色的腿和异常长的深色直喙（5.5-7厘米）。身体上部呈斑驳的棕色，饰有稻黄色条纹，腹部淡色。头部有暗色眼纹，两侧有明亮的条纹。翅膀尖锐。幼鸟与成鸟相似，但翼覆羽边缘更整洁、狭窄的淡褐色，尾羽末端缺乏暗色轴纹，次级飞羽和三级飞羽有较窄的白色尖端。","call":"最常听到的叫声是在快速逃避飞行或夜间迁徙时发出的嘶哑或粗糙的“schkape”声，有时略带双音节“ska-ip”。此外，还有一种硬而尖锐的“djugg”声，常在地面或飞行中由任一性别发出，尤其是在繁殖季节。另一种类似钟表发条的‘CHIP-per-CHIP-per-CHIP-per...’声，带有空洞的质感，通常在黎明和黄昏时分持续发出。","habits":"扇尾沙锥栖息于开放的淡水或咸水沼泽地，包括丰富的草甸、湖泊和河流的边缘，湿地牧场和沼泽苔原。在繁殖季节，偏好含有草本覆盖和湿润土壤的生境，富含有机物质，倾向于在繁殖地选择相对异质的植被结构。迁徙期主要向南至非洲热带地区和南亚热带地区过冬。","breeding":"繁殖期为4月至6月，雄鸟通过展示飞行吸引雌鸟，飞行中尾羽展开并产生特有的鼓动声。巢建于地面，由雌鸟负责，通常位于草丛下或沼泽地中的土丘上，巢内铺以枯草。每窝产卵4枚，卵呈淡绿色至橄榄色，带有黑色至红棕色斑点。孵化期17-21天，由雌鸟单独承担。雏鸟孵化后不久即可行走。","identification":"扇尾沙锥与针尾沙锥、大沙锥和拉氏沙锥的区别在于后者均无扇尾沙锥所具有的白色飞羽后缘，且飞行更为缓慢和稳定。此外，扇尾沙锥的颈部、胸部和侧腹部分的标记更为浓重，飞行时翅膀更为尖锐。","protection":"IUCN：LC（无危）全球数量估计超过400万只，但在欧洲、西伯利亚西部和英国的部分地区，由于栖息地变化尤其是排水工程，种群数量有所下降。","distribution":"繁殖区遍布北极低地至欧亚大陆的温带湿地，从冰岛至英国群岛、斯堪的纳维亚半岛，向东至俄罗斯中部的楚科奇半岛、勘察加半岛、鄂霍次克海和科曼多尔群岛。在南部分布至哈萨克斯坦北部、吉尔吉斯斯坦东部、塔吉克斯坦、阿富汗、克什米尔（喜马拉雅山脉西北部）、蒙古北部和中国东北部。非繁殖区主要分布在北纬赤道以北的东半球温带至热带湿地，包括英国群岛至南欧、马卡罗尼西亚（非洲西北部）、北非、西至东非、中东、东南亚、东亚、大巽他群岛、菲律宾、台湾岛、中国大陆东部、朝鲜半岛和日本中部、南部。","other":"扇尾沙锥在历史上的俗名包括“mire snipe”、“horse gowk”、“heather bleat”和“snite”。"},{"name":"美洲沙锥","english_name":"Wilson's Snipe","scientific_name":"Gallinago delicata","overview":"美洲沙锥（英文名：Wilson's Snipe，学名：Gallinago delicata），是鸻形目丘鹬科沙锥属的鸟类。小型涉禽。其名源自美国鸟类学家亚历山大·威尔逊(Alexander Wilson)，以纪念他在鸟类学上的贡献。体长约为23至28厘米，体重介于79至147克之间，具有典型的褐色斑驳外观，上部呈暗褐色，腹部颜色较淡，脸部带有独特的条纹。广泛分布于北美，包括加拿大和美国北部，以及俄罗斯的楚科奇半岛。","appearance":"成年美洲沙锥体长约23至28厘米，翼展39至45厘米，拥有绿色偏灰色的短腿和极长的直立黑喙。背部呈现杂色的棕色，腹部颜色较浅。眼周有一条深色条纹，上方和下方各有浅色条纹。翅膀尖锐，翼外缘的白色边缘较窄。尾羽共八对，比同类物种扇尾沙锥的七对尾羽多一对。","call":"该鸟在繁殖季节进行空中求偶表演时，会发出特有的‘winnowing’声，这种声音类似猫头鹰的叫声，白天和夜晚都能听到。","habits":"美洲沙锥栖息于湿地、沼泽、苔原和潮湿的草地，偏好加拿大和美国北部的繁殖环境。它们在软泥中觅食，通过视觉或触觉寻找昆虫、蠕虫和植物材料。它们善于隐蔽，通常靠近地面植被藏匿，只有在受到威胁时才会突然飞起，以曲折的飞行模式避开捕食者。","breeding":"繁殖期间，雄鸟会在空中进行求偶展示，通过快速俯冲产生独特的声音。它们在地面上隐蔽的地方筑巢。","identification":"与扇尾沙锥相比，美洲沙锥的翼外缘白色部分更窄，尾羽数量更多，达到八对。此外，美洲沙锥的‘winnowing’声比扇尾沙锥更深沉。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美，包括美国阿拉斯加州至加拿大东部和北部，以及美国大陆。非繁殖季节则迁移至北美南部直至南美北部。","other":"尽管19世纪末曾因猎杀和栖息地破坏导致数量减少，但目前美洲沙锥的数量相对稳定，未被列为受威胁物种。"},{"name":"南美沙锥","english_name":"Pantanal Snipe","scientific_name":"Gallinago paraguaiae","overview":"南美沙锥（英文名：Pantanal Snipe，学名：Gallinago paraguaiae），是鸻形目丘鹬科沙锥属的鸟类。广泛分布于南美洲热带至亚热带湿地，自特立尼达岛、哥伦比亚中部和东部，穿过圭亚那地区至阿根廷北部和乌拉圭。","appearance":"成年南美沙锥体长26至30厘米，雄鸟体重约105至140克，雌鸟115至185克，雌鸟较雄鸟稍大。它们具有短而灰绿色的腿和非常长的直而深色的喙。上部体羽呈复杂图案，以棕色为底，混杂着淡白色、浅黄色、赤褐色和黑色。胸部和两肋为浅黄色，带有黑色标记，其余下部体羽为白色。脸部有浅棕色和深棕色条纹相间。","call":"发出缓慢的“kek..kek..kek..kek..kek...”和快速的“kekkekkekkekkekkekkek”两种chip叫声，以及飞行中的“..kek......kek...kek-kek...”短而粗糙的叫声，和逃避飞行时的“KEK.kek.kek.....kek.kek...”冲撞叫声。","habits":"南美沙锥主要栖息在湿草地草原，最高可达委内瑞拉的1300米，秘鲁的2200米，可能在玻利维亚达到2600米。它们在冬季会做短距离迁移至永久沼泽地带。通过在泥地中探查的方式觅食，以昆虫幼虫和蚯蚓为主食。","breeding":"在南美洲大部分地区繁殖，包括特立尼达岛和福克兰群岛，繁殖季节因地理位置而异，尚未完全界定。雄鸟在求偶期间会表演winnowing展示，通过高空盘旋和浅俯冲产生独特的声音。一窝通常产四枚蛋，但巢穴、孵化期和雏鸟离巢时间尚不清楚。","identification":"与麦哲伦沙锥的区别在于更暗、更少赤褐色的上体，以及更重的标记和更少的黄白色下体。其winnowing声音为模糊的颤音系列，持续约2到3秒，每10秒重复一次。","protection":"IUCN：LC（无危）","distribution":"南美沙锥分布于特立尼达岛、委内瑞拉、圭亚那地区、哥伦比亚中部和东部，向南延伸至阿根廷北部和乌拉圭，遍及南美洲热带至亚热带湿地。","other":"过去曾被视为扇尾沙锥、麦哲伦沙锥和山沙锥的亚种，现在被国际鸟类分类体系视为独立物种。"},{"name":"山沙锥","english_name":"Puna Snipe","scientific_name":"Gallinago andina","overview":"山沙锥（英文名：Puna Snipe，学名：Gallinago andina），是鸻形目丘鹬科沙锥属的鸟类。小型鸟类，分布于南美洲西部的安第斯山脉高海拔地带，从秘鲁至智利北部和阿根廷西北部的高山湿地。以隐蔽的棕色外观著称，善于在沼泽、湿地及湖岸草丛中生存。","appearance":"山沙锥体长22.5至25厘米，体重介于65至105克之间。其上体呈现复杂交织的白色、淡褐色、锈色、黑色和棕色斑纹。翅膀边缘在飞行时显现出白色。胸部及两侧为带黑色标记的淡褐色，其余腹部纯白。脸部具有鲜明的棕色眼纹。两性外观相似，幼鸟特征未详述。与南美沙锥相比，山沙锥体型略小，喙更细长，腿较短且颜色更鲜艳。","call":"山沙锥的叫声包括从地面发出的快速而柔和的“tip-tip-tip-tip...”、“cut-cut-cut-cut...”或“dyak dyak dyak .... dyuc dyuc dyuc...”。飞行中的求偶展示声由空气通过展开的尾羽产生的特殊声音，被描述为“tch’ch’ch’ch’”的长而断续的轰鸣。","habits":"山沙锥栖息于安第斯山脉的高山湿草地，偏好湿润至潮湿的环境，如沼泽河流、垫状植物沼泽、池塘、湖泊和河流的芦苇边缘，有时也会出现在相对开阔的芦苇沼泽。部分种群在南半球冬季会向东部平原迁移，具体迁徙模式尚不清楚。","breeding":"山沙锥的繁殖季节在地理上有所变化，通常在秘鲁为10月至12月，在智利北部至少包括9月。雄鸟在求偶期间会展开求偶飞行，产生独特的声响，但关于繁殖生物学的其他细节仍未知。","identification":"山沙锥与南美沙锥相比，体型更小，喙更细长，腿较短且颜色更鲜艳。与本地共存的安第斯沙锥相比，山沙锥体型较小，颜色明显较淡，腹部干净无斑点，翼缘白色可见于飞行中。","protection":"IUCN：LC（无危）","distribution":"山沙锥分布于南美洲西部的安第斯山脉，包括秘鲁、智利北部和阿根廷西北部的高山湿地。在秘鲁，分布于3000米至4600米的高海拔地区；在智利，海拔范围为2000米至5000米；在阿根廷西北部，主要分布于2000米至4000米的地带。","other":"山沙锥在厄瓜多尔仅有一笔记录，于1992年10月在西南部Zamora-Chinchipe省的最南端被目击。"},{"name":"长嘴沙锥","english_name":"Noble Snipe","scientific_name":"Gallinago nobilis","overview":"长嘴沙锥（英文名：Noble Snipe，学名：Gallinago nobilis），是鸻形目丘鹬科沙锥属的鸟类。分布于南美洲安第斯山脉高海拔地区，从委内瑞拉西部至秘鲁北部。主要栖息在高山草地湿地、沼泽和泥炭地，具有独特的羽毛图案和较长的喙。","appearance":"长嘴沙锥身长30至33厘米，体重188至197克。拥有相对较大的体型和不成比例的长喙，喙呈双色，下翼较暗，翅膀宽而圆，尾部几乎无白色。与南美沙锥相比，它更大且颜色更深，翅膀更宽，没有白色的边缘。与安第斯沙锥的区别在于白色的腹部、双色的喙、更大的白色喉部斑块，以及飞行时脚趾超出尾端。与地理上遥远的马岛沙锥相似，但胸部颜色更暖，喙基部呈浅色。雌鸟外观类似，但喙更长。幼鸟与成鸟非常相似，但翼覆羽有狭窄的棕黄色边缘。","call":"雄鸟在黎明和黄昏进行展示飞行，或者在月光下进行，飞行通常是圆形的，涉及反复俯冲，产生空洞的哨声、芦苇般或磨盘的声音，尾羽展开时发出“cor-cor-cur-cur-keh-keh”的声音，并发出芦苇般的“keekeekee”叫声。雌鸟则在地面同时发出响亮的‘kyuck-kyuck-kyuck-kyuck-kyuck-’声。","habits":"栖息于高海拔的草地湿地、沼泽和泥炭地，主要在2500至3900米的高度，有时可达4100米，也下至2000米。通常出现在树线之上或之下，特别是在安第斯草原地带。其觅食和饮食习惯尚不清楚。","breeding":"繁殖季节为3月至9月，可能主要在雨季，已知在委内瑞拉7月和哥伦比亚9月收集到鸟蛋，厄瓜多尔发现幼鸟也在9月。空中展示飞行（见鸣叫特征）；有关潜在领地行为的参考是错误的。巢穴建在干燥的草丛和苔藓土堆上的凹陷处，由草和其他植物碎片组成。可能只有两个蛋，棕色橄榄色，上面有各种深褐色斑点，尤其是较大端；雏鸟为丰富的栗色，带有黑色图案和一排排白色斑点。","identification":"与安第斯沙锥比较，长嘴沙锥整体较浅，有不带标记的白色腹部，上体部分的白色条纹更为明显，喙更长。与马岛沙锥相比，胸部更温暖的浅黄色，喙基部颜色较浅。雌雄相似，但雌鸟的喙更长。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲安第斯山脉的高海拔湿地，从委内瑞拉最西部至秘鲁北部。在哥伦比亚局部较为常见，在厄瓜多尔数量稀少，可能因过度狩猎而减少，但在科托帕克斯国家公园仍存在大量种群，在波多卡洛国家公园也有记录。在秘鲁极为罕见。","other":"长嘴沙锥完全定居，对它的了解非常有限，需要更多的研究。"},{"name":"巨沙锥","english_name":"Giant Snipe","scientific_name":"Gallinago undulata","overview":"巨沙锥（英文名：Giant Snipe，学名：Gallinago undulata），是鸻形目丘鹬科沙锥属的鸟类。主要分布在南美洲北部和东南部，包括哥伦比亚、委内瑞拉、圭亚那、苏里南、法属圭亚那至巴西东北部，以及玻利维亚东部、巴拉圭东部和巴西东南部，可能还出现在乌拉圭和阿根廷东北部。具有非常长而宽的喙，头部带有黄色底色和两条大黑纹，胸部和腹部颜色较浅，有着浓重的条纹，背部则有鲜明的红褐色和黑色线条。在繁殖季节的叫声独特，被形容为机械般的鼻音。","appearance":"巨沙锥身长可达36至47厘米，是所有鹬科中体型最大的，其喙特别长，基部宽大，与身体比例协调。头部有黄色底色，饰以两道显著的黑色条纹。胸部和腹部呈淡色，布满密集条纹，与背部鲜明的红褐色和黑色条纹形成对比。飞行时，可见其宽阔的圆形翅膀和没有白色尾羽的特征。雄雌幼鸟的羽毛特征相似，没有明显的年龄或性别差异。","call":"巨沙锥在繁殖季节的叫声独特，包括在地面发出的机械般鼻音‘aga-aga-aga’，以及飞行时产生的诡异声音‘Hori-go, Hori-go’。展示飞行时发出的声音与普通沙锥截然不同，有似人类的鼓噪哭泣声，随系列减弱，‘HO-go, go’或‘GA-ga, ga’。","habits":"巨沙锥生活在沼泽中的高植被、潮湿的草原和泛滥的草地，海拔高度可达2200米。它们可能在雨后到达某些地区，但关于其季节性迁移的直接证据很少。食物主要包括青蛙，但也有报道称其胃中含有的主要是植物物质，如草类、莎草科植物和小型果实。巨沙锥可能在夜间觅食，且通常是孤独的，但在非繁殖季节可能会更群居。","breeding":"繁殖习性了解甚少。在巴西发现的巢穴通常位于9月至翌年3月间，位于沼泽间的土丘上，直径约140至220毫米，深55至60毫米。每窝产卵1至2枚，极少数报道为2至4枚，卵色为淡奶油色至橄榄色，带有棕色斑点，尺寸大约为52.7至56.2毫米×36.6至38.5毫米，重量约43克。雏鸟全身黑色，细密地布满白色斑点。","identification":"巨沙锥与其他沙锥的区别在于其巨大的体型、圆形的翅膀和独特的背部条纹，以及白色的腹部。与共存的普通沙锥和麦哲伦沙锥相比，它的体型巨大，翅膀圆润。与安第斯、火地岛和帝国沙锥等高山种类不同，巨沙锥具有明确的背部标记和白色的腹部。","protection":"IUCN：LC（无危）。然而，在巴拉圭被认为是近危物种。尽管在某些地区数量稀少，巴西可能是其主要的种群中心。由于夜间活动和对人类接近的极度警惕，可能夸大了其稀缺的印象。在哥伦比亚和法属圭亚那局部且罕见，遭受严重的狩猎压力。在玻利维亚、阿根廷等地最近的记录显示其分布可能比预想的更为广泛。","distribution":"巨沙锥主要分布在南美洲北部和东南部的湿地和泛滥草原，包括哥伦比亚、委内瑞拉、圭亚那、苏里南、法属圭亚那至巴西东北部，以及玻利维亚东部、巴拉圭东部和巴西东南部，可能延伸至乌拉圭和阿根廷东北部。","other":"巨沙锥的大型亚种gigantea似乎正在减少，因其较大的体型使其比其他共存的沙锥更容易成为猎物。在巴拉圭的Reserva Kanguery和Mbaracayú森林自然保护区中，有两个重要的种群受到保护。"},{"name":"安第斯沙锥","english_name":"Jameson's Snipe","scientific_name":"Gallinago jamesoni","overview":"安第斯沙锥（英文名：Jameson's Snipe，学名：Gallinago jamesoni），是鸻形目丘鹬科沙锥属的鸟类。小型、健壮。主要分布于南美洲安第斯山脉的玻利维亚、哥伦比亚、厄瓜多尔、秘鲁和委内瑞拉等地，具有复杂的棕、米色和黑色羽毛图案，腹部条纹明显，喙厚实且略向下弯曲。与诺布尔沙锥不同，其腹部非白色；与帝国沙锥相比，体型较小，缺乏温暖的肉桂色。安第斯沙锥栖息于高山草甸和接近树线的矮林地带。","appearance":"体长约28.5至30厘米，体重140至252克，外观粗壮，似木鹬。头部和上部羽毛呈棕色和米色条纹，背部羽毛边缘金色形成线条，不如其他沙锥种类的条纹清晰。腹部为白色，带有棕色横纹。喙角质色，长而直，相当结实。腿和脚为黄绿色。两性相似，幼鸟与成鸟差异不大，翼覆羽边缘浅色。","call":"发出一系列尖锐急促的'kek'音节，特别是在被惊飞时。展示飞行中会发出机械声，由空气通过尾羽产生的类似远处喷气飞机的低沉噪音，伴随系列'wee-kew'音符。","habits":"生活在海拔2100至3800米的高山区，偏好潮湿环境，如沼泽森林、竹林、Polylepis树林和高山草原。可能全年留居同一地区，夜间或黄昏时分觅食，以昆虫和蠕虫为主食。","breeding":"繁殖季节从2月持续到4月初，也可能在5月和8月至11月筑巢。巢建在干燥斜坡上的精致草盘中，远离沼泽地。通常产两枚蛋，雏鸟具有明显的暗褐色图案和一些米白条纹。","identification":"与火地岛沙锥相比，体型更大，飞行姿态类似木鹬，翅膀宽大且无白色边缘。地面活动时，无明显淡色条纹，与较小的同类有显著区别。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，从委内瑞拉西部至玻利维亚北部，包括哥伦比亚圣玛塔山脉。","other":"关于其行为和生态细节的了解有限，因其羽毛颜色与栖息环境相融合，很难发现和观察。"},{"name":"暗褐沙锥","english_name":"Imperial Snipe","scientific_name":"Gallinago imperialis","appearance":"暗褐沙锥体长29-31厘米，具有厚实的身体和略下垂的长喙。上体呈黑色，带有明显的肉桂色斑纹；下体为浅黄色，布满黑色斑点，腹部颜色更淡。雄雌相似，幼鸟的羽毛特征未知。飞行时，宽大的翅膀和短尾形成鲜明对比，下腹部的条纹与深色胸部和下翼形成反差。","call":"暗褐沙锥在空中展示飞行时会发出低沉、粗糙的叫声，随后是一连串机械般的嗡嗡声。声音响亮，远距离可闻。","habits":"栖息于安第斯山脉树线附近的沼泽和潮湿的精灵森林中，高度在2745-3800米之间。在阴雨天或光线昏暗时，它们更常出现在开阔的小径上。以蠕虫和节肢动物为食，通过在厚厚的苔藓层中探查觅食。","breeding":"关于繁殖的了解有限，已知在4月初在厄瓜多尔南部发现了巢穴，由几片蕨类植物叶覆盖在泥炭苔藓上，巢中有两枚蛋。求偶展示通常持续到夜晚，观察记录显示繁殖季节可能从10月持续至翌年5月。","identification":"与同域内的其他沙锥相比，暗褐沙锥体型更大，色彩更鲜艳，缺乏头部和背部的浅色条纹，下腹部有深色条纹。","protection":"IUCN：NT（近危）","distribution":"分布于南美洲西北部的安第斯山脉，从厄瓜多尔至秘鲁，旧有记录显示曾在哥伦比亚出现。","other":"暗褐沙锥的栖息地受到火灾、放牧和农业扩张的威胁。"},{"name":"麦哲伦沙锥","english_name":"Magellanic Snipe","scientific_name":"Gallinago magellanica","overview":"麦哲伦沙锥（英文名：Magellanic Snipe，学名：Gallinago magellanica），是鸻形目丘鹬科沙锥属的鸟类。原被视为南美沙锥的亚种，现独立为一物种。广泛分布于智利中部至南部、阿根廷、火地岛及福克兰群岛，栖息于低洼潮湿的草地和沼泽地带。","appearance":"麦哲伦沙锥体型小巧，上体呈暗褐色，夹杂白色、淡黄色和红褐色条纹，下体白底带斑驳，两翼较长。脸部具有显著的浅色线条，背部条纹复杂，腹部白色，尾羽红褐色，末端白色，喙直而长，尖端黑色，腿黄色。","call":"地面发出连续的“kek kek kek kek”声，飞行展示时会发出尖锐震动的‘鼓点’音节，由尾羽振动产生。","habits":"栖息于南美洲温带湿地，如草甸、泥炭沼泽、泛滥平原和沼泽边缘。部分迁徙，冬季向北迁移至阿根廷东北部和乌拉圭。以昆虫幼虫和蚯蚓为主食，通过在泥地中探查觅食。","breeding":"繁殖期自8月至11月，筑巢于高草丛中，靠近水源。每窝产卵2枚，具体孵化期和雏鸟成长时间未知。","identification":"与南美沙锥相比，麦哲伦沙锥上体更偏黄色调，颜色更为温暖，胸腹斑点较淡，翅膀更长。飞行‘歌曲’由尾羽产生的节奏更为断续。","protection":"IUCN：LC（无危）","distribution":"分布于智利中部至南部、阿根廷、火地岛及福克兰群岛，冬季部分个体迁徙至乌拉圭。","other":"曾被归入南美沙锥，后因显著的叫声差异而被确认为独立物种。"},{"name":"翘嘴鹬","english_name":"Terek Sandpiper","scientific_name":"Xenus cinereus","overview":"翘嘴鹬（英文名：Terek Sandpiper，学名：Xenus cinereus），是鸻形目丘鹬科翘嘴鹬属的鸟类。中等体型的灰色鹬类，以其长而上翘的嘴和独特的灰背白腹外观著称。繁殖于欧亚大陆北部，冬季迁至非洲、亚洲南部及澳大利亚等地。在中国被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"体长22-25厘米，重50-126克，翼展57-59厘米。特征鲜明，嘴长而明显上翘，腿短呈橙黄至绿黄色；上体灰褐色，羽翼中心几乎黑色，尤其在肩羽处更为突出；头部、颈后、脸颊及胸侧有条纹；翅膀边缘宽阔，白色明显，无翼带。雌鸟平均体型略大。非繁殖季节成鸟色彩较为平淡，上身棕灰色，头较淡；幼鸟似繁殖成鸟，但上体更暗更棕，带有窄边的浅黄色边缘；肩羽黑色线条不那么显著。","call":"被认为是全年非常善于鸣叫的鸟。鸣唱是一系列富有旋律的变音三音节哨声，被描述为‘per-rrrr-EEEEE per-rrrrr-EEEEE’；接触和飞行时发出柔和而悠扬的‘hühühühü’声，比相似的中杓鹬叫声更柔和、更悠扬；警报时发出悠扬的‘to-li’或‘wee-we’声，或更快速拉长的‘wit-wit-wit-wit’声，反映出更大的警戒。","habits":"栖息于低地山谷，特别是在有高草和灌木柳交错的洪水平原。迁徙期间偏好沿岸泥滩、河口及小河，通常单独或成小群活动，偶尔形成较大群体。进食时与其他涉禽混群，但飞行时不混群。主要在低潮时觅食，但也会在高潮时在海滩上的海藻附近觅食。以快速的动作觅食，突然改变方向；经常摇摆；啄食沙面或水面；追逐表面移动的猎物，也使用类似矶鹬的横向扫动动作；频繁探查；经常在水边清洗猎物。","breeding":"繁殖期为5月至7月中下旬。半群居繁殖，但欧洲常单独筑巢。一夫一妻制。巢为浅凹处（100-120毫米×30-40毫米），稀疏铺以草和杂物，位于近水的开阔或矮植被中。每年一窝。产卵四枚（2-5枚），间隔1-2天产一枚，蛋色淡黄到奶油色，带有黑色或棕色斑点，平均尺寸为38.6毫米×26.6毫米。单窝；孵化期23-24天，从第三枚卵开始；性别角色不明，但可能双亲都会孵卵。雏鸟背部灰色或锈灰色，有细小的点状和斑驳的深色，头顶和背部有黑色中线，下巴、喉咙和下体白色；约15天离巢，由双亲照料。","identification":"与其他小型涉禽的区别在于其长且向上弯曲的喙和较短的橙黄色腿。在飞行中，它低飞掠过水面，翅膀拍打时向下抖动，类似于矶鹬的行为，这有助于识别。与其他同属种类相比，它的体型和颜色模式提供了一定的辨识依据。","protection":"IUCN：LC（无危）","distribution":"繁殖于芬兰、乌克兰东部经俄罗斯至楚科奇半岛东部、堪察加半岛北部及阿穆尔河地区（俄罗斯东部）。非繁殖期广泛分布于非洲南部、东非、马达加斯加地区、中东、东南亚、印尼群岛、新几内亚、澳大利亚（主要是西北部、北部和东北部）、菲律宾、中国东南部和台湾；在俾斯麦群岛、所罗门群岛、新喀里多尼亚和新西兰较为罕见。","other":"在俄罗斯的繁殖地，数量普遍至丰富，估计有1万至10万对（1975-1990年）。在巴基斯坦常见至丰富。近年来在西欧、西非和新西兰的目击次数增加，但在热带澳大利亚没有立即的栖息地威胁。"},{"name":"细嘴瓣蹼鹬","english_name":"Wilson's Phalarope","scientific_name":"Phalaropus tricolor","overview":"细嘴瓣蹼鹬（英文名：Wilson's Phalarope，学名：Phalaropus tricolor），是鸻形目丘鹬科瓣蹼鹬属的小型涉禽，为瓣蹼鹬属中体型最大者。繁殖于北美洲大草原，包括加拿大西部和美国西部。该鸟以细长的喙和独特的旋转觅食方式闻名，常在淡水中搅动以捕获小型无脊椎动物。雌鸟较雄鸟色彩鲜艳，繁殖季节头部呈灰色，颈部有橙色与黑色条纹，背部灰红相间。雄鸟色彩较淡，上体灰褐色，黑色颈纹不明显。非繁殖季节全身呈现淡灰色，腹部白色，脸部平实，腿黄色。幼鸟上体灰棕，下体白，眼后有暗斑。偏好浅水湖泊、沼泽，常群居，冬季南迁至阿根廷安第斯山脉附近的盐湖。","appearance":"细嘴瓣蹼鹬身长约为23厘米（9.1英寸），翼展可达15.3-16.9英寸（39-43厘米），体重在1.3-3.9盎司（38-110克）之间。繁殖期雌鸟头部为灰色，带有白色眉线，黑色眼纹延伸至颈部，上体灰红相间，下体白色，尾部淡灰色。雄鸟较小，上体灰褐色，缺乏雌鸟鲜明的对比色。幼鸟上体灰棕色，下体白色，眼后有一黑色斑块。冬季成鸟上体淡灰色，下体白色，保留黑色眼纹。喙直而细，腿亮黄色。","habits":"细嘴瓣蹼鹬偏好浅水环境，如湖泊、沼泽和池塘，尤其在食物稀缺时会保卫觅食地。它们在迁徙途中会在北美西部的高盐分湖泊聚集，形成巨大群落。细嘴瓣蹼鹬的饮食主要由小昆虫和甲壳类构成，觅食时采用独特旋转方式制造漩涡，以捕获食物。春季向北迁徙，秋季则南迁至南美内陆盐湖。","breeding":"细嘴瓣蹼鹬的繁殖行为颠覆了传统的性别角色，雌鸟较大且色彩鲜艳，主动追求雄鸟，占据巢区，有时甚至一妻多夫。雌鸟产卵后便开始南迁，留下雄鸟独自孵化。每窝产卵3-4枚，孵化及育雏全由雄鸟负责。幼鸟自给自足，独立觅食。","identification":"与红颈瓣蹼鹬相比，细嘴瓣蹼鹬体型更大，喙更长更细，非繁殖季节的羽毛更为淡雅。雄性细嘴瓣蹼鹬在繁殖季节的色彩不如雌鸟鲜明，背部棕色，红斑较小或缺失。雌雄两性在繁殖季节的区别在于雌鸟的头部有灰色顶冠，颈部有橙色和黑色条纹，背部灰红相间。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美的大草原地带，包括加拿大西部、中部以及美国西部和西北部。非繁殖季节迁徙至南美内陆盐湖，主要在秘鲁至阿根廷的山区盐湖，也会出现在南美西海岸，从厄瓜多尔南部到阿根廷，最南至火地岛。"},{"name":"红颈瓣蹼鹬","english_name":"Red-necked Phalarope","scientific_name":"Phalaropus lobatus","overview":"红颈瓣蹼鹬（英文名：Red-necked Phalarope，学名：Phalaropus lobatus），是鸻形目丘鹬科瓣蹼鹬属的鸟类。小型鹬类，广泛繁殖于北美洲和欧亚大陆的北极地区。以独特的水中旋转捕食无脊椎动物而闻名，雌鸟比雄鸟色彩更为鲜艳，头部、颈部和胸部呈深灰色，颈侧有红色斑块，身体其余部分带有黄褐色条纹。在非繁殖季节，上体转为灰色，下体白色，耳部有黑色斑点，背部有条纹状图案。分布于低北极至亚北极的霍拉尔克特苔原和高山苔原，冬季则迁徙至热带和亚热带海域。","appearance":"红颈瓣蹼鹬长约18厘米，具有独特的分叉趾和纤细的喙。繁殖期雌鸟上体深灰，颈侧有醒目的红色斑块，雄鸟则较为暗淡。非繁殖期成鸟上体灰色，下体白色，背部有条纹，耳部黑色斑点明显。幼鸟背部灰色，腹部淡色，眼周有黑色斑块。","call":"红颈瓣蹼鹬发出尖锐的'whit'或'twit'声。","habits":"主要栖息于北极苔原，迁徙时经过内陆湖泊或海洋，冬季在热带和亚热带海域度过。常在小群中活动，但在秋季迁徙期间可形成大规模群体。以浮游生物为食，通过在水面快速旋转搅动水体，使猎物浮至水面。","breeding":"繁殖于北极苔原，雌鸟比雄鸟大且色彩鲜艳，负责追求和争斗雄鸟。雄鸟负责筑巢、孵卵和育雏，而雌鸟可能会寻找多个配偶。巢建在小土堆的凹陷处，通常产四枚橄榄色带斑点的卵，孵化期约20天，雏鸟孵化后20天即可飞行。","identification":"与细嘴瓣蹼鹬相比，红颈瓣蹼鹬体型较小，嘴更细长，背部有金色条纹。在非繁殖期，与灰瓣蹼鹬的区别在于嘴更细，背部颜色更深，有明显的黑色耳部斑点。","protection":"IUCN：LC（无危）","distribution":"繁殖于格陵兰南部、冰岛、苏格兰（罕见）、北欧斯堪的纳维亚、北极和亚北极俄罗斯至堪察加半岛、千岛群岛和司令官岛；阿留申群岛、北极和亚北极阿拉斯加和加拿大。非繁殖期分布于阿拉伯海、波斯湾、孟加拉湾；印度尼西亚群岛海域、新几内亚北部和西部、俾斯麦群岛；以及北美太平洋沿岸至墨西哥西部和中美洲至秘鲁和加拉帕戈斯群岛。","other":"红颈瓣蹼鹬已被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"灰瓣蹼鹬","english_name":"Red Phalarope","scientific_name":"Phalaropus fulicarius","overview":"灰瓣蹼鹬（英文名：Red Phalarope，学名：Phalaropus fulicarius），是鸻形目丘鹬科瓣蹼鹬属的鸟类。学名。三种瓣蹼鹬中体型最壮实、喙最粗厚的一种。繁殖期雌鸟色彩鲜艳，类似番茄汁色，雄鸟则颜色较淡，似稀释的番茄汁。分布于北极苔原繁殖，主要在开阔海洋迁徙和越冬，很少出现在内陆。","appearance":"灰瓣蹼鹬体长约21厘米，具有独特的脚趾分叶和笔直的喙，比红颈瓣蹼鹬的喙更粗。繁殖期雌鸟上身主要为暗棕色和黑色，下身红色，两颊白色，喙黄色带黑色尖端。雄鸟色彩较为暗淡。幼鸟上身淡灰褐，下身带有浅黄色调，眼部有深色斑点。冬季羽毛上身灰色，下身白色，保留黑色眼罩，喙变为黑色。","call":"鸣声为短促的'beek'声。","habits":"灰瓣蹼鹬主要栖息于北极苔原湿地，繁殖季节结束后迁徙至温带至热带沿海水域。它们善于游泳，通常在水面快速旋转形成旋涡，借此将水底食物带到水面捕食。在非繁殖季节，常结成小群或大群活动。","breeding":"繁殖于北极海岸的苔原湿地，雌鸟在交配产卵后会离开，由雄鸟负责孵化和育雏。巢建在水边湿地或苔藓地上，一窝产卵4枚，卵色淡黄褐色，带有绿色光泽和深色斑点，孵化期14至19天。","identification":"与红颈瓣蹼鹬相比，灰瓣蹼鹬体型更大，喙更粗厚，上身颜色更淡，表面平滑。在冬季，可通过黑色眼罩、更宽的翼展和较慢的翼拍频率加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美和欧亚大陆的高北极地区，从格陵兰岛西南部、冰岛、斯瓦尔巴群岛、俄罗斯新地岛至白令海峡，阿拉斯加北部和加拿大北部，包括加拿大北极岛屿南部。越冬于太平洋和大西洋的温带至热带沿海水域，范围从北加州至智利南部，大西洋美国至佛罗里达北部，非洲西北、西、西南部的热带和南大西洋沿海水域。","other":"性别角色反转，雌鸟追求雄鸟，竞争繁殖领地。"},{"name":"矶鹬","english_name":"Common Sandpiper","scientific_name":"Actitis hypoleucos","overview":"矶鹬（英文名：Common Sandpiper，学名：Actitis hypoleucos），是鸻形目丘鹬科矶鹬属的鸟类。小型鹬类，以其独特的摆尾动作著称。繁殖于欧亚大陆温带至亚北极地区，冬季迁徙至非洲、亚洲南部及澳大利亚等地。体型较小，上体灰褐，下体洁白，肩部有明显的白色斑点，与斑腹矶鹬相区别。","appearance":"成年矶鹬体长约18-20厘米，翼展可达32-35厘米。拥有灰褐上体，白色下体，短而偏黄的腿脚，喙基部淡色，尖端暗色。冬羽更暗淡，翼部条纹更明显，仅近身观察可见。幼鸟翼部羽毛边缘呈淡黄色，上体条纹更重。雌鸟平均比雄鸟略大，但在野外难以区分。","call":"叫声为快速而尖锐的“swee-wee-wee”三音节系列，有时为两或四音节。歌唱时，声音可变，连续而快速，由重复的单元组成，有渐强和渐弱，听起来仿佛脉冲。","habits":"栖息于多种淡水环境边缘，如河流、湖泊岸边，偏好有砾石、沙子或岩石的地面，亦可见于潮间带和泥滩。独行或小群活动，迁徙期间可能形成较大群体。食性广泛，包括昆虫、甲壳类、软体动物等，偶尔食用植物物质。夜间休息，日间觅食。","breeding":"繁殖期通常在5月至6月，一夫一妻制，偶尔出现雄鸟多配偶现象。巢建在靠近淡水的地面，如沙滩上的草丛中，每窝产卵4枚，孵化期约20-23天，雏鸟早成性，约22-28天后即可离巢飞行。","identification":"与斑腹矶鹬相比，矶鹬具有更明显的肩部白色斑点，腰不为纯白，尾巴和翅膀长度不等，黑色眼线不穿过眼睛，胸部侧面无白斑。此外，其叫声和行为特征亦可作为辨识依据。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖欧洲大部分、亚洲温带至亚北极区域，南至喜马拉雅山脉北部，东至日本。非繁殖季节迁徙至非洲、东南亚、澳大利亚等地，包括地中海地区、中东、南亚、印尼群岛等。","other":"历史上曾有在乌干达筑巢的记录，但罕见。"},{"name":"斑腹矶鹬","english_name":"Spotted Sandpiper","scientific_name":"Actitis macularius","overview":"斑腹矶鹬（英文名：Spotted Sandpiper，学名：Actitis macularius），是鸻形目丘鹬科矶鹬属的小型涉禽。斑腹矶鹬广泛分布于北美洲，从北极圈南缘直至美国南部诸州。该鸟以沿水边觅食无脊椎动物而闻名，常在河流、湖泊和农业水塘边活动。繁殖季节，其下体布满浓密的斑点，成为识别特征之一。","appearance":"斑腹矶鹬体长18-20厘米，翼展37-40厘米，雌鸟体重43-50克，雄鸟34-41克。雌鸟比雄鸟重约20-25%，体型更大。繁殖季节，上体橄榄灰至褐灰色，下体白色并布满黑色斑点，斑点在雌鸟下腹更明显。非繁殖季节，上体变为灰棕色，下体仅轻微斑点或无斑点。嘴橙色带黑尖，基部冬季转为橄榄色。腿和脚黄色至粉红色。","call":"鸣唱为两至三音节的口哨声，清脆响亮。飞行时发出尖锐的\"peet-weeet\"或\"weeet-weeet-weeet\"叫声。","habits":"栖息于淡水环境周边，包括河流、湖泊、池塘边缘。迁徙期间可见于海岸地带。飞行时翼拍快速而僵硬，低于水平线。独居或小群体迁徙，非繁殖期不形成大群。食物以昆虫、甲壳类、软体动物和小型鱼类为主。","breeding":"繁殖期在春季至夏季，雌鸟先于雄鸟到达繁殖地，建立领地并吸引雄鸟。实行多配偶制，雌鸟与多个雄鸟交配，由雄鸟承担孵化和育雏责任。孵化期约为20-23天。","identification":"与矶鹬相似，但后者不显示下体斑点，且尾较长，超出翼尖。斑腹矶鹬在繁殖季节有明显下体斑点，且飞行时有独特的白色翼条。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲大部分地区，从阿拉斯加到纽芬兰，南至美国西南部和东北部。冬季迁徙至美国南部、加勒比海和南美洲，远至南美洲南部。","other":"斑腹矶鹬是北美洲分布最广泛的繁殖砂鹬，适应性强，能利用各种近水栖息地。"},{"name":"白腰草鹬","english_name":"Green Sandpiper","scientific_name":"Tringa ochropus","overview":"白腰草鹬（英文名：Green Sandpiper，学名：Tringa ochropus），是鸻形目丘鹬科鹬属的鸟类。小型涉禽，以深绿色的背部和白色的腹部为显著特征，分布广泛，从北极圈至温带的泰加湿地，冬季迁徙至欧洲南部、非洲热带、亚洲南部及东南亚地区。繁殖期多见于林地中的沼泽，迁徙时则出现在淡水和咸淡水湿地。","appearance":"成鸟体长21-24厘米，体重53-119克，翼展57-61厘米。头部、前颈、胸部及上体侧有灰色至褐色条纹，下体纯白；臀部白色，尾部白色并带有粗黑横纹。繁殖期成鸟上体有白色斑点，更为明显。雌鸟体型略大于雄鸟。非繁殖期成鸟上体斑点减少，胸前及腹部更显白色。幼鸟似成鸟，但上体有淡黄色斑点，胸部较浅，两胁无条纹，眼环白色十分醒目。","call":"鸣唱为持续、悦耳的‘weet-weet-klooi-kooi-eet-EET’声，穿插其他如‘kit-klu-ee-tit’或‘kit-klu-aa-ee’t的短语。常见叫声为音乐般的‘weet’或‘klu-eet’，有时变为更悠扬的‘weet-loo-eetl-eetl’或‘ker-leet-till-leet-leet’，通常在受惊或飞行时发出。","habits":"繁殖期栖息于山地或平原森林中的湖泊、河流、沼泽和水塘附近。非繁殖期广泛分布于淡水和咸淡水湿地，包括湖泊、河流、水塘、农田和沼泽地带。通常单独或成对活动，有时形成小群。偏好有遮蔽的环境，而非开阔地带。主要以蠕虫、虾、蜘蛛、小蚌、昆虫及幼虫等小型无脊椎动物为食，偶尔也摄食小鱼和稻谷。","breeding":"繁殖期为5月至7月。在森林中的河流、湖泊岸边或林间沼泽地带营巢，巢址多选在草丛中或树下的树根间，有时使用其他鸟类的旧巢。每窝产卵3-4枚，卵呈梨形，颜色多样，有红褐色斑点。孵化期约为20-23天，由雌雄共同承担。","identification":"与矶鹬相比，白腰草鹬无黑色眼线，肩部无白斑；与林鹬相比，白腰草鹬腿色较浅，体型较矮胖，下体点斑较少，翼下颜色更深。","protection":"IUCN：LC（无危）。广泛分布且数量不少，全球范围内不被视为威胁物种。","distribution":"繁殖于亚北极至温带泰加湿地，范围从斯堪的纳维亚半岛至东西伯利亚，经中亚至中国西北部。冬季迁徙至欧洲南部、非洲热带、中东、南亚至东南亚、东亚及菲律宾等地。","other":"白腰草鹬已被列入中国国家林业局的《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。"},{"name":"褐腰草鹬","english_name":"Solitary Sandpiper","scientific_name":"Tringa solitaria","overview":"褐腰草鹬（英文名：Solitary Sandpiper，学名：Tringa solitaria），是鸻形目丘鹬科鹬属的鸟类。体长约19-23厘米，以其独行侠般的迁徙习性和树巢育雏行为著称。繁殖于加拿大和阿拉斯加的寒带森林，冬季迁往墨西哥、中美洲及南美洲。头部有灰色条纹，眼睛周围有一圈醒目的白环，上体橄榄绿色，翅膀点缀着白色斑点。","appearance":"褐腰草鹬体长介于19至23厘米，重约31.1至65.1克。头部有灰色条纹，眼睛周围环绕着独特窄白的眼环。背部为橄榄绿色，翅膀上散布着白色、淡黄至肉桂色的斑点。鸟喙灰绿渐变为黑色尖端，腿色偏暗绿。成鸟与幼鸟在外貌上有所差异，幼鸟上体更显暖褐色，斑点较大且颜色较淡。雄雌外观相似，但雌鸟平均稍大。","call":"飞行中会发出特有的三音节哨声，清脆响亮。","habits":"褐腰草鹬偏好在淡水湿地、小水塘、溪流边缘活动，偶尔踏入齐腹深的水域觅食。食物主要包括水生及陆生无脊椎动物，如昆虫、蜘蛛、小甲壳类及软体动物。在迁徙时，表现出与众不同的孤独行为，不结成大群。","breeding":"在繁殖季节，褐腰草鹬选择树上的旧鸟巢作为育雏场所，这是其独特习性之一。一窝通常产3-5枚蛋，雏鸟出生不久便能离开巢穴。","identification":"与白腰草鹬相似，但可通过其暗色臀部和中央尾羽、以及较为沉稳的飞行姿态加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美的亚北极至温带地带，包括阿拉斯加内陆、加拿大西北至西南部、哈德逊湾与詹姆斯湾以东、五大湖以北至魁北克东部。非繁殖季节广泛分布于墨西哥、中美洲、南美洲、加勒比海地区，最南可达秘鲁中部和阿根廷东北部。","other":"褐腰草鹬有两个亚种，solitaria分布于北美东部，cinnamomea则在西部。"},{"name":"漂鹬","english_name":"Wandering Tattler","scientific_name":"Tringa incana","overview":"漂鹬（英文名：Wandering Tattler，学名：Tringa incana），是鸻形目丘鹬科鹬属的鸟类。又名: 灰鹬，中等体型（约28厘米）的灰色鹬。栖息于多岩海岸，以晃动身体进食为特征，头部不断点动。在中国罕见，仅偶见于台湾越冬，可能常被忽略并误认为是灰尾漂鹬。","appearance":"漂鹬拥有灰色的上体、下体和翅膀，脸部及颈部亦为灰色，腹部白色。其短而暗黄色的腿和暗灰色的喙在繁殖季节会呈现出重叠的条纹。成鸟在繁殖季节下体条纹明显，而非繁殖季节下体则呈单一灰色。幼鸟的羽毛具有细小的白色尖端，形成不规则的斑点状图案，且下体颜色略显不均匀。","call":"漂鹬的叫声为快速的颤音，由加速的断续音符组成，通常包含3到4个节拍，形成独特的呼叫声。","habits":"漂鹬栖息于山地溪流、湖泊、水塘岸边和海边岩石与岩礁地带，常单独或成小群活动。它们多在岩石海边、岩礁、海滨沙滩和泥地上活动和觅食，也常出入于河口沙洲、沙石河边和水边浅水处。漂鹬主要在海边觅食小型甲壳类、软体动物、蠕虫等小型海洋无脊椎动物，也会在淡水水边浅水处和草地上觅食昆虫和昆虫幼虫。","breeding":"漂鹬的繁殖期为6至7月，繁殖于阿拉斯加、北美西北部和西伯利亚东北部高原地带。巢多置于山地河流岸边沙滩、沙石地上或岩石上的凹坑内，内垫有细草茎。求偶期间雌雄鸟进行求偶飞行，迅速的在巢地上空边叫边飞翔。每窝产卵4枚，卵的颜色为灰绿色，被有暗褐色斑点。","identification":"漂鹬与灰尾漂鹬相似，但嘴较短且呈灰色，翼下颜色更深，翼伸出尾后较长。两者最好的区分方式是通过声音。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于远东俄罗斯、阿拉斯加、加拿大西北部的亚北极高山苔原带，包括楚科奇半岛（西伯利亚东北部）、阿拉斯加大陆、育空、加拿大极北地区和不列颠哥伦比亚省西北部。非繁殖季节广泛分布于太平洋，主要栖息于温带至热带的多岩太平洋海岸，分布范围从美国西部到南美洲的厄瓜多尔，包括澳大利亚东部、新几内亚东南部的卫星岛、美拉尼西亚、密克罗尼西亚和所有波利尼西亚群岛，包括夏威夷群岛，以及太平洋中的孤立岛屿。"},{"name":"灰尾漂鹬","english_name":"Grey-tailed Tattler","scientific_name":"Tringa brevipes","overview":"灰尾漂鹬（英文名：Grey-tailed Tattler，学名：Tringa brevipes），是鸻形目丘鹬科鹬属的鸟类。又称: 灰尾鹬、黄足鹬，中型鹬类。其最显著的特征是灰色的羽毛，以及独特的叫声。繁殖于东北亚的苔原地带，冬季则迁徙至东南亚至澳大利亚一带。","appearance":"灰尾漂鹬喙直且长度中等，腿短呈黄色，上体暗灰色，下体灰白色，腹部白色，具宽白眉纹在前额上方相连。繁殖季节时，下体有较淡且细的条纹，不延伸至尾下覆羽。雌鸟平均体型较大，非繁殖季节时，侧翼呈现灰白相间。","call":"灰尾漂鹬的叫声为尖锐的双音节哨音，如“too-weet”，或在受惊时发出柔和的颤音。","habits":"灰尾漂鹬繁殖期栖息于山地河流沿岸，非繁殖期则选择岩石海岸、海滨沙滩、泥地及河口。它们通常单独或成小群活动，以石蛾、毛虫、水生昆虫、甲壳类和软体动物为食，偶尔食用小鱼。飞行快速轻盈。","breeding":"繁殖期为6月至7月，营巢于河边石头间的地上凹坑或洞穴中，有时利用树上鸦科鸟类废弃的旧巢。每窝产卵4枚，由雌雄亲鸟共同孵化。","identification":"与漂鹬相似，但可通过细节如鼻沟长度和胫部的鳞片状纹理来区分。叫声也是重要的辨识特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于东北亚的苔原地带，包括西伯利亚的北部和东部。非繁殖季节迁徙至东南亚至澳大利亚，包括马来西亚半岛、印度尼西亚群岛、新几内亚地区、澳大利亚、美拉尼西亚、新西兰、密克罗尼西亚、斐济和图瓦卢。","other":"在某些地区，如澳大利亚，灰尾漂鹬的数量估计约为36,000只。"},{"name":"小黄脚鹬","english_name":"Lesser Yellowlegs","scientific_name":"Tringa flavipes","overview":"小黄脚鹬（英文名：Lesser Yellowlegs，学名：Tringa flavipes），是鸻形目丘鹬科鹬属的中型涉禽，以其独特的亮黄色长腿著称。繁殖于北美北极森林带，从阿拉斯加至魁北克，冬季迁徙至中美洲、南美洲、西印度群岛及美国南部。在中国为罕见迷鸟，偶见于香港及东部沿海地区。","appearance":"小黄脚鹬是一种中等体型的鸟类，全长约23-25厘米，翼展59-64厘米，体重67-94克。雌雄外观相似，繁殖季节上身呈灰褐、黑、白斑驳，下身白色，颈胸有棕色条纹；非繁殖季上身为均匀灰褐色，下身白色，颈胸有淡灰色条纹。最显著特征为其亮黄色的长腿。相比大黄脚鹬，其喙更短、更直，长度大致等于头部，且颜色统一为深色。","call":"叫声较柔和，不同于大黄脚鹬更强而有力的声音。","habits":"栖息于近水的开阔地带，如湿地、沼泽、池塘边的林间空地，偏好浅水环境。活动于泥滩和浅水池，有时会用喙搅动水面觅食。食物主要包括昆虫、小鱼、甲壳类、水生蠕虫、螺类、蜘蛛和种子。","breeding":"巢筑于干燥苔藓地面上的凹陷处，隐蔽良好。一窝产四枚卵，卵色为浅色基底，带有棕色斑点，平均尺寸为42毫米×29毫米。双亲共同孵化约22-23天。雏鸟早熟，出生几小时后即可离巢自行觅食，飞翔能力在23至31天后形成。","identification":"小黄脚鹬与大黄脚鹬外形相似但体型较小，叫声更为柔和。实际上，小黄脚鹬与斑翅鹬关系更近。两者主要通过体型、喙长和叫声区分。","protection":"IUCN：VU（易危）","distribution":"繁殖于北美北部亚北极森林区域，主要在阿拉斯加大陆（除最西、最北部分）至加拿大中部，东至詹姆斯湾及魁北克省。非繁殖期分布于美国南部、加勒比海、南至火地岛，包括加拉帕戈斯群岛。在中国，偶见于香港及东部沿海地区。","other":"小黄脚鹬曾是猎物，现今面临狩猎威胁，特别是在加勒比海地区，每年可能有数千只被捕杀。"},{"name":"红脚鹬","english_name":"Common Redshank","scientific_name":"Tringa totanus","overview":"红脚鹬（英文名：Common Redshank，学名：Tringa totanus），是鸻形目丘鹬科鹬属的鸟类。别名: 赤足鹬、东方红腿，直译: 普通红脚鹬，广泛分布于欧亚大陆的中型涉禽。拥有橙红色的腿和半部红色的嘴基，胸腹部带有褐色纵纹。相较于鹤鹬，红脚鹬体型更小，矮胖，嘴较短较厚，上下嘴基红色较多。飞行时，腰部的白色和次级飞羽的白色外缘格外醒目。","appearance":"红脚鹬在繁殖季节呈现出斑驳的棕色羽毛，下体颜色略浅。冬季羽毛色调转为灰褐色，上体较为素淡，下体呈白色。其最显著的特征是鲜亮的红色腿脚和黑色尖端的红色喙。飞行时，可见翼后缘的白色和腰部的白色斑块。雌雄在羽毛颜色上有细微差别，通常雌鸟上体颜色更为淡雅。","call":"红脚鹬以其响亮的哨音闻名，这种声音在繁殖季节尤其频繁，能够有效警示周围的鸟群。","habits":"红脚鹬栖息于各种淡水和沿海湿地，包括盐沼、内陆湿草地、沼泽和湿地。繁殖期间，它们偏爱靠近水源的高沼地。迁徙时，主要在海岸线活动，包括岩石、泥泞和沙滩地带。它们的食物主要包括昆虫、蜘蛛、环节动物、软体动物和甲壳类，偶尔也会捕食小鱼和蝌蚪。","breeding":"繁殖期为每年的4月至6月，红脚鹬会在靠近水域的干燥地面筑巢，每窝产卵4枚。雌鸟负责筑巢，巢穴通常位于高草丛中的密丛底部，有叶子覆盖。","identification":"与鹤鹬相比，红脚鹬体型更小，矮胖，嘴较短较厚，上下嘴基红色较多。飞行时可见翼后缘白色，而鹤鹬无白色的翼后缘。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极至温带的欧亚大陆，包括冰岛至北斯堪的纳维亚半岛，南至伊比利亚半岛南部和突尼斯沿海。非繁殖期分布于非洲、中东、东南亚至马来半岛、印尼群岛、东亚的中国、菲律宾、台湾和日本琉球群岛。","other":"红脚鹬是《非洲-欧亚迁徙水鸟保护协定》适用物种之一。"},{"name":"泽鹬","english_name":"Marsh Sandpiper","scientific_name":"Tringa stagnatilis","overview":"泽鹬（英文名：Marsh Sandpiper，学名：Tringa stagnatilis），是鸻形目丘鹬科鹬属的小型涉禽。以细长的黑色喙、白色的额部、灰色的背部和偏绿的长腿为显著特征。分布广泛，从欧洲东部到俄罗斯远东地区，在开阔的草原湿地和针叶林湿地繁殖。在迁徙期间，泽鹬会出现在北美洲的阿拉斯加和加州，罕见的迷鸟。","appearance":"泽鹬体型小巧，长度约22-26厘米，翼展55-59厘米，体重45-120克。其喙细长且直，腿长且呈黄绿色。在繁殖季节，泽鹬的羽毛呈灰褐色，冬季则颜色变淡。背部有明显的白色条纹，可见于飞行中。上体有灰色肉桂和黑棕色斑点及斑块，胸前和两侧有黑色标记。雌鸟平均比雄鸟稍大。非繁殖季节成鸟的上体为灰色，有狭窄的白色边缘，与深色的翼覆羽形成对比；脸和下体为白色。幼鸟与非繁殖季成鸟相似，但上体更棕色，有浅色斑点和边缘。","call":"泽鹬发出重复的圆润叫声，与青脚鹬类似，但更加单调且音质更为尖锐。","habits":"泽鹬偏好栖息于淡水湿地，包括草原湿地、针叶林湿地、咸水浅滩，较少见于盐湖周边。非繁殖季节，它们常出现在内陆淡水至咸水湿地的边缘，包括稻田、沼泽、盐田、盐沼、污水处理厂、河口、泻湖和潮间带泥滩，但避免开放的海滩。泽鹬通常单独或小群活动，偶尔在冬季形成较大的群体。它们在浅水中觅食，以小型脊椎动物为主食，有时也会摄取无脊椎动物和少量植物物质。","breeding":"泽鹬的繁殖期从四月底持续至六月，一般为一夫一妻制。它们可能独居或松散地聚集成群，常见于沼泽燕鸥、红脚鹬、凤头麦鸡或黑尾塍鹬的繁殖地附近。泽鹬会在距离水源不远的矮草丛中的小土堆上筑巢，巢穴呈浅凹状，直径约8.2厘米，深度约6厘米，通常铺满干草。一窝产卵4枚，卵壳颜色从奶油色到浅黄色，带有红棕色或黑棕色的斑点，平均尺寸为38.5毫米×26.9毫米。雌雄双方共同承担孵化和照料雏鸟的责任，但具体的孵化周期未知。雏鸟出生时覆盖着奶油色的绒毛，上面有黑棕色的斑点，面部、下巴和腹部几乎全白。","identification":"泽鹬与青脚鹬的区别在于泽鹬体型较小，额部颜色较浅，腿更长更细，嘴也更细更直。","protection":"IUCN：LC（无危）","distribution":"泽鹬繁殖于欧洲东部至俄罗斯远东地区的温带淡水湿地，包括波兰东部、波罗的海国家，经俄罗斯南部、哈萨克斯坦北部和蒙古北部至阿穆尔地区和中国东北部。非繁殖季节，它们广泛分布于非洲、中东、东南亚、澳大利亚（除塔斯马尼亚）、密克罗尼西亚西部（马里亚纳群岛和帕劳）、菲律宾、中国南部、台湾和日本琉球群岛。部分泽鹬向南迁徙至非洲和印度过冬，一些则前往东南亚和澳大利亚。","other":"泽鹬是《非洲-欧亚迁徙水鸟保护协定》（AEWA）适用物种之一。"},{"name":"林鹬","english_name":"Wood Sandpiper","scientific_name":"Tringa glareola","overview":"林鹬（英文名：Wood Sandpiper，学名：Tringa glareola），是鸻形目丘鹬科鹬属的鸟类。别名: 叫林札子，旅鸟。体长约21厘米，繁殖期栖息于林中或林缘开阔的沼泽、湖泊等水域边缘，主要分布于欧亚大陆北部，以水生昆虫、蜘蛛、软体动物、甲壳类为食。","appearance":"林鹬为褐色中型鹬类，腹部白色，背部具淡色斑点。飞行时可见淡色的翼上覆羽和方形的白色腰斑。腿呈黄绿色，头、颈和胸部有细致的灰褐色条纹，上体黑褐色带白色斑点，下体白色。与白腰草鹬相比，林鹬腿更长，黄色更深，翼下色浅，眉纹长，外观更为纤细。","call":"林鹬的叫声为急促而尖锐的“皮啼一皮啼”，并不旋律优美。","habits":"林鹬繁殖期栖息于林中或林缘的开阔沼泽、湖泊、水塘与溪流岸边，也活动于有稀疏矮树或灌丛的平原水域和沼泽地带。非繁殖期则栖息于各种淡水和盐水湖泊、水塘、水库、沼泽和水田地带。通常单独或成小群活动，迁徙期会集成大群。它们常在水边浅滩和沙石地上活动，边走边觅食，时而在水边疾走，时而站立不动，或边觅食边缓慢前进。遇到危险时会立即起飞，边飞边叫。","breeding":"林鹬的繁殖期为5至7月。刚到达繁殖地时常成小群活动，随后逐渐成对并进行求偶飞行。营巢于森林河流两岸、湖泊、沼泽、草地和冻原地带，尤其偏爱森林中开阔的沼泽地和有稀疏矮小桦树、柳树或灌木的平原草地。巢多置于水边或附近的草丛与灌丛中的地面上，或沼泽中的土丘上和苔原上。每窝产卵4枚，偶尔3枚，卵为淡绿色或皮黄色，带有褐色或红褐色斑点。","identification":"林鹬与白腰草鹬的主要区别在于林鹬腿较长，黄色较深，翼下色浅，眉纹长，外观更为纤细。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要位于欧亚大陆北部，从苏格兰高地向东横跨欧洲至俄罗斯内陆，再延伸至西伯利亚东部和中国东北部。非繁殖区分布在非洲、阿拉伯半岛南部、东南亚、印尼群岛、新几内亚、澳大利亚（除塔斯马尼亚）、菲律宾、台湾岛、中国大陆东部和琉球群岛（日本南部）。","other":"林鹬的迁徙路线覆盖了广阔的区域，包括非洲、南亚、印度、澳大利亚等地。近年来，其在英国苏格兰的繁殖种群有所增加。"},{"name":"鹤鹬","english_name":"Spotted Redshank","scientific_name":"Tringa erythropus","overview":"鹤鹬（英文名：Spotted Redshank，学名：Tringa erythropus），是鸻形目丘鹬科鹬属的鸟类。直译: 点斑红脚鹬，繁殖羽为黑色具白色点斑，冬季羽毛更淡更灰，与红脚鹬相似但体型更大、灰色更深。分布于北极地区的低地至亚北极的森林苔原，迁徙至地中海、英国南部、法国、非洲热带、亚洲热带地区越冬。在中国，迁徙时常见于大部分省份。","appearance":"鹤鹬体长29-31厘米，翼展61-67厘米，体重121-205克。繁殖羽全身黑色带白色点斑，非繁殖羽更淡更灰。具有红色腿和喙，飞行时背部可见白色椭圆形斑块。幼鸟上部灰褐色，密布白色细斑点，下部颜色较淡，条纹细碎。成鸟在7月至10月间进行完全换羽，春季3月至5月换身体羽毛，幼鸟在8月至次年2月进行部分换羽。","call":"鹤鹬的叫声为尖锐的‘teu-it’（类似燕鸥的叫声），报警声为连续的‘kyip-kyip-kyip’。","habits":"栖息于北极的低地至亚北极的森林苔原。迁徙期间广泛分布于多种淡水或咸水湿地环境，包括污水处理厂、灌溉稻田、咸水湖、盐沼、盐田和海岸边的泥滩。主要以水生昆虫、幼虫、软体动物、甲壳动物、鱼类和两栖动物为食，偶尔在深水中游泳。","breeding":"繁殖期在5月中旬至6月末，一夫一妻制，但配对关系短暂，可能为多配偶制。巢筑于草丛或苔藓中的浅坑，通常位于草地、树旁或石头附近，用植物材料和羽毛简单铺垫。每窝产卵4枚，橄榄绿至淡绿色底，带有暗棕色和紫灰色斑点，平均尺寸47毫米×32.3毫米。孵化期未知，雏鸟28天离巢，雄鸟承担大部分孵化和抚育工作。","identification":"与红脚鹬区别在于：鹤鹬体型更大，灰色更深，嘴更长更细，上喙基部红色较少；飞行时可见翼后缘无白色，红脚鹬翼后缘有白色边缘。","protection":"IUCN：LC（无危）。欧洲和西非种群估计75,000-150,000只，北欧地区约23,000-40,000只繁殖。在俄罗斯北部，估计有10,000对繁殖。气候变化可能在未来50年内对北欧繁殖范围造成严重影响。","distribution":"繁殖于北欧、俄罗斯北部至楚科奇半岛；越冬于西欧、非洲热带、中东、南亚、东南亚至中国东南部和台湾。","other":"受《非洲-欧亚迁徙水鸟保护协定》（AEWA）保护。"},{"name":"青脚鹬","english_name":"Common Greenshank","scientific_name":"Tringa nebularia","overview":"青脚鹬（英文名：Common Greenshank，学名：Tringa nebularia），是鸻形目丘鹬科鹬属的鸟类。拥有淡绿色的腿，微上翘的喙，体色以灰色为主，腹部白色，背部和腰部在飞行时呈现明显的白色条纹。广泛分布于北欧至东亚的亚北极和温带沼泽地带，迁徙至非洲、印度次大陆和澳洲过冬。在中国，见于华北和华南地区。","appearance":"青脚鹬体型庞大，长度在30至35厘米之间，体重介于125至300克，翼展可达68至70厘米。其特征为长而结实的喙，略微上翘，腿呈淡绿色。繁殖季节，上体有黑色斑点和条纹，头部、颈部和上胸部有棕色黑斑；非繁殖季节，上体羽毛统一灰白，无暗色标记，胸前、颈前和脸部为白色。幼鸟与非繁殖成鸟相似，但上体更偏棕色，边缘呈淡褐色，颈部和胸部条纹更多。","call":"青脚鹬的叫声独特，通常发出连续的三声短促笛音，被描述为‘teu-teu-teu’，在受到惊扰时尤其明显。","habits":"青脚鹬偏好生活在亚北极和温带的森林沼泽地带，包括森林空地、林间沼泽或开阔的沼泽和湿地。繁殖季节在高达1200米的地区也有发现。迁徙期间，它们会出现在内陆的泛洪草甸、干涸湖泊、沙滩和沼泽。冬季，它们广泛分布于淡水和海洋湿地，包括河口、海岸滩涂、盐沼、红树林、沼泽和湖泊，也会利用人造湿地，如污水处理厂、水库、盐场和淹没的稻田。","breeding":"青脚鹬的繁殖期从4月底至6月中旬，主要在欧洲北部和俄罗斯的温带至亚北极区域。巢建在地面，通常靠近枯木、岩石、木头或草丛旁，巢穴为浅坑，直径约10至12厘米，深度约4至6厘米，内部铺垫植物材料和少量羽毛。每窝产卵4枚，卵壳颜色从淡白色到淡蓝色，带有红色和巧克力棕色斑点，平均大小为51.4毫米×34.8毫米。孵化期大约24天，由双亲共同承担，但主要是雌鸟，雄鸟如果有两个配偶则很少参与孵化。幼鸟孵化后，通常由一只亲鸟（通常是雌鸟）带领，直至离巢，离巢时间在25至31天。","identification":"青脚鹬与泽鹬相比，体型较大，腿相应较短，叫声独特，嘴更粗略上翘。与小青脚鹬的区别在于，青脚鹬翼下具深色细纹，而小青脚鹬的翼下为白色。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北欧至东亚的亚北极和温带沼泽地带，包括苏格兰、斯堪的纳维亚半岛、波罗的海国家，向东至俄罗斯远东、楚科奇半岛、堪察加半岛和阿穆尔地区。非繁殖区覆盖西南欧、非洲、马达加斯加区域、中东、南亚、东南亚至中国东部、印尼群岛、新几内亚地区、澳大利亚和塔斯马尼亚、台湾、朝鲜半岛、日本中部和南部、马里亚纳群岛和帕劳。","other":"青脚鹬在全球范围内数量稳定，由于广泛的繁殖区域，总体种群被认为是安全的。然而，气候变化可能对其繁殖地产生严重影响。"},{"name":"小青脚鹬","english_name":"Nordmann's Greenshank","scientific_name":"Tringa guttifer","overview":"小青脚鹬（英文名：Nordmann's Greenshank，学名：Tringa guttifer），是鸻形目丘鹬科鹬属的鸟类。别名: 诺氏鹬，稀有的大型鹬类，特征明显，头部较大，颈部较短且厚实，喙较粗钝且基部呈黄色。分布区域狭窄，主要在东亚和东南亚的沿海沼泽和滩涂繁殖，数量稀少，全球种群估计不足1000只。在中国，主要分布在长江以南的沿海省份以及海南、台湾等地。","appearance":"小青脚鹬体型中等，长度介于29至32厘米之间，体重136至158克，翼展可达55厘米。繁殖成鸟上体灰色，下体白色，胸部和侧身布满密集的黑色斑点。非繁殖成鸟上体珍珠灰色，下体雪白，喙双色，基部橄榄绿并向尖端渐暗。雄雌羽毛相似，幼鸟与非繁殖成鸟外观相近，但冠部和上体颜色更深，带有淡色斑纹和条纹，翼盖有淡色边缘，胸有棕色洗染。","call":"叫声独特，通常发出单一鼻音，而非青脚鹬的圆润三连音。","habits":"栖息于沿海低地沼泽、稀疏落叶松林旁的湿地、河口三角洲、盐田和稻田等环境。迁徙期间常见于大型沿海泥滩或沙滩、三角洲、浅泻湖、红树林和海草床。觅食时低头快速奔跑，主要以小鱼、多毛纲、寡毛纲、小型甲壳类、软体动物和昆虫为食，偏好螃蟹。","breeding":"繁殖期为6月至8月初，营巢于低矮落叶松树上，高度约2至4.5米，巢由落叶松枝、苔藓和地衣构成。每窝产四枚卵，双亲共同孵化。","identification":"与青脚鹬相比，小青脚鹬头更大，颈更短更厚，喙更粗钝且基部黄色，翼下无细纹。","protection":"IUCN：EN（濒危）；国家重点保护野生动物名录：I级（2021年2月5日调整）。","distribution":"繁殖于俄罗斯远东地区的库页岛及鄂霍茨克海西南及北部沿岸的沿海落叶松林。越冬地包括孟加拉国南部、泰国南部、马来半岛、苏门答腊和婆罗洲西南部，可能还有韩国南部、日本、中国东南沿海、台湾岛、菲律宾、印度、斯里兰卡、缅甸等地。"},{"name":"大黄脚鹬","english_name":"Greater Yellowlegs","scientific_name":"Tringa melanoleuca","overview":"大黄脚鹬（英文名：Greater Yellowlegs，学名：Tringa melanoleuca），是鸻形目丘鹬科鹬属的鸟类。大型涉禽。繁殖于加拿大中部和阿拉斯加南部的沼泽苔原环境，非繁殖季节广泛分布于美洲各地，从美国南部至南美。该鸟以其亮黄色的腿、直立的姿态和独特的鸣叫易于识别，与较小的小黄脚鹬亲缘关系密切。","appearance":"大黄脚鹬是一种体型较大的滨鸟，具有明亮的黄色腿部。成鸟的羽毛特征基本与小黄脚鹬相似：背部灰色，带有白色斑点，颈部条纹状，腹部白色。不过，其比例是辨认的关键：大黄脚鹬整体更大，拥有更长、更粗、略微上翘的喙，更长的颈部，头部更厚实，胸部更宽阔。幼鸟上部羽毛颜色更深，白色胸脯上有明显的暗色条纹。","call":"大黄脚鹬的鸣叫声为连续三到四个尖锐、高音的音节，比小黄脚鹬更为响亮且清晰，通常发出的是三或四个音符而非一或两个，尽管有时也会发出单个音符。","habits":"大黄脚鹬活跃于泥滩、浅水池塘和沼泽，常在较为开阔的环境中发现，虽然与小黄脚鹬的栖息地有所重叠。它们在迁徙期间会形成小群，独自或与其它滨鸟混群。其饮食包括各种无脊椎动物和小鱼。","breeding":"大黄脚鹬在靠近水源的开阔地带筑巢，巢由苔藓或干土构成，呈浅凹状，内部铺垫植物。繁殖期，每窝产卵三至四枚，平均长度49毫米，宽度33毫米，重量约28克，孵化期约为23天。雏鸟在孵化后24小时内离开巢穴，两天内离开巢区。","identification":"与小黄脚鹬相比，大黄脚鹬体型更大，喙更长更厚，上翘，颈部更长，胸部更饱满。在繁殖羽时，大黄脚鹬下部的暗色横纹更宽更明显。鸣叫声也有所不同，大黄脚鹬的声音更清脆响亮。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美，主要在阿拉斯加南部和加拿大西南部至东拉布拉多的温带针叶林苔原。非繁殖季节分布于美国南部、中美洲、南美洲，包括加利福尼亚北部、宾夕法尼亚州，遍及加勒比海至火地岛，以及加拉帕戈斯群岛。","other":"在二十世纪早期，大黄脚鹬曾被视为猎鸟目标，这可能对其数量造成了影响，但目前看来种群已恢复。"},{"name":"沙色走鸻","english_name":"Cream-colored Courser","scientific_name":"Cursorius cursor","appearance":"沙色走鸻高约19至24厘米，体重在102至156克之间，翼展51至57厘米。体羽上部为淡沙色或沙红褐色，有醒目的黑条纹从眼后延伸至颈背，由上方的白色条纹框住；下体淡沙色，下腹白色；翅膀上有黑色初级飞羽和覆羽，与沙色次级覆羽和次级飞羽形成强烈对比；翼下黑色，次级飞羽边缘有窄白边；喙黑色；腿和脚为黄白色。幼鸟上下的羽毛细碎斑驳，呈沙色和黑色相间，头部图案不显眼；主翼羽尖端沙色。不同亚种在色彩深浅、腹部暗色范围以及体型上有所区别。","call":"发出尖锐的管状‘wit’或‘krit’声，常在飞行中反复鸣叫，同时也会发出粗糙的‘hark’或‘praak’声，同样在飞行中频繁重复，还有喂食时的‘wut-quoi’声，以及成鸟带雏时的‘qua qua’或‘cluck’声。","habits":"栖息于温暖至炎热的沙漠和平沙漠，包括石质和沙质地带，海拔通常低于800米，但记录到高达2400米。在以色列的W Negev沙漠冬季可见，冬季沙特阿拉伯数量增加，可能从中东迁入。繁殖期在北非主要为2月至6月，毛里塔尼亚、以色列和伊朗等地，阿拉伯地区2月至4月，土库曼斯坦5月至7月，巴基斯坦4月，约旦4月至5月，加那利群岛2月至5月，佛得角群岛9月至5月，塞内加尔12月至5月，索科特拉岛9月至7月。部分个体可能一年两次繁殖。以昆虫为主食，包括甲虫、蝗虫、白蚁、蟑螂、蛆虫、蚂蚁、臭虫、苍蝇，也吃软体动物、蜘蛛、等足目、蛛形纲、种子，偶尔小蜥蜴和蜗牛。在地面奔跑并停下觅食，有时会用喙挖掘食物，接近村庄或沙漠道路，取食被猫粪吸引的昆虫或寻找路杀昆虫。","breeding":"繁殖季节主要为2月至6月，筑巢于裸露地面的浅坑中，通常产两枚蛋，偶尔三枚，蛋壳颜色为奶油色或淡黄色，密集点缀着棕色斑点，平均尺寸34.7毫米×27.1毫米，孵化期18至19天，双亲共同孵化。雏鸟羽色细碎斑驳，沙红褐色与白色相间，头顶有暗色条纹，下体白色，胸羽沾染沙色，偶尔更暖色调。成鸟会假装孵卵以分散观察者的注意力，避免接近雏鸟；雏鸟约26至30天离巢。","identification":"与同属其他物种的区别在于苍白的腹部，与其余下体部分缺乏明显的对比。幼鸟与成鸟的羽毛花纹不同，头部图案不明显。","protection":"IUCN：LC（无危）。全球范围内似乎稳定，但在欧洲中部的迷鸟记录减少可能指示自上个世纪以来数量下降。土耳其仅限于东南部，总繁殖数量相对较小；黎巴嫩最近确认繁殖，数量也少。阿拉伯种群估计保守地有4万对，其中卡塔尔30对，阿联酋100对，大部分在沙特阿拉伯北部和中部，索科特拉岛密度最高，估计有500对。在约旦Azraq沙漠国家公园报告有数百对，以色列也有几百对，但在20世纪叙利亚显著减少。","distribution":"分布于加那利群岛、佛得角群岛、北非、西亚。繁殖区包括中东从土耳其东南部至索科特拉岛、伊朗和土库曼斯坦西部至印度西北部最远区域。在印度、阿拉伯半岛和撒哈拉沙漠南部边缘过冬。在芬兰、爱尔兰和英国等非繁殖区极为罕见。","other":"在非洲西部毛里塔尼亚17°N至18°20’N之间23个地点记录繁殖季节出现。"},{"name":"索马里走鸻","english_name":"Somali Courser","scientific_name":"Cursorius somalensis","overview":"索马里走鸻（英文名：Somali Courser，学名：Cursorius somalensis），是鸻形目燕鸻科走鸻属的鸟类。其最显著的外部特征是眼睛后方的黑色线条，形成一个明显的“V”字型。主要分布在非洲东北部的半干旱区域，包括埃塞俄比亚东部、索马里以及肯尼亚北部等地。","appearance":"索马里走鸻体长约19至22厘米，体重介于93至107克之间。外观上，它比同类物种更长腿、更大，整体颜色较淡。头部的白色眉纹和黑色眼线在颈背处交汇，形成独特的V字图案。头顶前部呈沙色，后部蓝灰色，大部分羽毛呈浅黄褐色，下体浅棕色，尾巴末端有深色标记。飞行时，可以看到翅膀下方的黑色外侧和白色的边缘。嘴喙黑色，腿灰色。幼鸟的上部羽毛有暗褐色斑点和条纹，尾端也有条纹。","call":"其叫声包括轻微的‘whit’声和较为响亮的‘trow’声。","habits":"索马里走鸻生活在干燥的草原、灌木丛和沙漠地带，通常以小群体形式活动，受到干扰时倾向于步行逃离。它们偏好低于1000米的海拔，但在特定地区可达1800米高。主要以昆虫和种子为食，活动在开阔的短草地带和火烧草地。","breeding":"繁殖季节从二月至六月在索马里北部，四月至六月中旬再次在十一月至十二月在索马里南部，五月在埃塞俄比亚，四月至九月在肯尼亚。巢穴简单，是在裸露地面的浅坑，通常由两枚蛋组成，由双亲共同孵化，具体孵化期未知。","identification":"与黑腹走鸻相比，索马里走鸻体型更大，腿部更长，整体颜色更淡，飞行时可见部分黑化的翅膀下部和更宽的白色翼缘。与黑腹走鸻的区别在于整体更浅的颜色，缺乏胸红色调，飞行时翅膀下方颜色更淡。","protection":"IUCN：LC（无危）","distribution":"索马里走鸻主要分布在非洲东北部的半干旱地区，包括厄立特里亚、埃塞俄比亚东部、索马里以及肯尼亚北部。","other":"索马里走鸻与布氏走鸻、黑腹走鸻和印度走鸻关系密切，曾一度被认为与布氏走鸻同种。"},{"name":"布氏走鸻","english_name":"Burchell's Courser","scientific_name":"Cursorius rufus","overview":"布氏走鸻（英文名：Burchell's Courser，学名：Cursorius rufus），是鸻形目燕鸻科走鸻属的鸟类。以英国自然学家威廉·约翰·布氏命名。原生于非洲，主要分布在南部非洲较干燥的地区，如西南安哥拉至南非东北部。布氏走鸻体型较小，日间活动，善于奔跑，通常生活在开阔的短草地和烧过的灌木地带。","appearance":"布氏走鸻体长约20-22厘米，体重约75克。上身主色为淡红褐色，翼上覆羽同色。前额沙锈色，逐渐过渡到蓝灰色后冠，眼后有黑白条纹，形成V形于颈背。喉部和面部白色，胸部浅红褐色，下界为黑色腹带，与白色下腹部鲜明分隔。飞羽黑色，次级飞羽宽白尖。下翼黑色，覆羽灰褐色，次级飞羽大部白色。喙黑色，腿白色。新羽比旧羽颜色更深，更丰富。幼鸟有黑斑和淡色条纹，缺乏成鸟明显的黑白头部标记。","call":"有三种不同的叫声：起飞时发出粗糙的单音‘chuk’，飞行中发出更粗犷的双音‘chuk chuk’，以及接触时的三音节‘kok-kok-kwich’或双音‘kwirrt-kwirrt’。","habits":"布氏走鸻偏好开阔的短草平原、稀疏休耕地、过度放牧和烧过的草地，以及砂质或砾石沙漠。它们以昆虫为主食，尤其是收获白蚁（Hodotermes mossambicus），通过快速奔跑和啄食地面捕获猎物，也会在软沙下挖掘食物。通常成对或小群活动，偶尔会形成十只左右的小群。","breeding":"繁殖季节几乎全年都有可能，但主要集中在8月至12月。一夫一妻制，巢建在裸露地面的浅坑中，有时位于羚羊或绵羊粪便或小石头旁。每窝产两枚蛋，极少数一枚，蛋色从奶油白到浅石色或淡黄褐色，有深色斑点，大小约为27.8-32.9毫米×22.8-26.2毫米。孵化和离巢时间未知，但双方可能共同参与孵化。雏鸟类似于黑腹走鸻的雏鸟。","identification":"布氏走鸻与黑腹走鸻的区别在于体型更小、颜色更深，头部后方有锈色斑块，飞行时后翼全黑。成鸟蓝灰色后冠和广泛白色的次级飞羽是其独特之处。幼鸟有黑斑和淡色条纹，与成鸟明显不同。","protection":"IUCN：LC（无危）。尽管在分布区的干燥部分较为常见，但在更南的区域数量正在减少，可能是由于不良的放牧做法和家畜的干扰所致。南非的畜牧业区需要采取保护措施。","distribution":"布氏走鸻分布于南部非洲的亚热带干旱平原，从西南安哥拉延伸到南非南部和东北部。","other":"布氏走鸻在某些地区数量下降，尤其是在奥兰治自由州报告了显著减少。"},{"name":"黑腹走鸻","english_name":"Temminck's Courser","scientific_name":"Cursorius temminckii","appearance":"体长约19-21厘米，体重介于54-82克。上体和胸部呈淡棕色，冠羽鲜亮的锈色，眼周有黑色线条，眉纹白色并在颈背处汇合；上腹部红褐色，下腹部被大块深棕色斑块包围，腿间可见；下腹部白色；飞行时，黑色的翼羽与棕色的覆羽形成鲜明对比，下翼全为暗色；喙部暗色，基部较淡，腿呈灰白色。幼鸟具有淡黄色的冠羽，背部羽毛边缘黑色，形成斑驳效果；胸部淡锈色，腹部呈黑色。","call":"一般认为较为沉默，唯一的已知鸣声是在飞行中发出尖锐的金属质感的‘err-err-err’或‘het-het-het-herr het-het-het-herr…’，类似生锈的铰链或玩具小号的声音，尤其在清晨的空中展示时频繁出现。","habits":"栖息于包括棕榈树和金合欢树的稀树草原、短草区、湿地、休耕农田，尤其是最近烧过的地方和机场。在肯尼亚，80%的种群出现在非干旱环境中，避免了与沙色走鸻的重叠。可能在火烧草地的几小时内出现。在与布氏走鸻的分布重叠区域，后者占据更干旱的地区。迁徙时，可在高达3000米的海拔看到它们。","breeding":"主要在旱季繁殖，除9月和10月外，在塞内加尔全年均可发现繁殖行为；在加纳北部1月至3月筑巢（南部持续时间较长）；在尼日利亚和埃塞俄比亚2月至7月；在刚果民主共和国4月至10月；在乌干达4月和9月发现绒羽雏鸟；在赞比亚5月至11月，峰值在8月至10月；在马拉维6月至11月；在津巴布韦7月至11月；在南非5月至1月。巢穴简单，可能只是浅浅的凹痕，通常位于羚羊粪便中，常在最近烧过的地面。每窝产卵2枚（偶尔1或3枚），卵色从奶油黄到白色，密集地带有黑色和淡灰色斑点，大小约25-32.3毫米×21.5-24.8毫米。孵化由双亲共同承担，孵化期印度走鸻。","identification":"与其他同属物种如沙色走鸻和布氏走鸻相比，黑腹走鸻更小、颜色更深，具有红褐色的冠羽和颈背，以及全黑的次级飞羽。这一特征也使其与异域分布的区分开来。","protection":"IUCN：LC（无危）全球范围内不面临威胁，是撒哈拉以南非洲最常见和分布最广泛的走鸻，西非的种群可能至少有10万只。由于其广泛的栖息地适应性和普遍的生活习性，它是非洲最适应环境的走鸻之一。","distribution":"分布于撒哈拉以南非洲的热带至亚热带草原：从毛里塔尼亚南部至厄立特里亚东部和索马里西部，南至南非北部。","other":"黑腹走鸻的名字是为了纪念荷兰自然学家Coenraad Jacob Temminck。"},{"name":"印度走鸻","english_name":"Indian Courser","scientific_name":"Cursorius coromandelicus","overview":"印度走鸻（英文名：Indian Courser，学名：Cursorius coromandelicus），是鸻形目燕鸻科走鸻属的鸟类。这里是其类型产地。分布于南亚次大陆的干旱平原，尤其是恒河和印度河流域之间，从巴基斯坦北部到尼泊尔南部、印度大部分地区至斯里兰卡西北部的干燥地带。","appearance":"成年印度走鸻体长23-26厘米，翼展58-60厘米。上部沙灰色带白尾，冠部亮红褐色，下缘白色眉纹在颈背形成V字，穿过眼至喙部有黑色条纹；胸腹部肉桂色至栗色，下腹黑带，尾下白色；翼上黑色主羽和次级飞羽与灰褐色覆羽形成对比；翼下暗灰褐色，主羽黑色，有狭窄白边；喙黑色，腿白色。幼鸟上部深褐斑驳，冠部深褐，点状淡色。","call":"通常被认为较安静，受惊起飞时发出粗哑的“gwaat”或“wut”声，重复时声音变弱。孵化中的鸟会发出低沉的哼声。","habits":"栖息于干燥的石质平原、盐碱地、零星灌木丛生的荒地、耕作过的土地、过度放牧区和村庄周边的裸露牧场。避开降雨量大的地区。繁殖季外常以小群活动，数量可达十只。主要以甲虫及其幼虫、蚱蜢、蝼蛄和其他昆虫为食，偶尔捕食小型软体动物。通过快速奔跑和突然停止啄食地面的方式捕食昆虫。","breeding":"繁殖季至少从二月底至八月，幼鸟最早在三月于哈里亚纳邦被观察到，古吉拉特邦则在二月。在斯里兰卡主要集中在五月至六月。巢建在裸露地面的浅坑中，通常产两枚，有时三枚，蛋壳呈石赭色，带有深棕色斑点。孵化主要由雌鸟承担，孵化期约35天。雏鸟上部斑驳的姜黄色、奶油色和黑色，下部奶油色带姜色胸部，腿灰色。双亲共同照顾雏鸟，但主要由雌鸟负责。","identification":"与沙色走鸻相比，印度走鸻色彩更鲜艳，具有更宽的黑眼纹，始于喙基。冠部为栗色，胸部红褐色。飞行时，臀部显白色，翼尖不如沙色走鸻那样对比鲜明的黑色。","protection":"IUCN：LC（无危）。尽管在斯里兰卡列为极危，但在大部分分布区内仍较为常见。然而，由于农业扩张和定居点的蔓延，一些地区已报告数量下降。","distribution":"分布于南亚次大陆的干旱平原，从巴基斯坦北部至尼泊尔南部，印度大部分地区至斯里兰卡西北部的干燥地带。","other":"与同属的其他物种如、布氏走鸻和黑腹走鸻形成超种群关系。"},{"name":"双领斑走鸻","english_name":"Double-banded Courser","scientific_name":"Rhinoptilus africanus","overview":"双领斑走鸻（英文名：Double-banded Courser，学名：Rhinoptilus africanus），是鸻形目燕鸻科短嘴走鸻属的鸟类。其分布于非洲东部和南部的热带至亚热带石质平原上，以半沙漠地带为主要栖息环境。","appearance":"双领斑走鸻体型约为20-24厘米，体重69-104克，整体呈淡褐色。头部和背部因深棕色中心和宽阔的浅色边缘而呈现出鳞片状外观。颈部轻度带有黑色条纹；胸部有两条明显的黑色带纹延伸至肩部；其余下体部分无条纹，渐变为白色尾下覆羽；上尾白色，尾部黑色；外侧初级飞羽黑色，内侧初级飞羽和所有次级飞羽呈明亮的锈红色肉桂色；喙短且黑色；腿白色。幼鸟与成鸟相似，但上体羽毛边缘较窄，直至三个月大才形成胸带。成鸟的羽毛颜色和图案会随季节和个体差异有所变化。","call":"鸣叫特征包括加速的一系列高音哨声，以及在接触时发出的哀怨、柔和的‘peeu-weee’声，其中音调在中间下降后再上升；在警戒时发出尖锐的‘kikikikik’声；焦虑时发出尖锐的吹哨声‘pee pee ti-ti-ti-ti-ti’；起飞时发出清脆但尖锐的‘wik-wik’声；问候时发出柔软的‘prrr prrr’声；威胁时发出刺耳的‘zzzt’声；幼鸟发出‘peep’声；成鸟召唤雏鸟时发出柔和的‘quip quip’声。","habits":"双领斑走鸻主要栖息在非洲东部和南部的石质和砾石质半沙漠地带，散落着低矮灌木，过度放牧的草地和卡拉胡，干燥的红沙土和矮绿植被区域。它们在夜间活动，黎明和黄昏时觅食，主要以昆虫为食，尤其是收获白蚁。它们通过快速奔跑追捕猎物，然后停下来在地上啄食。在南非，它们与蝙蝠耳狐共栖，跟随狐狸觅食收获白蚁。","breeding":"繁殖季节在索马里为2月至7月（主要在5月至6月），埃塞俄比亚为4月和6月。在东非，繁殖季节受降雨影响而变化；在南非全年皆可繁殖，高峰期在10月至11月。通常一年产2-4窝。双领斑走鸻为一夫一妻制。巢为浅坑，环绕小石子，通常位于开阔半沙漠地带的裸露地面，具有良好的四周视野。巢间距通常为200米，不会少于40米。每窝产一枚蛋，孵化期为26-28天，由双亲轮流孵卵。雏鸟孵化后不久即可离开巢穴，但在3-4天内仍靠近巢穴，之后加入父母身边。幼鸟在约5-6周龄时自立。","identification":"双领斑走鸻通过双胸带、鳞片状上体和肉桂色飞羽与其它走鸻区别开来。相比和铜翅走鸻，本物种体型更小，缺乏对比鲜明的头部图案。","protection":"IUCN：LC（无危）。尽管总体上较为常见，但因夜间活动习性容易被忽视。在南非，过度放牧可能使它们的分布向东扩展到草地上；该物种能很好地适应大多数畜牧业实践，但在某些地区可能受到农业扩张的威胁。在埃塞俄比亚较为罕见。","distribution":"分布于东非和南非的热带至亚热带石质平原，包括埃塞俄比亚、索马里、南非和坦桑尼亚。","other":"最近在津巴布韦发现，但赞比亚尚无确切记录。"},{"name":"栗颈走鸻","english_name":"Three-banded Courser","scientific_name":"Rhinoptilus cinctus","overview":"栗颈走鸻（英文名：Three-banded Courser，学名：Rhinoptilus cinctus），是鸻形目燕鸻科短嘴走鸻属的鸟类。上翼暗色，飞行时展现出大部分白色的下翼。主要栖息于非洲东部至南部的稀树草原和灌木林地带，包括一些米奥姆比（miombo）林地。白天隐匿于浓密灌木下休息，夜间活跃，发出重复的金属质感‘chik’声。与双领斑走鸻相似，但为夜行性，头部和胸部条纹更为复杂。","appearance":"体长约25至28厘米，体重89.2至142克。上体深棕色，大胆地覆盖着丰富的淡褐色鳞片状斑纹；眉线宽且淡，眼前方呈淡褐色，后方白色，于颈背形成V字形；耳羽红褐色；上尾覆羽白色；尾羽深棕色，外侧羽毛白色并带有深色横斑；下翼主要白色，尖端黑色；下体白色，饰以复杂的条纹和带状图案：红褐色颈带自耳羽延伸至上胸；下胸浅红褐色，粗黑条纹边缘以黑、白和红褐色带；颈部两侧黑色条纹在宽阔的红褐色胸带上方汇合；喙尖黑色，基部黄色；眼环黄至白色；腿淡黄色。幼鸟与成鸟相似，但胸部条纹较淡或缺失。种族间在体型大小和色彩丰富度上有所差异，尤其是上体羽毛的色调。","call":"三种不同的叫声被记录：轻柔的‘chuick’声用于联系；响亮的哨音‘pieu’声表示警报；以及焦虑时使用的‘chuck-a-chuck-a-chuck...’或加速的‘wick-er-wick-er-wick-er...’，尾音渐弱。","habits":"偏好干燥的金合欢灌丛中的开阔沙地，偶尔出现在非洲南部的范围内，如赞比亚的类似生境。在东非的荆棘灌丛、灌木草原和灌木草地，包括米奥姆比（miombo）林地，以及南非带有裸露地面的稀疏莫潘（mopane）林地中也有记录。海拔记录最高可达2200米。主要是留鸟，可能进行局部移动，但似乎不是长途迁徙者。在赞比亚，高度活跃于夜晚，此时会访问碎石路；非繁殖季节时形成5至6只的小群，其余时间单独或成对出现。","breeding":"繁殖期在索马里为3月至7月和12月，在埃塞俄比亚为1月至10月，在非洲东部的其余地区则随降雨模式变化，主要在旱季；在赞比亚为4月至10月（高峰为7月至9月）；在津巴布韦为3月至11月（主要为8月至10月）；在南非至少有一次记录到10月。有时进行两次繁殖，首窝幼鸟与成鸟一同直到第二次繁殖开始（或甚至孵化）。一夫一妻制，领地间距大。巢为沙土填充的深坑，几乎完全埋藏了蛋，通常位于阴凉的树下或灌木下。每窝产卵两枚（偶尔三枚），淡褐色至赭色，带有灰色、黑色和赤褐色斑点，尺寸为36.4至41.2毫米×25.5至27毫米；双亲轮流孵化，约25至27天，孵化期间非孵化方通常在附近停留。雏鸟上体斑驳的淡褐色和灰白色，散布黑色斑点；下体白色；喙黑色；腿和脚灰色。离巢时间未知。","identification":"与其他走鸻种类的区别在于其独特的夜间活动习性、复杂的头部和胸部条纹图案，以及独特的鸣叫声。与双领斑走鸻相比，具有更复杂的头部和胸部条纹。","protection":"IUCN：LC（无危）。在索马里、肯尼亚和坦桑尼亚广泛且常见，在埃塞俄比亚某些地区甚至非常常见。南非的分布受限于莫潘林地，因此可能需要保护，但目前几个莫潘林区的游戏保护区似乎提供了足够的保护。","distribution":"分布于安哥拉、博茨瓦纳、埃塞俄比亚、肯尼亚、纳米比亚、卢旺达、索马里、索马里兰、南苏丹、坦桑尼亚、乌干达、赞比亚和津巴布韦。主要栖息于非洲东北部至南部的热带灌木林和开阔林地。"},{"name":"铜翅走鸻","english_name":"Bronze-winged Courser","scientific_name":"Rhinoptilus chalcopterus","overview":"铜翅走鸻（英文名：Bronze-winged Courser，学名：Rhinoptilus chalcopterus），是鸻形目燕鸻科短嘴走鸻属的鸟类。大型的燕鸻科短嘴走鸻属鸟类。以独特的青铜色翼尖羽毛命名，广泛分布于撒哈拉以南非洲的热带至亚热带灌木林和草原地带。夜间活动，日间常在浓密灌木下休息。其鸣声独特，夜晚时会发出哀婉的‘chee-yaaaa-oo’叫声。体型与鸻类相似，但形态上有所不同：更高挑，腿更长，头部和胸部的图案与任何鸻类都不匹配。","appearance":"铜翅走鸻体长25-29厘米，体重91-220克，翼展58厘米。上身呈暗灰色，上胸和背部颜色一致。白色尾羽上方，尾部深棕色边缘白色。胸部有一条黑色带状标记，其余下腹部为奶油色或白色。耳盖和眼周较暗，初级飞羽黑色，末端闪现紫色到铜色光泽。下翼覆羽白色，与黑色初级飞羽形成鲜明对比。喙黑色，基部紫红色，眼环紫红色，腿淡红色。幼鸟色泽较暗淡，背部羽毛尖端为奶油黄色，黑胸带更窄。","call":"夜间发出哀婉、滑音的‘chee-yaaaa-oo’叫声。","habits":"栖息于干燥的灌木林和草原，尤其是最近烧过的地面。夜间活动，白天隐蔽。在肯尼亚，超过70%的记录位于干季半湿润至半干旱气候区，多见于低海拔，但在马拉维/赞比亚记录可达2350米。严格夜行，以地面昆虫为主食，如蚱蜢，采取类似鸻类的觅食动作。","breeding":"在冈比亚于2月产卵，尼日利亚和乌干达于2-3月，东非繁殖时间随降雨而变，从马拉维到南非的7月至12月，尤其9月至10月。通常在旱季繁殖，偏好近期受火影响的地区。一夫一妻制，独居繁殖，相邻巢穴间距可能仅100米。通常不做巢，有时会在地面挖掘直径约10厘米、深度约1厘米的凹坑。产卵2-3枚，蛋壳颜色从黄色至浅黄色，带有灰色、紫罗兰色、黑色、赭石色和栗色斑点，类似Vanellus鸻类的蛋。孵卵期25-27天，由双亲轮流承担，不在巢中的亲鸟通常留在附近。","identification":"与其它短嘴走鸻相比，铜翅走鸻体型最大，上体色彩单一，头纹显著，飞行中可见青铜色翼尖，与lapwing（Vanellus）外观相似，但形态差异明显：更高挑，腿更长，头部和胸部的图案不匹配任何lapwing。","protection":"IUCN：LC（无危）","distribution":"分布于塞内加尔至苏丹东部，南至南非北部的撒哈拉以南非洲热带至亚热带灌木林和草原地带。","other":"近年来在埃塞俄比亚有观察记录。"},{"name":"约氏走鸻","english_name":"Jerdon's Courser","scientific_name":"Rhinoptilus bitorquatus","overview":"约氏走鸻（英文名：Jerdon's Courser，学名：Rhinoptilus bitorquatus），是鸻形目燕鸻科短嘴走鸻属的鸟类。夜间活动的鸟类，属于燕鸻科短嘴走鸻属，为印度特有种。拥有独特的外观特征，包括两道棕色胸带，黑色冠顶和橙色喉部斑块。这种鸟仅在安得拉邦东部高止山脉的特定干燥灌木丛地带被发现，数量极其稀少。","appearance":"约氏走鸻体长约27厘米，头部和颈后呈深棕色，头顶有一条白纹；宽阔的白色眉纹有时会在颈背形成V字形，眼睛前方则带有奶油色。上体和宽阔的胸带为粉红沙棕色，棕色胸部上下边缘由窄暗色带环绕；下巴和喉咙白色，前颈部有宽大的锈色斑块；胸部下方有白色横带，其下缘同样为窄暗色带；下体主要为白色；翼上覆羽边缘白色；飞行羽黑色，外侧3至4枚主飞羽尖端有白色斑点；下翼覆羽主要为乳白色，翼弯处有黑色和锈色斑块；尾部黑色，基部白色；喙黑色，基部黄色；腿为黄白色。是唯一翼尖带有白色的走鸻，头部和颈部的图案独特。幼鸟的羽毛细节未被描述，但可能具有淡色边缘的上体和模糊的头部及胸部标记，如同非洲热带地区的近亲。","call":"约氏走鸻的叫声为一系列短促的两音节口哨声‘tuick-tuoo’，在黎明和黄昏时分较为活跃。","habits":"约氏走鸻生活在岩石起伏的地带，那里有稀疏的荆棘（如金合欢、酸枣和刺梨）和非荆棘（如决明子、哈德维卡和阿诺吉苏斯）灌木丛，有时靠近水体。偏好光秃秃、无草的开放地面，位于密集森林和人类活动区之间，尤其喜欢大灌木（超过2米高）密度在每公顷300至700株，小灌木密度低于每公顷1000株的区域。白天隐藏在约50厘米高的刺梨灌木丛中。","breeding":"关于繁殖信息极为有限。曾有报道，六月份采集到的雄鸟标本具有增大的生殖腺。据称，1895年有人取走了一窝两个黄色的卵，当地居民也有类似说法，但至今尚未得到证实。","identification":"约氏走鸻最显著的辨识特征是其两道棕色胸带，橙色喉部斑块，以及翼尖的白色斑点，这些特征使其在同类中独树一帜。","protection":"IUCN：CR（极危）。约氏走鸻仅在印度安得拉邦东部高止山脉和马哈拉施特拉邦南部极少数地区有分布，极为罕见。其栖息地正面临因木柴收集、放牧、采石和农业开发而丧失的威胁。","distribution":"约氏走鸻分布于印度东部安得拉邦的东部高止山脉，主要栖息于热带干燥灌木丛地带，为极端稀有的物种。最近的记录来自安得拉邦库达帕地区。","other":"约氏走鸻被认为是世界上最濒危的鸟类之一，直到1986年才被重新发现。"},{"name":"澳洲燕鸻","english_name":"Australian Pratincole","scientific_name":"Stiltia isabella","overview":"澳洲燕鸻（英文名：Australian Pratincole，学名：Stiltia isabella），是鸻形目燕鸻科澳洲燕鸻属的鸟类。中型、细长的燕鸻。主要繁殖于澳大利亚内陆，广泛分布于该国干旱和半干旱地区，迁徙至澳大利亚北部、新几内亚、苏拉威西、婆罗洲等地过冬。全球数量估计约为60,000只。","appearance":"体长19-24厘米，翼展50-60厘米，体重55-75克，拥有细长的腿、尖锐的翅膀和弯曲的短喙。繁殖期头部、颈部、胸部和上体呈沙褐色渐变，翅膀尖端黑色，黑眼纹，白色下巴和喉咙，沙褐色胸部，鲜红的喙基部黑色，虹膜深棕色，灰黑色的腿和脚。非繁殖期羽色较淡，黑眼纹模糊，喙基部颜色较浅，上体灰褐色带沙黄色边缘，喉咙有暗色斑点。幼鸟羽色类似非繁殖期成鸟，但呈较浅的沙黄色，缺乏黑色眼纹，前额、头顶和颈背有深褐色条纹，喙灰黑色，基部微红。","call":"发出类似燕鸥的颤音“quirree-quirree”或“quee-quee”，还有清脆的“weetweet”，重复多次，以及接触时的哀婉“tsoo wee”。","habits":"栖息于树少、开阔的平原、草地、黏土盆、碎石地带，常见于澳大利亚干旱和半干旱区域。主要以昆虫、蜘蛛和蜈蚣为食，通过在空中或地面捕捉猎物。白天活跃，高峰活动时间在黎明和黄昏，需要频繁饮水。群居迁徙，迁徙期间持续发出叫声。","breeding":"繁殖季节从8月至次年1月，最活跃在9月至11月。在小而松散的群体中筑巢，巢通常位于开阔地带的裸露、石质地面，偶尔有浅坑，周围可能环绕着小石头和干植物材料，距离水源不超过2公里。每窝产2枚蛋，偶尔1-3枚，孵化期18-21天，双亲共同孵卵。雏鸟出生时重约5克，上体泥色带黑色图案，前额有淡褐色条纹，翅膀上有淡褐色斑块，下体淡蜂蜜色渐变为腹部的白色，喙黑色下颚粉色，腿粉灰色。幼鸟可能使用兔洞躲避危险，或在灌木下避难，由双亲喂养和保护，成鸟会在巢边表演断翅展示，孵化后3-4周离巢，最长可达五周。巢穴失败的主要原因是乌鸦、引入的狐狸、蛇和蜥蜴的捕食。","identification":"比普通燕鸻更纤瘦、体型略小、腿更长。幼鸟和换羽期的个体可能与普通燕鸻混淆，但可通过较淡的沙黄色羽色、缺乏黑色眼纹、深褐色头部条纹、灰黑色喙和微红基部进行区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于澳大利亚热带至亚热带开阔平原，从西澳大利亚北部到昆士兰州西部和新南威尔士州中部；非繁殖期分布至爪哇、苏拉威西地区、小巽他群岛、中南部马鲁古群岛和新几内亚地区（除北部以外）。","other":"在印尼，该物种可能会被狩猎。"},{"name":"领燕鸻","english_name":"Collared Pratincole","scientific_name":"Glareola pratincola","overview":"领燕鸻（英文名：Collared Pratincole，学名：Glareola pratincola），是鸻形目燕鸻科燕鸻属的鸟类。体型优雅，兼具鸻和燕子的特点，成鸟头部和背部呈暖灰棕色，喉部有独特的‘项链’状标记，喙基部红色。分布广泛，自欧洲南部至亚洲西南部和非洲热带地区。","appearance":"体长22-25厘米，体重60-98克，翼展60-70厘米。上体棕色略带橄榄色，长翼尖和深叉尾黑色，喉部赭黄色，边缘黑色，胸棕色渐变为白色腹部，下翼覆羽和腋羽深红色，翼缘白色明显，喙红色带黑尖，腿黑色。非繁殖季节黑色喉边不明显，头部两侧较淡，胸部杂以灰棕色。幼鸟上体和胸部斑驳黑色，喉部白色无黑色项圈。冬季羽毛与非繁殖期成鸟相似，但上体边缘更宽，头侧和喉侧有更多条纹。","call":"飞行中发出尖锐、断续和颤音的叫声，包括类似燕鸥的‘stwick’声和上升后下降的颤音，繁殖地发出较短而音调一致的颤音警告声，展示飞行时发出‘k’d’d’d’ik-kiik, kik’，首音下滑。","habits":"偏好开阔地带，从干燥的田野到有泥岸的草湿地。在欧洲和亚洲，可见于草原、耕地、沙丘等地。在非洲，常见于最近被烧过的草地、过度放牧的草地、耕田、沙丘、盐碱地或沙质平地，通常靠近水源，如大河沿岸和河口。迁徙时，可在海拔高达3550米的喜马拉雅山脉和2880米的埃塞俄比亚见到。主要以空中捕食为主，如飞蛾、甲虫、白蚁、苍蝇等大型昆虫，偶尔在地面追逐猎物。","breeding":"繁殖期在欧洲为5-8月，在约旦为5-6月，在巴基斯坦为4-7月。在非洲，繁殖时间因地区而异。集群筑巢，巢穴为地面的浅坑或自然凹陷，直径7-9厘米，深4厘米，通常位于干泥滩或沙滩。每次产卵2-4枚，平均大小32.3毫米×24.1毫米，孵化期17-19天，由双亲共同孵化。雏鸟出生2-3天后离开巢穴，由父母通过反刍或嘴尖递食喂养，直到大约7天大。22-30天后幼鸟离巢。","identification":"与其他燕鸻科物种如黑翅燕鸻和普通燕鸻的区别在于更长的尾巴、翅膀内外侧颜色的对比以及白色的翼缘（虽然有时不易观察）。幼鸟和非繁殖期成鸟的外观有显著差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆温带到热带的草地近水区域，广泛分布于西、中帕拉里克地区和非洲。非繁殖季节迁徙至非洲热带地区。","other":"在欧洲和非洲的繁殖地数量总体呈现下降趋势，主要受到农业活动、栖息地丧失和旅游压力的影响。"},{"name":"普通燕鸻","english_name":"Oriental Pratincole","scientific_name":"Glareola maldivarum","overview":"普通燕鸻（英文名：Oriental Pratincole，学名：Glareola maldivarum），是鸻形目燕鸻科燕鸻属的优雅鸟类，具有燕和鹬的双重习性。喉部和上胸部淡灰色，饰以黑色半环，飞行时展现其长且棱角分明的翅膀，给人留下深刻印象。","appearance":"成年普通燕鸻整体呈橄榄褐色，具亮白色臀部，喉部为淡黄色，环绕着狭窄的黑色项圈；上胸为棕色，逐渐变为腹部和下体的白色；飞行时可见黑色飞羽、栗色的翼下覆羽和明亮的白色翼缘。亚成鸟上体为斑驳的灰褐色，缺乏成鸟的项圈。嘴为黑色，基部红色，腿黑色。","call":"发出尖锐的'kyik'、'chik-chik'或'chet'叫声，主要在飞行中发出，但也描述了响亮的'cherr'和升调的'trooeet'叫声。","habits":"栖息于开阔平原地区的湖泊、河流、水塘、农田、耕地和沼泽地带，也出现在离水域不远的潮湿沙地和草地上。主要以昆虫和其它陆生节肢动物为食，如金黾甲、蚱蜢、蝗虫、螳螂等。飞行迅速，常在河流、湖泊和沼泽上空飞翔，边飞边叫。","breeding":"繁殖期为5月至7月，营巢于河流、湖泊岸边或附近沙土地上，巢甚简陋，产卵数为2至4枚，卵的颜色为黄灰色，土灰色或乳白色，带有暗褐色、灰色或棕黑色斑点。","identification":"与其它Pratincole种类如领燕鸻的区别在于较短的尾巴、较长的腿、栗色的翼下覆羽，以及一些细微的特征如鼻孔形状、喙部颜色和翼部颜色的差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于南亚至东亚的温带至热带草地，包括印度西部、斯里兰卡、东南亚、中国东部和东北部、菲律宾、台湾、西伯利亚东部和日本南部。冬季迁徙至印度次大陆、东南亚、澳大利亚等地。","other":"在非繁殖区，它们可以在印度洋的查戈斯群岛和马尔代夫、印度半岛、印度尼西亚群岛、澳大利亚北部、北马里亚纳群岛至帕劳、楚克、雅普和马绍尔群岛等地找到。"},{"name":"黑翅燕鸻","english_name":"Black-winged Pratincole","scientific_name":"Glareola nordmanni","overview":"黑翅燕鸻（英文名：Black-winged Pratincole，学名：Glareola nordmanni），是鸻形目燕鸻科燕鸻属的鸟类。以优雅的岸栖鸟著称，偏好干燥环境而非泥泞地带。与领燕鸻极为相似，但在飞行时可见其翼缘并非白色，而下翼羽为黑色。在站立时，腿更长，尾巴较短，导致主翼羽超出尾端。黑翅燕鸻繁殖于哈萨克斯坦的东部，可能在中国新疆西北部出现。其独特的外部特征包括黑色次级飞羽和颈背部带有的栗色。","appearance":"黑翅燕鸻长约23至26厘米，体重84至105克，翼展60至68厘米。背部呈褐色带橄榄色，尾羽深叉，喉部为赭黄色带窄黑边，胸部棕色渐变为白色腹部。喙黑色基部红色，腿黑色。非繁殖期时，喉部黑色边界不明显。与领燕鸻的区别在于黑色下翼羽，缺乏白色翼缘，上翼颜色更深且更均匀，喙部红色较少。幼鸟背部斑驳黑色，胸部有黑色斑点，喉部暗白色无黑色项圈。","call":"飞行叫声类似于领燕鸻，但音调略低，发出‘keye-kiche’或‘ti-kik’的尖锐声，还有警报时发出的短促单音节‘krirk’。","habits":"栖息于盐碱草原、耕地、河谷及湖泊或海洋沿岸的干燥地带，偏好盐土和稀疏植被的环境，近水或湿草地。在繁殖季节，常在人类居住地附近、距水源3公里以内、草高适中的地方形成繁殖群落。冬季迁徙至非洲南部，尤其南非、纳米比亚和博茨瓦纳，迁徙期间跟随昆虫群落移动，有时在苏丹、埃塞俄比亚边境等地也有记录。","breeding":"繁殖期为5月至7月，在黑海地区。松散的繁殖群落由几对至数百对组成，通常靠近水源。巢为简单的凹坑（约10厘米宽），铺以干植物碎片。每窝产卵3至5枚，橄榄绿至橄榄色，带有重黑色标记。双亲共同孵卵，孵化期未知。雏鸟类似领燕鸻，但颜色稍暗。幼鸟独立于出生后5至6周。","identification":"与领燕鸻和普通燕鸻的主要区别在于黑色下翼羽、无白色翼缘、更深的上翼色以及喙部红色较少。幼鸟可通过背部斑驳的黑色和喉部的暗白色识别。","protection":"IUCN：NT（近危）","distribution":"繁殖于东南欧至乌克兰西南部至俄罗斯西南部及哈萨克斯坦北部，偶尔出现在白俄罗斯、匈牙利和阿塞拜疆。越冬于非洲南部，主要在南非、纳米比亚和博茨瓦纳，偶尔在赞比亚和埃塞俄比亚的高海拔草地（高达1370米和1590米）。","other":"历史上曾被认为是领燕鸻的颜色变异型，与之杂交过。自苏联解体以来，由于适宜栖息地的增加，黑翅燕鸻在哈萨克斯坦中部和东北部以及俄罗斯东南部的数量似乎有所增加。"},{"name":"马岛燕鸻","english_name":"Madagascar Pratincole","scientific_name":"Glareola ocularis","overview":"马岛燕鸻（英文名：Madagascar Pratincole，学名：Glareola ocularis），是鸻形目燕鸻科燕鸻属的鸟类。体型介于燕鸥与涉禽之间，以优雅的飞行姿态著称。其主要繁殖于马达加斯加东部和西北部的岩石河岸与海岸线，亦为东非沿海地区冬季的非繁殖访客。","appearance":"成年马岛燕鸻体长约23至25厘米，体重82至103克。背部呈深橄榄棕色，前额为深巧克力色，臀部白色。眼周和耳羽黑色，眼下及后方有一条浅白线，与暗色头部形成鲜明对比。喉部和胸部棕褐色，逐渐过渡到上腹部的深红褐色，下腹部则为白色。飞行羽黑色，尾部分叉较浅，大部分为黑色，侧面白色。翼下的覆羽淡栗色，近翼弯处有白色斑点。喙黑色，基部红色，腿灰色至黑色。与相似物种相比，如乌燕鸻，马岛燕鸻体型更大，腹部和翼下呈栗色，颜色更深，尤其是头部，尾巴更短。幼鸟背部有轻微的红褐色鳞状斑纹，比成鸟颜色更淡，胸部有红褐色条纹，眼线下方的红褐色线条。","call":"马岛燕鸻声音多样，包括下降的‘vik vik, vikavik, vikavik’声，飞行时发出的‘veet ee veet - veet ee veet - veet ee veet’声，类似燕鸥的‘kitt-kirr’声，短暂尖锐的‘twik twik twik twik’声，以及起伏的‘kik’系列嘶鸣声。","habits":"马岛燕鸻主要栖息于马达加斯加的永久河流中的岩石小岛和沿海水域，海拔记录高达1500米。非繁殖季节，它们出现在非洲大陆的海岸地带，湖泊岸边，河流中的沙洲，河口，短草甸，河口滩涂，沿海沙丘等地方，几乎在任何环境中都能觅食，常在离岸岩石或开阔地休息，包括机场。","breeding":"繁殖季节大约从10月至12月，尤其集中在11月。以小松散群体形式繁殖，约2至20对，巢穴设在岩石上的凹陷处，有时用吐出的昆虫外壳铺垫。每窝产1至2枚蛋，偶尔3枚，颜色为缓冲色、黄色或奶油色，密布棕色或灰色斑点，尺寸约为32.4至35.4毫米×24.4至27.7毫米。","identification":"马岛燕鸻与乌燕鸻的区别在于体型更大，腹部和翼下呈栗色，颜色更深，尤其是头部，尾巴更短。与领燕鸻相比，颜色更深，尤其是在头部。","protection":"IUCN：NT（近危）","distribution":"繁殖于马达加斯加的东北部、东部岩石海岸和河流小岛。非繁殖期访问东非沿海地区，从索马里南部到莫桑比克北部，主要在肯尼亚和坦桑尼亚的沿海地区，海拔可达1500米。","other":"马岛燕鸻是Glareola属中最稀有的物种之一，面临栖息地丧失的威胁，特别是在马达加斯加东部的繁殖区域。"},{"name":"乌燕鸻","english_name":"Rock Pratincole","scientific_name":"Glareola nuchalis","overview":"乌燕鸻（英文名：Rock Pratincole，学名：Glareola nuchalis），是鸻形目燕鸻科燕鸻属的鸟类。非洲热带岩石河流栖息的鸟类。成年个体拥有暗灰或褐色羽毛，显著特征为白色眼线延伸至颈背形成环状，翼下有明显白条纹。喙黑色基部红色，腿红珊瑚色。","appearance":"体长16.5至19.5厘米，翼展14.3至16厘米，尾长5至6厘米，体重43至52克。头部至背部呈暗褐色，白色眼线连接形成颈背白色环状。臀部及尾根白色，腹部灰白色渐变为下腹白色，翼下深灰色带白色条纹。喙黑色，基部红色，腿及眼红色。幼鸟缺乏淡色颈环及眼线，上体及下体斑驳淡棕色，腿更偏橙色。","call":"发出微弱的哨声接触鸣叫及音乐般的咕噜声，争斗时变得非常吵闹。","habits":"栖息于河流和湖泊岸边的岩石地带，受当地水位影响季节性迁移。成群生活，约26对组成群体，于晨昏时段在空中捕食昆虫，日间炎热时在水中活动。以飞虫、蛾、蚂蚁、甲虫、蚱蜢和蝉为主食，空中捕食。","breeding":"飞行中的复杂求偶仪式，翅膀高举露出颈羽强调其环状特征。一夫一妻制，终身伴侣。旱季时繁殖，雌鸟在被水环绕的平滑岩石凹处产卵1-2枚，双亲轮流孵卵，常湿腹毛以保持卵温。幼鸟出生时具伪装色，迅速学会在岩石缝隙中躲避，快速掌握游泳技巧。","identification":"比马岛燕鸻小，有白色颈环，翼下有白条纹，腿红色；比黄颈灰燕鸻暗色，后者有明显的翼型图案。幼鸟缺乏颈环和眼线，上下体斑点淡棕色。","protection":"IUCN：LC（无危）","distribution":"分布于非洲热带地区的岩石河流，具体见东鸟网-地理分布。"},{"name":"黄颈灰燕鸻","english_name":"Grey Pratincole","scientific_name":"Glareola cinerea","overview":"黄颈灰燕鸻（英文名：Grey Pratincole，学名：Glareola cinerea），是鸻形目燕鸻科燕鸻属的鸟类。优雅紧凑，主要分布在西非至中非的大型河流沙洲上。其最显著的特征为淡灰色的上体、温暖的赤褐色颈背和独特的黑白脸部花纹。","appearance":"成年黄颈灰燕鸻长约18-20厘米，重约37.4克。上体呈淡灰色，颈背为温暖的赤褐色，臀部白色；眼纹窄黑，曲向眼后，眉线白色；尾巴黑色，边缘和基部白色，微叉；翼上有黑色和白色的图案；下体白色，胸部和上腹部泛赤褐色；翅膀下部大部分白色，带有黑色和白色的图案；喙黑色，基部红色；腿红色。幼鸟背部有黑和赤褐色斑点，脸部无黑色标记，尾端杂色黑赤褐色。","call":"鸣叫包括一系列\"zi\"音调，音符间的间隔逐渐缩短；警戒时发出连续的\"tic-tic-tic\"或起伏的\"tie-tie-tie\"音节。","habits":"黄颈灰燕鸻偏好宽阔流速缓慢的河流，常栖息于开放的沙洲或沿岸地带。它们会因洪水或干旱而迁移，飞行时展示出典型的燕鸻空中技巧。迁徙期间，会在尼日利亚等地散居。","breeding":"繁殖季节在河流水位最低时，大约在3月至5月间，筑巢于沙洲或砾石上，巢为浅坑状，直径约8厘米，无铺垫。每次产卵1-2枚，卵壳颜色为奶油色到淡黄色，带橄榄褐色和石灰色斑点，大小约为25-28毫米×20-22毫米。雏鸟上体淡砂灰色，有细小黑斑，下体白色。","identification":"与完全异域分布的灰燕鸻通过头部图案和大部分白色下翼区区分。与部分同域分布的乌燕鸻相比，后者颜色更深，具有白色或红棕色后颈环和脸部条纹。","protection":"IUCN：LC（无危）","distribution":"主要分布于西非至中非的大型河流沙洲上，从马里南部和尼日尔南部到安哥拉北部和刚果民主共和国中部。","other":"黄颈灰燕鸻在某些地区的数量可能受到人类干扰的影响，但在保护区内如中非共和国的Dzanga-Ndoki国家公园和Dzanga-Sangha雨林保护区仍有记录。"},{"name":"灰燕鸻","english_name":"Small Pratincole","scientific_name":"Glareola lactea","overview":"灰燕鸻（英文名：Small Pratincole，学名：Glareola lactea），是鸻形目燕鸻科燕鸻属的鸟类。又称小印度燕鸻或小燕鸻，体型较小。其主要特征为软灰褐色的羽毛，喉部带有淡褐色斑纹，黑色眼眶，飞行时展现出黑白相间的翼型。分布于印度、巴基斯坦西部、斯里兰卡、泰国、老挝、柬埔寨及中国南部的云南等地，偏好河流、湖泊附近的沙地或石滩作为栖息地。","appearance":"灰燕鸻体长约16.5至19厘米，翼展42至48厘米。上体呈淡沙灰色，头部前额偏棕色，眼眶黑色，臀部及尾基白色，尾端有一黑色横带；翅膀上部黑色，与淡色覆羽形成鲜明对比，次级飞羽白色边缘；腹部淡红褐色渐变为白色，下腹和尾下覆羽更白；下翼黑色，次级飞羽和内侧初级飞羽上有白色条纹；喙黑色，基部稍带红色；腿色从暗灰色到黑色。成鸟非繁殖季节颜色较淡，失去黑色眼眶。与黄颈灰燕鸻相比，头部更单一，下翼颜色更深。幼鸟背部有斑点和鳞片状花纹，腹部有淡棕色斑点和条纹，喙全黑。","call":"发出粗糙的、向下滑音的短促“chirrrt”声，频率为1至2秒1至2个音符，以及在飞行中的高音滚动“prrip”或“tiririt”声，以及孵卵时的短促“tuck-tuck-tuck”。广告叫声类似白额燕鸥，上升的“temik-temik-temik”声。","habits":"灰燕鸻偏好栖息在大河流沿岸的沙地和石滩上，也可见于附近的沼泽和农田地带，非繁殖期则会出现在河口和海边的小水塘旁的沙地上。常集群活动，飞行敏捷快速，尤其黄昏时飞行最为活跃，与雨燕和蝙蝠一同捕猎，直至天黑。它们在地上奔跑觅食，食物主要为昆虫，偶尔也会捕食小型甲壳类和软体动物。主要在水面和沼泽地上空飞翔捕食，也会在地上追捕猎物。","breeding":"繁殖期通常为3月至5月。在大的河边裸露的沙地或沙石地上营巢，常成群繁殖，仅在沙地上刨一个浅坑，有时垫有少许枯草。每窝产卵2至4枚，卵色为灰色、淡绿色、沙皮黄色或橄榄绿色，带有小的红褐色斑点。由雄鸟和雌鸟轮流孵化，野外数量不多，应注意保护。","identification":"与黄颈灰燕鸻相比，灰燕鸻头部图案更简单，下翼颜色更深。幼鸟背部斑点和鳞片状花纹明显，腹部有淡棕色斑点和条纹。","protection":"IUCN：LC（无危）。总估计数量在1万至10万只之间。物种似乎能够在较大范围内以相当数量生存，对人类干扰有相当容忍度。","distribution":"繁殖于喜马拉雅山脉东侧的河流至斯里兰卡，向东经尼泊尔、不丹、中国南部的云南至越南。非繁殖期分布至其他水体类型。在中国大陆，分布于云南等地。"},{"name":"白顶玄燕鸥","english_name":"Brown Noddy","scientific_name":"Anous stolidus","overview":"白顶玄燕鸥（英文名：Brown Noddy，学名：Anous stolidus），是鸻形目鸥科玄燕鸥属的鸟类。体型较大，主要分布在热带及亚热带大洋与澳大利亚北部。繁殖于全球热带岛屿，包括太平洋的夏威夷至图阿莫图群岛、印度洋的红海至塞舌尔群岛，以及大西洋的加勒比海至特里斯坦达库尼亚群岛。在中国南海南部或台湾东南部海域可能有其踪迹。","appearance":"成年白顶玄燕鸥体长约38-45厘米，翼展75-86厘米，羽毛呈深巧克力棕色，头部有淡灰色或白色的冠和额头，眼周有狭窄的不完整白色环。尾部长而楔形，脚和腿色暗。幼鸟羽毛较暗，头上的白色仅限于额部。雄鸟个体比雌鸟稍大。","call":"叫声为独特的低沉咆哮声，觅食群体会发出尖锐的‘eyeak’音。","habits":"栖息于热带海洋环境，通常在悬崖、树木或灌木丛中筑巢，偶尔在地面繁殖。以小鱼、乌贼、软体动物、水生昆虫和鱼类为食，如沙丁鱼、鳀鱼等，也会食用果实，主要是螺丝松果。飞行时动作缓慢，不似多数燕鸥般冲入水中捕鱼，而是掠过水面啄食。","breeding":"繁殖季节，雌雄鸟会进行点头炫耀的求偶仪式，雄鸟向雌鸟传递新鲜捕获的小鱼。每季产一卵，蛋呈粉奶油色，带有紫罗兰和栗色斑点，尺寸约为52x35毫米，由双亲轮流孵育33至36天。雏鸟孵化后快速成长，三周内体重接近父母，约六到七周后离巢，开始学习自给自足。","identification":"与玄燕鸥相比，体型更大，羽色为深棕色而非黑色，且顶冠白色较少，不延伸至枕部。","protection":"IUCN：LC（无危）","distribution":"广泛分布于热带和亚热带岛屿，遍及所有海洋。在中国，于南海南部或台湾东南部海域可能有分布。","other":"在印度，受PM Sayeed海洋鸟类保护区保护。"},{"name":"小玄燕鸥","english_name":"Lesser Noddy","scientific_name":"Anous tenuirostris","overview":"小玄燕鸥（英文名：Lesser Noddy，学名：Anous tenuirostris），是鸻形目鸥科玄燕鸥属的鸟类。体型较小的海鸟，羽毛呈灰黑褐色，额头和冠部颜色较淡，与玄燕鸥和白顶玄燕鸥相似，但体型更小，色泽稍淡，具细长喙。繁殖于热带及亚热带印度洋岛屿，自塞舌尔群岛至查戈斯群岛和马尔代夫，西至澳大利亚西部的Houtman Abrolhos岛和Ashmore礁。","appearance":"体长30-34厘米，翼展58-63厘米，体重97-120克。全身羽毛为黑褐色，前额和头顶颜色较浅，颈侧和喉部呈烟灰色，虹膜深棕色，喙黑色，腿褐色。幼鸟色泽更淡，头顶有白色斑纹。与玄燕鸥相比，体型更小，色泽更淡，眼周色浅，头部暗色与颈部颜色过渡自然。","call":"巢中鸟会反复发出刺耳的‘arrrk arrrk’声，同时还有低沉的‘ugugug’声。兴奋时，会发出机械般的‘byowp’声。","habits":"栖息于海上，非繁殖季节在东非海岸出现，常访问阿曼海岸，主要在6月中旬至8月初，有时直到11月，甚至2月。在坦桑尼亚海岸，一月至三月间有大量个体出现，如2013年3月在坦噶北面沙洲上发现超过2000只。在印度和斯里兰卡也有记录。以小型鱼类和无脊椎动物为食，通过悬停和空中接触捕食，不会潜水捕食。","breeding":"在大型群落中繁殖，群落数量可达数万对。繁殖时间因群落而异。在塞舌尔群岛Aride岛，繁殖期通常在5月末至6月末。在澳大利亚西部Houtman Abrolhos岛，繁殖期为8月至12月初。巢建于高树上，相距约5米，或低矮灌木丛中，偶尔地面筑巢。巢由棕色藻类和粪便构成，巢间距仅30厘米。每窝产卵一枚，平均孵化期和离巢期分别为34天和40天。孵化成功率约为60%，在Houtman Abrolhos岛曾报告66%-90%的成功率。","identification":"与玄燕鸥相似，但体型更小，色泽更淡，眼周色浅。幼鸟头部有白色斑纹，可与成鸟区分。","protection":"IUCN：LC（无危）。全球数量估计为1,200,000只，其中塞舌尔群岛（Cousin和Aride岛）、毛里求斯（Serpent岛）和查戈斯群岛拥有最大群落。澳大利亚西部种群在20世纪中期开始恢复，至2009年估计有150,000只个体。","distribution":"繁殖于印度洋热带及亚热带岛屿，包括塞舌尔群岛、马斯卡雷恩群岛、查戈斯群岛、马尔代夫、澳大利亚西部的Houtman Abrolhos岛和Ashmore礁。非繁殖季节至东非、科摩罗和马达加斯加北部。","other":"历史上曾被视作玄燕鸥的亚种，分子系统发生学研究确认了两者间的密切关系。"},{"name":"玄燕鸥","english_name":"Black Noddy","scientific_name":"Anous minutus","overview":"玄燕鸥（英文名：Black Noddy，学名：Anous minutus），是鸻形目鸥科玄燕鸥属的鸟类。拥有黑色的羽毛和醒目的白色头冠，与较小的小玄燕鸥相似，但其羽毛颜色更深，脸部图案更明显。主要在热带和亚热带海域的岛屿上筑群巢，以其独特的繁殖习性和对人类的容忍度著称。","appearance":"成年玄燕鸥体长约35-40厘米，翼展65-72厘米，体重约110克。全身呈深黑色，头部有白色的前额和王冠，逐渐与暗色颈后部融合。眼睑边缘有白色新月形标记，喙黑色，腿和脚呈红棕色或橙色。尾巴中等长度，闭合时略显方形或叉状，展开时呈楔形。雄雌外观相似。幼鸟的白色头冠与暗色颈后部分界更为明显，体色较淡。","habits":"玄燕鸥群居性极强，常在沿海悬崖、洞穴和树木中筑巢，利用可用材料如树叶、草、海藻和羽毛建造巢穴。它们在热带地区寿命较长，达到性成熟需数年，通常一窝只产一枚卵，但在一个繁殖季节里，一对鸟有时能抚育两窝幼鸟。它们在近岸水域觅食，通常依赖于大型掠食鱼类驱赶猎物至水面，因此很少远离繁殖和栖息的岛屿。","breeding":"繁殖期在热带地区，通常在树上或灌木丛中筑巢，偶尔在悬崖峭壁和海洞中。每年夏季，它们会聚集数千至近万只，飞至特定的海岛繁殖。每季产一枚卵，巢穴会被反复使用多年。","identification":"与白顶玄燕鸥相比，玄燕鸥体型更小，羽毛更黑，喙更细长，白色头冠对比更鲜明。与小玄燕鸥的区别在于体型更大，但比白顶玄燕鸥小，且羽毛颜色更深。不同亚种之间可能存在颜色上的细微差异。","protection":"IUCN：LC（无危）","distribution":"玄燕鸥广泛分布于太平洋和大西洋的热带和亚热带海域，零星分布在印度洋东北部和加勒比海。在中国大陆，主要繁殖于澎湖猫屿等保持原始环境的海岛。"},{"name":"蓝灰燕鸥","english_name":"Blue Noddy","scientific_name":"Anous ceruleus","overview":"蓝灰燕鸥（英文名：Blue Noddy，学名：Anous ceruleus），是鸻形目鸥科玄燕鸥属的小型海鸟。其羽毛呈淡灰色，头部和身体几乎统一色调，仅腹部略浅，具有一双大而深邃的眼睛。分布于热带太平洋岛屿，从日本远东南部至密克罗尼西亚，再到夏威夷西北群岛、马尔凯萨斯群岛和甘比尔群岛。该物种曾在澳大利亚和日本出现过迷鸟记录。","appearance":"蓝灰燕鸥体型小巧，长度约为25至28厘米，平均体重45.4克（非繁殖个体较轻），翼展可达46至60厘米。羽毛呈现独特的淡灰色，头部和身体颜色一致，仅腹部稍显苍白；眼睛周围有白色部分环绕，前方点缀一小黑斑；翅膀上覆羽略深，主翼羽黑色；下体与翅膀下部颜色相近；喙和腿均为黑色。与灰燕鸥相比，蓝灰燕鸥体型更小，颜色更深。","call":"发出独特鼻音的‘kearr’声。","habits":"栖息于热带海洋岛屿上的悬崖或岩石地带，通常在近岸水域和泻湖上空觅食，常以小群形式低飞掠水，快速拍打翅膀，偶尔悬停，脚部轻触水面捕捉猎物。其食谱主要包括极小的鱼、鱿鱼、甲壳类动物和海面漂浮的昆虫。","breeding":"在夏威夷全年繁殖，筑巢高峰期为2月至3月，少数巢穴出现在5月、8月和11月，可能是一种非同步春季繁殖者。在基里蒂马蒂岛，8月至11月繁殖；在凤凰群岛，6月至8月繁殖。巢穴通常位于悬崖缝隙、岩架或凹陷处，有时在砾石或珊瑚碎屑上，或藏于珊瑚板下或植被中。每窝产一枚蛋，孵化期间不详；雏鸟全身白色，喙和眼黑色；出生时体重不足10克；通过反刍喂养，连续抚育2至3周。","identification":"与灰燕鸥相比，蓝灰燕鸥体型更小，颜色更深。亚种间存在差异，主要体现在羽毛色调上。","protection":"IUCN：LC（无危）。全球数量未知，但在部分范围内至少记录了30,000对，总数量可能接近100,000对。最多的亚种可能是nebouxi，数量超过100,000只；saxatilis估计有10,000至25,000只，而指名亚种少于10,000只。","distribution":"分布于热带太平洋海域的众多岛屿，从远东日本和密克罗尼西亚到夏威夷西北群岛、马尔凯萨斯群岛和甘比尔群岛（东图阿莫图群岛，东波利尼西亚）。在西北夏威夷群岛的蓝灰燕鸥亚种saxatilis估计有4,000对繁殖个体加8,000非繁殖个体。线岛（指名亚种）和凤凰群岛（亚种nebouxi）各有高达10,000对。甘比尔群岛（murphyi）约有2000只。基里蒂马蒂岛（指名亚种）有2000只个体。","other":"已知最长寿个体为11岁。"},{"name":"灰燕鸥","english_name":"Grey Noddy","scientific_name":"Anous albivitta","overview":"灰燕鸥（英文名：Grey Noddy，学名：Anous albivitta），是鸻形目鸥科玄燕鸥属的鸟类。这种优雅的银色海鸟具有细长的黑色喙和大而深邃的眼睛。头部和下体呈白色，与灰色的背部和翅膀形成鲜明对比。广泛分布于太平洋亚热带南部，从澳大利亚远东的Lord Howe和诺福克岛，到新西兰东北的Kermadec群岛，直至波利尼西亚东南部和智利北部远西的岛屿。","appearance":"灰燕鸥体长约28至31厘米，翼展可达46至60厘米，体重约75克。其尾部相对较长，末端呈V字型。羽毛色彩以浅灰色为主，头部和腹部几乎呈白色，背部、翅膀和尾部颜色较深。翅膀尖端有暗色边缘，下方主要是白色。眼睛周围有黑色半圈，后面有一块白色斑点。喙薄而尖，呈黑色，腿和脚也是黑色，带有淡黄色蹼。幼鸟的颜色比成鸟更偏褐色，飞行羽颜色更深，对比度更高。","call":"在繁殖群落附近，灰燕鸥会发出低沉哀怨的尖叫，‘kraarr’声，无论是在飞行还是在地面都能听到。在其他地方，它们大多保持沉默。","habits":"灰燕鸥栖息于温带和亚热带海洋岛屿，繁殖期间在岩石岛屿周边活动，筑巢于高达600米的悬崖上，或地面。它们在近岸水域觅食，通常在沿海岛屿附近的浅水区聚集。它们以浮游生物为主要食物来源，也会捕食小鱼。","breeding":"繁殖期在南太平洋的8月至11月（指名亚种）。在繁殖季节，它们会在悬崖缝隙或岩石下筑巢，或在裸露的岩石上，或植被下，如Kermadecs的草丛中。每次产一枚蛋，孵化期未知；雏鸟全身呈烟灰色或巧克力棕色，无斑点，前额深色绒毛，腹部、颈背和面部颜色较浅；约第17天开始长出绒羽，32至45天后离巢。","identification":"灰燕鸥与体型略小的蓝灰燕鸥通过更浅的羽毛色彩、更白的头部和下体以及更长的喙、脚趾和翅膀区分。亚种之间主要在羽毛色调上有所差异。","protection":"IUCN：LC（无危）。全球范围内不被视为受威胁，但确切状况了解不多，可能较为罕见。总数量可能不足25,000对，其中大部分在南太平洋的指名亚种。部分亚种，如东南太平洋的两个亚种，可能处于濒危状态。","distribution":"分布于太平洋的亚热带南部，范围从澳大利亚的远东（Lord Howe和诺福克岛）、新西兰东北的Kermadec群岛，至波利尼西亚东南部和智利北部远西的岛屿。","other":"灰燕鸥曾被认为是蓝灰燕鸥的浅色形态，但现在普遍认为是独立物种。"},{"name":"白燕鸥","english_name":"White Tern","scientific_name":"Gygis alba","overview":"白燕鸥（英文名：Atlantic White Tern，学名：Gygis alba），是鸻形目鸥科白玄鸥属的小型海鸟。通体雪白，尾浅叉，眼如黑曜，为南大西洋群岛特有种。成鸟体长约28–33厘米，翼展80–87厘米，体重110–157克，无两性异形及季节羽色变化。仅繁殖于南大西洋的阿森松岛、圣赫勒拿岛、费尔南多—迪诺罗尼亚及特林达迪等岩礁岛屿，不筑巢，直接将单枚卵置于岩缝或树枝上。","appearance":"成鸟通体纯白，初级飞羽和尾羽羽轴黑色，翼与尾在头顶透光时呈半透明。尾叉较浅，外尾羽仅略长于内尾羽。喙粗短，黑色，仅基线处呈微蓝；腿足石板蓝，趾蹼淡黄至白色。幼鸟与成鸟相似，但初级飞羽外缘及背部羽缘略染褐色，喙基黑色更浓。","call":"成鸟发出连续而轻柔的“eenk-eenk-eenk”或“grrich-grrich”声，常在飞行或停栖时重复。鸣声节奏与音调变化可传递警戒及配对信息。雏鸟乞食时发出微弱“cheep”。","habits":"繁殖期占据岛屿上的岩崖、岩洞或人工建筑突出部，非繁殖期则漂泊于南大西洋开阔海域。觅食多在近岸浅水及上升流区，常随金枪鱼、海豚等掠食性鱼类活动，以水面掠食方式捕捉小型飞鱼和鱿鱼。","breeding":"繁殖期集中于11月至翌年3月，1月达高峰。每窝仅1卵，双亲轮流孵卵约36天。雏鸟约60–75天后离巢，离巢后仍接受亲鸟约2个月补饲。若卵或雏丢失，可在10–21天内补产，部分配对一年成功育成2窝。","identification":"通体纯白在南大西洋区域独一无二，体型明显大于同域的小白燕鸥，尾叉更浅，喙基蓝色范围更小。与蓝灰燕鸥相比，后者在阳光直射下方显白色，且体型更小。","protection":"IUCN: LC（无危）","distribution":"繁殖区域仅限于南大西洋的阿森松岛、圣赫勒拿岛、费尔南多—迪诺罗尼亚群岛、特林达迪岛与马丁—瓦斯群岛。非繁殖期广泛分布于南大西洋热带与亚热带水域，偶见于非洲西岸近海。","other":"曾与小白燕鸥、蓝嘴白燕鸥，目前已分拆为三种。外来黑鼠、猫及人类活动已导致费尔南多—迪诺罗尼亚局部繁殖成功率下降；阿森松岛因军事基地建筑提供了额外筑巢平台，种群近年略有增长。"},{"name":"黑剪嘴鸥","english_name":"Black Skimmer","scientific_name":"Rynchops niger","overview":"黑剪嘴鸥（英文名：Black Skimmer，学名：Rynchops niger），是鸻形目鸥科剪嘴鸥属的鸟类。独特的海岸水鸟，以其特殊的捕食方式和声音而闻名。这种鸥科鸟类的显著特征是其下喙远长于上喙，这一独特的适应性使它能在浅水区捕捉小鱼。分布于北美、中美及南美的沿海地带，从美国加州南部到墨西哥西部，再到美国马萨诸塞州至墨西哥东部，以及南至阿根廷东北部的河流系统。","appearance":"黑剪嘴鸥是一种中等体型的窄身鸟类，全长约40-50厘米，翼展可达107-127厘米。雄鸟平均重349克，雌鸟平均重254克。上半身为黑色，下半身为白色，尾巴外缘为白色，内侧为暗灰色。翅膀较长，边缘呈白色，下翼颜色从白色到灰褐色不等。喙基部红色，其余部分黑色，下喙显著延长。眼睛虹膜深棕色，瞳孔狭长，类似猫眼，腿部红色。幼鸟背部棕色，有白色的羽尖和边缘，腹部和额头白色。","call":"黑剪嘴鸥的叫声为犬吠般的'kak-kak-kak'声。","habits":"黑剪嘴鸥偏好沙滩、沙洲以及河口等环境，常聚集于沙洲休息。它们通常在白天繁殖季节离开巢穴觅食，幼鸟孵化后便离开巢穴，隐蔽于巢边或自行挖掘沙坑。成鸟主要在日间喂养幼鸟，夜间几乎不喂食。飞行轻盈优雅，以大群的形式低飞于水面，利用下喙触碰水面寻找小鱼、昆虫、甲壳类和软体动物。","breeding":"黑剪嘴鸥在沙滩或沙洲上松散地筑巢，每次产三到七个斑点明显的淡色或蓝色蛋，由双亲共同孵化。幼鸟出生后不久即可离巢，由父母在日间几乎独占性地喂养。下喙和上喙长度在孵化时相等，但在离巢前迅速变得不等。","identification":"黑剪嘴鸥最显著的特点是其下喙的异常延长，以及黑白分明的体色和红黑色的喙。与同类物种非洲剪嘴鸥相比，体型更大，喙端更深色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要在美国沿海，从南加州至墨西哥西部，以及从马萨诸塞州至墨西哥东部的海岸线。南美繁殖区域包括北部、中南部至阿根廷东北部的河流系统。非繁殖期间，北美的黑剪嘴鸥会迁移到加勒比海和热带、亚热带太平洋及大西洋沿岸水域，而南美种群仅作较短距离的迁移。","other":"黑剪嘴鸥有三种亚种，分别分布于北美、南美部分地区及印度和非洲。"},{"name":"非洲剪嘴鸥","english_name":"African Skimmer","scientific_name":"Rynchops flavirostris","overview":"非洲剪嘴鸥（英文名：African Skimmer，学名：Rynchops flavirostris），是鸻形目鸥科剪嘴鸥属的鸟类。独特的鸥类。拥有长翼、短尾和特异的喙，上喙比下喙短。分布于撒哈拉以南非洲的河流、湖泊和泻湖地带。其显著特征为橙色长喙，顶端黄色（幼鸟黑色），黑背、白腹，红腿。叫声尖锐，类似‘kip-kip’。","appearance":"体长约38厘米，重111至204克，翼展约106厘米。雄鸟上喙长61至70毫米，雌鸟51至62毫米。繁殖季节，黑颈，非繁殖期具白色颈圈，上体较浅褐色。雌雄相似，幼鸟上体更褐，羽缘带淡色斑点。","call":"叫声为尖锐的‘kip-kip’声。","habits":"栖息于低水位河流、沿海泻湖、盐田、开阔沼泽和湖泊。常在沙洲和沙滩上休息和繁殖。食性主要为鱼，如丽鱼科、罗非鱼科等，通过飞行时下喙掠水捕食。日间、黄昏和夜间活动。","breeding":"繁殖期通常为3月至6月在西非和东非，赤道以南主要为7月至11月。集群繁殖，与燕鸥、鸻、矶鹬等混居。巢为沙中无衬里的坑穴，通常产卵1至3枚，偶尔4至5枚，孵化期约21天，雏鸟孵化后2天离巢，约4周后离巢。","identification":"体型小于同属其他种类，通过黄白色喙尖、繁殖期黑颈等特征辨识。与黑剪嘴鸥的区别在于喙尖颜色，与剪嘴鸥的区别在于繁殖期的黑颈。","protection":"IUCN：LC（无危）。总数量估计在10,000至17,000只成熟个体，或15,000至25,000只个体总体，列入《迁徙物种公约》附录二。","distribution":"繁殖区：从塞内加尔到刚果河北部、尼罗河南部，坦桑尼亚南部至赞比西河谷，再到南非夸祖鲁-纳塔尔省和安哥拉。非繁殖区扩展至河口和泻湖。","other":"面临栖息地破坏、DDT喷洒、人类干扰、巢蛋收集等威胁，导致种群减少。"},{"name":"剪嘴鸥","english_name":"Indian Skimmer","scientific_name":"Rynchops albicollis","overview":"剪嘴鸥（英文名：Indian Skimmer，学名：Rynchops albicollis），是鸻形目鸥科剪嘴鸥属的鸟类。独特的鸟类，以其显著的黑色上部和白色下部羽毛，以及带有亮橙色长喙而闻名。这种鸥科鸟类主要栖息于缓慢流动的河流中，形成喧闹的群落，常与燕鸥为伴。拥有独一无二的下喙，比上喙更长，用于掠食水面下的猎物。","appearance":"成年剪嘴鸥体长约38至43厘米，翼展102至114厘米，喙长58至75毫米。全身黑色与白色相间，头部有宽阔的白色额部，翅膀和初级飞羽内侧有明显的白色边缘。最引人注目的是其带有黄色尖端的红色长喙，下喙明显长于上喙。腿较短，呈红色。雌雄外观相似，但雌鸟略小。幼鸟与非繁殖期成鸟相似，但羽毛颜色更偏棕色，有更重的斑点。","call":"剪嘴鸥发出尖锐的‘kyap kyap’叫声，被形容为小型犬吠声。幼鸟无法飞行时会发出柔和的叽叽声。","habits":"剪嘴鸥偏好大型河流，尤其是水流平缓、有沙洲的区域。它们随季节变化沿河移动，低水位时向上游迁移，洪水期则向下游移动。它们的饮食以鱼类、昆虫幼虫和虾为主，常在极浅的水域觅食。它们在黄昏、夜间甚至月光下活动，行为受天气和猎物活动影响。","breeding":"繁殖期通常在2月至6月之间，受水位影响。剪嘴鸥一夫一妻制，群居繁殖，每窝产卵2至5枚，孵化期约21至24天，主要由雌鸟孵化。雏鸟有灰色或沙色绒毛，散布着暗棕色斑点。","identification":"剪嘴鸥的长下喙是其最显著特征，与完全分离分布的黑剪嘴鸥和非洲剪嘴鸥相比，成鸟繁殖期有白色颈环。幼鸟和非繁殖期成鸟的喙较短且暗淡。","protection":"IUCN：EN（濒危）。总数量估计在6000至10000只之间，可能正在减少，但在大部分分布范围内状况记录不足。","distribution":"主要分布在印度次大陆的中北部、中东部河流，以及缅甸中部。非繁殖期分布至阿拉伯海东北部海岸线、印度半岛湾西北部和北部、孟加拉国等地。","other":"人类干扰、栖息地改变和大规模灌溉项目对其造成威胁，特别是在繁殖地。"},{"name":"燕尾鸥","english_name":"Swallow-tailed Gull","scientific_name":"Creagrus furcatus","overview":"燕尾鸥（英文名：Swallow-tailed Gull，学名：Creagrus furcatus），是鸻形目鸥科燕尾鸥属的夜间活动的鸥类。其独特之处在于拥有深灰色头部、红润的眼环、粉红的腿脚以及带有白色尖端的喙。燕尾鸥主要分布于加拉帕戈斯群岛及附近的马尔佩洛岛，偏好温暖水域。","appearance":"成年燕尾鸥在繁殖季节头部呈珍珠灰色，非繁殖季节头部变为白色，眼周有黑色眼线。喙大多黑色，尖端苍白，眼虹膜深棕色，眼环鲜红。背部、翅膀为灰色，臀部和尾巴白色，腹部纯白。飞行时可见翼间有三角形白色斑块。幼鸟与非繁殖期成鸟相似，但上身颜色更深，呈鳞状图案，喙全黑。","call":"发出一系列叫声，最常见的是咔嗒声与刺耳的‘pee’声，被认为用于回声定位。","habits":"燕尾鸥主要栖息于加拉帕戈斯群岛的悬崖峭壁，尤其偏爱东部岛屿的温暖水域。它们高度海洋性，大部分时间在远离陆地的海域飞翔和觅食。夜间活动，以鱿鱼和小鱼为食，白天也会活动。","breeding":"全年繁殖，但各岛之间不同步。繁殖周期约6个月，单卵孵化，蛋色浅绿或蓝白，有大块褐色斑点。孵化期33-35天，双亲轮流孵卵。雏鸟在出生后头48小时被持续照顾，之后几周内仍靠近巢穴。飞行期58-65天，但依赖父母至90-140天。","identification":"燕尾鸥与其他海鸥显著不同，拥有深分叉的尾巴和红色眼环。在夜间活动，这在海鸥中独一无二。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拉帕戈斯群岛及哥伦比亚西海岸的马尔佩洛岛。非繁殖季节分散至厄瓜多尔至秘鲁中部的海域，偶尔至智利中部。","other":"燕尾鸥的夜间活动与其大眼睛和特殊的视觉机制有关，使其成为世界上唯一的全夜行性海鸥。"},{"name":"三趾鸥","english_name":"Black-legged Kittiwake","scientific_name":"Rissa tridactyla","overview":"三趾鸥（英文名：Black-legged Kittiwake，学名：Rissa tridactyla），是鸻形目鸥科三趾鸥属的鸟类。亦被称为黑腿燕鸥，小型海鸥，广泛分布于北半球的高纬度海域。其显著特征为黄色喙、黑色腿脚和翅膀末端如同墨染的黑色翼尖。成年鸟体长约38-41厘米，翼展91-97厘米。繁殖期间，聚集在悬崖上筑巢，而非繁殖季节则栖息于开阔的海洋。主要以海洋表面的小鱼和大型浮游动物为食。","appearance":"成年三趾鸥拥有珍珠灰色的背部和翅膀，翅膀稍淡，翼尖呈现独特的黑色，宛如蘸墨。头部和腹部白色，喙绿色至黄绿色，腿脚黑色。非繁殖季节，成鸟头颈后方有灰暗的冠带，颈部后侧有深色斑块。幼鸟的颈部和头顶有灰色斑点，颈后有一条醒目的黑色颈环，翅膀上有明显的暗色条纹和黑色翼尖。翼展时，形成一个明显的'M'图案。","call":"三趾鸥的叫声尖锐，似“kit-te-wa-aaake”，这也是其英文名的来源。","habits":"三趾鸥是典型的海洋鸟类，栖息于北极至温带的海洋海岸线上，繁殖期聚居于悬崖上，非繁殖期则广泛分布于开阔海域。它们成群活动，常见于海面上空飞翔，或漂浮于海面，也会跟随船只觅食。主要食物为小鱼，偶尔食用甲壳类和软体动物。","breeding":"繁殖期为6-7月，巢筑于海岸和海岛的悬崖岩石上，由枯草和枯枝构成，内衬羽毛。每窝产卵2-3枚，孵化期约21-25天，雌雄轮流孵化。","identification":"与红腿三趾鸥相似，但后者腿部颜色更鲜艳，背部和翅膀颜色更深，翼尖黑色较浅。幼鸟的区别在于红腿三趾鸥幼鸟缺乏黑色斜杠或腕部横纹。","protection":"IUCN：VU（易危）","distribution":"繁殖区域遍布欧亚和北美高纬度海域，从格陵兰到俄罗斯东部库页岛等地；非繁殖季节分布于大西洋、日本、朝鲜半岛等地。","other":"三趾鸥是受《1918年候鸟条约法》保护的物种，目前全球没有特别的保护计划。"},{"name":"红腿三趾鸥","english_name":"Red-legged Kittiwake","scientific_name":"Rissa brevirostris","appearance":"成年红腿三趾鸥体长介于35-39厘米，翼展可达84-92厘米，体重在325-510克之间。背部呈现深灰色，翼尖黑色，腿脚鲜红，喙较短。非繁殖期个体眼周有暗斑，耳部有一薄灰色斑块。幼鸟外观与非繁殖期成鸟相似，但具黑色喙，腿色较暗，翅膀图案更为鲜明，需三年才能成熟。","call":"红腿三趾鸥的叫声音调高于三趾鸥。","habits":"红腿三趾鸥在夏季栖息于崖壁上的繁殖群落，以鱼、鱿鱼和其他无脊椎动物为食，昼夜活动。它会在9月迁徙至海洋过冬，活动范围广泛，包括北太平洋和阿拉斯加湾。","breeding":"红腿三趾鸥在夏季繁殖，营巢于峭壁的狭小平台上，通常与三趾鸥等其他海鸟共同筑巢。繁殖季节、求偶、产卵等具体细节尚待更多研究。","identification":"与三趾鸥相比，红腿三趾鸥具有更深的背部颜色、较短的喙、较短的腿和鲜红色的腿脚，翼下颜色也更深。幼鸟缺乏三趾鸥幼鸟特有的黑色尾带和翼上的“W”型标记。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于北美科曼多尔群岛（俄罗斯东南部）、阿留申群岛和普里比洛夫群岛，以及白令海北部的圣马修岛。非繁殖季节，它们会迁徙至白令海至冰缘区及南部，以及阿留申群岛。","other":"红腿三趾鸥的种群数量自1970年代中期到1990年代中期减少了约35%，原因可能与食物资源的减少有关，这可能与过度商业捕鱼或气候变化相关。"},{"name":"白鸥","english_name":"Ivory Gull","scientific_name":"Pagophila eburnea","overview":"白鸥（英文名：Ivory Gull，学名：Pagophila eburnea），是鸻形目鸥科白鸥属的鸟类。本属唯一鸟类。拥有独特的全白色羽毛，仅以黑色的腿和蓝绿色带橙尖的喙为特征。分布于北极地区的高纬度地带，包括格陵兰、北美最北端及欧亚大陆北部。","appearance":"成年白鸥体型中等，约40-43厘米长，翼展108-120厘米，体重520-700克。性别间外观相似，无明显季节性变化，两岁达到成熟。全身羽毛纯白，喙厚重呈蓝灰色渐变为灰绿色，末端黄色或红色，腿黑色。幼鸟具有黑色面罩，尾部常有一条狭窄的黑色亚端带，上体和飞羽尖端有黑色斑点，赋予其独特的\"貂皮\"外观。","call":"白鸥发出尖锐的双音节kee-urr声，类似燕鸥的叫声，与大多数大型鸥类截然不同。","habits":"白鸥主要栖息于北极的冰冻海域，冬季靠近浮冰边缘生活。它们以鱼、甲壳类、小型哺乳动物、蛋和小鸟为食，同时也是一种机会主义的食腐动物，经常在海豹或海豚尸体旁觅食。飞行敏捷，常跟随北极熊等捕食者，以捕食它们猎杀后留下的残余。","breeding":"白鸥在北极海岸和悬崖上筑巢繁殖，每次产1-3枚橄榄色的蛋，巢通常由苔藓、地衣或海藻衬里。","identification":"白鸥与其他鸥类相比，体型更为圆胖，颈部较短，头部圆润，喙相对较小且直，比波拿巴鸥稍大，比冰岛鸥小。成鸟完全雪白，眼睛深色，腿黑，喙蓝绿色带黄尖。幼鸟脸部暗色，翅膀和尾巴上有深灰色斑点。","protection":"IUCN：NT（近危）","distribution":"繁殖区域位于北极的高纬度岛屿，从格陵兰至斯瓦尔巴群岛，Franz Josef Land至Herald Island，Wrangel Island，Chukotka半岛北部，俄罗斯北部，以及加拿大北部。非繁殖季节分布于北极海洋的浮冰边缘至格陵兰东南部，加拿大拉布拉多和白令海。","other":"白鸥因其神秘的生活方式和有限的研究，对其生态学、迁徙、越冬生物学、种群规模和动态的了解仍然有限。"},{"name":"叉尾鸥","english_name":"Sabine's Gull","scientific_name":"Xema sabini","overview":"叉尾鸥（英文名：Sabine's Gull，学名：Xema sabini），是鸻形目鸥科叉尾鸥属的鸟类。繁殖于高纬度极地，如格陵兰岛西北部、斯瓦尔巴群岛、西伯利亚东北部、楚科奇半岛、圣劳伦斯岛、阿拉斯加西部和北部以及加拿大北极地区。越冬于东大西洋及东太平洋水域，如南美西海岸和非洲西南部海域。其显著特征包括暗灰色头部、带黄色尖端的黑色喙以及翼上黑白灰三色的标志性图案。","appearance":"小型鸥类，体长27至33厘米，翼展81至87厘米，体重135至225克。拥有细长而尖锐的翅膀。成年鸟背部呈淡灰色，翅膀覆羽相同颜色，初级飞羽黑色，次级飞羽白色，形成鲜明对比。尾巴白色并有分叉。繁殖季节时，雄鸟的头部变暗。幼鸟的翅膀同样呈现三色模式，但灰色部分被棕色取代，尾巴末端有黑色横纹。喙为黑色，尖端黄色，约2.5厘米长。","call":"发出高音调且尖锐的叫声。","habits":"繁殖于北极海岸和苔原地带，越冬时向南迁徙至较温暖的海域。在繁殖季节，以淡水和陆生猎物为主，包括甲虫、水生昆虫、蜘蛛、软体动物、昆虫幼虫、甲壳类动物、鱼类及其它小型脊椎动物。非繁殖季节，主要在海上觅食，可能捕食鱼类、乌贼和浮游生物。","breeding":"繁殖于北极苔原，通常在潮湿地区筑巢，巢材简单，由草构成。每窝产2到3枚橄榄褐色斑点蛋。孵化期约为20至25天。雏鸟出生后迅速成长，以淡水或咸水岸线上的昆虫为主要食物。","identification":"与三趾鸥、楔尾鸥、小鸥和 伯氏鸥最易混淆，主要通过翼上的独特黑白灰图案辨识。幼鸟与 笑鸥的幼鸟相似，但可以通过翅膀上的图案区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于格陵兰岛、斯瓦尔巴群岛、西伯利亚东北部、楚科奇半岛、圣劳伦斯岛、阿拉斯加西部和北部、加拿大北极地区。越冬时分布于南美西海岸至智利北部、非洲西南海域从安哥拉至南非东南部。","other":"叉尾鸥在春季到达繁殖地时，腹部有时会呈现淡粉色，但这种颜色随时间逐渐消退。"},{"name":"细嘴鸥","english_name":"Slender-billed Gull","scientific_name":"Chroicocephalus genei","overview":"细嘴鸥（英文名：Slender-billed Gull，学名：Chroicocephalus genei），是鸻形目鸥科彩头鸥属的鸟类。中型鸥类，体长约37至40厘米，翼展可达90至102厘米，略大于红嘴鸥。繁殖于地中海周边和印度洋西北部的特定地区，如巴基斯坦沿海岛屿和盐湖。分布范围分散，部分群体迁徙至北非和印度过冬，偶见于西欧。命名源自古希腊语，纪念意大利自然学家Giuseppe Gené。","appearance":"成年细嘴鸥具有一身淡灰色体羽，头部与胸部白色，初级飞羽尖端黑色。繁殖季节的个体头颈部细长，嘴部与腿部暗红色，虹膜呈黄色。夏季胸部可能带有微弱的粉色。第一年幼鸟尾端有黑色带纹，翅膀上有深色区域。两岁成熟，与红嘴鸥相比，嘴更细长，颈更为僵硬。","call":"叫声比红嘴鸥更深沉、更浑厚，尤其是滚动叫声更低沉、干燥且有力。","habits":"栖息于地中海和印度洋西北部的沿海湿地、咸水湖和三角洲。在冬季，迁徙至海岸、河口和海湾，觅食场所包括沼泽、草地和垃圾填埋场。主要食物为小鱼和水生无脊椎动物，通过空中俯冲、探泥觅食和捕食飞虫。","breeding":"繁殖期为5月至6月，集群筑巢于海滩、沙洲或盐沼，巢由枯草简单铺垫，产卵数量通常为3枚，有时为2枚或1枚，卵色白或乳白，带黑褐色斑点，孵化期约25天，幼鸟约25天后离巢。","identification":"与红嘴鸥的区别在于细嘴鸥耳上斑点模糊，嘴端无黑色，嘴和腿的橙色更深，飞行时颈和尾显得更长，背部弓起。虹膜颜色也是辨识关键，细嘴鸥为黄色，红嘴鸥为褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖于地中海沿岸、伊比利亚半岛南部、南欧、黑海、里海、土耳其至中亚，巴基斯坦和印度西北部沿海，毛里塔尼亚、塞内加尔和冈比亚。非繁殖季节分布至阿拉伯半岛和印度西部海岸。","other":"《非洲-欧亚迁徙水鸟保护协定》适用物种之一。"},{"name":"伯氏鸥","english_name":"Bonaparte's Gull","scientific_name":"Chroicocephalus philadelphia","overview":"伯氏鸥（英文名：Bonaparte's Gull，学名：Chroicocephalus philadelphia），是鸻形目鸥科彩头鸥属的鸟类。小型鸥科鸟类，广泛分布于北美地区的北部。其最显著的特征为繁殖季节时的黑色头部，以及独特的翼尖白色图案。伯氏鸥偏好栖息于靠近水源的针叶林地带。","appearance":"伯氏鸥体型较小，长度约28-30厘米，翼展90-100厘米。繁殖期成鸟头部全黑，眼周有细白弧，上体灰色，翅膀尖端黑色，腿脚鲜红。非繁殖期成鸟及幼鸟头部多呈白色，耳部有黑色斑点，腿部偏粉色，翅膀上有褐色和黑色的标记。幼鸟的翅膀标记更为明显。","call":"伯氏鸥的声音被描述为鼻音重、沙哑，常见叫声转写为cherr或cheeer。","habits":"伯氏鸥栖息于针叶林地带近水处，以小鱼和无脊椎动物为食，常在水面优雅地飞舞捕食。迁徙期间，它们会聚集于海滩、海湾、湖边等地。","breeding":"繁殖季节始于六月中旬，通常在树上筑巢，尤其偏好针叶树，每窝产2-4枚蛋，由双亲共同孵化。幼鸟孵化后不久便会离巢跟随父母到最近的水域。","identification":"伯氏鸥与红嘴鸥相似，但后者体型更大，喙部更长且厚重，翼拍速度较慢，翅膀更宽，背部颜色更淡，翼下有明显的黑色区域。此外，幼鸟的喙部颜色和翅膀上的标记也有差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美的针叶林地带，从美国阿拉斯加南部至加拿大魁北克省东部。非繁殖期分布于太平洋东部海岸至墨西哥中西部，美国内陆东南部，大西洋西部海岸线至佛罗里达，巴哈马群岛和古巴。","other":"伯氏鸥的生命周期为两年，成年羽衣在两岁时获得。"},{"name":"澳洲红嘴鸥","english_name":"Silver Gull","scientific_name":"Chroicocephalus novaehollandiae","overview":"澳洲红嘴鸥（英文名：Silver Gull，学名：Chroicocephalus novaehollandiae），是鸻形目鸥科彩头鸥属的鸟类。属于彩头鸥属，是澳大利亚最普遍的鸥类，广泛分布于整个大陆的沿海地带，尤其是南澳大利亚内陆至沿海地区。比太平洋鸥体型小，与银鸥容易混淆，但后者体型更大，两者分布区域不重叠。","appearance":"成年澳洲红嘴鸥体长38-43厘米，体重195-430克，翼展91-96厘米。头部、身体和尾巴白色，翅膀呈淡灰色，翼尖有黑白相间的斑点。喙全为鲜红色，腿色暗红。眼睛白色，有窄窄的肉色眼环。雄鸟喙深超过11毫米，雌鸟喙深小于11毫米。幼鸟头部有棕色斑纹，翅膀有棕色斑点，喙、眼睛和眼环颜色较暗，腿色介于肉色到黑色之间。","call":"声音响亮，常发出尖锐的‘kwarr’或‘kwe-aarrr’声，也有急促的吠叫音。","habits":"栖息于海岸和内陆水域附近，包括沙滩、岩石岸、公园、海滩、垃圾堆和农田。以各种无脊椎动物、小鱼、两栖动物、鸟类、哺乳动物和植物为食，适应性强，常见于城市环境，依赖人类产生的食物源。","breeding":"繁殖期从3月持续至11月，每窝产卵1-6枚，通常3枚，蛋色绿色至棕色，带深色斑点，孵化期19-27天，由双亲共同孵卵。雏鸟出生时覆盖着灰褐色绒羽，约四周后随父母离开巢区，六周左右停止接受亲鸟喂养。","identification":"与银鸥相比，体型较小，分布区域不同，可借此区分。","protection":"IUCN：LC（无危）","distribution":"广泛分布于澳大利亚内陆南部及沿海区域，新西兰沿海及外围岛屿，以及新喀里多尼亚。","other":"在某些地区，如机场和其他海鸟群落，可能成为害鸟。随着其他海鸟数量的增加，如黑背鸥和澳洲鲣鸟，其数量在当地有所下降。"},{"name":"新西兰黑嘴鸥","english_name":"Black-billed Gull","scientific_name":"Chroicocephalus bulleri","overview":"新西兰黑嘴鸥（英文名：Black-billed Gull，学名：Chroicocephalus bulleri），是鸻形目鸥科彩头鸥属的鸟类。属于近危物种，仅分布于新西兰，约25万年前其祖先从澳大利亚迁徙而来。体型适中，身长35-38厘米，翼展约90厘米，体重约230克，头部、身体和部分翅膀呈白色，背部和翅膀银灰色，翼尖带有黑色边缘。","appearance":"新西兰黑嘴鸥的头部、躯干和尾部为白色，翅膀和肩部为淡灰色，翼尖具有细窄的黑色边缘。成鸟的喙长而纤细，呈黑色，腿色通常为黑色或暗红色，但在繁殖季节晚期变为亮红色。非繁殖期成鸟喙基部有红褐色调，幼鸟喙为浅粉色，尖端深色，腿粉红色。眼环颜色随季节变化，通常黑色，但在某些时期可能呈现橙红色或红色。","call":"叫声多样，包括短促的嘶哑尖叫“krrreh”和更加强烈拉长的“krrreeah”，可以单独发出或以松散系列形式发出，尤其是在繁殖群体附近叫声更为频繁。","habits":"主要栖息于新西兰南岛的交错河流床、湖泊、公园、湿润草地、牧场和耕地。繁殖期以外，它们常在海岸、河流、湖泊边活动，也会在农田觅食和城市垃圾堆中寻找食物残渣。它们以蚯蚓、昆虫、小鱼和水生无脊椎动物为主食，群居觅食，跟随耕作机具在新翻的土地上觅食，偏好在湿润草地和牧场进食。","breeding":"繁殖期始于8月沿海岸开始，9月中旬占领巢址。群落同步筑巢，巢由小树枝构成，内铺草料。通常产卵2枚（1-3枚），双亲共同孵化，孵化期20-24天，孵化期间蛋不会被弃置。孵化后，家庭可能因干扰而在一天内离开巢穴。雏鸟识别父母的叫声，约26天后离巢。最早可在2岁繁殖，但通常在3-4岁。","identification":"与银鸥相比，新西兰黑嘴鸥的喙更长更细，翼尖黑色部分较少，整体色调更浅。幼鸟与成鸟相似，但冠羽、背部和翅膀上有淡棕色羽尖，次级飞羽上有更多黑色斑块。","protection":"IUCN：NT（近危）。过去20年，南岛某些河流上的繁殖鸟数量下降高达90%，北岛的小型繁殖群虽有增加，但不足以弥补南岛的损失。总数量估计约为100,000只，但需重新评估。","distribution":"繁殖区主要位于新西兰南岛的交错河流系统，北岛也有少量繁殖点。非繁殖期大部分移至北岛南部和南岛北部的海岸线，偶尔出现在斯图尔特岛和斯内尔斯群岛。","other":"新西兰黑嘴鸥在20世纪因农业活动的扩展而数量增加，因其帮助控制害虫。然而，栖息地受到外来植物（如紫花苜蓿）过度生长、人类休闲活动、水电开发、水和砂石开采的影响，以及鼠类、鼬类和野猫的捕食威胁。"},{"name":"安第斯鸥","english_name":"Andean Gull","scientific_name":"Chroicocephalus serranus","overview":"安第斯鸥（英文名：Andean Gull，学名：Chroicocephalus serranus），是鸻形目鸥科彩头鸥属的鸟类。属于彩头鸥属的大型鸥类，广泛分布于南美洲的安第斯山脉，从哥伦比亚远西南部至智利中南部和阿根廷西南部。其特征为拥有光泽黑顶，白眼眉纹，灰背及有时带粉红晕的下体，翅膀展示独特的黑白相间图案。","appearance":"成年安第斯鸥长42至48厘米，体重约480克。繁殖季节的成鸟具有光亮的黑色头部，白色后眼眉纹，灰色背部，有时下体带粉色。翼展上显示复杂的黑白交替图案，初级飞羽形成白色-黑色-白色-黑色的序列。第一年的幼鸟头部有斑驳的黑色，翼部有复杂的黑白花纹，尾巴末端附近有黑色条带。","call":"发出激动的、有时颤抖的“yeeer”叫声，还有嘶哑的‘raggh-aggh-keeaagh’和其他低沉粗糙的音符。","habits":"安第斯鸥栖息于高山湖泊、沼泽、湿地和田野，冬季会迁移到太平洋沿岸，常见于秘鲁中部至智利北部的沿海地区。它们在山地以蚯蚓、昆虫、两栖动物、小鱼和水鸟的蛋与幼鸟为食；沿海地区则以残渣、鱼类和海洋无脊椎动物为主食。","breeding":"繁殖季节主要在7月至8月，但依据气候条件而异。通常单独或小群繁殖，筑巢于河岸或湖泊中的小岛上。巢距一般为1至3米，平均1.3米，通常位于岩石或植被基部。每窝产2至3枚卵（1至4枚），孵化和抚育细节未知。","identification":"比其他头戴帽状的鸥类体型更大且更为粗壮，翼尖具有标志性的白色宽带，所有年龄段都有相对较小的暗色喙和腿脚。与较小的L. maculipennis相似，但后者腿脚颜色更暗。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美洲安第斯山脉，从哥伦比亚远西南部至智利中南部和阿根廷西南部。冬季部分个体移动至太平洋沿岸，主要分布于秘鲁中部至智利北部。"},{"name":"棕头鸥","english_name":"Brown-headed Gull","scientific_name":"Chroicocephalus brunnicephalus","overview":"棕头鸥（英文名：Brown-headed Gull，学名：Chroicocephalus brunnicephalus），是鸻形目鸥科彩头鸥属的鸟类。繁殖期头部前部呈棕黑色，背部灰色，初级飞羽基部有显著的白色大块斑点，翼尖黑色并带有白色点斑，这是其独特的识别特征。分布于中国新疆、青海、甘肃、西藏、四川、山西、河北、云南、广东等地，以及欧亚地区的青藏高原内陆、塔吉克斯坦、中国西部、印度远西北部和西藏。","appearance":"成鸟体长41-45厘米，体重450-714克，翼展105-115厘米。较红嘴鸥体型更大、更粗壮，头顶平坦。繁殖期头部呈浅棕色，接近奶巧克力色，向喙部渐淡。非繁殖期和第一冬龄的个体有深色耳斑和暗色兜帽痕迹。所有羽毛状态可能与较小的黑头鸥混淆，但具有淡色的眼睛和所有羽毛状态下初级飞羽上的更多黑色部分。成鸟的翼尖特征为坚实的黑色，与红嘴鸥不同。虹膜淡黄色或灰白色，有狭窄的红色眼眶环。","call":"发出沙哑的'gek, gek'声及响亮的哭泣叫声'ko-yek, ko yek'。","habits":"棕头鸥栖息于高海拔湖泊、沼泽、草原湿地及环水岛屿，主要以鱼类和水生软体动物为食。它们的捕食能力不及鸬鹚和鱼鸥，因此常跟随这些鸟类寻找剩余食物。春季迁徙至青海，秋季集群南飞越冬，与其他鸥类混群，栖息于海上、沿海及河口地带。群体防御能力强，特别是在产卵孵化和育雏期。","breeding":"每年3月中下旬迁至青海湖，4月中旬开始在鸟岛营巢。偷取斑头雁的筑巢材料，并在雁外出时偷食雁卵。5月中旬产卵，每巢3-4枚，孵化期约25天。幼鸟待飞羽齐整后随亲鸟离开。","identification":"与红嘴鸥相比，棕头鸥体型更大，虹膜颜色更浅，翼尖有明显的白色大块斑点。亚成鸟时，两者的区别在于红嘴鸥翼前缘白色呈条状，而棕头鸥翼尖形成黑三角形。","protection":"IUCN：LC（无危）","distribution":"繁殖于青藏高原内陆，塔吉克斯坦，中国西部（Xinjiang），印度远西北部（Ladakh）和西藏。冬季迁徙至印度次大陆内陆和沿海，中国西南部，亚洲西部东南部。"},{"name":"褐头鸥","english_name":"Brown-hooded Gull","scientific_name":"Chroicocephalus maculipennis","overview":"褐头鸥（英文名：Brown-hooded Gull，学名：Chroicocephalus maculipennis），是鸻形目鸥科彩头鸥属的鸟类。彩头鸥属的鸥科鸟类。其特征为头部和喉部呈深棕色，眼后有一圈白色，颈、胸和腹白色，喙与脚为红色。广泛分布于南美洲，包括阿根廷、巴西、智利、福克兰群岛和乌拉圭。繁殖季节在南美内陆与沿海地区，冬季则北移至智利北部和巴西中部。","appearance":"成熟个体头部与喉咙呈深棕色，眼后环绕一圈白色，颈部、胸部和腹部均为白色。喙与腿为鲜红色。初级飞羽为暗灰色，次级飞羽与覆羽为较浅的灰色。雌雄两性在外观上并无显著差异。","call":"发出尖锐而高音的叫声，类似燕鸥的“zhree”声，以及短促的“kip kip kip”。在巢穴防卫时会发出刺耳的、喉音的“kwarr”声。","habits":"群居性鸟类，以昆虫、腐肉为主食，常从其他鸟类处通过偷窃寄生的方式获取食物，如红腰凤头䴙䴘和美国蛎鹬的蟹和蛤蜊。筑巢于水边的浮草中，偏好淡水湖、潮间带沼泽、河岸和开阔田野。","breeding":"繁殖期在11月至12月之间，有时单独筑巢，但通常集群，每群5-50个巢，偶尔超过500个。与白脸琵鹭、海鸥和南美燕鸥共栖。巢由大量草构成，直径约25厘米。每窝产2-3枚蛋（平均2.6枚），孵化与离巢时间未详。","identification":"与富兰克林鸥相似，但可通过头部颜色、翼尖斑点和叫声区分开来。在非繁殖期，脸颊上的深色斑点是明显的辨识特征。","protection":"IUCN：LC（无危）；总数量估计在5万至10万对之间，似乎正在增加。在福克兰群岛，数量估计为4200-7800只。在智利常见，在阿根廷东部通常被认为是常见的。","distribution":"繁殖于南美洲内陆与沿海，包括巴西东南部、智利中部、阿根廷中北部及福克兰群岛。冬季北移至智利北部和巴西中部。","other":"与黑头鸭存在寄生关系，黑头鸭会将卵产在褐头鸥的巢中，让后者代为孵化。"},{"name":"红嘴鸥","english_name":"Black-headed Gull","scientific_name":"Chroicocephalus ridibundus","overview":"红嘴鸥（英文名：Black-headed Gull，学名：Chroicocephalus ridibundus），是鸻形目鸥科彩头鸥属的鸟类。俗称: “水鸽子”，包括湿地、海边、农田等，常以群体形式出现，数量可达数千。在中国，红嘴鸥繁殖于西北部天山和东北湿地，冬季南迁至东南部及北纬32°以南的所有湖泊、河流及沿海地带。","appearance":"红嘴鸥体长37至43厘米，翼展94至110厘米，体重195至325克。繁殖成鸟头部深巧克力棕色至近黑色，有黑色边缘；眼睛周围有白色新月形纹，颈部白色；身体下部白色，部分个体腹部有粉红色光泽；背部、上覆羽、次级飞羽和内侧初级飞羽灰色，次级飞羽有白色尖端；外侧初级飞羽白色，边缘和尖端黑色；尾巴白色；嘴和腿深红色；眼睛深棕色。亚成鸟背部斑驳的棕色，冬季换羽后变为浅灰色。喙和脚红色，身体大部分羽毛白色，尾羽黑色。","call":"红嘴鸥在繁殖季节叫声嘈杂，发出尖叫的、下降的、但旋律优美的'krreeaarh'或类似叫声，常连续重复。觅食群体则发出较安静的类似叫声。也发出短促的'kek'或'kekekek'声。","habits":"红嘴鸥栖息于沿海、河流、湖泊，常集群活动，有时与其他海鸟混群。它们在水面或陆地上停歇，以鱼虾、昆虫为食，也会在城镇中寻找人类丢弃的食物残渣。它们是机会主义喂食者，冬季依赖人类提供的食物源，如在垃圾场、公园和渔港附近觅食。","breeding":"红嘴鸥在古北界繁殖，南迁至印度、东南亚及菲律宾越冬。在中国西北部天山西部地区及中国东北的湿地繁殖。它们在芦苇或草丛地面上筑巢，巢相当简陋，产卵2至6枚，孵化期为23至24天。幼鸟可能返回出生地繁殖。","identification":"红嘴鸥与棕头鸥的区别在于体型大小、虹膜颜色、翼尖的白色标记。与遗鸥相比，遗鸥的白色眼睑更粗，翼合拢时翼尖具数个白点，而非繁殖期遗鸥头顶及颈背具暗色纵纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆，从格陵兰沿海远南部至中国东北部。非繁殖期分布于非洲、印度洋、远东至菲律宾，以及内陆部分地区，如非洲、印度次大陆和亚洲东南部。","other":"红嘴鸥在某些地区的数量增长迅速，尤其是在人类居住地附近，如垃圾场和城市。"},{"name":"灰头鸥","english_name":"Grey-headed Gull","scientific_name":"Chroicocephalus cirrocephalus","overview":"灰头鸥（英文名：Grey-headed Gull，学名：Chroicocephalus cirrocephalus），是鸻形目鸥科彩头鸥属的鸟类。分布于南美洲与非洲撒哈拉以南地区的中型鸥类。其繁殖于南美、非洲沿海及内陆湖泊，形成大型群落，尤其在阿根廷东北部至圣菲省、乌拉圭南部等地常见。成鸟具有独特的灰色头冠，红嘴红腿，冬季时头冠褪色留下暗色条纹。","appearance":"成年灰头鸥身长42厘米，夏季具灰色头冠，体羽呈灰色，比黑头鸥稍暗。翅膀上的初级飞羽尖端黑色，带有显眼的白色镜状斑。下翼深灰色，翼尖黑色。冬季时，灰头冠消失，仅留有深色条纹。两性相似，南美亚种较非洲亚种体型略大，背部更淡。幼鸟具黑色尾端带，翼上更多暗色区域。","call":"灰头鸥叫声嘈杂，类似乌鸦的“嘎嘎”声，但在音调上更深沉、嘶哑。","habits":"灰头鸥主要栖息于热带和亚热带的海岸、离岸岛屿、内陆湖泊及河流。它们在岩石岛、土堤及罕见的沿海沙丘上繁殖。非洲的灰头鸥可见于河口、港口、淡水和碱水湖，非繁殖期也会出现在人类聚居区、牛棚和渔港。它们通常不会大规模迁徙，但会向北移动至2000公里沿大西洋或印度洋海岸线。","breeding":"灰头鸥在4月至5月间繁殖，筑巢于芦苇丛或沼泽中，有时巢建于浮游植物之上。每窝产2至3枚蛋，孵化及育雏期未知。雏鸟体色黄褐色，头部和上体有不规则的黑色斑点。","identification":"灰头鸥与黑头鸥相比体型略大，翼下颜色更深，翼尖图案不同。幼鸟与黑头鸥幼鸟相似，但翼尖全黑，翼下颜色更深，尾部暗色带更窄。","protection":"IUCN：LC（无危）。全球估计数量在455,000至940,000之间，其中最大种群位于非洲赤道地区，包括中非和东非的200,000至400,000只，西非最多30,000只，南非200,000至400,000只，马达加斯加最多10,000只。","distribution":"分布于南美、非洲沿海和内陆南部，撒哈拉沙漠以南，马达加斯加，厄瓜多尔沿海和秘鲁，乌拉圭南部和阿根廷东北部至圣菲（阿根廷中北部）。","other":"灰头鸥在北美洲、意大利和西班牙有零星迷鸟记录。"},{"name":"哈氏鸥","english_name":"Hartlaub's Gull","scientific_name":"Chroicocephalus hartlaubii","overview":"哈氏鸥（英文名：Hartlaub's Gull，学名：Chroicocephalus hartlaubii），是鸻形目鸥科彩头鸥属的鸟类。现在归入彩头鸥属。该物种以德国医师兼动物学家Gustav Hartlaub命名。哈氏鸥主要分布在南非洲西南部沿海地区，从纳米比亚中部到南非西开普省，适应力强，常在人类聚居区附近活动。","appearance":"哈氏鸥体长约37-39厘米，翼展89-92厘米，体重235-340克。成鸟白色身体，背部和上翅灰色，翼尖黑色，带有显著的白色斑点。喙和腿深红色，眼睛棕色。繁殖季节头部有淡淡的薰衣草灰色，边缘较暗。非繁殖季头部全白。幼鸟头部和身体白色，翅膀和背部棕色，尾巴白色，无黑色末端带。","call":"哈氏鸥叫声嘈杂，发出一系列刺耳的尖叫，如‘krreeh..krreeh..krreeh..’，还有更强调的下滑音‘krrraaah’和高音尖叫。","habits":"哈氏鸥栖息于海岸、港口、湿地草坪、垃圾堆和屠宰场。繁殖于低平岛屿，包括人造岛屿和污水处理厂或盐田中的堤坝。有时在建筑物上筑巢。大量聚集在水淹的田野觅食。城市环境中常见，能适应人类环境，已向内陆扩展至50公里。夜间活动频繁。","breeding":"繁殖季节因地点而异，一般从2月到9月，或4月至6月高峰。北部11月开始繁殖，南部1月开始。全年在斯瓦科普蒙德繁殖。巢通常由10-1000对组成，巢间距1-2米。巢建于裸露或稍有植被的地面上，偶尔在灌木上。每窝1-3枚蛋，平均孵化期约25天，雏鸟约40天离巢。繁殖成功率往往很低。","identification":"与灰头鸥相比，哈氏鸥体型略小，喙更细长、颜色更深，腿色更深红，头部更苍白且头部无明显灰罩，眼睛颜色更深。幼鸟与同龄灰头鸥的区别在于缺乏黑色尾端带，翅膀上的暗色区域较少，腿色更深，头部全白。","protection":"IUCN：LC（无危）。总数量估计约为30,000只，自2001年以来呈现上升趋势。繁殖失败率高，受到天敌和人为因素的影响。","distribution":"哈氏鸥是非迁徙性鸟类，主要分布于南非洲西南部沿海，从纳米比亚中部至南非西开普省，包括开普敦周边地区。","other":"哈氏鸥在城市中被视为害鸟，因污染建筑和城市池塘而受到诟病。"},{"name":"黑嘴鸥","english_name":"Saunders's Gull","scientific_name":"Saundersilarus saundersi","appearance":"体长29–32厘米，体重170–220克，翼展87–91厘米。成鸟繁殖期头部及后颈黑色，眼周上下有白色新月形斑；背部及上翼覆羽蓝灰色；外初级飞羽白色，尖端黑色；内初级飞羽主要为黑色，形成翼下特征性黑斑；次级飞羽多为白色；喙黑色；腿和脚红色；虹膜深褐色。非繁殖期头部白色，颈部有灰斑，眼前后各有一黑斑。第一冬鸟翼部图案似红嘴鸥，但头部及粗重黑喙似小鸥。尾羽黑色横带极窄。","call":"鸣声高亢尖锐，似燕鸥，常见叫声为“kee-eek”或“kip”，另有“chao”声。","habits":"主要栖息于沿海区域，偶见于近岸淡水水体。繁殖于沿海盐沼及河口三角洲，非繁殖期活动于潮间带泥滩。觅食活动与潮汐密切相关，退潮时最为活跃。主要以小型蟹类（如Macrophthalmus abbreviatus）、小鱼及多毛类为食，具强壮喙部可撕裂猎物。","breeding":"繁殖资料有限。所有已知繁殖地均位于沿海盐沼，巢建于碱蓬（Suaeda glauca）群落中。巢为浅杯状，内衬碱蓬枝条。每窝通常产卵3枚，偶见5–6枚，可能与雌-雌配对有关。在中国辽宁双台河口国家级自然保护区，3月中旬抵达，4月下旬开始求偶，5月初建群并开始孵化，5月底雏鸟出壳，6月底首次离巢。","identification":"与红嘴鸥相似，但体型更小，喙全黑且粗短略钩，翼尖白色，繁殖期头部全黑。与小鸥相比体型更大，翼部图案不同。与伯氏鸥相似但喙更厚重。第一冬鸟翼部似红嘴鸥，但头部及喙部特征更接近小鸥。","protection":"IUCN: VU（易危）。此前列为濒危。曾因栖息地丧失及人为干扰导致种群锐减，2008年重新评估全球种群不少于14,400只。主要威胁包括潮滩及盐沼围垦、外来种互花米草扩张、石油勘探、人为拾卵、工业污染及繁殖期台风等。","distribution":"繁殖于中国东部沿海，自辽宁经河北、山东至江苏，韩国西海岸偶见。非繁殖期分布于韩国南部、日本九州、中国东南部、海南及越南北部，极罕见于菲律宾吕宋岛。","other":"该种繁殖地直至1984年才被正式确认。雌-雌配对现象可能与化学污染有关。"},{"name":"小鸥","english_name":"Little Gull","scientific_name":"Hydrocoloeus minutus","overview":"小鸥（英文名：Little Gull，学名：Hydrocoloeus minutus），是鸻形目鸥科小鸥属的鸟类。世界最小的鸥类，分布广泛，主要于欧亚大陆的淡水环境中繁殖，冬季则迁徙至沿海区域。其显著特征包括黑色头部、红腿、深色翅膀底部，以及独特的淡灰色背部和翅膀上方。小鸥为单型属物种。","appearance":"成年小鸥体长24至28厘米，翼展62至69厘米，是全球最小的鸥类。繁殖季节，其头部呈黑色，喙为暗红色，腿部鲜红，下体带粉红色调。非繁殖季节，头部具黑帽和耳斑，白色下体，喙和腿部颜色较淡。所有阶段均具有淡灰色背部和翅膀，白色初级飞羽与深灰下翼形成鲜明对比。幼鸟背部和头部有大片黑色，飞行时可见上翼的暗‘W’形图案与白色下翼。首冬时，头部和身体外观似成鸟，但上翼图案保留。次年，接近成鸟，但仍留有黑色初级飞羽。","call":"鸣声描述未详。","habits":"小鸥栖息于密集植被覆盖的淡水环境，如缓慢流动的河流、沼泽和湿地。迁徙期间，它们可能出现在内陆水域。冬季，它们偏好海岸、河口、沙质和泥泞的底质，甚至远至海洋。小鸥倾向于群体活动，觅食时主要捕食飞行中的昆虫，冬季转向小型鱼类和海洋无脊椎动物。","breeding":"繁殖期始于5月至6月，小鸥通常成群繁殖，有时与其它鸥类共栖。巢建于水边或近水的沼泽地，主要由干草和芦苇构成。每窝产卵2至3枚，颜色为橄榄绿或褐色，带有褐色斑点。孵化由双亲共同承担。","identification":"小鸥与伯氏鸥相比，体型更小，翼尖白色，下翼深色，且翅膀更为圆润。幼鸟的上翼呈现明显的黑色‘M’形图案，区别于其他鸥类。","protection":"IUCN：LC（无危）","distribution":"繁殖于北欧至西伯利亚，蒙古西北部，中国东北部，北美五大湖区。非繁殖期分布于欧洲北部海岸，地中海，巴伦支海，黑海和里海，北美大西洋沿岸至北卡罗来纳州。","other":"近年来，小鸥在英国成功繁殖，显示了其分布范围的潜在扩张。"},{"name":"楔尾鸥","english_name":"Ross's Gull","scientific_name":"Rhodostethia rosea","overview":"楔尾鸥（英文名：Ross's Gull，学名：Rhodostethia rosea），是鸻形目鸥科楔尾鸥属的鸟类。小型鸥科鸟类，独属于其属，以其独特的玫瑰色胸部而得名。分布于北极圈内的高纬度地区，包括北美洲最北端和东北西伯利亚，偏好苔原湿地作为繁殖地。","appearance":"楔尾鸥体型与小鸥相近，略大，翼展宽广，尾部呈楔形，腿红。繁殖期成鸟背部淡灰色，腹部白色，胸部泛玫瑰色，颈部有黑色环带。非繁殖期失去粉色和黑色环带，眼后形成小暗色新月形。幼鸟类似非繁殖期成鸟，但翅膀上有明显的暗色W型图案。","call":"叫声比多数鸥类音调更高，更为悦耳，包括在繁殖地听到的短促、干燥的吠声'a-dac a-dac a-dac'或'de-urr de-urr'，以及报警时发出的短促、似燕鸥的'kik kik kik kik'声。","habits":"繁殖期栖息于北极苔原或森林苔原，偏好生长有草本苔原植物的湖泊和水塘。飞行轻盈敏捷。非繁殖期则在靠近浮冰的开阔海洋上和冰上活动，冬季主要栖息于开阔的海洋。繁殖期以昆虫和幼虫为主食，非繁殖期则捕食甲壳类、软体动物和小鱼。","breeding":"繁殖期为6月至7月，成小群繁殖，巢筑于湖边或沼泽地的土丘上，由枯草和苔藓构成。每窝产卵3枚，有时2至4枚不等，卵色为褐色或橄榄绿色，带有黑褐色或栗褐色斑点，孵化期约为21天。","identification":"与小鸥相比，楔尾鸥翼展更宽，翅膀更尖，尾部呈楔形，腿部颜色鲜艳。在繁殖期，成鸟具有明显的粉红色胸部和黑色颈环，非繁殖期则失去这些特征。","protection":"IUCN：LC（无危）","distribution":"繁殖于格陵兰西部、北极西伯利亚东北部、加拿大东北部和曼尼托巴省的丘吉尔（中西部哈德逊湾，中东部加拿大）。非繁殖期分布在北极海洋、美国阿拉斯加州的北博福特海和加拿大的拉布拉多海。","other":"人类干扰、掠食者如鸥类、贼鸥和游隼，以及恶劣天气对繁殖成功率造成影响。"},{"name":"豚鸥","english_name":"Dolphin Gull","scientific_name":"Leucophaeus scoresbii","overview":"豚鸥（英文名：Dolphin Gull，学名：Leucophaeus scoresbii），是鸻形目鸥科豚鸥属的鸟类。原产于南美洲南部，包括智利沿海中部、南部和阿根廷至火地群岛，以及福克兰群岛。拥有灰色的身体，翅膀颜色较深，头部在繁殖季节为灰色，而非繁殖季节则为白色。豚鸥栖息于岩石、沙质及泥质海岸，常见于海鸟群落附近。","appearance":"豚鸥体型中等，长度介于40-46厘米，体重约524克，翼展可达104-110厘米。全身覆盖着均匀的灰色羽毛，头部和腹部色调一致，背部和翅膀上的主羽呈深色，没有白色的斑点，而次级飞羽和内侧主羽则有宽阔的白色三角形边缘。尾巴全白，喙和腿鲜红色，眼睛白色，周围有明显的红色眼环。","call":"豚鸥发出的长鸣是由粗哑的喋喋声和一到两个高音尖锐的尖叫组合而成。还有响亮的摩擦音，单独或连续发出，高音尖叫和低沉的‘chuk’音。","habits":"豚鸥主要以腐肉、废弃物、鸟蛋、雏鸟、海洋无脊椎动物和其他天然食物为食。它们会在海鸟和海洋哺乳动物群落附近觅食，寻找死鱼、胎盘，尤其是粪便。自然食物大多在鸟蛋可获取之前食用。豚鸥也会利用人类干扰海鸟群落的机会，捕食无人看管的鸟蛋和雏鸟。偶尔会从企鹅和鸬鹚的雏鸟那里抢夺食物，甚至从手中盗取企鹅蛋。雏鸟主要以企鹅巢穴周围的鱼残骸为食。","breeding":"豚鸥自9月起聚集于繁殖群落，产卵时间从11月初（火地群岛）到11月末（Punta Tombo），主要在12月。繁殖地点年年变化。它们主要在小型密集的群落中筑巢（每平方米1-1.6对），最多可达25对，有时多达200对以上。巢穴由海藻和植被构成，内衬草，位于巨石之间或光秃的火山岩上（如Punta Tombo），通常被苔草遮蔽。每窝产2-3枚卵（平均1.9-2.0枚在Punta Tombo），孵化期为24-27天。雏鸟具有鲜明的标记，由分散的黑点和条纹形成从嘴裂到眼下的长条纹，底色非常淡。平均孵化重量为41克。2-5天大的雏鸟会跟随父母离开巢穴，较大的雏鸟可能会聚集在一起。","identification":"豚鸥与斑尾鸥相比，体型较小，没有黑色的尾带，裸露部分的颜色明显不同，幼鸟独特的暗棕色外观，腹部白色，翼覆羽板岩棕色，帮助区分。","protection":"IUCN：LC（无危）","distribution":"豚鸥主要分布在南美洲南部，包括智利沿海中部、南部至阿根廷的火地群岛，以及福克兰群岛。非繁殖季节，它们会稍微向北移动至大陆沿岸。"},{"name":"岩鸥","english_name":"Lava Gull","scientific_name":"Leucophaeus fuliginosus","overview":"岩鸥（英文名：Lava Gull，学名：Leucophaeus fuliginosus），是鸻形目鸥科豚鸥属的中型鸥类，隶属于‘罩头鸥’群体，与笑鸥和富兰克林鸥亲缘关系最近，是全球最为罕见的鸥类之一。仅分布于加拉帕戈斯群岛，全球数量极为有限。","appearance":"成年岩鸥体长51至55厘米，平均体重约380克，具有明显的外观特征：头部呈烟灰色至黑色，无论季节如何始终保持不变。翅膀深灰色，前缘有一条醒目的白色线条，有助于社交互动和幼鸟识别，同时也可能在巢筑于枝叶丛生或被鸟粪覆盖的熔岩上时提供伪装。身体暗灰色，腹部颜色渐淡至灰白色。尾巴上部白色，下部淡灰色。喙、腿和脚均为黑色，口内鲜红色，拥有白眉和红眼睑。幼鸥主要为烟灰色，带有黑色初级飞羽，背部和肩羽尖端浅色。雄性岩鸥比雌鸟更高大，喙基更粗壮，前额和枕部斜度更缓，上体色调更偏棕色。","call":"在领地防御时，尤其是面对同类入侵者时，岩鸥会发出重复的‘kow’警戒音，随后是一长串领域叫声，通常由一对伴侣共同发出。成鸟在飞入或飞过自己领地时会发出单声尖锐的‘kow’音，以示对雏鸟和伴侣的告知。","habits":"岩鸥主要栖息于加拉帕戈斯群岛的沙滩和碎石滩，偶尔出现在港口附近，与船只相伴。它们不迁徙，活动范围局限于加拉帕戈斯群岛，最长的岛屿间移动记录为130公里，但长时间的海上飞行较为罕见，有时乘坐船只移动。岩鸥主要以海鸟蛋、幼小的海鬣蜥、小型鱼类、甲壳类、废弃物和残渣为食，通常沿岸觅食，飞行高度3至5米，寻找食物，很少在海上停留，但在岩石、码头和船只上栖息。它们与海狮共生，吃胎盘和鱼片，还会在水面盘旋捕捉漂浮的食物残渣，甚至从绿背（岩）苍鹭那里抢夺螃蟹。","breeding":"岩鸥全年繁殖，高峰期在5月至10月。它们是独居繁殖者，拥有广阔的领地，通常在靠近水边的沙滩或低矮的岩石上筑巢，从未在悬崖上筑巢。巢穴是一个凹陷处，铺垫植被，位于加拉帕戈斯岛上的盐灌木旁或下方，衬以柔软的木质茎。巢离高潮线5至50米远。巢内产卵1至2枚，橄榄绿色至淡褐色，带灰色和深褐色斑点，孵化期约为33天。雏鸟在4至5天后离开巢穴，留在几米远的遮蔽处。约7.5周龄时离巢，但父母的照顾将持续近三周。","identification":"岩鸥与其他鸥类的区别在于其独特的烟灰色至黑色头部，白色的眉毛和眼睑，以及翅膀前缘的白色线条。与同属鸥类相比，这些特征使得岩鸥在视觉上易于辨认。","protection":"IUCN：VU（易危）","distribution":"岩鸥的整个族群居住在加拉帕戈斯群岛，主要分布在圣克鲁兹岛、伊莎贝拉岛、圣克里斯托瓦尔岛和热诺维萨岛。根据2015年的最新估计，全球数量约为300至600只个体。","other":"岩鸥被认为是全球最稀有的鸥类，尽管其栖息地目前受到加拉帕戈斯国家公园系统的保护，但由于其极低的数量和面临的威胁，仍然被认为是全球受威胁物种。"},{"name":"笑鸥","english_name":"Laughing Gull","scientific_name":"Leucophaeus atricilla","overview":"笑鸥（英文名：Laughing Gull，学名：Leucophaeus atricilla），是鸻形目鸥科豚鸥属的鸟类。这种中型海鸥以它那像笑声般的叫声闻名，繁殖季节时展现出黑色头部、红色喙以及白色眼圈（眼圈中部断开）。笑鸥主要分布在北美洲和南美洲的沿海地区，从美国东北部、东部至南部，直至南美洲北部。其分布范围包括大西洋沿岸的岛屿，从缅因州至佛罗里达州，墨西哥湾至德克萨斯州南部，尤卡坦半岛，加利福尼亚湾至科利马，西印度群岛，尤卡坦半岛附近的岛屿，委内瑞拉、特立尼达、多巴哥北部的岛屿，直至法属圭亚那。","appearance":"笑鸥体型中等，身长36-41厘米，翼展98-110厘米，体重203-371克。繁殖季节的成鸟全身除暗灰色背部和翅膀以及黑色头部外皆为白色，翅膀比同尺寸大多数鸥类更暗，翼尖无白色新月状斑纹，喙长且呈红色。冬季时，黑色头罩几乎消失。幼鸟颜色更深，第一年幼鸟下方较灰，头部较淡，第二年幼鸟通过翼型和结构可识别。","call":"笑鸥以其高音的'kee-agh'叫声著称，听起来像是尖锐的笑声。","habits":"笑鸥是海岸物种，偶尔出现在内陆，常见于耕地、垃圾场、停车场和海岸线。它们在靠近海岸但远离陆地掠食者的岛屿上筑巢。夏季，笑鸥聚集在停车区、沙滩和泥滩寻找食物，也会在农田和垃圾填埋场觅食，吃鱼、甲壳类动物、蠕虫、腐肉和垃圾。","breeding":"笑鸥在北美洲东北部、东部、南部和南美洲北部的海滨繁殖，秋季和冬季，最北端的笑鸥会向南迁移。笑鸥在第四年才能达到性成熟并繁殖。","identification":"笑鸥与弗氏鸥相似，但体型更大，身体比例更重，头、喙和腿更长，翅膀更长且更尖。笑鸥的喙更长、更厚且略微下垂，而非短而直。繁殖羽中，笑鸥的中央尾羽为灰色，而不是白色，且眼圈更细白。","protection":"IUCN：LC（无危）","distribution":"笑鸥在北美洲的东北部、东部和南部以及南美洲北部的海滨繁殖。秋季和冬季，最北端的笑鸥会南迁至南美，罕见于欧洲，被视为迷鸟。","other":"笑鸥曾因蛋和羽毛贸易在19世纪末和20世纪初被大量捕杀，但20世纪早期数量有所恢复。然而，后来由于大型鸥类向南扩展领地的竞争，笑鸥数量再次受到打击。目前笑鸥在其大部分范围内数量正在增加，特别是在美国东海岸，从缅因州到佛罗里达州，它是最常见的繁殖海鸟。"},{"name":"弗氏鸥","english_name":"Franklin's Gull","scientific_name":"Leucophaeus pipixcan","overview":"弗氏鸥（英文名：Franklin's Gull，学名：Leucophaeus pipixcan），是鸻形目鸥科豚鸥属的鸟类。中型鸥科鸟类，体长约32至36厘米。其名源自北极探险家约翰·富兰克林爵士。繁殖季节，弗氏鸥的上体呈中灰色，头部黑色带有厚白眼弧，翼尖有大白色斑点，喙和腿深红色，腹部常带粉色。冬季，头部部分黑色，喙和腿暗色。幼鸟上体褐色。弗氏鸥在北美中北部草原湖泊和沼泽地带繁殖。","appearance":"弗氏鸥的繁殖羽色展现中灰色上体，头部黑色带有宽厚的白色眼环，翼尖有大白色斑点。喙和腿深红色，腹部白色常带粉色。非繁殖期头部部分黑色，喙和腿颜色较暗。幼鸟上体褐色，翅膀和尾巴有灰褐色中心。成鸟翼尖图案特征明显，有白色‘窗户’与翼尖黑斑之间。雄鸟和雌鸟在外表上相似。","habits":"弗氏鸥栖息于北美中北部草原的湖泊和沼泽，冬季迁徙至南美阿根廷、加勒比海、智利和秘鲁。它们会成群结队迁徙，主要食物为昆虫、蚯蚓、小鼠、鱼、谷物，也会食用垃圾。具有独特的两次完全换羽模式。","breeding":"弗氏鸥在靠近草原湖泊的群落中繁殖，巢建于地面或有时漂浮。每窝产两到三个蛋，孵化期约三周。幼鸟经过两年达到成熟。","identification":"弗氏鸥与笑鸥最为相似，但体型略小，腿更短，喙较短且钝，翼尖的白色斑点更大。在所有非繁殖羽色中，弗氏鸥保持特有的黑色半罩，耳部覆盖物、后冠和颈背有明显的白色新月形图案。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西部、北阿尔伯塔省、东俄勒冈州至曼尼托巴省西南部和明尼苏达州西北部。冬季迁徙至南美洲太平洋沿岸，从厄瓜多尔和加拉帕戈斯群岛至智利中部。","other":"弗氏鸥是少数几种每年经历两次完全换羽的鸟类之一。"},{"name":"灰鸥","english_name":"Grey Gull","scientific_name":"Leucophaeus modestus","overview":"灰鸥（英文名：Grey Gull，学名：Leucophaeus modestus），是鸻形目鸥科豚鸥属的鸟类。中型鸥科鸟类，原生于南美洲。在极端干燥的智利北部阿塔卡马沙漠内陆繁殖，而在南美洲太平洋沿岸大部地区作为非繁殖鸟出现。其显著的外部特征包括中等大小、暗灰色外观，白色头部（夏季），以及黑色翼尖。","appearance":"灰鸥的两性相似，体长约45厘米，体重约360至400克。夏季头白，冬季转为棕色。身体和翅膀呈灰色，背部较腹部深。飞行羽黑色，内侧主羽和次级飞羽有白色尖端，飞行中可见。尾巴有黑色带纹和白色边缘。腿和喙均为黑色，虹膜棕色。","call":"其叫声类似笑鸥，但以单个拉长的鼻音结尾，持续约一秒，例如“wa-wa-wa-wa-wheaaaaoooww”。其他叫声包括鼻音‘meyaaw’、更粗哑的‘r-r-r-aaoh’和更高音的尖叫。","habits":"栖息于南美洲西部的沙滩和泥滩，避免岩石区域。在阿塔卡马沙漠内陆的贫瘠山区沙漠繁殖，距离海岸35至100公里，无植被和淡水。非繁殖季节，活动范围覆盖从厄瓜多尔到智利中部的海岸线。","breeding":"繁殖期为11月至1月，产卵从中下旬开始。受严重厄尔尼诺事件影响时不繁殖。在5.5平方公里范围内有大约6万个巢穴，密度约为每平方米1个。巢为沙地中的凹坑，通常靠近岩石。产卵1至3枚，通常2枚，颜色偏淡，有时纯白，水汽传导极低。孵化期约29至31天。雏鸟灰色，偶尔带米色，头部两侧、喉咙、背部和侧腹有模糊的黑斑点。","identification":"与红嘴灰鸥相比，灰鸥具有较小的全黑喙和整体羽毛色调。成年非繁殖期头部为灰色，幼鸟比成鸟更棕色。","protection":"IUCN：LC（无危）","distribution":"繁殖于智利北部的阿塔卡马沙漠内陆。非繁殖期分布从厄瓜多尔南部至智利中部海岸线，常见至瓦尔迪维亚，偶尔至佩纳斯湾。","other":"在极端厄尔尼诺事件期间，灰鸥在智利北部海岸异常繁殖。"},{"name":"遗鸥","english_name":"Relict Gull","scientific_name":"Ichthyaetus relictus","overview":"遗鸥（英文名：Relict Gull，学名：Ichthyaetus relictus），是鸻形目鸥科渔鸥属的鸟类。中等体型的鸥类，曾一度被认为地中海鸥的东方亚种，后确认为独立物种。繁殖于亚洲中部和北部的盐湖，分布于蒙古、哈萨克斯坦、中国中北部和俄罗斯东南部。越冬于海岸线、朝鲜半岛、渤海湾、黄海和中国东部海域。成鸟非繁殖羽具暗色耳羽及冠后纹，翼尖具独特标记，喙腿橙红色。","appearance":"遗鸥体长44至45厘米，拥有厚实的身躯。繁殖期成鸟头部黑色，包括颈部，前额灰棕色，眼睑宽阔，呈白色半月形。翼尖具独特的白色点状标记，翼下覆羽浅灰色，翼尖黑色，具白色次端斑。喙及腿橙红色。非繁殖期成鸟头顶及颈背具暗色纵纹。幼鸟背部鳞状花纹，翼上覆羽具深褐色斑点，尾部有黑色横带，喙暗褐色，腿暗灰色。","call":"鸣声与红嘴鸥相似，繁殖期发出短促的三音节叫声“kaw kaw kaw”，还有较粗哑的音调。","habits":"栖息于开阔平原和荒漠地区的咸水或淡水湖泊。繁殖期在湖心岛营巢，巢由枯水草构成，常与燕鸥、噪鸥、巨鸥的巢混在一起。主要食物为水生昆虫、水生无脊椎动物等。非繁殖期结群生活于其他湖泊。","breeding":"繁殖期为5月至7月初，5月初开始营巢。巢群密集，巢距最小可达7厘米。每窝产卵2-3枚，孵化期24-26天。雏鸟早成性，出生后即可行走，体重约50克，全身被浅灰色绒羽，嘴、脚黑色，趾间有蹼。","identification":"与红嘴鸥、棕头鸥区别在于：遗鸥眼睑更宽，翼尖具数个白点，非繁殖期头顶及颈背具暗色纵纹，而红嘴鸥与棕头鸥不具备这些特征。","protection":"IUCN：VU（易危）；CITES I；中国国家一级保护动物。","distribution":"繁殖于哈萨克斯坦东北部、蒙古、中国中北部（Inner Mongolia和Shaanxi）和俄罗斯东南部的湖泊。越冬于中国东部沿海、朝鲜半岛、渤海湾和黄海。","other":"1971年，哈萨克斯坦的繁殖种群发现后，遗鸥的独立物种地位得到科学界认可。"},{"name":"奥氏鸥","english_name":"Audouin's Gull","scientific_name":"Ichthyaetus audouinii","overview":"奥氏鸥（英文名：Audouin's Gull，学名：Ichthyaetus audouinii），是鸻形目鸥科渔鸥属的鸟类。大型鸥科鸟类，分布于地中海沿岸及伊比利亚半岛和撒哈拉以西非洲西部海岸。其名称来源于法国自然学家Jean Victoire Audouin。这种鸥曾极度稀少，1960年代仅存约1000对，但近年来已建立新群落，全球数量约10000对。","appearance":"体长约48-52厘米，体重451-770克，翼展125-138厘米。头部与身体白色，背部及上翼淡灰色。成年鸥具浅灰色体羽，头部较白。翅膀淡灰带黑色尖端，无明显白斑。腿深灰至黑色，喙暗红，眼眶呈深红色。幼鸥与小黑背鸥相似，具强烈条纹的下翼和U形白色臀部斑点。","call":"发出一系列嘶哑的吼叫声，如连续的‘braying sounds’，以及面对捕食者的‘gagaga’声和尖锐的‘me-o’警报叫声。","habits":"主要栖息于地中海沿岸和岛屿，冬季迁徙至大西洋海岸线，远至冈比亚。常在近海巡逻，夜间捕鱼，偶尔拖腿增加阻力。以鱼为主食，尤其偏爱鲱鱼。","breeding":"2月晚至4月中旬返回繁殖地，4月末开始筑巢，5月末为孵化高峰。巢多位于岩石和植被间，通常每窝产卵1-4枚，平均2.8枚，孵化期26-33天。雏鸟出生46克重，35-40天后离巢，独立需3-4个月。","identification":"相较于黄腿银鸥，体型更小、颜色更淡、翅尖更黑，白色翼尖较少；腿色和裸露部分颜色不同。幼鸥具均匀灰褐色脸和身体。","protection":"IUCN：VU（易危）","distribution":"繁殖于伊比利亚半岛南部至地中海及其周边海域至塞浦路斯和土耳其南部。非繁殖季节分散至地中海沿岸和大西洋海岸，最远至冈比亚。","other":"自1960年代以来，因建立新群落，特别是西班牙埃布罗三角洲的群落，其数量迅速恢复。"},{"name":"地中海鸥","english_name":"Mediterranean Gull","scientific_name":"Ichthyaetus melanocephalus","overview":"地中海鸥（英文名：Mediterranean Gull，学名：Ichthyaetus melanocephalus），是鸻形目鸥科渔鸥属的鸟类。中等体型的鸥类，比红嘴鸥略大，外形与普通海鸥相近但嘴更粗壮。其显著特征是雪白的翼尖，成鸟在繁殖季节头部全黑，非繁殖季节和幼鸟则在耳后有明显的暗色斑点。幼鸟背部呈斑驳棕色，冬季褪变为浅灰色。分布于欧洲和西亚的水域周边，常与红嘴鸥混群繁殖。","appearance":"体长36-38厘米，体重215-350克，翼展98-105厘米。介于普通海鸥和红嘴鸥L. ridibundus之间，比红嘴鸥更为庞大，头部更大，喙较厚，翅膀更宽，飞行更为浮游。成鸟外观普遍偏淡，翼尖无明显黑色。繁殖期成鸟头部全黑，黑色兜帽覆盖大部分颈背；突出的白色眼眉；颈部白色；上身非常浅灰；飞羽白色；尾巴白色；下身白色；喙鲜红，有变化的暗色亚端带，通常主要在下颌，常带黄色尖端；腿鲜红；虹膜深棕色，有红色眼眶环。非繁殖期成鸟非常淡，头部白色，仅耳覆羽和颈背有明显暗色条纹，远看全白；裸露部分深红至黑红。","call":"发出特有的起伏的、柔和的哀鸣声“yee-ah”或“ee-ar”。","habits":"栖息于海岸、河口、港口、沼泽、内陆湖泊、田野和草地。繁殖于地中海沿岸、沿海泻湖、低地开阔地区的草原湖泊和沼泽，偏好稀疏植被，但一般避开光秃沙地；有时在海岸盐沼（西欧）。能够适应新环境，无论是繁殖还是越冬，近年来成功殖民与原始栖息地气候和植被明显不同的地区。迁徙性物种，主要在地中海、黑海、西北欧和西北非洲越冬。","breeding":"4月初返回繁殖地，多数在5月上半月产卵。高度同步，产卵期仅持续10天。繁殖群通常不到1000对；偶尔单对在其他物种的繁殖群中定居。新繁殖群往往由几对在已建立的红嘴鸥繁殖群中定居的个体创建。巢建在稀疏植被、灌木丛或芦苇床中，是浅凹处铺草的巢。巢间距密集，巢边有时相距仅8厘米；平均最近邻距离63厘米。窝卵数通常2-3枚（1-5枚）；孵化期23-26天，孵化相对同步；雏鸟头部有棕色、灰色和米色斑点，背上2-3条宽棕色带，下身淡灰色至粉米色；离巢35-40天。生产力常很低。首次繁殖年龄为2-3岁。记录最长寿命为15年，但有些可能活得更长。","identification":"与红嘴鸥相比，地中海鸥体形更健壮，喙更粗，翅膀更宽，飞行更浮游。成鸟外观更淡，翼尖无明显黑色，繁殖期头部全黑，非繁殖期和幼鸟在耳后有明显的暗色斑点。幼鸟背部斑驳棕色，冬季褪变为浅灰色。","protection":"IUCN：LC（无危）","distribution":"主要繁殖于乌克兰的黑海沿岸，近期扩散到北高加索平原和阿塞拜疆（巴库群岛）；在欧洲各地也有零星分布，荷兰、法国南部（卡马尔格）、意大利、希腊和土耳其数量较多，英国南部（逐年增加）、比利时、德国东北部、西班牙东部和中欧有有限繁殖。越冬于地中海、黑海、西北欧和西北非洲。","other":"该物种面临的主要威胁是在繁殖地的捕食，尤其是乌克兰的里海银鸥、鸦科鸟类和鹞鹰，以及人类收集鸟蛋和干扰。"},{"name":"渔鸥","english_name":"Pallas's Gull","scientific_name":"Ichthyaetus ichthyaetus","overview":"渔鸥（英文名：Pallas's Gull，学名：Ichthyaetus ichthyaetus），是鸻形目鸥科渔鸥属的鸟类。大型鸥科鸟类，以其强壮的体型和栖息于咸水、半咸水和淡水环境而著称。繁殖期成鸟头部呈黑色，喙尖具红黑色，眼周有醒目的白色新月形标记。分布区域从黑海至蒙古西部，中国境内可见于青海、内蒙古等地。","appearance":"渔鸥体长60-72厘米，体重900-2000克，翼展可达155-170厘米。其头部扁平，喙长而细，赋予其三角形头部外观。胸部丰满，翅膀比其他大型鸥类更长、更纤细且尖端更锐利。繁殖期成鸟头部黑色，从脸部至后颈，眼周有显著的白色新月标记；非繁殖期成鸟头部后方有一块暗斑。亚成鸟亦有此特征，但暗斑明显较小。眼周的白色新月和闪亮的白色腰部将第一年冬羽的亚成鸟与各种银鸥区分开来。","call":"发出深沉而短促的叫声，繁殖期间的鸟儿会发出深沉的'ha-u'声。其他叫声包括低沉、略带鼻音的'oow'声和犬吠般的警报声'whe-ow'。","habits":"栖息于海岸、大型河流和湖泊，受人类活动吸引，常出现在港口、鱼塘和垃圾堆附近。在繁殖季节，于一般干旱地区的淡水和咸水湖泊及内陆海中的荒凉岛屿集群筑巢。具有迁徙习性，冬季分布于地中海东部、红海、里海南部、印度洋北部直至缅甸，偶尔远至泰国；在恒河平原和埃塞俄比亚南部也可见其踪迹。","breeding":"通常于三月初返回繁殖地，四月初开始产卵。繁殖群可由70至3000对组成，巢由干燥的水生植物和羽毛构成，位于裸露的岩石基质上，有时在芦苇丛中或植被覆盖的沙丘中。每窝产卵2枚（1-3枚），孵化期约25天，幼鸟出生5天后即可被父母识别，大约5天后可能离开领地。","identification":"通过体型可将其与头部深色的小型鸥类区分开，尤其是成鸟的黑色头部和白色新月标记。第一年冬羽的亚成鸟可通过眼周的白色新月和亮白的腰部与银鸥区分开。","protection":"IUCN：LC（无危）","distribution":"繁殖区从克里米亚至哈萨克斯坦，蒙古西部，中国甘肃、青海和内蒙古。非繁殖区延伸至黑海、里海、咸海沿岸；红海、波斯湾、阿拉伯海和孟加拉湾（北印度洋）至孟加拉国和马塔班湾（缅甸南部）；印度和缅甸的大河也可见其身影。","other":"全球数量未知，但估计黑海、里海和西南亚洲的数量超过10万只，中亚有额外2.5万至10万只。"},{"name":"白眼鸥","english_name":"White-eyed Gull","scientific_name":"Ichthyaetus leucophthalmus","overview":"白眼鸥（英文名：White-eyed Gull，学名：Ichthyaetus leucophthalmus），是鸻形目鸥科渔鸥属的鸟类。特有于红海地区。其上体颜色为深棕色或灰色，喙长而纤细，略向下弯曲。成鸟头部呈黑色，带有醒目的白色眼环。幼鸟颜色较淡，头部更浅。与外观相似的白领鸥相比，白眼鸥体型较小，更为纤细，喙部更细且全黑，无双色喙的特征。在偏远岛屿和珊瑚礁上繁殖，主要栖息于沿海地带。","appearance":"白眼鸥体长39至43厘米，体重275至415克，翼展110至115厘米。比黑头鸥稍大，但比赫氏鸥小，头部更扁平，喙更纤细。成年白眼鸥的头部为煤黑色，延伸至上胸，颈部两侧白色，背部灰色，最突出的特征是白色的眼睑，眼睛本身为深棕色，有红色眼眶环；腹部和尾巴白色；翅膀上下均为深灰色，边缘白色。喙长而细，略向下弯，红色，尖端黑色；腿为鲜黄色。冬季成鸟色彩暗淡，头部有白色条纹，喙色也较暗。幼鸟为深灰褐色，羽毛边缘较浅。一岁幼鸟与幼鸟类似，但头部、胸部和上身有更灰色的羽毛；二岁幼鸟上体更灰，尾巴为白色，末端有一条窄而不完整的黑色横带。","call":"白眼鸥的叫声类似于赫氏鸥，但更为柔和和深沉。长叫声为“kioow”，重复12至16次。警报声为重复的“ke”音，还有“koup koup koup”的叫声。","habits":"白眼鸥主要栖息于沿海地带，尤其偏好近岸岛屿上的裸岩和沙滩。与赫氏鸥相比，它们与渔船和港口联系较少，因此更常出现在离海更远的地方。它们在岩石、珊瑚礁、码头和渔船等地方栖息。白眼鸥主要以鱼为食，也会吃螃蟹、软体动物、环节动物，甚至埃及的某些果实（如Nitraria retusa）。它们主要通过从水面俯冲潜水觅食。虽然不像赫氏鸥那样依赖垃圾，但在某些时候也会在港口拾食。然而，在埃及的胡尔加达，大量白眼鸥，包括刚离巢的幼鸟，在垃圾堆上觅食，食用各种食物，如米饭、鸡肉、西瓜和面包。","breeding":"白眼鸥的繁殖季节通常为6月至9月，至少在沙特阿拉伯如此。主要在7月筑巢，到8月底孵化完成。每年只繁殖一次，但如果第一次巢失败，可能会再筑巢。在埃及，最早可能在5月的第二周或第三周开始筑巢。它们松散地集群繁殖，每群约有十几对到数百对，间隔2至12米，通常距离海岸线100米以内。巢为浅坑，铺有海藻或碎片，位于裸露的岩石、沙滩或靠近海洋的开阔地带。每窝产1至3枚蛋，颜色为奶油橄榄色至淡土黄色，带有橄榄色至深棕色或紫灰色的斑点，平均大小为56毫米×41毫米；雏鸟上部灰色，有深色斑点和条纹；关于孵化和离巢期的信息未知。巢有时会被赫氏鸥掠食。","identification":"白眼鸥与赫氏鸥的主要区别在于体型、喙部颜色、腿部颜色以及上胸部位的颜色差异。白眼鸥体型更小，喙部和腿部颜色为红色和黄色，上胸部位颜色更浅，与头部形成鲜明对比。幼鸟阶段，白眼鸥尾部全黑，与赫氏鸥幼鸟的尾部不同。","protection":"IUCN：LC（无危）","distribution":"白眼鸥繁殖于红海，范围从苏伊士湾和阿卡巴湾（提兰岛）向南延伸至亚丁湾，在埃及、苏丹、厄立特里亚、吉布提、沙特阿拉伯、也门和索马里等地的岛屿和小岛上繁殖。在冬季，它们分散在整个繁殖范围内。在埃及红海沿岸，八个岛屿上共有2672对繁殖，估计总数量约为8000只个体；其中最大的繁殖地在乌姆加维什岛，苏伊士湾南部，有1450至1850对繁殖。在苏丹有300至1000对，在吉布提有600至700对，在沙特阿拉伯有超过1500对（可能多达3000对），在也门至少有3900对（可能有5000对），在索马里有1200至2200对。全球种群数量稳定，但未来几十年可能下降。","other":"白眼鸥面临的主要威胁包括人类压力和油污染，以及外来物种如鼠类（Rattus）对繁殖岛屿的威胁。然而，它们从垃圾堆的食物供应中受益，尤其是在埃及的胡尔加达旅游设施附近的垃圾堆。"},{"name":"白领鸥","english_name":"Sooty Gull","scientific_name":"Ichthyaetus hemprichii","overview":"白领鸥（英文名：Sooty Gull，学名：Ichthyaetus hemprichii），是鸻形目鸥科渔鸥属的鸟类。此鸥体型中等，体羽呈棕色，喙长而具双色，翼下暗色，与白眼鸥相似但翼下较暗，体型更大，成鸟羽毛更偏棕色。分布于红海、亚丁湾、波斯湾、阿曼湾至巴基斯坦南部，东非海岸至坦桑尼亚和莫桑比克北部，偶尔漂泊至印度、斯里兰卡、马尔代夫等地。命名以纪念德国自然学家Wilhelm Hemprich。","appearance":"体长43-48厘米，体重400-510克，翼展105-118厘米。全身棕色，腿长，喙长且双色。成鸟头部黑色延伸至上胸形成围巾状，颈侧有白色宽环，后方较窄，眼上方有白色新月形斑纹。背部、肩部和上胸灰色，翅膀上下暗棕色，内翼边缘白色。腹部、臀部和尾巴白色。喙黄绿色，尖端红色，根部黑色环绕；腿黄橄榄色；虹膜棕色，眼周红色。","call":"求偶叫声似鹅，重复'gar gar'声。发出升调哀鸣'corr-ga'。长叫声为响亮尖叫'kioow'，连续12-16次。激怒叫声为断续的'ke'。","habits":"沿海分布，主要在海岸线和岛屿繁殖。罕见内陆，但在肯尼亚的鲁道夫湖有迷鸟记录。与人类共存，常随渔船活动，停泊在码头、浮标和渔船。偶尔在泥滩觅食。","breeding":"夏季繁殖，筑巢于珊瑚礁岛或外岛，有时单独，有时集群。巢为简单凹陷，覆盖少量植被，位于裸露珊瑚、灌木下或草丛中。每窝产卵1-3枚，孵化约25天，雏鸟离巢时间未详，但部分于11月离巢。","identification":"与白眼鸥相比，翼下更暗，体型较大，成鸟羽毛更偏棕色，喙厚且两色分明。","protection":"IUCN：LC（无危）全球数量估计在150,000-300,000之间。面临石油勘探、土地回收和油污威胁。","distribution":"繁殖于红海、亚丁湾、索科特拉岛、印度洋西北部至肯尼亚东北部、波斯湾和阿拉伯海西北部至巴基斯坦南部。非繁殖季节分布至Gulf、Aqaba（以色列东南部）和坦桑尼亚中部、桑给巴尔。"},{"name":"太平洋鸥","english_name":"Pacific Gull","scientific_name":"Larus pacificus","overview":"太平洋鸥（英文名：Pacific Gull，学名：Larus pacificus），是鸻形目鸥科鸥属的鸟类。与黑背鸥存在竞争关系。","appearance":"体长58-65厘米，体重900-1185克，翼展137-157厘米。头部和腹部白色，翅膀和背部黑色，翼缘白色，但初级飞羽无白色斑点；尾部白色带窄黑亚端带；喙深而厚重，黄色，端部红色宽大；鼻孔呈椭圆形而非裂缝状；腿和脚黄色。成鸟比黑背鸥更大，具深色背部，黑色尾带和更厚重的喙。幼鸟全身斑驳暗棕色，喙亮黑色；一年生羽毛仍深色但脸较淡；二年生鸟具暗棕色翅膀，斑驳白色身体，较淡臀部和黑尖黄喙。成年羽毛至第五年才完全获得。东部亚种（pacificus）具白眼，喙端全红；西部亚种（gergii）具红眼，喙端红不完整。","call":"发出响亮的‘ow-ow’声，有时较长。还有短促的‘oh oh’声，沙哑的‘cark-cark’或‘auk-auk’声以及粗犷的笑声和呜咽的口吃。","habits":"栖息于海岸，偶尔出现在内陆农田和近海垃圾堆，偏好沙滩或岩石海岸，以及受保护的河口、海湾和港口。主要在沿海区域活动，偶尔沿河流向上游迁移。以鱼类、鱿鱼、潮间带软体动物、棘皮动物和蟹类为食，也吃鱼类废弃物、腐肉和垃圾。捕食其他鸟类的蛋和幼鸟，甚至成鸟，例如White-faced Storm-pelican。通过在海滩和潮间带行走、潜水抓取猎物，或在岩石和其他硬表面砸碎螺壳。","breeding":"繁殖期为9月至次年1月。单对分散或小群松散群居于海岬或岛屿高处繁殖。巢可能仅是地面的凹坑，也可能由树枝、草、海藻或羽毛构成浅碗状。雌雄共同筑巢，雌鸟主要孵卵，雄鸟觅食并守卫巢穴。每窝产卵3枚（1-3枚），孵化期23-26天。","identification":"与黑背鸥相比，太平洋鸥更大，喙更厚重，尾部有黑色带。幼鸟斑驳暗棕色，易于区分。两个亚种主要区别在于眼睛颜色和喙端的红色程度。","protection":"IUCN：LC（无危）。全球范围内不处于严重威胁之下，但数量并不普遍。约有100个已知繁殖群落，总数量估计不到10,000对。20世纪初，东部亚种繁殖范围曾扩展至昆士兰南部，后向南收缩，可能因黑背鸥的竞争所致。西部亚种近年来沿澳大利亚西海岸北扩。在塔斯马尼亚，为了保护其他海鸟，进行了种群控制。","distribution":"分布于澳大利亚西南至东南部海岸线，包括塔斯马尼亚，主要在Carnarvon至Sydney之间。东部亚种分布于东南沿海和塔斯马尼亚，西部亚种分布于南澳和西澳。","other":"两个亚种：东部亚种L. p. pacificus和西部亚种L. p. georgii。"},{"name":"斑尾鸥","english_name":"Belcher's Gull","scientific_name":"Larus belcheri","overview":"斑尾鸥（英文名：Belcher's Gull，学名：Larus belcheri），是鸻形目鸥科鸥属的鸟类。体型中等，广泛分布于南美洲太平洋沿岸，从秘鲁北部至智利北部的海岸线和岛屿上。其命名是为了纪念英国探险家爱德华·贝尔彻爵士。","appearance":"斑尾鸥体长约49厘米，两性外观相似。繁殖季节，成鸟头部洁白，颈项与下体淡灰色，背部和翅膀覆羽呈灰黑色，尾部具宽黑带与白色边缘。喙黄色，尖端红黑相间，腿脚亦黄。非繁殖季头部变为暗褐色，眼周白圈明显。幼鸟杂色，至第三年换羽成成鸟模样。与较大型的黑背鸥区别在于后者翼尖有小白点且无尾部黑带。","call":"发出清晰的短促‘yap’声或‘yeow’声。长叫声是一连串加速的清晰音符，有时省略开头的长音。","habits":"斑尾鸥栖息于南美太平洋沿岸，偏好岩石海岸和近海岛屿，不迁徙。以鱼、蟹、贝类、腐肉为食，季节性捕食海鸟的蛋和幼鸟。通常沿海滩和海鸟聚居地觅食，退潮时在潮间带捡食，海上活动不紧跟船只。","breeding":"繁殖始于11月中旬至12月中旬，筑巢于沙滩或岩石凹处，靠近高潮线。每窝产卵1-3枚，平均65x45毫米，橄榄色带深色斑点。关于孵化和离巢期的资料尚未可知。","identification":"与大西洋鸥相似但分布于太平洋沿岸，而后者位于大西洋沿岸。比黑背鸥小，尾部具宽黑带，翼尖无小白点。","protection":"IUCN：LC（无危）","distribution":"繁殖于秘鲁北部至智利北部的南美太平洋沿岸。非繁殖季节部分个体移动至厄瓜多尔北部和智利中部海岸。"},{"name":"大西洋鸥","english_name":"Olrog's Gull","scientific_name":"Larus atlanticus","overview":"大西洋鸥（英文名：Olrog's Gull，学名：Larus atlanticus），是鸻形目鸥科鸥属的鸟类。大型鸥科鸟类，广泛分布在南美洲的阿根廷、乌拉圭及巴西南部的沿海地带。其主要以蟹类为食，拥有黑色背部与翅膀，白色头部和下体，尾部带有一条醒目的黑色横带。该物种因瑞典裔阿根廷生物学家Claes C. Olrog而得名，由于栖息地丧失，已被IUCN列为近危物种。","appearance":"大西洋鸥为体型较大的鸥，体长可达50-60厘米，翼展130-140厘米。成鸟特征为白色头部、颈部、臀部和腹部，其余上体为黑色。翅膀黑色，边缘白色，尾部白色，末端具宽幅黑色横带。喙黄色，带有黑色环和红色尖端。眼睛棕色，眼周红色。腿和脚呈暗黄色。幼鸟则主要为褐色，头部和颈部深色，尾部亦为深色。","habits":"大西洋鸥栖息于岩石海岸、港口、沙滩、沿海泻湖、咸水区及河口。主要以蟹类为食，偶尔也会补充双壳类软体动物、多毛类蠕虫、昆虫、腹足类软体动物、鱼类、鱼杂碎等。常在露出水面的岸线或海底寻找食物，有时也会访问污水处理口和垃圾堆。","breeding":"繁殖始于9月至10月，大西洋鸥为一夫一妻制，群居繁殖。巢筑于岩石、沙地或砾石上，通常用植被铺垫，有时会使用海藻、羽毛、贝壳或骨头。每窝产2-3枚橄榄棕色带斑点的蛋，孵化期约30天。幼鸟在11月至次年1月间离巢。","identification":"与黑背鸥相似，但可通过全白尾部、无尾部黑色横带及白色初级飞羽尖端加以区分。黑背鸥幼鸟有黑色尾部横带。两种鸥的繁殖和越冬分布有重叠，但黑背鸥分布更广泛。","protection":"IUCN：NT（近危）","distribution":"繁殖于阿根廷Buenos Aires Chubut provinces沿海南部（东北部，中东部）。越冬时部分个体向北移动至巴西东南部海岸线。"},{"name":"黑尾鸥","english_name":"Black-tailed Gull","scientific_name":"Larus crassirostris","overview":"黑尾鸥（英文名：Black-tailed Gull，学名：Larus crassirostris），是鸻形目鸥科鸥属的鸟类。分布于中国、日本和韩国，亦漂泊至阿拉斯加及北美东北部。成鸟体长45厘米，翼展126至128厘米，拥有黄色脚和带红斑点的黑色喙端。尾部黑色，叫声似猫，故在日本被称为\"海猫\"，在韩国有\"猫鸥\"之称。","appearance":"黑尾鸥体长43-51厘米，体重436-640克，翼展126-128厘米。成鸟具有白色头和下体，石板灰色的背部和上翼，黑色的初级飞羽仅微露白色尖端，白色的次级飞羽和尾羽带有宽阔的黑色亚端斑；喙黄色，尖端有红斑和黑色亚端环。幼鸟整体呈暗褐色，翼尖黑色，腰部白色，喙淡粉色且尖端黑色，眼睑白色明显，腿粉色。","call":"其叫声深沉，类似猫叫，发\"kaoo kaoo\"或\"kau kau\"之声。","habits":"栖息于沿海沙滩、悬岩及邻近水域，成群活动，追随船只或渔船觅食。主要以小型鱼类、甲壳类、软体动物为食，也取食废弃物。分布于东亚海岸线，从俄罗斯远东至日本、朝鲜半岛及中国东部，越冬时南至中国东南部。","breeding":"繁殖期4月至7月，营巢于人迹罕至的悬崖或岛屿，巢由枯草构成，每窝产卵2至3枚，孵化期24至27天。雏鸟孵化后约30至45天即可飞翔。","identification":"黑尾鸥以其黑色尾羽和独特叫声易于识别。与同属物种相比，其翼长而尖，飞行更为优雅。","protection":"IUCN：LC（无危）。全球估计数量105万只，日本和俄罗斯彼得大帝湾有较大集中。","distribution":"繁殖于俄罗斯远东、日本北海道、朝鲜半岛、中国东部及台湾马祖岛。越冬分布扩展至中国南海及菲律宾。","other":"在日本的Hachinohe，其叫声被列入日本百音之一。在Aomori的Kabushima，黑尾鸥被视为渔业女神的使者，受到当地人的崇敬和保护。"},{"name":"红嘴灰鸥","english_name":"Heermann's Gull","scientific_name":"Larus heermanni","overview":"红嘴灰鸥（英文名：Heermann's Gull，学名：Larus heermanni），是鸻形目鸥科鸥属的鸟类。独特的中等体型鸥类，以其红嘴和烟灰色羽毛而闻名。这种鸥鸟主要繁殖于墨西哥加利福尼亚湾的伊莎拉扎岛，全球90-95%的种群在此筑巢。成鸟具有鲜明的白色头部，与灰暗的颈部无缝连接，而幼鸟全身呈深棕色。红嘴灰鸥几乎完全栖息于沿海地带，冬季迁徙至北至华盛顿和不列颠哥伦比亚省。","appearance":"红嘴灰鸥是一种中等体型的鸥，体长46-53厘米，体重371-643克，雌雄羽毛颜色相似。成鸟在繁殖季节头部和颈部白色，后颈、上尾覆羽和下体淡灰色，逐渐变暗至背部的石板色。二级飞羽黑色尖端带有白色，一级飞羽黑色，有3-4个顶点白色斑点。尾部黑色，尾端狭窄处白色。虹膜深褐色，腿和脚呈棕黑色。喙明显两色，基部红色，尖端黑色。冬季成鸟头部被灰色、棕色和白色斑纹覆盖。二年生个体均匀的石板灰色，喙基部淡橙色至暗红色，尖端黑色。一年生和幼鸟全身深灰色，尾部和飞羽黑色；幼鸟上部有浅黄色边缘，呈现鳞状外观。喙在两个年龄段均为两色，基部肉色，尖端黑色。","habits":"红嘴灰鸥倾向于群体生活，它们在加利福尼亚湾的干燥岛屿上形成大型繁殖群落，主要在3月至7月间繁殖。最大的繁殖群位于伊莎拉扎岛，估计有90-95%的世界种群在此繁殖。非繁殖期的红嘴灰鸥首次出现在南加州海岸，之后加入繁殖者行列，进行了一次显著的向北迁移，从加州圣迭戈到不列颠哥伦比亚省温哥华岛的太平洋沿岸，高峰数量在7月和8月抵达加拿大。随后，秋季和冬季期间发生南迁，部分种群全年停留。红嘴灰鸥主要在近海水域觅食，常与多种海鸟混群，通过偷窃方式从其他海鸟那里获取食物，特别是从褐鹈鹕的囊中抢夺鱼。","breeding":"红嘴灰鸥在地面上简单挖坑作巢，有时以碎片铺垫。产卵数通常为1-3枚，但常见的是产1或2枚蛋。半早成鸟孵化后经过28天的孵化期，雏鸟在45天后离巢。","identification":"红嘴灰鸥在所有年龄组都有独特的双色喙，成鸟的深色体羽使其在北美鸥类中独一无二。幼鸟和未成年个体常被误认为贼鸥，但红嘴灰鸥缺乏明显的翼部白色条纹，且不会在腹部或下翼显示浅色斑点。","protection":"IUCN：NT（近危）","distribution":"红嘴灰鸥主要繁殖于墨西哥加利福尼亚湾北部的伊莎拉扎岛，零星繁殖于从美国加州海滨至墨西哥纳亚里特的岛礁。非繁殖期分布于从加拿大西南部不列颠哥伦比亚省南部至墨西哥西南部的海岸线。"},{"name":"普通海鸥","english_name":"Common Gull","scientific_name":"Larus canus","overview":"普通海鸥（英文名：Common Gull，学名：Larus canus），是鸻形目鸥科鸥属的鸟类。中型鸥科鸟类，广泛分布于欧亚大陆，包括冰岛、欧洲西北部至中部，以及远东至堪察加半岛。这种鸥体型较小，翼长而圆头，眼色深邃，嘴尖而长。繁殖期间头部全白，非繁殖期头部带有灰褐色斑纹。幼鸟呈棕色，嘴端粉黑。其分布广泛，数量众多，尤其在欧洲占全球种群的大部分比例。","appearance":"成年普通海鸥总长41-46厘米，翼展可达110-125厘米。头部圆润，眼睛相对较大，嘴细长，稍向下弯曲，嘴端有轻微的角质突起。繁殖期头部纯白，尾部和体羽亦为白色，背部和肩羽呈中灰色，翼尖黑色，具大白色斑点。冬季头部和颈部有灰褐色斑纹。嘴黄色至绿黄色，腿和脚灰绿色至黄绿色。性别相似，但雄鸟略大且重。幼鸟呈棕色，翼尖黑色，嘴端粉黑，下体有灰褐色条纹。","call":"普通海鸥的常见叫声是一声尖锐的吱吱声，比大多数其他鸥类的叫声更为突然。","habits":"普通海鸥栖息于湿地、草地、海滩，冬季偏好水边栖息地和田野，尤其是沿海地带。繁殖期在湿地、草地和海滩筑巢。成群结队，活动范围广泛，觅食方式多样，以鱼类、昆虫和其他无脊椎动物为主食，偶尔食用谷物和浆果。","breeding":"繁殖期为每年4月至8月，巢建于海岸、岛屿、河流岸边的地面或岩石上，巢简单，由海藻、枯草等构成。每次产卵2-3枚，雌雄交替孵化，孵化期24-28天。","identification":"与环嘴鸥最为相似，但可通过体型、嘴形、翼斑和叫声加以区分。普通海鸥嘴更短，翼尖具大白色斑点，叫声尖锐。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖北美和欧亚，包括冰岛、欧洲西北部至中部，以及远东至堪察加半岛。非繁殖期分布于欧洲至北非、地中海、黑海、里海、波斯湾、鄂霍茨克海、日本、朝鲜半岛至中国东南部。","other":"普通海鸥的骨骼为空心管状，具有预测天气变化的能力，是海上航行安全的‘预报员’。"},{"name":"环嘴鸥","english_name":"Ring-billed Gull","scientific_name":"Larus delawarensis","overview":"环嘴鸥（英文名：Ring-billed Gull，学名：Larus delawarensis），是鸻形目鸥科鸥属的鸟类。中等体型的鸥科鸥属鸟类，以其嘴部特有的黑色环带著称。常见于北美大陆，遍布北美洲大部分地区。繁殖期间头部洁白，非繁殖季节头部带有淡褐色斑纹。其黄色腿脚和浅色眼睛为显著特征。幼鸟呈棕色斑驳状，喙端呈粉色并带有黑色尖端。喜爱湖泊、河流、池塘及海滩等环境，尤其偏爱停车场和城市区域。","appearance":"环嘴鸥体长介于43至54厘米，体重300至700克，雌雄存在细微差异，雄鸟平均比雌鸟大6-7%。繁殖期成鸟头部雪白，喙部具醒目黑色环带，非繁殖期头部可见淡褐色斑点。幼鸟整体呈斑驳的棕褐色，喙基粉色，尖端黑色。翅膀上有独特的白色翼尖斑点。","habits":"栖息于湖泊、河流、海滩及城市环境，偏好内陆地区，常见于停车场和城市地带。以昆虫、蚯蚓、鱼类、鼠类及谷物为食，集群活动，善于利用人类活动区域获取食物。迁徙至美国南部沿海及内陆、墨西哥南部、巴哈马群岛等地过冬。","breeding":"繁殖期在近水的岛屿或半岛上筑巢，通常与鲱鸥、燕鸥等物种共享繁殖地。巢穴建于地面，多位于植被稀疏的大湖岛屿。营巢、交配、产卵、孵化和育雏等繁殖行为在群体中进行。","identification":"与美洲海鸥相似但体型更大，喙部更粗壮。幼鸟的辨识较为困难，但环嘴鸥通常斑驳更为粗糙。与鲱鸥相比，体型较小且体态轻盈。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大及美国北部，包括不列颠哥伦比亚省东部、五大湖区及太平洋西北部。非繁殖期广泛分布于美国南部沿海及内陆、墨西哥南部、巴哈马及大安的列斯群岛。","other":"曾因人类猎杀而数量锐减，20世纪中叶后逐渐恢复，成为北美最常见的鸥类之一。"},{"name":"加州鸥","english_name":"California Gull","scientific_name":"Larus californicus","overview":"加州鸥（英文名：California Gull，学名：Larus californicus），是鸻形目鸥科鸥属的鸟类。体型介于环嘴鸥和银鸥之间，广泛分布于北美西部内陆湖泊和海岸。成年个体具有中灰色上体，红黑相间的喙，以及深色的眼睛，夏季常见于内陆水域，冬季则迁徙至太平洋沿岸。","appearance":"加州鸥为中等体型的鸥类，成鸟具中灰上体，喙部带有红黑色斑点，腿脚黄色。幼鸟羽色多为杂乱的棕白相间，随年龄增长逐渐变为成鸟的灰白色。喙色从粉红转蓝，直至成年的黄绿色。眼睛颜色深邃，有助于与同类物种区分。","habits":"栖息于内陆湖泊和河流岛屿，繁殖季节在稀疏植被覆盖的岛屿上筑巢。冬季迁徙至太平洋沿岸，常见于海滩、河口、垃圾场等开放地带寻找食物，包括昆虫、鱼、小型水生动物及人类丢弃的食物残渣。","breeding":"繁殖期主要集中在春季，通常在内陆湖泊的岛屿上集体筑巢。每窝产卵2至3枚，双亲共同承担孵化和育雏责任。","identification":"与环嘴鸥相比体型略大，而比银鸥小，通过喙部的红黑标记、黄色腿脚以及较圆润的头部轮廓与同类区分。幼鸟与成鸟在羽色上有明显差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中部至美国科罗拉多州和加利福尼亚州中部，非繁殖季节迁徙至太平洋沿岸，从加拿大西南部至墨西哥中西部。","other":"加州鸥是犹他州的州鸟，因历史上帮助早期摩门教徒控制蝗虫灾害而闻名。"},{"name":"大黑背鸥","english_name":"Great Black-backed Gull","scientific_name":"Larus marinus","overview":"大黑背鸥（英文名：Great Black-backed Gull，学名：Larus marinus），是鸻形目鸥科鸥属的鸟类。亦为全球最大的海鸥之一，体长可达79厘米，翼展达1.7米。分布于北美东北部、欧亚大陆的大西洋沿岸，尤其在北美的大湖区域可见其身影。该鸟拥有深黑的背部和翅膀，白色头颈及下体，粉色腿脚，以及黄色带红斑的喙。以其凶猛的猎食行为著称。","appearance":"成鸟特征明显，具深灰色近乎黑色的上体，白色头颈和下体。喙呈黄色，末端带有红色斑点，眼圈红色，腿部呈粉红色。幼鸟上体具鳞状暗褐色，头和下体有灰色条纹，尾部白色，具黑色斑点和边缘，翼部暗褐色。体型庞大，喙粗壮。","call":"发出深沉的‘kaa-ga-ga’叫声，首音有时拉长，近似牛哞声。","habits":"栖息于海岸线、河口、湖泊、河流、湿地等水域附近，常见于垃圾填埋场。以鱼、甲壳类、软体动物、昆虫、浆果为主食，也捕食小型鸟类、哺乳动物和鸟蛋。适应性强，善于利用人类活动创造的食物资源。","breeding":"单个或小群繁殖，常在难以被陆地捕食者接近的地方筑巢，如岛屿、沙丘、屋顶等。每年产卵三枚，孵化期约28天，幼鸟50天离巢，与父母共同生活约六个月。四岁达到成熟。","identification":"与其它大型海鸥相比，体型更大，背部颜色更深，喙更为粗壮。幼鸟的鳞片状上体和较大的体型有助于识别。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美东北部沿海及大湖区域，欧亚大陆从格陵兰南部至欧洲西北部。非繁殖季节分布于欧洲西南沿海至美国佛罗里达州。","other":"历史上曾因羽毛贸易而遭受过度猎杀，现数量稳定，甚至在某些地区被视为害鸟。"},{"name":"黑背鸥","english_name":"Kelp Gull","scientific_name":"Larus dominicanus","overview":"黑背鸥（英文名：Kelp Gull，学名：Larus dominicanus），是鸻形目鸥科鸥属的鸟类。广泛分布于南半球沿海和岛屿的大型鸥类。其命名源自于穿着黑白服饰的多米尼加修士。在澳大利亚和新西兰，被称为太平洋鸥、mollyhawk或毛利语中的karoro。南非的亚种vetula则被称作开普鸥。","appearance":"黑背鸥体长介于54至65厘米之间，翼展可达128到142厘米，体重在540至1390克之间。成鸟具有黑色背部和翅膀，头部、腹部、尾巴以及翼尖的小‘镜面’均为白色。喙部黄色，带有红色斑点，腿部呈绿色至黄绿色。幼鸟腿部暗淡，喙部黑色，尾部有暗色带纹，整体呈现灰褐色羽毛，边缘泛白，但很快就会出现喙部基部变淡，头部和下体大部分变为白色。达到成熟需三至四年。","call":"发出尖锐的ki-och叫声。","habits":"黑背鸥主要栖息于沿海区域，包括沿海水域，也会造访大型内陆湖泊，并在湖泊、水库、河口、河流、草地和农田上觅食或休息。它们在海洋岛屿、近岸岛屿、海岬、悬崖、海滩、牧场、熔岩场、河流中的岩石岛屿和城市区域筑巢。在南非，它们甚至在距海岸10公里的内陆繁殖，高度达350米。","breeding":"繁殖季节因地理位置而异，从十月在南非到十二月在南美洲。巢通常位于数十至数百对鸥群中，偶尔单独筑巢。巢由干植物、海藻、羽毛等构成，放置于沙质或岩石底质上，常有植被覆盖。每窝产卵1-3枚，平均孵化期为24-30天，幼鸟约7周后离巢。","identification":"与北方大西洋的较小型黑背鸥和较大型黑背鸥相似，但介于两者之间。与太平洋鸥相比，体型更大，喙部更厚重。南非亚种vetula具有更尖锐的头部形状和较小、较短的喙。","protection":"IUCN：LC（无危）。全球估计数量在330万至430万只之间。新西兰的亚种antipodus拥有超过一百万对，而南美的dominicanus亚种估计有至少16万对。南非的vetula亚种约有7万只。","distribution":"分布于南美洲、澳大利亚和新西兰的海岸线，非洲南部海岸，以及南极海域。在阿根廷的巴塔哥尼亚和南非的部分地区，它们的数量显著增加，部分原因在于农业和渔业的发展。","other":"黑背鸥是杂食性动物，会从垃圾填埋场觅食，因此其数量的急剧增长被视为环境退化的指标。在阿根廷水域，它们被观察到攻击活着的露脊鲸，用喙啄入鲸鱼皮肤和脂肪，造成大面积开放性伤口。"},{"name":"灰翅鸥","english_name":"Glaucous-winged Gull","scientific_name":"Larus glaucescens","overview":"灰翅鸥（英文名：Glaucous-winged Gull，学名：Larus glaucescens），是鸻形目鸥科鸥属的鸟类。广泛分布在北美西北海岸，从阿拉斯加到华盛顿州，夏季也见于阿拉斯加西北部海岸和俄罗斯远东地区。平均寿命约为15年，但有记录显示个别个体能活超过37年。灰翅鸥与西美鸥和北极鸥相似，但翅膀和背部呈现独特的灰蓝色调。","appearance":"灰翅鸥是一种体型庞大的海鸥，身长可达58-62厘米，翼展132-137厘米，体重介于890-1360克之间。成鸟具有白色的头、颈、胸和尾，翅膀和背部呈淡灰色，翼尖颜色与背部一致。它们的眼睛较小，呈深色，位于头部较高位置，喙钝而粗壮，带有红色的下颌斑点，腿和脚为粉色。幼鸟和亚成鸟的羽毛颜色从灰色到深灰色不等，带有斑点，经过四年才能达到成鸟的羽毛状态。","call":"灰翅鸥发出低沉的“kak-kak-kak”或“wow”声，或是更高音的哀鸣。","habits":"灰翅鸥栖息于海岸线，包括岩石岛屿、海滩和城市公园，以沿海水域为主要活动范围，冬季分布至南至加利福尼亚州、俄勒冈州、下加利福尼亚州、下加利福尼亚苏尔州和索诺拉州。它们主要在海岸边寻找食物，以死鱼、弱小动物、贝类和人类丢弃的食物残渣为食，城市环境中它们会接受人类喂食并搜寻垃圾袋中的食物。","breeding":"灰翅鸥在夏季繁殖，每对繁殖伴侣一般产下2-3枚卵，雏鸟大约在六周后离巢。它们倾向于在人迹罕至的海岸悬崖上筑巢，巢材主要由水生植物和干草构成，内部铺有羽毛。卵为橄榄绿色，带有暗色斑点，尺寸约66-82×46-56毫米。","identification":"灰翅鸥与西美鸥在外观上有细微差异，西美鸥的背部颜色更深，翼尖黑色，喙更黄，虹膜金棕色。灰翅鸥与北极鸥相比，后者体型略小，翼尖有白色斑点，虹膜金棕色。灰翅鸥的亚成鸟和成鸟之间有明显的羽色过渡。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括欧亚大陆的北部太平洋沿岸，从俄罗斯东部的西伯利亚东北部、堪察加半岛、科曼多尔群岛，到美国阿拉斯加州西南部大陆至华盛顿州北部。非繁殖季节分布至日本和美国加利福尼亚州。","other":"灰翅鸥与西美鸥、北极鸥频繁杂交，产生难以识别的后代，称为奥林匹克鸥和库克湾鸥，这些杂交种在某些地区的数量可能超过纯种。"},{"name":"西美鸥","english_name":"Western Gull","scientific_name":"Larus occidentalis","overview":"西美鸥（英文名：Western Gull，学名：Larus occidentalis），是鸻形目鸥科鸥属的鸟类。又名: 西方鸥，又称西方鸥，是北美洲西海岸特有的大型白头海鸥。分布范围自加拿大不列颠哥伦比亚至墨西哥下加利福尼亚，主要栖息于太平洋沿岸。体长约60厘米，具暗灰色背部、明亮粉色腿脚，成鸟拥有白色的头部和身体，黄色喙带有红色末端斑点。在北部分布区与灰翅鸥杂交，形成复杂的混血地带。","appearance":"西美鸥体型庞大，全长约55至68厘米，翼展可达130至144厘米，体重介于800至1400克之间。头部和身体白色，背部和翅膀上部为深灰色，喙黄色，近端有一红色斑点，眼睛颜色随亚种不同而异，南方亚种眼色较浅，北方亚种则较深。幼鸟呈斑驳的灰褐色，成鸟需四年时间才能达到成熟羽毛状态。","call":"西美鸥发出响亮、刺耳且重复的叫声。","habits":"西美鸥几乎全年居住于加州、俄勒冈、下加利福尼亚和华盛顿南部，迁徙至北部华盛顿、不列颠哥伦比亚和下加利福尼亚南部度过非繁殖季节。它们偏好沿海岛屿、岩石和河口内的岛屿筑巢，偶尔在人类活动区域如垃圾填埋场和公园觅食。","breeding":"在繁殖季节，西美鸥在领地内以植物构建巢穴，通常产下3枚蛋，孵化期约为一个月。雏鸟留在父母领地直到离巢。成活率低，平均一窝仅有一只幼鸟能存活至离巢。","identification":"西美鸥与大黑背鸥相似，但后者眼睛颜色更浅，腿脚和眼眶更偏粉红色。在分布区北端，与灰翅鸥形成杂交地带，混血个体特征介于两者之间。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美西太平洋沿岸，从美国西北华盛顿至墨西哥下加利福尼亚中部；非繁殖区向北延伸至不列颠哥伦比亚南部，向南至墨西哥下加利福尼亚南部。","other":"西美鸥曾因人类采集鸟蛋和栖息地破坏导致数量减少，现在受气候变化和石油泄漏威胁。"},{"name":"黄脚鸥","english_name":"Yellow-footed Gull","scientific_name":"Larus livens","overview":"黄脚鸥（英文名：Yellow-footed Gull，学名：Larus livens），是鸻形目鸥科鸥属的鸟类。又名:银鸥鸥，大型鸥科鸟类，身披暗灰石板色背部，黄色腿脚，与西美鸥极为相似。曾一度被认为是西美鸥的亚种，现确认其为独立物种，且与南半球的海鸥关系更为密切。加利福尼亚湾的特有种，繁殖范围完全位于墨西哥境内，但在美国加州东南部的萨尔顿海作为非繁殖季节访客定期出现。","appearance":"成年黄脚鸥具有白色头部、颈部和身体，深灰色的背羽，黄色喙带有红色下颌斑点，黄色至淡黄色虹膜，橙黄色或黄色的眼眶。幼鸟在第一年整体呈棕色，腿脚粉红，到第二年发展出灰色背部和黄色腿脚。成鸟拥有黑色翼尖，与深灰色背部和黄色腿脚形成鲜明对比。","call":"未提供具体描述。","habits":"黄脚鸥偏好沙滩、岩礁和泥滩潮间带以及渔港环境，主要栖息于加利福尼亚湾。它们是杂食性鸟类，以小鱼、无脊椎动物、海洋哺乳动物尸体和内脏为食，偶尔掠食海鸟的雏鸟和鸟蛋，包括鹈鹕的蛋。它们在垃圾堆和码头附近觅食残渣，但很少飞往内陆。","breeding":"黄脚鸥在四月于加利福尼亚湾繁殖，既可单独筑巢也可群居繁殖。巢通常建在海滩上，离最高潮线几米处。每对黄脚鸥会保卫一块从巢到海边的小领地。巢穴是在沙地上挖出的浅坑，内铺少量海藻或干植物材料。通常产三枚橄榄绿或淡褐色带有深色斑点的蛋，由双亲共同孵化。雏鸟约在七周大时完全羽化并离开巢穴。","identification":"成年黄脚鸥最明显的识别特征是深灰色背部、黑色翼尖和黄色腿脚。与西美鸥相比，黄脚鸥的腿脚颜色是主要区别之一。幼鸟与西美鸥幼鸟区分较为困难，但黄脚鸥幼鸟腹部和下尾覆羽有大量白色，而西美鸥幼鸟全身颜色较均匀。","protection":"IUCN：LC（无危）","distribution":"繁殖区域集中在墨西哥的加利福尼亚湾，从Roca Consag至拉丁美洲的拉巴斯湾。非繁殖季节，黄脚鸥会前往美国加利福尼亚州中南部的萨尔顿海，以及墨西哥西北部的加利福尼亚湾各地。","other":"黄脚鸥的生物学特性仍有待研究，尤其是其觅食生态、迁徙控制机制和生理学。"},{"name":"北极鸥","english_name":"Glaucous Gull","scientific_name":"Larus hyperboreus","overview":"北极鸥（英文名：Glaucous Gull，学名：Larus hyperboreus），是鸻形目鸥科鸥属的鸟类。体型庞大的鸥类，以其白色的翼尖和厚重的黄色喙著称。繁殖于北极地区，冬季南迁至温带海域。成鸟几乎全白，背部呈淡灰色，幼鸟则为白色或淡褐色，带有浅棕色斑点。该鸟种广泛分布于北极圈，包括北美、欧亚大陆的高纬度地带。","appearance":"北极鸥是大型鸥类，体长64-77厘米，翼展132-142厘米，体重1.25-2.7千克。成鸟背部淡灰，翼尖纯白；喙色从黄色到淡黄橙色不等，眼虹膜金黄，腿色粉红。头部在繁殖季节为纯白色，冬季则可能带有棕色斑纹。幼鸟具双色喙，上半部粉色下半部黑色，全身羽毛为淡棕色，翼尖透明白色。","call":"发出类似银鸥的‘笑’声，但音调更低沉。","habits":"北极鸥栖息于北极圈内的多种环境，如开阔的苔原、高山悬崖、淡水湖中的岛屿及河口沙洲。冬季迁徙至温带海域，常见于沿海地区，有时会到达大湖和圣劳伦斯河。它们是杂食性鸟类，食物包括海洋和淡水鱼类、无脊椎动物、鸟蛋、小鸟、小型哺乳动物、浆果、腐肉、人类丢弃的食物。","breeding":"北极鸥在北极地区的各种环境中筑巢，包括开阔的苔原、高山悬崖、淡水湖岛屿。通常每对北极鸥能抚养2-3只幼鸟。它们的社会性一夫一妻制，伴侣关系往往维持多个繁殖季节。","identification":"与冰岛鸥相比，北极鸥体型更大，喙更粗壮，通常颜色更浅；冰岛鸥翼尖通常有更多暗色标记。北极鸥的翼尖较短，不会远伸过尾端。在识别时，体型、喙型和翼尖长度是关键区别。","protection":"IUCN：LC（无危）；已列入中国《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","distribution":"繁殖于北极圈，包括北美、格陵兰、冰岛和欧亚大陆的北极地带。越冬于温带海域，最南可达英国和美国北部，偶尔见于美国南部和墨西哥北部。","other":"北极鸥有四个亚种，它们在大小和背部颜色上有细微差异。"},{"name":"冰岛鸥","english_name":"Iceland Gull","scientific_name":"Larus glaucoides","overview":"冰岛鸥（英文名：Iceland Gull，学名：Larus glaucoides），是鸻形目鸥科鸥属的鸟类。一种体型中等、头部较圆的海鸥，拥有大而黑的眼睛，外观类似鸽子。这种鸥的翅膀异常苍白，翼尖呈雪白色，常被误认为白翼鸥。在冬季偶尔访问英国，数量稀少，有时仅见单只。繁殖范围广泛，从北极圈延伸至南至纽约和英国。在北极多岩石的海岸高悬崖上筑巢繁殖，冬季则迁徙至海边港口、靠近垃圾堆的地区以及内陆的水库和垃圾堆附近。","appearance":"冰岛鸥是一种中等体型的海鸥，长度介于50至64厘米之间，翼展可达115至150厘米，体重范围在480至1100克之间。它的体型较瘦长，重量较轻，比大型的灰背鸥更小巧，通常也比鲱鸥小。冰岛鸥的背部和翅膀颜色较为淡雅，喙呈黄绿色，幼鸟的灰色更加浅淡，喙部的暗色部分比灰背鸥更为广泛，没有粉色。","call":"冰岛鸥的叫声类似于鲱鸥的‘笑’声，但音调更高。","habits":"冰岛鸥是迁徙性鸟类，冬季迁徙至北欧大西洋沿岸，远至英国和美国东北部的北部州份，以及北美内陆直至五大湖西部地区。它们在北极加拿大东北部至格陵兰繁殖，不在冰岛繁殖。它们在海岸和悬崖上群居或单独繁殖，用草、苔藓或海藻铺垫的巢穴建在地面或悬崖上。以鱼、软体动物、垃圾、残余物和鸟蛋为食，飞行中觅食，从水面或水下拾取食物，也会在行走或游泳时进食。","breeding":"冰岛鸥通常在春季繁殖，每窝产2至3枚淡褐色的蛋。","identification":"冰岛鸥与灰背鸥相比，体型较小，喙部较细，翼尖颜色差异明显，成年冰岛鸥翼尖几乎不含黑色素，而灰背鸥则有明显的黑色翼尖。幼鸟阶段，冰岛鸥喙部的暗色部分比灰背鸥更为广泛，缺乏粉色。","protection":"IUCN：LC（无危）","distribution":"冰岛鸥繁殖于北极加拿大东北部至格陵兰，冬季迁徙至冰岛沿海至欧洲西北部，加拿大拉布拉多至大西洋中西部北部海岸线，以及太平洋中东部北部海岸线。","other":"冰岛鸥的三个亚种在翼尖颜色上有显著差异，其中指名亚种L. g. glaucoides的翼尖在成年时几乎不含黑色素，整体颜色非常淡雅。"},{"name":"银鸥","english_name":"European Herring Gull","scientific_name":"Larus argentatus","overview":"银鸥（英文名：European Herring Gull，学名：Larus argentatus），是鸻形目鸥科鸥属的鸟类。又名: 鱼鹰子、淡红脚鸥、黄腿鸥、鱼鹰子和叼鱼狼，大型鸥。银鸥分布广泛，从冰岛沿海和内陆至法国西部和俄罗斯西北部，西南部，是沿海、内陆水域及垃圾成堆等地方的清道夫。","appearance":"成年银鸥体长可达64厘米，背部呈淡灰色，嘴厚，前额长缓而下，头顶平坦，外观显得凶猛。飞行时，初级飞羽外侧有小块翼镜，翼合拢时可见六枚白色羽尖。非繁殖期头部和颈部有纵纹，眼区和耳覆羽为黑色。第一冬鸟具褐色杂斑，嘴黑色；第二冬鸟色略淡而多灰色，嘴黄色而端黑。幼鸟类似其他银鸥，但有区分特征。虹膜褐色，嘴深黄，上具红点；脚红色。","call":"银鸥的叫声包括响亮的kleow叫声，klaow-klaow-kla-ow…的大叫及短促的嘀嘀咕咕声ge-ge-ge。在繁殖地驱赶其他入侵者时会发出愤怒的ping声。","habits":"银鸥是松散的群居性鸟类，常数十只或成百只一起活动，喜跟随来往的船舶，索食船中的遗弃物。它们活动在近海附近，是船舶即将靠岸的‘活指示’。以动物性食物为主，包括水里的鱼、虾、海星和陆地上的昆虫及鼠类等。","breeding":"银鸥在繁殖季节，两到四枚橄榄棕色带暗斑的蛋被产在地面或悬崖边缘的巢穴中，由双方共同孵化28-30天。雏鸟孵化后眼睛已开，覆盖着绒毛，数小时内即可行走。父母通过雏鸟啄击其嘴上的红点来识别饥饿信号，从而喂食。幼鸟在35-40天后能飞行，五或六周后离巢。","identification":"银鸥与小黑背鸥在分类上复杂，它们在北半球形成环物种分布。银鸥比小黑背鸥体型更大，背部颜色更淡，且腿部颜色为淡粉色。","protection":"IUCN：LC（无危）","distribution":"银鸥繁殖于欧洲北部和西部，包括冰岛、英国、爱尔兰和法国等地。在冬季，它们向南迁徙，主要分布在西北欧的海岸线。在中国大陆，银鸥为新疆、内蒙古的普遍夏候鸟，冬季在河北沿海，长江以南越冬。","other":"尽管整体数量稳定，但在某些地区，如英国，银鸥的种群数量显著下降，特别是在城市环境中。"},{"name":"美洲银鸥","english_name":"American Herring Gull","scientific_name":"Larus smithsonianus","overview":"美洲银鸥（英文名：American Herring Gull，学名：Larus smithsonianus），是鸻形目鸥科鸥属的鸟类。是大型鸥科鸥属的一种海鸟，原被视为银鸥的一个亚种。其广泛分布于北美洲，自加拿大北部至美国东北部沿海地区。成鸟拥有灰背白腹的特征性外观，黑色翼尖带有白色斑点，粉红色的腿脚。幼鸟呈灰褐色，较欧洲银鸥更为暗淡和均匀。通常栖息于海岸、湖泊、河流、停车场和垃圾堆，食谱广泛。","appearance":"美洲银鸥体态健壮，喙长有力，胸部丰满，前额平缓。雄鸟体长60-66厘米，体重1050-1650克；雌鸟略小，体长53-62厘米，体重600-900克。翼展可达120到155厘米。成鸟头部、臀部、尾巴和下体为白色，背部和上翅为浅灰色。翼尖黑色，带有白色‘镜’状斑点，翼缘白色。幼鸟需四年时间才能完全换羽成成年羽毛，期间会经历多个换羽阶段，外观变化多样。","call":"美洲银鸥没有特定的歌曲，但能发出一系列叫声，包括面对威胁时的快速‘hahaha’声，强度随威胁程度变化；更强烈的‘keow’声用于警告；‘长叫声’由一连串响亮音符组成，头先下垂再抬起；‘窒息声’在求偶、筑巢或领土争端时发出，伴随头部快速点头；‘mew’声用于引起注意，如呼唤幼鸟或伴侣及巢穴防卫；幼鸟会发出高音哀求声以刺激亲鸟喂食。","habits":"美洲银鸥栖息于近水的群落，包括海岸、岛屿、悬崖，也会在城市屋顶筑巢。它们在海滩、泥滩、湖泊、河流、田野和垃圾场觅食，偏好海洋无脊椎动物、鱼类、昆虫和其他鸟类的雏鸟和蛋，也常吃腐肉和人类丢弃的食物。食物获取方式多样，包括表面拾取、浅水捕捞、高空投掷贝类以破壳。","breeding":"繁殖季节在每年3月或4月开始，巢建于地面，用草、海藻和羽毛衬垫。每窝产卵三枚，卵长72毫米，颜色多变，有棕色斑点。孵化期约30-32天，自第二枚卵产下起算。幼鸟约6-7周后离巢，之后数周内仍由父母在巢区喂养，直至约6个月大完全独立。双方父母共同参与巢筑、孵化和幼鸟喂养。","identification":"成年美洲银鸥与欧洲银鸥相似，但后者体型较小，灰色更深。美洲银鸥在第6、7、8级初级飞羽上有较长的灰色舌状斑，以及在第5、6级初级飞羽上的实黑标记，这是欧洲银鸥所缺乏的。幼鸟阶段，美洲银鸥的上体更斑驳，下体条纹更多，臀部和尾基颜色更淡。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美的广阔区域，从阿拉斯加中部和南部至加拿大北部，向南延伸至美国五大湖区、东北内陆和大西洋西岸，最南至北卡罗来纳州。冬季分布向南扩展至墨西哥，少数个体可达夏威夷、中美洲和西印度群岛。","other":"19世纪曾因猎杀而稀少，20世纪中叶因保护措施、渔业废弃物增加及大型捕食者减少而数量激增。然而，自1970年代以来，增长趋势已放缓，部分地区甚至开始下降。"},{"name":"西伯利亚银鸥","english_name":"Vega Gull","scientific_name":"Larus vegae","overview":"西伯利亚银鸥（英文名：Vega Gull，学名：Larus vegae），是鸻形目鸥科鸥属的鸟类。东亚大型鸥类，体型壮实，成鸟背羽淡灰，眼淡色，腿呈暗粉色。幼鸟需四年完成从棕褐色到灰白成羽的渐变，羽色多变，辨识难度高。繁殖于西伯利亚东北部及阿拉斯加圣劳伦斯岛，越冬于西北太平洋至日本、韩国及中国沿海至香港。","appearance":"体长55–67厘米，翼展125–155厘米；雄鸟重1318–1368克，雌鸟1083–1158克，雄鸟明显更大，嘴更粗。繁殖羽：头颈体尾纯白，背及翼淡灰，翼尖黑色具白镜斑；嘴黄至淡橙，尖端下具红斑；虹膜金黄，眼周橙红；腿粉红，偶见黄色。非繁殖羽：头颈具灰褐色纵纹，色泽暗淡。幼鸟羽色多变，第一年整体棕褐，翼尾深褐，嘴黑，腿暗粉；第二、三年渐淡，背羽出现灰色；第四年达成羽，部分个体仍留褐斑。","call":"鸣声与银鸥属指名亚种极似，常见“哈哈”笑声或响亮沙哑的“guwaa”声。","habits":"活动于海岸及内陆水体，常见于河口、港口、海滩、湖泊、池塘。常与其他鸥混群。食性杂，捕食鱼、软体动物、甲壳类、昆虫、蚯蚓、小型哺乳动物、浆果，亦食其他海鸟卵、雏鸟和尸体，并大量利用人类废弃食物。繁殖地多样，包括海岸悬崖、岩礁岛、沙滩、砾石洲、盐沼、石灰岩露头及建筑物，亦利用采土场。非繁殖期多在海陆交界水域活动，偶尔深入内陆。","breeding":"繁殖于西伯利亚东北部至楚科奇半岛以东及阿拉斯加圣劳伦斯岛；巢建于开阔水域附近，可远离水源觅食。繁殖期巢位多样，从海岸到内陆城市皆可。","identification":"成鸟背羽比美洲银鸥略深；与蒙古银鸥极似，但头与嘴较大，腿偏粉色。翼尖黑色范围小于蒙古银鸥（外5–7枚初级飞羽，蒙古为6–9枚），冬羽头部白色更纯，后颈仅具淡褐纹。","protection":"IUCN: LC（无危）　（BirdLife International将其与蒙古银鸥、美洲银鸥视为同一评估单元，整体列为无危。）","distribution":"繁殖：西伯利亚东北部（泰梅尔半岛以东）及阿拉斯加圣劳伦斯岛。越冬：西北太平洋至日本、韩国，并沿中国沿海达香港，可能至越南；西部种群主要越冬日本。部分个体繁殖后移至阿拉斯加北海岸。春秋迁徙时常见于白令海及阿留申群岛西部。偶作为迷鸟出现于北美太平洋沿岸至加利福尼亚。","other":"分类长期归入“银鸥复合体”，现基于遗传、形态、羽色及鸣声差异被独立为种。曾与美洲银鸥、银鸥、蒙古银鸥等视为同一物种。已记录与灰背鸥、灰翅鸥、冰岛鸥杂交，亦与小黑背鸥亚种heuglini与barabensis杂交形成“taimyrensis”型。"},{"name":"里海银鸥","english_name":"Caspian Gull","scientific_name":"Larus cachinnans","overview":"里海银鸥（英文名：Caspian Gull，学名：Larus cachinnans），是鸻形目鸥科鸥属的鸟类。属于银鸥/小黑背鸥复合体。大型鸥类，体长约60厘米，上体呈浅灰至中灰色，具黄色腿部。冬季头部和颈背无褐色条纹。繁殖于黑海、里海区域，东至中亚及中国西北部。","appearance":"成年繁殖期里海银鸥体长56-68厘米，翼展137-155厘米，体重680-1590克。拥有长而细的喙，斜向的前额突出其特征。腿、翅和颈较长，眼小且颜色较深。背部和翅膀略暗于普通银鸥，但比黄腿银鸥稍淡。成鸟翼尖外侧初级飞羽有大白色端斑和白色边缘。幼鸟头部灰褐，颈背有暗色条纹，下体淡色，背部灰，翼上覆羽有白色端斑。","call":"其叫声音调低于普通银鸥，领地防卫时发出的长叫声比黄腿银鸥高亢，带有笑声特质，有时仅发出类似海狮、驴或非洲企鹅的单一声响。","habits":"栖息于海岸及内陆水体，包括湖泊、河流、沙漠地带、沙丘等。非繁殖季节更倾向于沿海栖息，常见于港口、农田、垃圾场等地。繁殖于岩石、沙滩、岛屿、河岸及灌木丛中。迁徙期间向西和南移动，部分个体仅作短距离迁移。以鱼、无脊椎动物、哺乳动物、废弃物、昆虫、鸟蛋和幼鸟为食。","breeding":"繁殖期从三月中旬开始，筑巢于低洼的地面或灌木下，通常靠近水源。巢由附近植被、羽毛、垃圾构成，有时用鳗草衬垫。每窝产卵2-3枚，孵化期平均26-29天。雏鸟孵化重约60克，10天左右能游泳，6-7周后离巢。","identification":"与黄腿银鸥和普通银鸥相比，里海银鸥具有更长更细的喙，较小的头部，更长的颈部和腿，以及不同的背部色彩。与黄腿银鸥的区别在于黄色的腿、红色的眼眶环和更深的初级飞羽。","protection":"IUCN：LC（无危）。在欧洲的种群估计为54,100-87,500对，数量正在增长。面临石油污染和人为猎杀的威胁。","distribution":"繁殖于黑海至里海区域，东至中亚和中国西北部（新疆西部）。非繁殖期扩散至欧洲东南部、黑海、地中海东部、波斯湾及阿拉伯海北部。","other":"近年来，其分布范围向西扩展至波兰、德国东部、俄罗斯南部等地。"},{"name":"黄腿银鸥","english_name":"Yellow-legged Gull","scientific_name":"Larus michahellis","overview":"黄腿银鸥（英文名：Yellow-legged Gull，学名：Larus michahellis），是鸻形目鸥科鸥属的鸟类。广泛分布在欧亚大陆的沿海和内陆南部、西部、中部，马卡罗尼西亚，地中海以及北非西北部。曾被认为是里海银鸥的一个亚种，但近年来已被广泛认可为独立物种。黄腿银鸥具有黄色的腿脚，背部颜色介于银鸥和小黑背鸥之间，头部在秋季更为洁白。","appearance":"黄腿银鸥体长52至58厘米，体重420至1600克，翼展可达120至140厘米。雄鸟体型大于雌鸟。成年夏季头部白色，眼眶红色，喙黄色带宽大的红色下颌斑点，腿部鲜黄。冬季背部稍暗，翼尖黑色面积较大，初级飞羽末端较白，头部斑纹少于黄腿大鸥。幼鸟灰色褐色，面部白色，具深色面罩，胸部和侧腹棕色斑点，腹部和中央尾下覆羽淡色，背部、肩羽和三级飞羽暗褐色边缘浅色，内侧大覆羽条纹明显，逐渐变暗，喙黑色，腿部和脚粉色。","call":"叫声为响亮的笑声，比银鸥更深沉、更鼻音。","habits":"黄腿银鸥栖息于海岸和内陆多种生境，包括岩石和沙质岛屿、海滩、悬崖、草地或灌木丛中的河流岛屿，偶尔在屋顶筑巢。它们是杂食性和机会主义捕食者，从垃圾堆到田野和海岸寻找食物，甚至从较小的鸥类和其他海鸟那里抢夺猎物。","breeding":"通常在群落中繁殖，每窝产卵通常三枚，从3月中旬至5月初开始孵卵，孵化期27至31天，雏鸟在35至40天后离巢。","identification":"与银鸥相比，黄腿银鸥背部颜色略暗，翼尖黑色更多，头部斑纹较少，腿部黄色更鲜明。与小黑背鸥的区别在于背部颜色更浅，腿部黄色。亚种atlantis背部颜色深如小黑背鸥，但体型更小，头部方形，喙粗壮。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要集中在地中海周边、北非、伊比利亚半岛、巴尔干半岛、黑海西岸以及土耳其。非繁殖季节，它们广泛分布于西欧、英国、波罗的海沿岸、塞内加尔、冈比亚和红海。","other":"黄腿银鸥在某些地区如西班牙北部和葡萄牙的城市屋顶上筑巢。"},{"name":"亚美尼亚鸥","english_name":"Armenian Gull","scientific_name":"Larus armenicus","overview":"亚美尼亚鸥（英文名：Armenian Gull，学名：Larus armenicus），是鸻形目鸥科鸥属的鸟类。现普遍认为是独立物种，但BirdLife International将其与黄腿银鸥归并。该鸥体型较小，背部偏暗，眼睛深色，翼尖黑色部分较多，白色斑点小。","appearance":"亚美尼亚鸥体长57至60厘米，体重950至1050克，翼展约140厘米。成年鸟头部白色，腿部黄色，背部及上翅灰色，喙鲜黄色，带有一条窄黑环（有时缺失），红色基部和象牙色尖端，四色分明。虹膜深色，眼眶红色。与黄腿银鸥相比，体型略小，头圆，眼色深，喙短粗。飞行时显得更结实，腹部平坦，翼尖黑色部分更多，仅小部分白色翼尖和P10羽翼镜面白色。幼鸟呈棕色，具斑纹。一冬龄个体头部及下体淡色，眼周及颈后有深色斑纹，喙全黑，腿淡粉色。二冬龄个体背部及肩羽主要为灰色，翼型与一冬龄相似但颜色较浅，大覆羽灰褐色，具细纹；喙可能全黑，通常黄色，顶端深色。三冬龄个体接近成鸟，但初级飞羽覆羽上部有黑色标记。","call":"叫声尖锐而嘶哑，类似普通海鸥，有急促兴奋的长叫，如里海银鸥，但展示时不张开翅膀。","habits":"栖息于沿海及内陆水域，农田和养鱼池旁。食物包括鱼、无脊椎动物、小型陆生脊椎动物和垃圾。分布于高加索山脉通过亚美尼亚至土耳其西部和伊朗西北部。","breeding":"群居繁殖，每群可达数千对，4月末至5月初筑巢，巢由可用的草和其他植物材料堆积而成，内衬精细材料。每窝产卵3枚，5月末孵化，幼鸟6月末离巢。","identification":"与黄腿银鸥和里海银鸥的区别在于体型、翼尖颜色、喙的特征和眼色。与加州鸥在某些特征上相似，但分布区域不重叠。","protection":"IUCN：LC（无危）","distribution":"繁殖于格鲁吉亚南部、亚美尼亚、土耳其东部和伊朗西北部的山区湖泊。越冬于东地中海、黑海和里海南部，以及波斯湾。","other":"全球数量估计在69,000至75,000只之间，但自1999年后明显减少。在伊朗和亚美尼亚的某些地区，数量曾经大幅下降，之后有所恢复，但近期再次减少。"},{"name":"灰背鸥","english_name":"Slaty-backed Gull","scientific_name":"Larus schistisagus","overview":"灰背鸥（英文名：Slaty-backed Gull，学名：Larus schistisagus），是鸻形目鸥科鸥属的鸟类。大型鸥类，以其深灰色的背部、白色的头部、亮粉色的腿以及独特的‘新月’形状白色三级飞羽边缘著称。分布于欧亚东北部海岸线和湖泊，尤其在西伯利亚东北部南部至日本北海道和本州北部。繁殖季节结束后广泛游荡。","appearance":"成鸟体长55-68.5厘米，翼展132-160厘米，体重1.05-1.7千克。背部呈暗灰色，翅膀带有宽阔的白色边缘。头部、腹部和尾巴白色，翅膀和背部比西部鸥略暗。腿粉红色，较短，体型显得粗壮。嘴黄色，带有橙红色亚端斑点。幼鸟羽色呈棕色，类似大黑背鸥，但更淡。","call":"发出低沉而生动的叫声。","habits":"栖息于海滨沙滩、岩石海岸、岛屿及河口地带，迁徙期间也出现在内陆河流与湖泊。以死鱼、鼠类、蜥蜴、昆虫、小鱼、甲壳类和软体动物等为食。春季依赖死鱼和其他动物尸体，夏季则捕食地面的鼠类、蜥蜴、昆虫及水生生物。","breeding":"繁殖期为5月至7月，巢筑于海岛和海岸悬崖上，靠近悬崖边缘。巢由枯草构成，内衬羽毛。每窝产卵2-3枚，卵呈橄榄绿或赭色，带有褐色或黑褐色斑点。","identification":"与黑尾鸥区别在于，灰背鸥嘴黄色带红点，尾白色，初级飞羽黑色，飞行时与黑尾鸥的黑尾形成明显对比。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚东北部海岸线和湖泊，包括西伯利亚东北部南部、Anadyr、堪察加半岛、鄂霍次克海、库页岛、千岛群岛（俄罗斯东部）、中国东北部，以及日本北海道和本州北部。非繁殖季节分布至日本和朝鲜半岛海岸、渤海（中国东北部）和台湾，偶尔极远迷鸟至其他地区。"},{"name":"小黑背鸥","english_name":"Lesser Black-backed Gull","scientific_name":"Larus fuscus","overview":"小黑背鸥（英文名：Lesser Black-backed Gull，学名：Larus fuscus），是鸻形目鸥科鸥属的鸟类。繁殖于欧洲大西洋沿岸，冬季迁徙至英国至西非，近年来在北美东海岸数量显著增加，成为全年可见的物种。英国是其欧洲种群的40%所在地，关键繁殖地不足十处。","appearance":"体长51-64厘米，翼展124-150厘米，体重452-1100克，比欧洲银鸥体型略小，头部更圆，喙稍细且向下弯曲，翅膀长而窄，尖端更锐利。成鸟背部深灰至黑色，腿部黄色，喙黄色带红色下颚点，眼睛黄色，具红色眼环。亚成鸟经过四至五年才能达到成鸟的羽毛颜色。","call":"叫声类似于银鸥的‘笑声’，但音调明显更深。","habits":"栖息于广泛的沿海和内陆水域，包括开阔海域，偏好沙滩和平原。以小型鱼类、水生无脊椎动物、鸟类蛋和幼鸟、渔船废弃物、啮齿动物和浆果为食。在欧洲，越来越多依赖垃圾堆的废弃食物。","breeding":"春季抵达繁殖地，主要在5月至6月中旬产卵。通常在海岸或湖泊附近群体繁殖，地面筑巢。每窝产卵2-3枚，孵化期24-28天，幼鸟约30-40天离巢。首次繁殖年龄为4岁。","identification":"与大黑背鸥相比，体型较小，体态更为纤细，腿部黄色而非粉红，翼尖白色镜状斑较小。亚成鸟上体呈鳞状黑褐色，翼型整洁。","protection":"IUCN：LC（无危）。芬兰种群自1970年代中期的约15,000对降至2013年的3,700对，归因于繁殖成功率低和环境污染物的影响。","distribution":"繁殖于格陵兰、冰岛、欧洲西部至西伯利亚中北部。冬季迁徙至欧洲西南部、非洲中西部、中东部、印度西北部及北美东海岸。","other":"已扩张到格林兰岛并在1980年代首次繁殖。与美国银鸥的杂交记录存在。"},{"name":"美洲海鸥","english_name":"Short-billed Gull","scientific_name":"Larus brachyrhynchus","overview":"美洲海鸥（英文名：Short-billed Gull，学名：Larus brachyrhynchus），是鸻形目鸥科鸥属的鸟类。其分布和生态特征与欧亚普通鸥有显著差异。","appearance":"美洲海鸥体长40-45厘米，翼展100-120厘米。它比鸥科中的同类体型小，具有较短的喙和较长的翅膀。在繁殖季节，成鸟头部全白，眼睛周围有红色眼环，腿和喙均为黄色，喙上无斑点。冬季时，头部呈现棕色斑纹，眼环变为灰色，喙色变暗淡并带有一抹暗色标记。飞行时，最外侧的两根初级飞羽（p9和p10）有明显的白色斑点或‘镜状’斑块。从p5到p8的初级飞羽有白色‘舌状’尖端，形成一串珍珠般的过渡，至宽大的白色尾缘。p4通常在许多个体上有黑色标记。与之相比，欧亚普通鸥的喙较大，翅膀较短，翼尖的黑色面积更广，p9-10的‘镜状’斑块较小，尾缘较窄，且p4通常没有黑色标记，p8也缺少白色‘舌状’尖端。","call":"常见叫声为高亢、尖锐的尖叫，比大多数其他海鸥的哀号更加突然。","habits":"繁殖于北美西部沿海和内陆湿地，主要在阿拉斯加和加拿大。冬季则迁徙至太平洋沿岸，南至墨西哥下加利福尼亚州。偏好水域边环境和田野，不如其他一些海鸥频繁出现在大型城市中心。","breeding":"在湿地、草地和海滩繁殖；冬季则栖息于水边栖息地和田野。","identification":"与欧亚普通鸥的区别在于喙的长度、翅膀的比例、翼尖的白色图案和叫声。与环嘴鸥的主要区别在于体型略小、喙较细长、背部颜色较浅、喙较粗且平行，且具有明显的黑色亚端部环带。","protection":"IUCN：LC（无危）","distribution":"繁殖于美国阿拉斯加州西部至不列颠哥伦比亚省西南部（Vancouver I.），以及加拿大西北部至艾伯塔省西北部。冬季分布于太平洋东岸，从加拿大西南部的不列颠哥伦比亚省至墨西哥西北部的下加利福尼亚州。","other":"在2021年，美国鸟类学会正式将其与欧亚普通鸥分离为独立物种，基于遗传学、羽毛、形态和鸣叫的差异。"},{"name":"鸥嘴噪鸥","english_name":"Gull-billed Tern","scientific_name":"Gelochelidon nilotica","overview":"鸥嘴噪鸥（英文名：Gull-billed Tern，学名：Gelochelidon nilotica），是鸻形目鸥科噪鸥属的鸟类。中等体型的浅色燕鸥。其特征为厚实的黑色喙，繁殖季节头顶黑色，其余部分羽毛非常淡。分布广泛，遍及欧洲、亚洲、西北非和美洲的温带及热带地区。繁殖期常见于内陆淡水和咸水湖泊，非繁殖期则栖息于海岸及河口地区。","appearance":"鸥嘴噪鸥体型较大，喙粗壮呈黑色，翼宽，腿长，体态健硕。繁殖季节，上体灰色，下体白色，头顶全黑；非繁殖季节，头顶白色，颈部背面有灰色杂斑，眼周有一黑色块斑。第一年幼鸟，头顶和上体有褐色杂斑。嘴和脚均为黑色。","call":"鸥嘴噪鸥的叫声独特，发出类似'ker-wik'的声音。","habits":"鸥嘴噪鸥偏好栖息在淡水湖泊、河流和沼泽地带，非繁殖期倾向于海岸及河口地区。单独或小群活动，飞行轻快灵敏，频繁在水面低空飞翔。主要以昆虫、昆虫幼虫、蜥蜴和小鱼为食，也摄食甲壳类和软体动物。","breeding":"繁殖期为5-7月，成对或小群在湖泊、河流岸边的沙地或泥地上营巢。巢甚简陋，产卵数量通常为3枚，孵化期约22-23天，幼鸟经亲鸟28-35天的喂养后即可飞翔。","identification":"鸥嘴噪鸥与其它燕鸥相比，最显著的区别在于其厚实的喙和独特的叫声。在非繁殖季节，通过眼周的黑色块斑可以辨认。","protection":"IUCN：LC（无危）","distribution":"繁殖区域遍布欧洲南部至中国东北部，中国沿海，北美东西两岸，中美洲，南美北部内陆。非繁殖期分布至全球亚热带和热带海岸线，除偏远岛屿。","other":"鸥嘴噪鸥的模式产地在埃及，历史上曾被视为Sterna属的一部分，后基于分子研究被归入Gelochelidon属。"},{"name":"澳洲鸥嘴噪鸥","english_name":"Australian Tern","scientific_name":"Gelochelidon macrotarsa","overview":"澳洲鸥嘴噪鸥（英文名：Australian Tern，学名：Gelochelidon macrotarsa），是鸻形目鸥科噪鸥属的鸟类。其体型中等，喙厚且呈黑色，整体羽色非常苍白。繁殖季节头顶黑色，腿为黑色。曾被认为是鸥嘴噪鸥的一个亚种，但现已独立成种。分布于澳大利亚内陆，繁殖于澳大利亚中南部，非繁殖季会迁至新几内亚沿海南部和帝汶岛。","appearance":"成鸟在繁殖期上体灰色，下体白色，头戴黑色帽，喙与腿均为黑色，叫声独特，呈ker-wik声。体长介于33-42厘米，翼展76-91厘米，体重150-292克。冬季时黑色帽子消失，眼周有暗斑，与弗氏燕鸥或地中海鸥相似。幼鸟面具较淡，外观与成鸟冬季羽毛类似。","call":"发出独特的ker-wik叫声。","habits":"栖息于湖泊、沼泽和海岸的多种湿地环境，如海滩、泥滩、淡水沼泽乃至湿润的田野。飞行优雅，常在池塘和沼泽上空捕食表面的无脊椎动物。偶尔与其他燕鸥混群，但更常见的是单独或成对活动。","breeding":"在湖泊、沼泽和海岸的群体中繁殖，筑巢于地面凹坑，每窝产卵2至5枚。","identification":"与弗氏燕鸥和地中海鸥相比，眼周有暗斑，幼鸟面具较淡。与其他白燕鸥不同，它不会垂直潜水捕鱼，而是以飞行中的昆虫为主食，同时也会在湿润的田野和灌木丛中捕食两栖动物和小型哺乳动物。","protection":"IUCN状态未知，未列入华盛顿公约(CITES)或中国国家重点保护野生动物名录。","distribution":"繁殖于澳大利亚内陆（除塔斯马尼亚州中南部），非繁殖期迁至新几内亚沿海南部和帝汶岛（小巽他群岛东部）。","other":"曾被视为鸥嘴噪鸥的一部分，现在确认为独立物种，其与鸥嘴噪鸥在新几内亚和印尼南部的分布界限尚不清楚。"},{"name":"红嘴巨燕鸥","english_name":"Caspian Tern","scientific_name":"Hydroprogne caspia","overview":"红嘴巨燕鸥（英文名：Caspian Tern，学名：Hydroprogne caspia），是鸻形目鸥科巨鸥属的鸟类。是全球体型最大的燕鸥种类，拥有厚重鲜红的喙，夏羽时头顶全黑，冬羽则为黑色条纹。广泛分布于北美洲、欧洲、亚洲、非洲和澳大利亚的海岸线及大型湖泊附近。","appearance":"红嘴巨燕鸥体长47-54厘米，翼展127-140厘米，体重530-782克。具有厚实血红的喙，端部颜色变化，及微叉的尾。夏羽上体淡灰，下体白色，臀部和尾白色；头部黑色帽状，延伸至眼下方，形成轻微颈背冠。幼鸟的背部有V形标记，喙呈红橙色，端部深色。成鸟的翼下初级飞羽暗灰色或黑色，形成显著暗斑。冬羽时，额部和冠部斑驳，近似灰色，不同于其他燕鸥明显的白色前额。","call":"红嘴巨燕鸥鸣叫特征明显，会发出响亮粗糙的尖叫。","habits":"红嘴巨燕鸥栖息于海岸沙滩、河口、湖泊与河流。它们在水面低空飞翔，发现猎物时垂直俯冲入水捕食。主要以鱼类为食，偶尔捕食昆虫、鸟蛋和小鸟。迁徙时，北美种群南迁至南美海岸，欧亚种群向热带迁徙，非洲和澳大利亚种群则保持居留或短距离迁移。","breeding":"繁殖期在春季到夏季，一窝产卵1-3枚，卵色蓝绿带重棕色斑点。巢筑于地面砾石或沙土中，有时位于植被中，孵化期约26-28天。雏鸟在35-45天后离巢。","identification":"与橙嘴凤头燕鸥相比，红嘴巨燕鸥体型更大，翅膀更宽，喙更深红色且较粗，腿部更长更粗，尾部仅末端四分之一处有缺口，而非一半。此外，红嘴巨燕鸥的翼下初级飞羽完全黑色，而橙嘴凤头燕鸥仅初级飞羽有暗缘。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲大湖区域、欧洲沿岸、亚洲内陆至蒙古西部、俄罗斯远东及中国东北、亚洲南部沿海、非洲西部和南部、马达加斯加、澳大利亚和新西兰。非繁殖季节分布于非洲沿海、红海、波斯湾、印度、泰国、马来半岛、越南、东太平洋和加勒比至巴拿马。","other":"2016年，红嘴巨燕鸥在阿拉斯加卡普克鲁森斯特恩国家纪念碑筑巢，比以往记录北移1000英里，这一现象与全球变暖有关。"},{"name":"橙嘴凤头燕鸥","english_name":"Royal Tern","scientific_name":"Thalasseus maximus","overview":"橙嘴凤头燕鸥（英文名：Royal Tern，学名：Thalasseus maximus），是鸻形目鸥科凤头燕鸥属的鸟类。主要分布在美洲，从北美到南美的沿海地区都有其踪迹。这种燕鸥以其橙色的喙、灰白色的羽毛和黑色的顶冠而著称，体长介于45至50厘米之间，翼展可达125至135厘米。","appearance":"橙嘴凤头燕鸥拥有长长的橙红色喙，喙尖有明显的弯钩，成年个体头部有完整的黑色顶冠，冬季时顶冠变得斑驳。上体呈淡灰色，下体白色，尾巴深叉状，腿部黑色。在繁殖季节，头顶有蓬松的黑羽，形成显著的顶冠。非繁殖季，额头和眼周变为白色，顶冠仅在后部保留黑色条纹。幼鸟与非繁殖期成鸟相似，但翼部有黑色斑点，喙色较淡，呈黄色。","call":"叫声通常为短促清晰的啸声，类似“kree”或“tsirr”，还有较长的、滚动的、悦耳的哨音。","habits":"栖息于海岸线附近的浅水区，如河口、红树林和泻湖，偶尔也会在开放水域觅食，距离岸边约100米以内。以小型鱼类为主食，包括鳀鱼、弱鱼和鼓鱼，同时也捕食昆虫、虾、蟹和海龟幼体。它们会从大约30英尺的高度俯冲入水捕食。","breeding":"在岛屿海滩或隔离的沙滩上筑巢，远离天敌。每窝产卵一至两枚，孵化期25至30天。雏鸟出生后会在巢穴停留一周左右，两周后聚集形成托儿所，由父母喂养。一个月后开始飞翔。","identification":"与美洲凤头燕鸥相比，橙嘴凤头燕鸥的喙更短直，冬季时额头更加白色。与红嘴巨燕鸥相比，橙嘴凤头燕鸥的喙颜色为橙色而非深红。","protection":"IUCN：LC（无危）","distribution":"分布于北美洲、中美洲和南美洲的沿海地区，从美国弗吉尼亚州至佛罗里达州，墨西哥湾至得克萨斯州南部，墨西哥东北部的Campeche Bank，洪都拉斯北部外海，西印度群岛，委内瑞拉北部至法属圭亚那，美国加州南部，加利福尼亚湾北部至墨西哥锡那罗亚州，以及巴西南部沿海、乌拉圭和阿根廷中东部。","other":"皇家燕鸥的分类曾有争议，现归类于Thalasseus属。西非凤头燕鸥于2021年被确认为独立物种。"},{"name":"大凤头燕鸥","english_name":"Greater Crested Tern","scientific_name":"Thalasseus bergii","overview":"大凤头燕鸥（英文名：Greater Crested Tern，学名：Thalasseus bergii），是鸻形目鸥科凤头燕鸥属的鸟类。又称凤头燕鸥或速燕鸥，体长46-49厘米，翼展125-130厘米，体重325-397克。以其优雅的外观和长长的柠檬黄色喙著称。繁殖季节头部有光泽的黑色羽冠，冬季时羽冠变为白色。分布广泛，从南非沿印度洋至太平洋和澳大利亚的热带与亚热带地区，形成密集的繁殖群落。在中国大陆，见于马祖、基隆和宜兰。","appearance":"大凤头燕鸥体态优雅，体长46-49厘米，翼展可达125-130厘米，体重介于325-397克之间。繁殖期的成鸟具有鲜明的特征：前额和下体白色，上体灰暗，喙黄色，黑色的羽冠在繁殖季节尤为显著，冬季时羽冠变为白色。幼鸟头部类似冬季成鸟，上体呈灰、棕、白相间的斑驳图案。不同亚种在上体颜色和喙的色调上有细微差异。","call":"大凤头燕鸥在繁殖地极为嘈杂，发出响亮的、嘶哑的、类似乌鸦的“kerrak”叫声。此外，还有在巢边焦虑或兴奋时发出的“korrkorrkorr”声，以及飞行中的硬朗“wep wep”声。","habits":"栖息于热带和亚热带海岸线及岛屿，偏好低洼的珊瑚、沙质或岩石岛屿。觅食于浅水区、河口、海滩和远离海岸的海域，主要以鱼为食，也会捕食鱿鱼、蟹、昆虫等。经常跟随渔船寻找丢弃的渔获。适应性强，能利用建筑物屋顶和人工岛屿作为繁殖地。","breeding":"繁殖期在5月至6月间，形成大型密集的繁殖群落，巢间距约为一米。巢穴简单，由亲鸟在沙石地上刨出浅坑构成。每窝产卵1-2枚，偶见3枚。孵化期约25-30天。雏鸟孵化后两天左右离开巢穴，约38-40天后离巢，依赖父母喂养至少四个月。","identification":"与橙嘴凤头燕鸥相比，体型更苗条，上体颜色更深，喙色偏冷黄而非橙色，且有更陡峭的颌角。与小凤头燕鸥相比，体型更大，喙更长，黄色更深。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚、大洋洲、非洲西南部、印度洋北部及周边海域，从日本南部远至东波利尼西亚，遍布印度洋沿海及波斯湾。在中国，分布于马祖、基隆、宜兰等地。","other":"在中国国家重点保护野生动物名录中列为二级保护动物（自2021年2月5日起）。"},{"name":"小凤头燕鸥","english_name":"Lesser Crested Tern","scientific_name":"Thalasseus bengalensis","appearance":"体长35至43厘米，体重185至242克，翼展88至105厘米。头顶及帽状顶羽黑色，背部均匀灰色，喙橙色至橙黄色，尖端微弯，腿脚黑色，脚蹼黄色，虹膜棕色。下体白色，比美洲凤头燕鸥或白嘴端凤头燕鸥更少呈现粉色。与白嘴端凤头燕鸥大小相似，但喙色有异；与大凤头燕鸥相似，但体型较小，喙较长较细，橙色而非暗黄色；与相似物种的区别在于臀和尾为灰色，而非白色。幼鸟腿色暗淡，次级飞羽中心暗色，翅膀上部图案较弱。","call":"发出响亮的摩擦声'kerrick'。","habits":"栖息于热带和亚热带海岸，常与大凤头燕鸥为伴，但在肯尼亚和印度海域更为远洋。在低洼的沙滩、珊瑚岛和珊瑚滩上繁殖。在海浪中觅食，远海活动。沿海迁徙，海滩休憩，经常在河口滞留。","breeding":"繁殖期在5月至6月（波斯湾）、7月至8月（利比亚）、8月（索马里）、澳大利亚东部9月至12月、北部3月至6月、西部两季。形成大型密集群落（高达2万对），在离岸岛屿、沙洲和珊瑚礁上繁殖，频繁更换繁殖地。与T. dougallii或大凤头燕鸥共栖；欧洲的流浪者与白嘴端凤头燕鸥杂交繁殖。平均密度为每平方米2.76个巢，高密度区域巢穴相连，可达每平方米9至10个。在沙或贝壳中筑浅巢。产卵1枚，偶见2枚，孵化期21至26天，有时长达30天。雏鸟绒毛极淡至几乎白色，头顶、背和翅上有黑色斑点形成细纹，下体纯白，喙橄榄黄或黑色。2至4天后离开巢穴，巢外喂食；7天后不同年龄的雏鸟形成托儿所，由成鸟保护；离巢期30至35天；亲鸟照顾至5个月大。首次繁殖年龄推测为2岁。","identification":"与Great Crested Tern的区别在于比例上更长、更橙色的喙；与白嘴端凤头燕鸥的区别在于灰色上翼；臀和尾为灰色，而非白色，是识别关键。","protection":"IUCN：LC（无危）。全球约22.5万对，半数以上在澳大利亚；南太平洋约1万对；印尼8千对；东非1万对；中东5万至6万对。利比亚种群约4000只（1993年）。","distribution":"繁殖于亚热带沿海地区，主要分布从红海至印度洋，西太平洋，澳大利亚，以及地中海南部。非繁殖季节迁徙至旧世界的亚热带和热带水域，从西北非至新几内亚。","other":"在意大利、法国、英格兰有报道纯种或与白嘴端凤头燕鸥杂交繁殖的记录。"},{"name":"中华凤头燕鸥","english_name":"Chinese Crested Tern","scientific_name":"Thalasseus bernsteini","overview":"中华凤头燕鸥（英文名：Chinese Crested Tern，学名：Thalasseus bernsteini），是鸻形目鸥科凤头燕鸥属的鸟类。又名: 黑嘴端凤头燕鸥、神话之鸟，中国沿海特有的极度濒危海鸟，长期被认为仅繁殖于福建沿海少数岛屿，近年亦在韩国近海小岛发现繁殖记录。外形酷似大凤头燕鸥但体型较小、体色更淡，初级飞羽色深，黑色头冠延伸至橙嘴基部。","appearance":"体长38–43厘米，体重240–320克，翼展94厘米。繁殖成鸟具完整黑色头冠和较蓬松的冠羽，非繁殖期额、前头及眼先白色，眼至后颈形成黑色面罩；初级飞羽黑褐色，与白色翼下形成鲜明对比。幼鸟似非繁殖期成鸟，但翼面具两条棕褐色横斑。与大凤头燕鸥相比，嘴更粗厚，嘴基具明显棱脊，橙黄色嘴端具宽阔黑色斑；背羽灰度更浅。","call":"记录稀少，叫声包括高而滚动的“keerrick”及较低哑的摩擦音。","habits":"完全栖息于沿海及外海区域。繁殖季成鸟在繁殖小岛周围约5公里范围内觅食，主食小型集群幼鱼。非繁殖期分布于中国东南沿海、泰国、砂拉越、菲律宾及北、中摩鹿加群岛（哈马黑拉、斯兰岛）。","breeding":"繁殖期5月下旬至8月下旬，在浙江韭山列岛与五峙山列岛及福建马祖列岛的小岛裸地上与大凤头燕鸥混群营巢；每巢单卵，孵化期22–28天，育雏期31–35天，幼鸟随后加入大凤头燕鸥的幼鸟群。监测巢的繁殖成功率为100%。","identification":"与大凤头燕鸥相比体型小、羽色淡，初级飞羽色深，嘴橙黑而非黄绿且嘴基无白；嘴更粗厚，嘴峰棱脊明显。与小凤头燕鸥相较，嘴色橙黄且端部具大黑斑，背羽更浅。","protection":"IUCN: CR（极危）","distribution":"繁殖区域主要位于中国东部沿海浙江和福建附近的岛屿，山东日照和青岛胶州湾是重要的换羽和育雏地。近年新增韩国西南近海小岛及台湾海峡澎湖吉山屿。非繁殖区：中国东南沿海、泰国南部、砂拉越、菲律宾及印尼哈马黑拉、斯兰岛等摩鹿加群岛。","other":"曾因标本稀少而长期失踪，2000年在马祖重新发现；2013年起浙江韭山列岛开展人工招引与栖地恢复，种群略有回升。与大凤头燕鸥存在自然杂交记录。"},{"name":"白嘴端凤头燕鸥","english_name":"Sandwich Tern","scientific_name":"Thalasseus sandvicensis","overview":"白嘴端凤头燕鸥（英文名：Sandwich Tern，学名：Thalasseus sandvicensis），是鸻形目鸥科凤头燕鸥属的鸟类。中型凤头燕鸥，繁殖羽头顶具黑色羽冠，喙黑色并具黄色端斑。全球分三亚种：旧大陆的sandvicensis、北美及加勒比海的亚种acuflavidus - Cabot's Tern及南美黄喙型的eurygnathus - Cayenne Tern。主要繁殖于欧洲、北非、北美东南沿海及加勒比离岸沙洲，冬季南下至非洲西岸、南美及南亚沿海。","appearance":"体长34–45厘米，翼展约1米，体重130–300克。繁殖羽头顶全黑，冠羽呈尖耸状；非繁殖羽前额逐渐变白，仅留黑色后冠。喙细长，黑色具鲜明黄色端斑（加勒比及南美亚种喙全黄）。翼长而尖，上翼与背均淡灰色，初级飞羽外缘色深；腰、尾洁白。脚黑色。雌雄同色，雄鸟跗跖略长。幼鸟背、翼覆羽具黑褐色鳞状斑，尾羽端斑明显，喙短粗且常缺黄端。","call":"繁殖群嘈杂，最常见为金属般的“kirrik”广告声；警戒时发短促“krit krit”；群飞时伴沙哑“ga-ga-ga”。成鸟衔鱼返巢时发出节奏清晰的“鱼叫声”，雏鸟乞食则发出尖细“pee-up”。","habits":"严格沿海，栖息温暖水域的沙洲、河口、潟湖及近海，极少涉足淡水。迁徙性，北美种群越冬至加勒比、南美北岸及秘鲁。常结成数百至上万的混合群，与橙嘴凤头燕鸥、笑鸥、粉红燕鸥等同栖。觅食多在距岸2千米内浅水，俯冲潜水捕小鱼，偶尔水面掠食。","breeding":"每年一季，北美4–6月产卵，南美10月产卵。密集群巢于裸露沙洲或珊瑚礁，巢距仅20–60厘米，每巢1–2枚卵，孵化期23–29天。雏鸟半早成，25–29天离巢，但亲鸟继续补饲数周。部分区域雏鸟形成托儿群（crèche），由少数成鸟共同看护。","identification":"是唯一具黑色喙的中型凤头燕鸥，黄端喙为关键特征。南美黄喙型易与美洲凤头燕鸥、小凤头燕鸥混淆，但后者体型更大，喙色橙红且略下弯。与体型更大的橙嘴凤头燕鸥同域时，体色更淡，喙更细长。","protection":"IUCN：LC（无危）。种群约49–64万只。","distribution":"繁殖区：欧洲自大西洋岸至里海，地中海、黑海沿岸；北美自大西洋切萨皮克湾至德州及加勒比离岸沙洲；南美自委内瑞拉到阿根廷。越冬区：非洲西岸、南亚沿海、南美东北岸及秘鲁沿海。","other":"近一百年北美大西洋种群北扩至马里兰；南美黄喙型向北扩散至维尔京群岛。曾受羽饰贸易与采蛋影响，现主要威胁为滨海栖息地侵蚀及人类干扰。"},{"name":"卡氏凤头燕鸥","english_name":"Cabot's Tern","scientific_name":"Thalasseus acuflavidus","overview":"卡氏凤头燕鸥（英文名：Cabot's Tern，学名：Thalasseus acuflavidus），是鸻形目鸥科凤头燕鸥属的鸟类。其特征显著，拥有针状黄色喙尖和黑色顶冠，分布广泛，主要见于美国东部、中东美洲、加勒比海地区、特立尼达和多巴哥以及南美洲除玻利维亚和巴拉圭之外的所有大陆国家。","appearance":"卡氏凤头燕鸥体型中等，长度介于34到45厘米之间，翼展约1米。体重因亚种而异，从170到300克不等。其特征在于黑色的顶冠、白色的体羽、浅灰色的背部，有时腹部带有淡淡的玫瑰色。尾巴叉形，白色，翅膀上部主要是淡灰色，带深色初级飞羽。腿脚全黑或带黄色足底，虹膜呈深棕色至黑色。不同亚种主要通过喙的颜色区分：指名亚种的喙黑色带黄尖，而另一个亚种的喙主要或完全黄色。","call":"卡氏凤头燕鸥的主要叫声被描述为kerr-ick，kjerr-it，keerik，kreejik，它还有多种其他叫声。","habits":"卡氏凤头燕鸥是部分迁徙的物种，冬季会离开最北端的繁殖区。它们偏爱温暖水域的海岸环境，繁殖季节栖息于沙洲、疏浚废弃物岛或低洼的沙质或珊瑚小岛。非繁殖季节则在沙滩、沙洲、海岸礁石以及沿巴拿马运河和流入咸水的河流短距离范围内活动。","breeding":"繁殖期间，卡氏凤头燕鸥在春季迁徙途中形成配对。雄鸟会在地面做出展示飞行或姿势。巢建在植被稀少或无植被的地区，由两性共同建造，通常是一窝一蛋，有时产两枚。孵化期北部约为24天，南方平均29天。雏鸟大约5天后能自我调节体温，依赖父母喂食直到离巢，通常由母亲单独照顾。","identification":"与其他凤头燕鸥属物种相比，卡氏凤头燕鸥的喙尖黄色更明显，且在非繁殖季具有白色前额和中冠。亚种T. a. eurygnathus与指名亚种主要通过喙的颜色差异来辨认。","protection":"IUCN：LC（无危）","distribution":"繁殖区主要在美国东海岸至得克萨斯州南部，加勒比地区，法属圭亚那，巴西东部和阿根廷。非繁殖区覆盖太平洋海岸从墨西哥至厄瓜多尔，大西洋海岸从佛罗里达到乌拉圭。","other":"曾独立成种，目前被视为白嘴端凤头燕鸥的一个亚种。"},{"name":"美洲凤头燕鸥","english_name":"Elegant Tern","scientific_name":"Thalasseus elegans","overview":"美洲凤头燕鸥（英文名：Elegant Tern，学名：Thalasseus elegans），是鸻形目鸥科凤头燕鸥属的鸟类。中等体型的海鸟，最显著的外部特征是拥有长而弯曲的橙色喙，以及在繁殖季节头部覆盖的黑色蓬松羽冠。分布于太平洋沿岸，从美国西南部到墨西哥，冬季迁徙至南至秘鲁、厄瓜多尔和智利。","appearance":"成年鸟体长约42厘米，体重约260克。繁殖期时，头部有黑色羽冠，背部呈蓝灰色，与深灰色的外侧初级飞羽形成对比，其余部分白色，腹部常带有粉红色调。尾部深叉状，腿黑色，有时带黄色或橙色斑点，喙长而细，颜色从淡黄色至红橙色不等，尖端常呈黄色或淡灰色。雌雄相似，但雌鸟的喙较短、较粗且更黄。幼鸟背部有棕色斑驳，上覆羽暗灰至棕色，具有鳞片状外观，下覆羽浅灰色。","call":"发出尖锐刺耳的叫声，音调下降，类似于白嘴端凤头燕鸥，但音调更高，不那么刺耳。","habits":"严格沿海栖息，常见于海滩和河口地带。以小型鱼类为食，通常从海上潜水捕食。与其他海鸟混群觅食，繁殖于非常密集的岛屿和沙滩上的巢穴。","breeding":"繁殖于海岸和岛屿上，包括墨西哥的Isla Rasa和Montague岛，偶尔在靠近海岸的大淡水湖繁殖。巢筑于地面凹坑中，产卵一至两枚。雄鸟通过向雌鸟献鱼作为求偶展示的一部分。","identification":"与橙嘴凤头燕鸥相比，体型较小，喙更细长，身体更纤瘦，腿部较短，羽冠更长且蓬松，尾部分叉更深。喙尖更透明，颜色对比更明显。冬季，面部黑色面具更宽且呈三角形。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美太平洋沿岸，包括美国加利福尼亚州西南部和墨西哥下加利福尼亚州；冬季迁徙至南至秘鲁中部的太平洋沿岸。","other":"已知在欧洲西部罕见迷鸟，曾在西班牙筑巢，并与白嘴端凤头燕鸥杂交；非洲首例记录出现在2006年南非开普敦。"},{"name":"西非凤头燕鸥","english_name":"West African Crested Tern","scientific_name":"Thalasseus albididorsalis","overview":"西非凤头燕鸥（英文名：West African Crested Tern，学名：Thalasseus albididorsalis），是鸻形目鸥科凤头燕鸥属的鸟类。近期遗传研究表明其与小凤头燕鸥关系更近，形态上与橙嘴凤头燕鸥有显著差异。","appearance":"体型大，羽毛非常淡，尾部长而分叉。繁殖季节头部有黑色冠羽和橙色喙，非繁殖季则为白色冠羽、头部后部黑色，喙黄橙色。腿和脚黑色，虹膜深褐色。","call":"鸣叫特征未知。","habits":"在开阔海洋和盐水湾上空觅食，寻找小鱼。常在海滩上休息，与其他燕鸥混群。偏好沿海区域，迁徙模式尚不明晰。","breeding":"通常在密集的群体中筑巢，每窝产一卵，巢距极近，可达每平方米6-9个巢。","identification":"与大凤头燕鸥和橙嘴凤头燕鸥有明显区别，尤其是体型更大，喙更细长，尾部更长，翼色更浅。与较少凤头燕鸥相似，但体型更大。","protection":"IUCN：LC（无危）","distribution":"繁殖于非洲西海岸，从毛里塔尼亚至几内亚。非繁殖期分布北至摩洛哥，南至纳米比亚。","other":"关于其自然历史的了解相对较少，但似乎种群稳定或增加，未面临紧迫的保护问题。"},{"name":"白额燕鸥","english_name":"Little Tern","scientific_name":"Sternula albifrons","overview":"白额燕鸥（英文名：Little Tern，学名：Sternula albifrons），是鸻形目鸥科小燕鸥属的鸟类。体型最小的燕鸥之一，繁殖时具黑色顶冠与白色额斑，黑尖黄喙。分布遍及欧洲、亚洲、非洲及大洋洲的沿海与内陆水域，常集群在沙滩、河石或盐沼繁殖。","appearance":"体长22–28厘米，体重47–63克，翼展47–55厘米。繁殖羽：额白色呈倒“V”形，头顶及眼先黑色；背、翼灰色，腰及下体白色；喙鲜黄色，端部黑色；腿橙黄至黄色。非繁殖羽：额部杂白，眼先白且具黑色点斑，喙、腿转为黑褐色。幼鸟上体具黑色V形斑，次级飞羽及内侧初级飞羽色淡，与深色覆羽及外侧初级飞羽形成对比。五个亚种差异甚微，主要在外侧三枚初级飞羽羽轴颜色及rump色。","call":"常见叫声为刺耳的“kriet”；警戒或炫耀时发出连续的“kerre-kiet kerre-kiet…”。雏鸟乞食时发出轻柔的“plee”或“plee-we”。","habits":"栖息于亚热带至温带沿海、河口、湖泊及水库，最高记录至海拔2000米。迁徙：古北界种群多为候鸟，冬季南迁至非洲、阿拉伯海、东南亚及澳大利亚沿海；部分澳洲种群仅在境内移动。觅食：在水面上方低空来回巡飞，长时间悬停后垂直俯冲入浅水捕食，常成群同步潜水；亦可在空中掠取水面或植被上的昆虫。食物以小至中型鱼类、甲壳类、昆虫、环节动物及软体动物为主。","breeding":"繁殖期因地而异：欧洲及印度5–6月，斯里兰卡5–8月，西非3–7月，澳大利亚温带种群春夏季，热带种群几乎全年可繁殖。通常在海、湖、河边的裸露砂砾地、盐沼或人工盐池营巢，植被覆盖率需低于15%，偶见在浮标、屋顶等漂浮物或建筑物上筑巢。每巢2–3枚卵（1–4枚），孵化21–24天，雏鸟绒羽灰白具黑斑，日龄雏鸟可辨识亲鸟声，日喂哺可达63次，20–24日龄可飞。平均首次繁殖年龄3岁，记录寿命21年。","identification":"与桑氏白额燕鸥的区别：白额延伸至眼后，初级飞羽黑色部分更少，腿色更鲜黄。与眼斑燕鸥的区别：眼先黑色（非白色）且喙具黑尖；杂交个体眼先黑色仅达基部、黑尖极小。冬季成鸟易与普通燕鸥混淆，可通过肩至翼尖的黑色条纹辨识。与同属其他小型燕鸥相比，体形更小，飞行时翼拍急促。","protection":"IUCN: LC（无危）。全球未精确统计，估计19–41万只；欧洲种群3.6–5.3万对，近年西欧种群因海岸开发、人类干扰、捕食及巢区淹没等因素明显下降。","distribution":"繁殖：欧洲至西亚（至阿富汗）、北非大西洋及地中海沿岸、波斯湾岛屿、西非加纳至加蓬及尼日尔河流域、斯里兰卡、东南亚、中国东部、日本、菲律宾、北澳大利亚及东澳大利亚、塔斯马尼亚；近年拓殖密克罗尼西亚（塞班）及夏威夷。非繁殖：非洲沿岸、红海、阿拉伯海、印度西部、马来西亚、菲律宾、印尼、新几内亚、澳大利亚沿海及新西兰（少量越冬）。","other":"与眼斑燕鸥在南澳大利亚有自然杂交记录，提示两物种亲缘关系较近。部分文献将小白额燕鸥及桑氏白额燕鸥视为本种亚种。"},{"name":"桑氏白额燕鸥","english_name":"Saunders's Tern","scientific_name":"Sternula saundersi","overview":"桑氏白额燕鸥（英文名：Saunders's Tern，学名：Sternula saundersi），是鸻形目鸥科小燕鸥属的鸟类。有时称为黑羽轴燕鸥。分布于北印度洋沿岸，包括南部索马里、阿拉伯半岛、索科特拉岛、巴基斯坦、安达曼和尼科巴群岛以及斯里兰卡北部。与白额燕鸥关系密切，非繁殖期几乎无法区分。","appearance":"体型细小，约20至28厘米长，体重40至45克，翼展50至55厘米。具有白色身躯，黑色尖端的黄色喙，以及带有白色前额斑的黑色头帽。繁殖期时，前额斑呈方形，边缘直，黑色外侧初级飞羽较多，腿和脚呈暗橄榄黄色，区别于白额燕鸥的鲜黄色腿。","call":"叫声为双音节，比白额燕鸥的叫声更强，略似普通燕鸥。","habits":"栖息于海岸、河口和潮汐泻湖，罕见于内陆。以小型鱼类、甲壳类、软体动物及各类昆虫为食。主要通过垂直潜水觅食，通常在长时间盘旋后进行。","breeding":"繁殖季节始于5月，如巴基斯坦的卡拉奇和斯里兰卡，红海地区自4月开始。形成小型稀疏群落，巢距20至100米。巢建于高于高潮线的沙丘上或泥滩上，通常由风刮起的小沙丘围绕。巢穴为凹坑或动物足迹，可能铺有贝壳碎片和小石子。产2枚淡色蛋。","identification":"与白额燕鸥非常相似，但可通过繁殖期的方形前额斑、较暗的腿和脚颜色以及更多黑色外侧初级飞羽来区分。","protection":"IUCN：LC（无危）。全球种群数量未知，阿拉伯半岛繁殖种群约4000对。","distribution":"繁殖于红海岛屿、波斯湾沿岸、索马里南部、索科特拉岛、巴基斯坦沿海、印度西北部、亚当桥岛（印度与斯里兰卡间）、斯里兰卡北部。非繁殖期分布至坦桑尼亚沿海、塞舌尔群岛、马达加斯加、查戈斯群岛和马尔代夫。","other":"曾被认为是白额燕鸥的一个亚种或同种异名。"},{"name":"小白额燕鸥","english_name":"Least Tern","scientific_name":"Sternula antillarum","overview":"小白额燕鸥（英文名：Least Tern，学名：Sternula antillarum），是鸻形目鸥科小燕鸥属的鸟类。广泛分布在北美洲及南美洲局部地区。世界上最小的燕鸥之一，与旧大陆的白额燕鸥关系密切，也曾被认为与之同种。以快速的翅膀拍打和独特的海滩活动著称。","appearance":"小白额燕鸥体长约21至23厘米，翼展48至53厘米。繁殖期成鸟头部黑白分明，黑帽和眼线与白色前额形成鲜明对比，非繁殖期和幼鸟则呈黑喙、暗颈背和肩部暗斑，但仍可通过其体型和快速的翅膀拍打识别。雄雌相似，仅雄鸟的暗眉纹可能更宽。成鸟背部灰，腹部白，外侧两至四根初级飞羽黑色，喙尖黄色或橙色，冬季转暗。幼鸟背部有深U或V形标记，翅下灰至黄褐色。喙、腿黄色，冬季转暗。","call":"小白额燕鸥发出尖锐高亢的叫声。","habits":"小白额燕鸥栖息于海岸沙滩、河流和湖泊边，偏好沙质或砾石地面。它们在内陆和沿海水域觅食，以鱼类和其他小型水生生物为食，常在水面低空飞行并俯冲捕鱼。迁徙期间，会前往中美洲、加勒比海和南美洲北部。","breeding":"繁殖季节始于4月末，巢筑于近水的沙或砾石上，通常每窝产卵2至3枚。孵化期约三周，双亲共同育雏。雏鸟四周大即可飞行。","identification":"小白额燕鸥与白额燕鸥在基本和亚成鸟羽衣中通过体型大小区分。白额燕鸥臀部和中央尾羽白色或淡灰色，而小白额燕鸥的臀部和尾羽颜色与背部一致。叫声也有差异。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布北美大平原至德克萨斯州和路易斯安那州北部，加州中部至墨西哥西部，北纬墨西哥湾沿岸至尼加拉瓜，大西洋海岸从缅因州至佛罗里达州，墨西哥湾和加勒比海地区。非繁殖区位于南美北部海岸。","other":"存在五个相似的亚种，包括广泛分布的antillarum、加州的browni、内陆的athalassos，以及墨西哥的mexicana和staebleri。"},{"name":"南美白额燕鸥","english_name":"Yellow-billed Tern","scientific_name":"Sternula superciliaris","overview":"南美白额燕鸥（英文名：Yellow-billed Tern，学名：Sternula superciliaris），是鸻形目鸥科小燕鸥属的小型燕鸥。在南美洲的大型河流与湖泊边广泛分布，以其黄色的喙和额头上的白色斑块而闻名。","appearance":"体长约23厘米，体重介于40至57克之间。具有结实的黄色喙，喙端无黑色尖端。繁殖季节时，头部有广泛的黑色冠羽和一个小的白色前额斑点。非繁殖季节，头部主要为白色，带有深色面罩。亚成鸟的喙为黄色带暗褐色尖端，上颌基部暗色，冠羽灰褐色带黑色条纹。幼鸟的前额、眉纹和冠羽呈赭色，有深色条纹和深色耳侧区；上体灰褐色，有淡色斑点，每根羽毛有深色亚端斑点；有暗色腕带。","call":"叫声包括短促鼻音的'kuk'声和略长些的沙哑'rreh'声，通常以松散的系列重复。互动时，会发出一系列更急促的三音节音符，'chee-chee-chew'。","habits":"栖息于宽阔的河流边，主要在河岸沙滩和湖边筑巢，常与黑燕鸥和大嘴燕鸥混群。觅食时，主要在大型河流的浅滩上空盘旋，常聚集在支流入口处。在巴西，主要沿内陆河流和湖泊繁殖，偶尔在海岸河口繁殖；在阿根廷沿乌拉圭河、巴拉那河和皮尔科马约河至布宜诺斯艾利斯东北部繁殖；在乌拉圭常见于湖泊和河流，沿海岸线较少见。非繁殖季节，主要出现在海岸和河口，也在各种水体中，从稻田到咸水泻湖。","breeding":"繁殖时间在11月（苏里南）、12月（乌拉圭）、7月（秘鲁），取决于旱季河流沙滩的暴露。每群最多20对，更常见的是3-10对，巢间距宽，常超过50米，经常单独筑巢。每窝产2-3枚卵，平均1.94枚。生产力为1.04/巢，洪水是卵损失的主要原因。","identification":"与小白额燕鸥的区别在于喙的形状和颜色，以及翅膀上更广泛的暗色部分。亚成鸟和幼鸟的特征也与最小燕鸥不同，尤其是喙的颜色和腕部的暗色带。","protection":"IUCN：LC（无危）","distribution":"主要分布在南美洲的大型河流区域，从秘鲁东北部、哥伦比亚北部和中部、委内瑞拉北部、圭亚那地区延伸至阿根廷东部。在非繁殖季节，它们也可能出现在海岸、河口和各种水体中。","other":"其迁徙模式主要沿着河流谷地到达海岸，非繁殖个体在那里聚集。太平洋海岸的记录极为罕见。"},{"name":"秘鲁燕鸥","english_name":"Peruvian Tern","scientific_name":"Sternula lorata","overview":"秘鲁燕鸥（英文名：Peruvian Tern，学名：Sternula lorata），是鸻形目鸥科小燕鸥属的鸟类。小型燕鸥，体长约24厘米，头部上半部和颈部呈黑色，其余部分白色，背部、翅膀和尾巴灰褐色。分布于南美洲热带西海岸，从厄瓜多尔中部至智利北部，栖息于热沙漠、沙滩和沿海盐湖。全球数量估计约1000-2500个个体，正面临因栖息地丧失导致的数量下降。","appearance":"秘鲁燕鸥体型非常小，全长约24厘米。头部上半部和颈部为黑色，其余部分白色。背部、翅膀和尾巴呈灰色，喉部、下巴和胸部白色，腹部和两肋淡灰色。下尾羽覆羽白色。喙黄色，尖端黑色，虹膜棕色，腿黄色。下体的淡灰色区分其与其它小型燕鸥。飞行时翼拍迅速而具特色。叫声尖锐的'kik'声和刺耳的'gree'声，也会发出一系列降调的'kee-ee-eer'音符。","call":"秘鲁燕鸥的叫声包括尖锐的'kik'声和刺耳的'gree'声，以及一系列降调的'kee-ee-eer'音符。","habits":"秘鲁燕鸥栖息于南美西岸的热沙漠、沙滩和沿海盐湖，以小型鱼类为主食，尤其是秘鲁鳀鱼（Engraulis ringens）。它们在秋季返回繁殖地，非繁殖季节的迁徙模式未知，可能在近海区域分散活动。在El Niño年份，它们可能长时间远离海岸，停留在海上。","breeding":"繁殖期在8月至次年2月，主要集中在10月至1月。巢点散布在松散的群体中，最多可达25对。通常靠近海岸湿地和咸水湖觅食。巢筑于离高潮线一至两百米的海滩和沙丘上，或在一公里以上的内陆沙地上。每窝产卵1-2枚，蛋和雏鸟都有良好的伪装以躲避天敌。繁殖后，鸟类会离开海岸，可能向海迁移。在El Niño年份，它们不会尝试繁殖，可能一直留在海上。","identification":"秘鲁燕鸥可通过其非常小的体型、快速而深沉的翼拍和独特的淡灰色下体与其它燕鸥区分。幼鸟有宽大的暗褐色面部面具，从眼周延伸至耳羽覆盖，下体淡褐色，背部有明显的黑色V字形标记。","protection":"IUCN：EN（濒危）","distribution":"秘鲁燕鸥分布于南美西岸，从厄瓜多尔中部至智利北部。在厄瓜多尔、秘鲁和智利均有确认的繁殖地，特别是在秘鲁的Pacasmayo、Paraíso、Puerto Viejo、Pampa Lechuzas和Yanyarina，以及智利的Mejillones半岛附近。","other":"秘鲁燕鸥面临的主要威胁包括栖息地丧失、休闲活动、渔民和游客的越野驾驶、湿地污染、农业用地扩张、湿地水位管理不当、野猫和狗的存在，以及石油勘探。"},{"name":"眼斑燕鸥","english_name":"Fairy Tern","scientific_name":"Sternula nereis","overview":"眼斑燕鸥（英文名：Fairy Tern，学名：Sternula nereis），是鸻形目鸥科小燕鸥属的鸟类。小型燕鸥。这种小型沿海燕鸥以沙滩筑巢，对干扰极为敏感。分布于西南太平洋地区，包括澳大利亚东南部、新西兰北岛北部和新喀里多尼亚。其显著特征为黄色喙（在南部澳大利亚缺乏黑色尖端）和橙黄色腿脚。","appearance":"眼斑燕鸥体长约25厘米，翼展45-51厘米。额头与眼圈白色，未延伸至眼后；头顶和颈背黑色，延伸形成眼后暗斑；上体与翅膀上覆羽淡灰色，臀部颜色更浅；尾叉淡灰色，内侧羽毛白色；颈项与下体白色；喙亮黄色，通常无黑色尖端；腿脚橙色至橙黄色。非繁殖季时，喙颜色更暗，头部有白色条纹覆盖，颈背有宽黑带。","call":"发出尖锐响亮的“tchi-wick”声，兴奋时会发出急促的“kirrikiki-kirrikiki”和快速的“ket-ket-ket-ket”。","habits":"栖息于海岸线，偶尔内陆。主要在海湾和河口觅食，偶尔在浪花外活动。以小型鱼类为主食，亦捕食软体动物和甲壳类。通过低飞掠过水面并俯冲捕捉猎物。","breeding":"繁殖季节在澳大利亚为9月至次年1月，新西兰则从9月开始至次年1月。巢建于沙滩或珊瑚岛上，常单独或分散筑巢，巢间距可达20米。每窝产1-2枚卵，平均孵化期20-25天，幼鸟孵化后依赖父母喂养直至约50天。","identification":"与白额燕鸥相似，但体型更圆润，喙更深，腿更短。眼斑燕鸥喙全黄，眼后有黑斑与喙之间有空隙（白额燕鸥繁殖期黑斑延伸至喙）。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于澳大利亚西部至东南部，新西兰北岛北部，以及新喀里多尼亚。非繁殖期间，部分群体向北迁移至西北澳大利亚。","other":"新西兰亚种（ davisae）极度濒危，仅存于四个繁殖地点，受军区保护的帕帕卡努伊沙嘴为其一。"},{"name":"西非燕鸥","english_name":"Damara Tern","scientific_name":"Sternula balaenarum","overview":"西非燕鸥（英文名：Damara Tern，学名：Sternula balaenarum），是鸻形目鸥科小燕鸥属的鸟类。以黑色头冠、浅灰色背部和独特的飞行姿态著称。繁殖季节中，主要分布于非洲南部沿海地带，包括安哥拉南部、纳米比亚和南非。非繁殖期会迁徙至加纳等热带非洲海岸。","appearance":"这种燕鸥长约23厘米，重约46克，翼展可达51厘米。成鸟在繁殖季节具有全黑的头盖和喙，非繁殖期前额转白，头顶斑驳灰黑。幼鸟具淡褐色顶冠，眼带深色，颈部亦有深色条纹，翼羽灰，翼覆羽棕色带暗边。冬季成鸟与非繁殖期成鸟相似，但初级飞羽更暗，有模糊的腕斑。","call":"其鸣声尖锐高亢，常发出‘tsit-tsit’的叫声，另有急促刺耳的‘kid-ick’或‘rrreekikkik’叫声。","habits":"偏好栖息在干旱沙漠地区的海岸线，尤其在有海湾、河口、泻湖和礁石的地带。主要食物为小鱼和少量鱿鱼，通过悬停后俯冲潜水捕食。在高风速下，捕食成功率提高，总潜水率下降。","breeding":"繁殖期为晚秋至早春，通常一窝仅产一枚卵，偶见两枚，孵化期18-22天。雏鸟孵化后几天便离开巢穴，向岸边移动，20天后离巢，依赖成鸟喂养长达两个半月。","identification":"与小燕鸥相比，西非燕鸥的背部、臀部和尾巴颜色一致，均为浅灰色，而小燕鸥的臀部和尾巴颜色较淡。","protection":"IUCN：LC（无危）","distribution":"繁殖于安哥拉南部沿海至南非，非繁殖期迁徙至加纳。部分个体全年留驻纳米比亚海岸。"},{"name":"白腰燕鸥","english_name":"Aleutian Tern","scientific_name":"Onychoprion aleuticus","overview":"白腰燕鸥（英文名：Aleutian Tern，学名：Onychoprion aleuticus），是鸻形目鸥科褐背燕鸥属的鸟类。优雅的海鸟，以深灰色的羽毛、黑色的头冠和雪白的前额为显著特征。喙和腿均为黑色。幼鸟在夏末短暂时期披上黄褐色调的羽毛。分布于阿拉斯加海岸和亚洲东北部，繁殖后迁往东南亚热带水域，确切越冬范围尚不完全清楚。叫声柔和颤动，与同类燕鸥尖锐刺耳的鸣叫形成鲜明对比。","appearance":"中等体型的燕鸥，比北极燕鸥略大，长度约32.0至38.4厘米，翼展75至80厘米，体重介于83.4至140克之间。繁殖期成鸟头部为黑色，额头为白色，背部和翅膀为灰中带暗，腹部呈暗灰色，臀部和尾巴为白色。翼下白色，带有黑色翼尖，最显著的特征是次级飞羽上的暗色条纹。喙和腿为黑色。非繁殖期成鸟的特征不甚明了，但与繁殖期相似，只是下体白色，头顶有白色斑点，肩羽有白色边缘，尾巴为灰色，两侧白色。幼鸟具有白色的颈圈和宽大的额头，下体白色，尾部灰色，尾羽外缘白色。","call":"发出一系列轻柔的哨声，与其它燕鸥种类的尖锐叫声明显不同。","habits":"白腰燕鸥在阿拉斯加和俄罗斯东岸的海岸线繁殖，冬季迁徙至东南亚热带海域。它们偏好在部分植被覆盖的沙滩、草地、苔藓沼泽和湿地筑巢，通常位于孤立的岩石岛屿或沿岸地带，靠近河口。在非繁殖季节，它们成为海洋性鸟类。","breeding":"繁殖期为6月至7月，成对或成群在海岛、河流或湖泊岸边营巢。巢通常位于水边的沙滩或沙石地上，内铺枯草等植物材料。每窝产卵2至3枚，卵为橄榄褐色或橄榄黄色，上有黑褐色或黑色斑点，大小约为40至47×28至32毫米。孵化期大约17天，由雌雄双方共同承担。","identification":"白腰燕鸥与北极燕鸥的区别在于其独特的白色额头，以及更暗的羽毛色彩。叫声也更为柔和。与普通燕鸥相比，白腰燕鸥的尾部外缘为白色，翼前缘较宽，背部和尾覆羽颜色更深，尤其是背部羽毛边缘呈宽幅黄褐色，额头、头顶、颈后和胸侧有棕色色调。","protection":"IUCN：VU（易危）","distribution":"繁殖于欧亚大陆北部太平洋海岸线，从库页岛、鄂霍次克海、堪察加半岛至阿留申群岛，西至阿拉斯加西南部。非繁殖期迁徙至泰国沿海、菲律宾、新几内亚北部、印度尼西亚、马来西亚南部、新加坡，以及澳大利亚中东部的新南威尔士州北部。迁徙路线沿太平洋海岸，经日本北部、朝鲜半岛、中国东部和台湾。","other":"白腰燕鸥的迁徙模式独特，是唯一一种在亚北极繁殖区和南太平洋热带越冬区之间迁徙的物种。"},{"name":"灰背燕鸥","english_name":"Spectacled Tern","scientific_name":"Onychoprion lunatus","overview":"灰背燕鸥（英文名：Spectacled Tern，学名：Onychoprion lunatus），是鸻形目鸥科褐背燕鸥属的鸟类。中等体型的热带太平洋海鸟。其背部呈灰色，而非黑色，额部有一白色月牙状斑纹延伸至眼后，形成独特的“眼镜”外观。分布于太平洋热带岛屿，包括西北夏威夷群岛、土阿莫土群岛、社会群岛等地。","appearance":"灰背燕鸥体长35-38厘米，翼展73-76厘米，体重95-145克。成年繁殖羽色的背部为板岩灰色，头部具黑色帽状斑块，额部有半月形白纹，眼上眉纹白色，眼线下方为黑色。翅膀和尾羽比背部颜色更深，尾羽深叉。非繁殖季节，头部的黑色斑块和眼线变得斑驳。幼鸟背部鳞片状，头部图案模糊，尾羽较短。","habits":"灰背燕鸥栖息于热带岛屿地面或峭壁上，极少在陆地上被观察到。它们在海上飞行，具有短翼和向上倾斜的翅膀及尾羽姿态。以海洋鱼类、甲壳类为食，采取潜水的方式捕食。迁徙模式未知，但部分种群会南迁。","breeding":"灰背燕鸥在热带太平洋岛屿上筑巢繁殖，具体繁殖行为、巢穴建设、孵化及育雏过程尚待详细研究。","identification":"与乌燕鸥相比，灰背燕鸥背部颜色更浅，额头白色斑纹更宽，眼上眉纹延伸至眼后。与其它近似种如褐翅燕鸥、白腰燕鸥在羽色和分布上存在差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于太平洋热带区域，包括西北夏威夷群岛、土阿莫土群岛、社会群岛、凤凰群岛、马里亚纳群岛、美属萨摩亚等地。非繁殖季节分散至美拉尼西亚东北部、波利尼西亚西南部及远东地区。"},{"name":"褐翅燕鸥","english_name":"Bridled Tern","scientific_name":"Onychoprion anaethetus","overview":"褐翅燕鸥（英文名：Bridled Tern，学名：Onychoprion anaethetus），是鸻形目鸥科褐背燕鸥属的鸟类。最显著的特征是灰色的背部、黑色的头盖和白色的前额，以及一条引人注目的颈环。全球热带海域均有分布，繁殖于岩石岛屿上，冬季迁徙至更广泛的热带海洋。","appearance":"体长约30-32厘米，翼展77-81厘米，重110-180克。成鸟有灰色的上体，白色的下体，额头和眉毛白色，颈后有一圈醒目的白色颈环。喙、腿和脚均为黑色。幼鸟上体鳞状灰暗，下体较淡。两性相似。","call":"叫声似“wep-wep”，警戒时发出沙哑的“kee-errr-krr”声。","habits":"主要栖息于开阔海域，仅在恶劣天气或繁殖季节接近陆地或岛屿。飞行轻盈有力，以俯冲潜水的方式捕鱼，偶尔低飞掠过海面。晚上常栖息在船只桅杆上。","breeding":"繁殖期为5-6月，集群在岩石岛屿上筑巢繁殖。巢建于地面或洞穴中，每窝产卵1-2枚，多为2枚，孵化期约28-30天。","identification":"与乌燕鸥相似，但背部颜色较淡，尾部白边更宽，飞羽下表面颜色较浅。与灰背燕鸥相比，颜色更为淡灰。","protection":"IUCN：LC（无危）","distribution":"广泛分布于热带和亚热带岛屿，大多靠近大陆（除波利尼西亚东部、夏威夷群岛和其他偏远岛屿）。","other":"迁徙和分散性物种，冬季分布更广泛于热带海洋。"},{"name":"乌燕鸥","english_name":"Sooty Tern","scientific_name":"Onychoprion fuscatus","overview":"乌燕鸥（英文名：Sooty Tern，学名：Onychoprion fuscatus），是鸻形目鸥科褐背燕鸥属的鸟类。广泛分布于全球热带海域的中型海鸟。其显著特征为通体黑褐色，前额具白色斑块，尾部深叉。乌燕鸥几乎终生在海上活动，仅在繁殖期登陆偏远的珊瑚岛或沙洲。其种群数量庞大，估计全球有6000万至8000万只，但局部地区因人类干扰、栖息地破坏和外来捕食者而减少。","appearance":"乌燕鸥体长36–45厘米，翼展82–94厘米，体重约200克。成鸟繁殖羽通体黑褐色，头顶至背部黑色，前额有白色斑，腹部白色，尾羽深叉，外侧尾羽具白缘。非繁殖羽与繁殖羽相似，但头部羽毛具白缘。幼鸟通体烟褐色，具白色或棕色斑点，腹部灰色。雌雄外形相似，雄鸟略大。","call":"乌燕鸥在繁殖群中极为喧闹，昼夜均可发出叫声。最典型的叫声为“wideawake”声，常用于配偶或亲鸟与幼鸟之间的联系，声音响亮且重复。其他叫声包括警告声“wup”、求偶时的“chuckle”及群体鸣叫“yah-yah-yah”等。叫声在群体中具有识别和定位功能。","habits":"乌燕鸥是典型的热带海洋性鸟类，常年栖息于热带和亚热带海域，极少靠近陆地。非繁殖期几乎完全在空中活动，甚至可在飞行中入眠。觅食方式主要为“点水式”捕食，从空中掠过水面捕捉小鱼或头足类，常随金枪鱼等掠食性鱼类活动。觅食范围通常距离繁殖地不超过80公里。","breeding":"乌燕鸥在热带偏远岛屿上繁殖，繁殖期因地区而异，通常为每年一次。集群繁殖，密度极高，每对产卵一枚，卵产于沙地或稀疏植被中，无巢结构。孵化期约28–30天，由双亲轮流孵化。幼鸟约8–10周后可飞行，但仍依赖亲鸟喂食数周。首次繁殖年龄为4–10年。","identification":"乌燕鸥与同属的褐翅燕鸥和灰背燕鸥相似，但乌燕鸥背部颜色更深，腹部无灰色胸带，尾羽白缘较窄，飞行时翼下覆羽为白色，初级飞羽为黑色。幼鸟与成鸟差异明显，通体烟褐色，具白色斑点。","protection":"IUCN: LC（无危）","distribution":"乌燕鸥繁殖于全球热带海域的岛屿，包括加勒比海、夏威夷群岛、印度洋、西太平洋和中太平洋的珊瑚岛。非繁殖期则广泛分布于热带洋面，偶因风暴被带至温带地区。中国南海诸岛亦有分布记录。","other":"乌燕鸥被认为是世界上数量最多的热带海鸟之一。其英文名“Wideawake”源于其繁殖群中持续不断的叫声。该鸟种曾被归入Sterna属，后基于分子系统学研究移至Onychoprion属。"},{"name":"黄嘴河燕鸥","english_name":"River Tern","scientific_name":"Sterna aurantia","overview":"黄嘴河燕鸥（英文名：River Tern，学名：Sterna aurantia），是鸻形目鸥科燕鸥属的鸟类。直译: 河燕鸥，中型燕鸥，以其独特的黄嘴和红色腿著称。广泛分布于南亚和东南亚内陆河流，主要在巴基斯坦东部至印度南部，向东至尼泊尔、中国云南省、湄公河三角洲（越南南部）。繁殖季节主要在干燥季节，即2月至5月。","appearance":"成鸟具有黑色冠羽和深叉状尾巴，暗灰色背部，腹部白色。喙粗壮，亮黄色，虹膜深棕色，腿红色。非繁殖期成鸟额头和前冠白色，眼周有黑色斑点；喙呈暗黄色，尖端灰暗。幼鸟背部灰色，斑驳的白色斑点，头部和背部有明显的黑色箭头标记；额头和宽眼线白色；喙淡赭色。首次换羽的个体与成鸟相似，但冠部有少量白色羽毛，尾流稍短。","call":"鸣叫包括强调的弹性的下滑音“kyEEer”和短促的嘶哑声“krree”。兴奋时，会重复发出滚动的双音节“keerrr-wick”。","habits":"主要栖息于淡水湖泊和河流中的沙岛，偶尔出现在河口，避免大陆地点。主要食物为鱼、小甲壳类和昆虫，通过俯冲潜水捕食。在兴奋时，会发出一系列的叫声以示警。","breeding":"繁殖期主要在2月至5月，但极端日期可延至11月至6月。在沙地上筑巢，通常每窝产3枚蛋，孵化期约18-19天，幼鸟独立于3周后离巢。一些个体在1岁时开始繁殖。","identification":"与黑腹燕鸥相比，黄嘴河燕鸥体型更大，下体全白。幼鸟头部棕色，背部有棕色标记，两侧灰色，下体白色。","protection":"IUCN：VU（易危）。在中国，黄嘴河燕鸥的保护级别由Ⅱ级调整为I级（2021.02.05）。全球数量估计在50,000至100,000之间，主要集中在印度。","distribution":"主要分布在巴基斯坦东部至印度南部，向东至尼泊尔、中国云南省、湄公河三角洲（越南南部）。在伊朗和阿富汗也有记录到流浪个体。","other":"黄嘴河燕鸥的种群数量因栖息地污染而减少。"},{"name":"粉红燕鸥","english_name":"Roseate Tern","scientific_name":"Sterna dougallii","overview":"粉红燕鸥（英文名：Roseate Tern，学名：Sterna dougallii），是鸻形目鸥科燕鸥属的鸟类。中型海鸟，因其腹部淡粉色而闻名。分布于温带至热带的全球各大洋，包括大西洋、印度洋和太平洋。体长约33-41厘米，尾叉长且优美，喙色随季节和地理位置变化。在东北部繁殖区，繁殖羽喙由黑转红，而在加勒比海，喙全年大部分时间呈橙红色。","appearance":"粉红燕鸥是一种中等体型的白色燕鸥，体长33-41厘米，翼展72-80厘米，尾叉极长。繁殖羽为几乎无瑕的白色，头顶至颈背有深黑色帽状羽毛，翅膀和背部为淡灰色，最外2-4根初级飞羽上翼显得较黑，有长长的白色尾流线。下体白色，春季时胸部和腹部带有淡淡的奶油粉色。非繁殖羽中，黑色帽状羽毛变为眼后至颈背的黑色面具，前额白色，后冠有淡色条纹，下体白色，尾部较短。幼鸟上体有黑色和棕色月牙纹，下体有复杂的图案，类似卡博特燕鸥。","call":"粉红燕鸥的叫声为独特的高音双音节飞行叫声，‘chi-vik’或‘ki-rik’，在东北部和加勒比海种群中均可辨认，声音清晰，即使在混群中也能轻易区分。","habits":"粉红燕鸥主要栖息于海岸、岩礁、海中岛屿和开阔的海洋上，偏好成群活动。它们在水边浅水处或频繁地在水面上方飞翔搜寻食物，冬季多在开阔的海洋活动。主要以小鱼为食，通过水面捕食或潜水捕食，也会抢夺其他鸥类的食物。","breeding":"繁殖期为4-7月，常成群在海岛、岩礁、珊瑚礁和海滨沙滩或草地上营巢。巢甚简陋，通常为地面凹坑，有时垫有少许海草。每窝产卵2枚，偶见1或3枚，孵化期21-26天。雌雄轮流孵卵。","identification":"与普通燕鸥相比，粉红燕鸥翅膀更白，胸纯白色，翅膀上的黑色部分仅限于最外侧的3个初级飞羽。在所有羽毛中，翅膀下的羽毛全白，没有黑色边缘。飞行时，腿和脚在繁殖季节为橙红色，冬季变黑或暗红色。","protection":"IUCN：LC（无危）","distribution":"分布于温带至热带的全球各大洋，包括大西洋、印度洋和太平洋西部至瓦努阿图。在北美和欧洲的大西洋沿岸繁殖，冬季南下至加勒比海和西非。","other":"粉红燕鸥的生态和行为上与‘冠状’燕鸥属的物种更为接近，尤其是优雅燕鸥、三明治燕鸥和卡博特燕鸥。然而，遗传研究表明，粉红燕鸥与‘冠状’燕鸥的关系较为遥远。"},{"name":"澳洲燕鸥","english_name":"White-fronted Tern","scientific_name":"Sterna striata","overview":"澳洲燕鸥（英文名：White-fronted Tern，学名：Sterna striata），是鸻形目鸥科燕鸥属的鸟类。由Johann Friedrich Gmelin于1789年首次描述。中等体型，拥有白色身体和翼下，翼上呈灰色调，叉状尾巴显著。繁殖期头部黑色帽状羽毛覆盖至颈背，仅留一小段白色条纹与黑色喙相接。在新西兰极为常见，沿岸线和众多小岛广泛分布。","appearance":"体长39–42厘米，体重103–160克。头部黑色冠羽与狭窄白色前额相连；背部淡灰色，包括长尾，超出折叠翼尖；腹部白色，有时胸部略带粉色或锈色；虹膜棕色；喙黑色；腿深褐色。非繁殖期成鸟前额白色扩展，冠羽具白点，眼前方有黑斑；与非繁殖期相似。幼鸟类似非繁殖期成鸟，但冠羽有白色条纹，翅膀覆羽具独特浅棕色斑驳。刚离巢幼鸟背部和翅膀覆羽有细小黑色人字纹，翼端黑色，内前翼有大黑色三角斑块。","call":"主要叫声为尖锐的‘siet’；防御巢穴时发出粗糙的‘keark’或‘keeahk’。","habits":"栖息于海岸带，筑巢于岩石或沙滩、河中砾石岛、海岸悬崖及废弃驳船上，常靠近浪花区。冬季部分个体向北迁移至澳大利亚东南部。几乎完全以鱼为食，也吃虾。常在浪花区或数公里外海面捕食，常群居。潜水捕食，从7–10米高空垂直下潜，有时悬停后再下潜；亦通过接触式啄食。常遭贼鸥攻击。冬季风暴导致成鸟高死亡率。","breeding":"繁殖期为10月至12月。多数群体含100–500对，但边缘地带报告有单独对。部分群体多年稳定，但贝斯海峡岛屿（incerta）群体位置年年变化。筑巢于沙地或小石堆中，有时用大量植物茎构建较大巢。产卵1–2枚，平均1.54枚（塔斯马尼亚数据），颜色高度变化以匹配基质，间隔2–3天产出，平均尺寸46.9毫米×33.4毫米；孵化期约24天；雏鸟白色至棕色，有斑点；孵化后4–6天内被亲鸟保护，随后可能形成托儿所；离巢时间29–35天；依赖亲鸟3–6个月。首次繁殖年龄为2岁。已知最长寿个体为20岁。","identification":"与北极燕鸥和普通燕鸥相似，但在新西兰罕见；澳洲燕鸥更大，羽毛更浅。不同亚种间外观差异不大。","protection":"IUCN：NT（近危）。大部分个体在新西兰繁殖，90年代调查估计总数量12,000–15,000对，物种正在下降。全球数量极不可能超过50,000只，早先估计1,500,000只被认为是极大高估。在新西兰沿岸仍很常见。贝斯海峡亚种incerta罕见；2009年估计180只。面临多种威胁，包括洪水、引入的哺乳类捕食者和人类干扰。","distribution":"繁殖于新西兰海岸线及周边岛屿，斯图尔特岛北部，查塔姆群岛（东部、南部）和奥克兰群岛（南部、南部、新西兰），以及（少数）Furneaux群、贝斯海峡岛屿（澳大利亚东部）。非繁殖期见于澳大利亚东南部沿海至昆士兰州南部（澳大利亚南部、东部）。","other":"由于引入新西兰的哺乳类捕食者，如鼬、黄鼠狼、野猫和鼠，澳洲燕鸥近期被赋予新西兰国家自然保护状态为'At risk, declining'（有风险，衰退中）。"},{"name":"黑枕燕鸥","english_name":"Black-naped Tern","scientific_name":"Sterna sumatrana","overview":"黑枕燕鸥（英文名：Black-naped Tern，学名：Sterna sumatrana），是鸻形目鸥科燕鸥属的鸟类。中型长翅长尾的燕鸥，常见于热带和亚热带的太平洋及印度洋海域。其显著特征为雪白的羽毛，仅枕部有一条细黑纹，黑色嘴喙细长。广泛分布于西南太平洋及印度洋岛屿，偶尔在马来西亚水域数量减少。在中国大陆，黑枕燕鸥在海南岛和台湾为留鸟，而在浙江、福建、广东、香港则为夏候鸟。","appearance":"黑枕燕鸥体长约33-35厘米，体重97-120克，翼展约66厘米。头部和背部雪白，枕部有黑色细纹，从眼睛延伸至颈后，形成鲜明对比。背部浅灰色，尾部分叉深，外侧初级飞羽有黑色边缘。下体白色，有时略带粉红。嘴喙黑色，偶尔尖端微黄，腿黑色。非繁殖期成鸟相似，但枕纹较淡。幼鸟头部呈淡褐色，点缀灰色或黑色，背部淡灰色，有黑色V字形图案，缺乏下体粉色调。","call":"鸣声为尖锐的‘grrri’声。","habits":"黑枕燕鸥偏好小而岩石密集的珊瑚和沙质离岸岛屿、礁石、沙洲和岩石沙洲。在环礁泻湖和近岸捕食，偶尔在开阔海域活动。主要食物为小型鱼类，如鳀鱼、飞鱼、鲱鱼和鲻鱼等，通过浅水俯冲捕鱼或在水面掠食。在大堡礁北部，主要在礁石附近觅食，80%的觅食活动距离巢穴2公里以内。","breeding":"繁殖季节在印度和波利尼西亚为5月，在印度洋为9月至11月（在查戈斯群岛可能更长），在菲律宾为7月，在澳大利亚东北部为9月，在南大堡礁为11月至12月。通常形成5-20对的小群落繁殖，有时多达200对。巢筑于沙中（澳大利亚）或珊瑚岸的砾石或凹槽中，靠近高潮线。巢中产卵数为1-3枚，平均孵化期为21-23天。雏鸟白色至黄色，有黑色标记和黑色斑点，红色或橙色嘴喙和腿脚。成鸟会保护雏鸟免受天敌侵害。","identification":"黑枕燕鸥与白眉燕鸥、红燕鸥及凤头燕鸥容易混淆，但可以通过枕部的黑色细纹和飞行姿态加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区分布于非洲、远东、澳新界，从塞舌尔至库克群岛（波利尼西亚东部）。非繁殖区主要在印度洋和南太平洋。在中国大陆，黑枕燕鸥在海南岛和台湾为留鸟，而在浙江、福建、广东、香港则为夏候鸟。","other":"黑枕燕鸥在马来西亚水域的数量已降至不足2000对。在印尼，它是最常见的海鸟之一，有大约50个已知的繁殖地点，每个地点最多可达100对。"},{"name":"南美燕鸥","english_name":"South American Tern","scientific_name":"Sterna hirundinacea","overview":"南美燕鸥（英文名：South American Tern，学名：Sterna hirundinacea），是鸻形目鸥科燕鸥属的鸟类。主要栖息于南美洲沿海地带，从秘鲁南部至火地岛，包括福克兰群岛。其显著特征为繁殖季节时灰白的上体和下体，配以宽大的黑色头帽，红色的喙和腿脚。体型中等，翼展可达84至86厘米。","appearance":"成年南美燕鸥在繁殖季节呈现淡灰色的上体和下体，黑色的头帽覆盖头顶，红嘴红腿。休息时，尾巴超出翼尖。翅膀均匀淡灰色，无黑色斑点。非繁殖季节的个体具有半黑半白的头帽。幼鸟背部有斑驳的棕色。整体外观与普通燕鸥相似，但体型更大，约等于大西洋燕鸥。","call":"飞行时会发出短促、尖锐、高音的'kyik'叫声。在繁殖群落中极为嘈杂，面对人类和其他入侵者时会发出尖锐下降的尖叫'keeeerr'或短促的'ik-ik-ik'声。","habits":"几乎完全生活在沿海地带，繁殖于沙质或岩石海滩、悬崖顶或小岛上。冬季时，会向北迁徙至厄瓜多尔和巴西的Bahia。主要以小型鱼类和甲壳类为食，也会捕食昆虫。常伴随海豚或掠食性鱼类群聚捕食。","breeding":"繁殖季节随纬度而异，从巴西的4月至6月，到阿根廷南部的12月初。形成数千对至数万对的大规模繁殖群体，巢穴通常建在沙或细砾石上，有时被小贝壳包围。每窝产卵1至3枚，孵化期21至23天，雏鸟27天离巢。孵化成功率可高达70%，但受到天敌如海鸥的威胁。","identification":"与普通燕鸥相比，南美燕鸥体型更大，翅膀更长，下体颜色更深，且喙更粗壮。幼鸟背部的斑驳棕色有助于与成鸟区别。","protection":"IUCN：LC（无危）。全球数量不明，存在一些大型繁殖群落。在阿根廷和巴西海岸线上的某些地区非常丰富，但在智利的数量已减少。面临的主要威胁有人类干扰、蛋收集、商业捕鱼和工业污染。","distribution":"分布于南美洲沿海，从秘鲁南部至火地岛，包括合恩角和福克兰群岛。冬季迁徙至厄瓜多尔和巴西的Bahia。","other":"在福克兰群岛，南美燕鸥曾在1990年代被估计有6000至12000对繁殖对。"},{"name":"普通燕鸥","english_name":"Common Tern","scientific_name":"Sterna hirundo","overview":"普通燕鸥（英文名：Common Tern，学名：Sterna hirundo），是鸻形目鸥科燕鸥属的鸟类。中型燕鸥，广泛分布于北极、欧洲、亚洲和北美东部及中部的温带与亚北极区域。以浅灰色的上体、黑色的头冠、橙红色的腿和喙（尖端黑色）为显著特征。在繁殖季节，喙基部可能呈现红色或橙红色。这种燕鸥具有迁徙习性，冬季会在热带和亚热带的海岸线上过冬。经常集群活动，特别是在夏末时节。","appearance":"成年普通燕鸥的总长度为32-39厘米，包括6-9厘米的叉状尾羽，体重97-146克，翼展72-83厘米。头部和背部呈浅灰色，腹部颜色较淡，头冠黑色，腿和脚橙红色。喙在繁殖季为橙红色，尖端黑色；非繁殖季则几乎全黑。一龄鸟的头冠仅部分黑色，初级飞羽边缘、肩部及颈背有黑色。随着年龄增长，喙和腿的颜色变化，成年鸟的喙在繁殖季为橙红色，尖端黑色。雌雄外形相似，但在尺寸上有微小差异，雄鸟略大。","call":"普通燕鸥发出尖锐的‘KEEE-yurrrr’叫声，尤其是在警戒或求偶时。","habits":"普通燕鸥栖息于开阔的海域、海滩和大型湖泊，常在水面上空轻快飞行，以小鱼、虾、甲壳类和昆虫为食。它们会潜水捕食，也会在水面或空中捕捉飞行昆虫。在繁殖季节，它们会在沙滩、岛屿或盐沼上筑巢。","breeding":"繁殖期为5月至7月，通常在群体中营巢，巢位于沙地或石地，简单构筑，内部铺垫少量干草和羽毛。每窝产卵2-5枚，平均孵化期为20-24天。雏鸟出生后即被覆盖着沙棕色绒羽，能够立即离开巢穴行走。约一个月后即可飞行。","identification":"与弗氏燕鸥、北极燕鸥和粉红燕鸥较为相似，但可通过体型、颜色和叫声来区分。普通燕鸥的翅膀更为深色，尾巴更短，叫声也有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区遍布北极、欧洲、亚洲和北美东部及中部。冬季迁徙至美洲南部、非洲南部、马达加斯加西部和澳大利亚南部。","other":"历史上，普通燕鸥曾因羽毛贸易遭受大量捕杀，但得益于立法保护，数量在20世纪初有所恢复。然而，近年来在北美，其数量减少了70%以上。"},{"name":"白颊燕鸥","english_name":"White-cheeked Tern","scientific_name":"Sterna repressa","overview":"白颊燕鸥（英文名：White-cheeked Tern，学名：Sterna repressa），是鸻形目鸥科燕鸥属的鸟类。白色脸颊与灰暗的下体形成鲜明对比。主要分布在红海沿岸，东非至肯尼亚，波斯湾到伊朗海岸，巴基斯坦和印度西部沿海地区。","appearance":"成鸟拥有中等深灰色的下体和暗色翼缘，上体包括翅膀、臀部和尾巴呈暗灰褐色，黑色前额至颈背，白色脸颊。喙基部暗红色，尖端黑色，腿色从鲜红到深褐红色。幼鸟背部棕色，覆羽具淡棕色斑点，暗灰色初级飞羽，上颌和喙尖黑色。全长约32至35厘米，体重78至142克，翼展73至83厘米。","call":"鸣叫与普通燕鸥类似，但更为柔和。二音节的'kee-err'和'ker-rit'叫声，重音在短促的第二个音节，与普通燕鸥的重音模式相反；'kip'声比普通燕鸥的叫声更柔和。","habits":"主要栖息于热带海岸和近海水域，筑巢于岩石、沙地、砾石或珊瑚岛，常远离海洋100米以上。觅食范围通常在离岸3公里以内，主要在珊瑚礁上空。迁徙模式复杂，部分群体全年留驻东非，其他群体则季节性迁徙。","breeding":"繁殖期在苏丹和阿曼为5月至6月，在埃及、索马里和肯尼亚为7月至9月。在混合群落中繁殖，每群10至200对，有时可达900对。巢为浅坑，常无衬垫。产卵数2至3枚，孵化期和离巢时间未详细记录，雏鸟依赖父母数周。","identification":"与普通燕鸥相似，但体型更小，翅膀和腿较短，飞行时外观更圆润。冬季与普通燕鸥和北极燕鸥非常相似，但可通过更强的标记和更紧凑的飞行姿态区分。","protection":"IUCN：LC（无危）。全球数量估计在1990年代初约为60万只，但存在过度采集鸟蛋导致的数量下降趋势。","distribution":"繁殖区包括红海南至索马里和肯尼亚，东至波斯湾和阿曼，西印度（孟买）。越冬区位于东北非海岸和阿拉伯海至西南印度和拉克代夫群岛。","other":"在一些地区，白颊燕鸥面临人类过度采集鸟蛋和天敌捕食的威胁，例如在肯尼亚的Kiunga岛，天敌包括中白鹭、非洲白鹮和黄嘴鹮鹳。"},{"name":"北极燕鸥","english_name":"Arctic Tern","scientific_name":"Sterna paradisaea","appearance":"北极燕鸥体长28-39厘米，翼展65-75厘米，体重90-120克。它有极长的翅膀和分叉的尾巴，成鸟的上体浅灰，腹灰，有黑帽、红喙和腿，白颊。幼鸟具黑喙和腿，背部鳞状，冠暗，前额白。在第二年和成年期之间，外观差异明显。","call":"北极燕鸥发出尖锐、高音的kip声，尤其在觅食或在繁殖群落中时频繁。","habits":"北极燕鸥栖息于北极和亚北极地区的海岸和岛屿，以小鱼、甲壳类和其他无脊椎动物为食。它们在繁殖季节短促，仅在巢区停留2-3个月。在南极非繁殖季节，它们与少数几种鸟类共存于浮冰区。","breeding":"北极燕鸥每1-3年繁殖一次，筑巢于地面，通常在开阔的苔原、北方森林或沿海岛屿。它们成双结对，终身伴侣，常返回同一繁殖地。每窝产卵1-3枚，孵化期22-27天，幼鸟21-24天后离巢。","identification":"北极燕鸥与普通燕鸥区别在于更短的喙、腿和更深的尾叉。成鸟有透明的翼尖，而普通燕鸥的翼尖有暗色楔形斑。幼鸟通过下颌颜色和胫骨长度区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区广泛分布于北极和亚北极海岸及内陆，从格陵兰岛、冰岛至俄罗斯远东地区、阿拉斯加、加拿大直至詹姆斯湾。非繁殖期分布于南极洲边缘浮冰区。","other":"北极燕鸥的生存受全球变暖影响，极地冰架融化对其构成威胁。"},{"name":"南极燕鸥","english_name":"Antarctic Tern","scientific_name":"Sterna vittata","overview":"南极燕鸥（英文名：Antarctic Tern，学名：Sterna vittata），是鸻形目鸥科燕鸥属的鸟类。广泛分布于南半球的南极海域及周边岛屿，主食小鱼与甲壳类动物。其繁殖地遍布南极大陆、亚南极岛屿及南极半岛东北部新近冰融的地带。","appearance":"南极燕鸥体长35至40厘米，翼展74至79厘米，体重150至180克。繁殖季节时，头部至颈背呈黑色，上体灰白，尾叉深分，下体灰白色，具白色尾羽覆羽。嘴、腿红色。非繁殖期头部黑色减少，仅限眼后，嘴色暗红，下体白色。幼鸟背部具黄褐色斑点，腹面黄褐，嘴色暗黑，腿色暗红。","call":"在繁殖地和栖息地发出嘈杂的声音。主要的叫声为飞行或觅食时的“trr-trr-kriah”，以及防御巢穴时的“chrrrr”。","habits":"偏好岩石岛屿，有或无植被，常与其他海鸟共栖。繁殖期在悬崖、海滩筑巢，避开猫、鼠和海狮出没的地方。非繁殖期在南极寻找冰缘地带。在南非沿海的岩石和沙滩上度过冬季。","breeding":"繁殖期主要在11月至12月，依气候和食物状况有所不同。形成5至20对的松散群体，偶尔上千对。巢建于岩石、崖边、土壤、沙地或植被垫上。产卵1至2枚，孵化期23至25天，雏鸟孵化后27至32天离巢。成鸟生存率高，首次离巢后存活的幼鸟预期寿命约17年。","identification":"与北极燕鸥区别在于体型更壮实，腿部较长，初级飞羽边缘颜色较浅。与澳洲燕鸥区别明显，后者体型更大，颜色更淡，喙更长更细，全黑。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南极圈内的亚南极和南极岛屿，南大西洋、南印度洋、西南太平洋和南极半岛。","other":"南极燕鸥在全球的估计数量为13万至14.5万只，其中约11万只为gaini亚种。部分岛屿上的种群规模很小，如麦克夸里岛上的bethunei亚种，2009年记录有150只。"},{"name":"克岛燕鸥","english_name":"Kerguelen Tern","scientific_name":"Sterna virgata","overview":"克岛燕鸥（英文名：Kerguelen Tern，学名：Sterna virgata），是鸻形目鸥科燕鸥属的鸟类。以及Crozet岛屿繁殖。这种燕鸥数量估计在3,500至6,500只之间，但具体数据尤其是克岛主群的数量尚不明确。倾向于选择猫类掠食者无法到达的小岛筑巢。","appearance":"成年克岛燕鸥具有细长的体型和短喙，繁殖季节时头部呈黑色，身体灰烬色，脸颊和臀部有鲜明的白色条纹，喙和腿红色。飞行时，翼下和尾上覆羽多为灰色。非繁殖季节时，其外观与其他非繁殖燕鸥相似，但结构可作区分。幼鸟则呈现灰色、棕色和淡色的细斑纹，带有宽窄不一的深浅条纹。","call":"发出尖锐的‘chittick’声和拉长音的‘keeeaaar’叫声。","habits":"栖息于南极汇聚区附近的几个亚南极岛屿，觅食主要在近岸水域，以鱼类、甲壳类、软体动物、蚯蚓、昆虫和蜘蛛为食。食物种类随季节变化，从九月的甲壳类为主，十一月转为鱼类，十二月变为昆虫，再到一月至二月的鱼类。单独或群聚觅食，群可达二十只以上。在空中接触水面捕食（占83%）和潜入水中捕食，或在海藻附近觅食，甚至步行于海藻上捕捉无脊椎动物。","breeding":"克岛燕鸥在亚南极岛屿上繁殖，饮食和繁殖生态会受到天气影响，如风暴可能导致繁殖群体弃巢。繁殖期间，雄鸟通过喂食小鱼（50%）、甲壳类（14%）、昆虫（36%）等方式进行求偶。雏鸟主要以蜘蛛、昆虫、甲壳类、软体动物和蚯蚓为食。","identification":"与南极燕鸥相比，克岛燕鸥体型更大，颜色更暗，喙较大，尾上覆羽和翼下覆羽为灰色而非白色。与南极燕鸥的区别在于略小的体型、较短的喙和翅膀、颜色更深，尾上覆羽和翼下覆羽为灰色。","protection":"IUCN：NT（近危）","distribution":"主要分布于南印度洋靠近南极汇聚区的几个亚南极岛屿，包括Crozet、Prince Edward、Marion和Kerguelen岛屿。在繁殖季节与同域分布，但存在不同的生态位和繁殖周期。","other":"恶劣天气条件，如强风，可能干扰其觅食活动，影响繁殖成功率。"},{"name":"弗氏燕鸥","english_name":"Forster's Tern","scientific_name":"Sterna forsteri","appearance":"弗氏燕鸥体长33-36厘米，体重130-190克，具有明显的性别相似性。繁殖季节，其羽毛呈现洁净的白色，头部有黑色的帽状斑块，翅膀和背部为淡灰色，翼羽银灰色，尾部分叉深，橙色的腿和嘴基部带有黑色尖端。非繁殖季节，黑色帽状斑块变为眼罩状黑斑，前额白色，嘴黑色，脚暗橙色。幼鸟的翅膀和背部颜色更深，可能展示暗色的三级飞羽中心。","call":"发出尖锐的下降叫声，类似黑头鸥的叫声。","habits":"弗氏燕鸥主要在浅水湿地觅食，通过盘旋和悬停后俯冲抓鱼。它们常在沙洲、码头和其他结构上与海鸥和燕鸥共栖。飞行时翼拍迅速，动作敏捷。","breeding":"在夏季，弗氏燕鸥在北美内陆的淡水、咸水和盐水沼泽中繁殖，筑巢于地面凹陷处，使用周围植被建造巢穴。一窝产卵2-4枚，孵化期约24-25天。幼鸟孵化后不久即能跟随父母移动到更密集的植被中，约28天后离巢。","identification":"与普通燕鸥相比，弗氏燕鸥繁殖期更为洁白，尤其是翅膀和下体，尾部模式不同，看起来尾巴更长，嘴更粗壮、更橙色，腿更长。幼鸟和成鸟的磨损期，一级飞羽变暗。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大中南部至美国加州北部和墨西哥下加利福尼亚州北部，以及美国大西洋沿岸从新泽西至北卡罗来纳州，墨西哥湾沿岸从阿拉巴马至塔毛利帕斯北部。非繁殖期分布至墨西哥湾沿岸、巴哈马、古巴和墨西哥南部。","other":"由于栖息地不稳定，弗氏燕鸥在某些地区的年周转率较高。"},{"name":"白顶燕鸥","english_name":"Snowy-crowned Tern","scientific_name":"Sterna trudeaui","overview":"白顶燕鸥（英文名：Snowy-crowned Tern，学名：Sterna trudeaui），是鸻形目鸥科燕鸥属的鸟类。分布于南美洲东南部，从巴西沿海到阿根廷的中东部，以及智利中部到中南部的Aconcagua沿海至Llanquihue provinces。其显著特征为白色头部，黑色眼带，以及红橙色的脚。","appearance":"白顶燕鸥身长28至35厘米，翼展76至78厘米，体重146至160克。拥有较为粗壮的头部、细长的颈部、宽大的翅膀和叉状尾巴。成鸟的头部和上颈为白色，有一条黑色眼带，背部和翅膀上覆羽呈淡灰色，臀部和尾上覆羽白色。腹部灰白色。翅膀上覆羽淡灰色，初级飞羽银色，下翼白色。虹膜深棕色，喙橙色，尖端黄色，中间有黑色环带。腿和脚红橙色。非繁殖季节成鸟类似，但面部条纹更灰，喙黑色，尖端黄绿色。幼鸟背部黑白相间，尾羽末端有黑色标记，喙黑色，腿暗色。","call":"发出一系列快速的音节“je-je-je-je”，或短促、沙哑的“jeeer”。","habits":"栖息于沿海和内陆的淡水和咸水湿地。繁殖于潘帕斯和巴塔哥尼亚的植被丰富湖泊，亦见于盐湖的堤坝和岛屿。在湿地边缘、河流和湖泊觅食，偶尔在耕地捕食。迁徙时沿太平洋海岸向北最远可达秘鲁南部，大西洋海岸可达里约热内卢区域。在乌拉圭海岸和拉普拉塔河口被认为数量众多；在阿根廷布宜诺斯艾利斯潘帕斯平原9月至2月期间常见，但冬季较少。在巴西里奥格兰德杜苏尔州的海岸秋季和冬季最为丰富。","breeding":"繁殖季节大致在10月至12月。在浅水区建立浮动平台巢，由植物茎构成，自由漂浮或固定在水生植物上，水深10至150厘米。每窝产卵2至4枚，通常为3枚。成鸟会积极防御巢穴，攻击入侵者。繁殖成功率尚未研究。","identification":"与弗氏燕鸥相似，但后者全黑喙和灰暗后颈。非繁殖季成鸟头部侧条纹更灰，喙黑色，尖端黄绿色。幼鸟背部有黑白相间的图案，尾羽末端有黑色标记。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美洲东南部，从巴西沿海至阿根廷内陆中东部，以及智利中部至中南部的Aconcagua至Llanquihue省份。非繁殖季节沿太平洋海岸北至秘鲁南部，大西洋海岸北至里约热内卢区域。","other":"全球种群规模尚不清楚，但估计在西南（太平洋）区域不超过1万只，在东南（大西洋）区域介于2.5万至10万只之间。在智利，分布于Aconcagua至Llanquihue省份，数量不多。"},{"name":"黑腹燕鸥","english_name":"Black-bellied Tern","scientific_name":"Sterna acuticauda","overview":"黑腹燕鸥（英文名：Black-bellied Tern，学名：Sterna acuticauda），是鸻形目鸥科燕鸥属的鸟类。优雅的普通燕鸥，拥有长尾和橙色细喙，广泛分布于印度次大陆的大河流域，包括巴基斯坦、尼泊尔和印度，直至缅甸。其独特的黑色腹部和深叉尾使其在夏季易于识别。在全球范围内，该物种已被列为易危物种。","appearance":"黑腹燕鸥体型中等，长度约32至35厘米。繁殖期时，头部全黑，背部呈灰色，翅膀长而尖，尾部分叉明显。胸部浅灰，逐渐过渡至深黑色腹部。非繁殖期腹部变白，尾部缩短，喙尖黑色。喙和脚呈橙黄或黄色，眼睛为红棕色。幼鸟嘴基部红色，脚黑色，容易与“portlandica”形态的混淆，但体色更暗。","call":"发出短暂而饱满的犬吠声，如'nyap'或'nyark'，音调略有变化，通常不连续，但有时会以3-4秒的频率连串发出。","habits":"栖息于内陆湖泊和河流，偏好广阔的、光秃的、无特征的沙地、沙洲和河中岛屿。觅食范围广泛，包括河流、湖泊、稻田、沟渠和乡村池塘，海拔可达700米。飞行缓慢，多拍打翅膀，以昆虫和小鱼为食，通过水面掠食和斜向潜水捕捉猎物。","breeding":"繁殖期为2月至5月，筑巢于河流或湖泊附近的平坦沙地，可能与黄嘴河燕鸥、鹬和剪嘴鸥共栖，但不集群繁殖，巢间距大，有时超过1公里。巢穴简单，位于裸露的沙地上，靠近小物体，离水边通常超过200米。一窝产卵2-4枚，多为3枚，卵孵化期和雏鸟成长期未详细研究，报告的15-16天和8周孵化时间可能是错误的。","identification":"与须浮鸥相似，但黑腹燕鸥的尾部分叉更深，腹部黑色延伸更远，须浮鸥的尾部分叉较浅，黑色靠近胸部。基因分析支持将相似的黑额普通燕鸥（\"Sterna\" albostriata）归入Chlidonias属，此物种也可能更适合归入该属，但尚无相关研究。","protection":"IUCN：EN（濒危）","distribution":"主要分布于巴基斯坦的印度河谷内陆、喜马拉雅山南麓印度、缅甸中部的伊洛瓦底江。曾分布至中国南部和越南，现非常罕见，可能在泰国、老挝、柬埔寨和越南已灭绝。在巴基斯坦、印度和孟加拉国仍有一定数量，但总体处于严重下降趋势。","other":"在中国，黑腹燕鸥被列为国家二级重点保护野生动物（2021.02.05）。"},{"name":"黑额燕鸥","english_name":"Black-fronted Tern","scientific_name":"Chlidonias albostriatus","overview":"黑额燕鸥（英文名：Black-fronted Tern，学名：Chlidonias albostriatus），是鸻形目鸥科浮鸥属的鸟类。这种中到小型蓝灰色燕鸥为新西兰特有种，常见于新鲜水源附近，以淡水鱼、节肢动物和蠕虫为食。繁殖仅限于南岛东部地区，正面临外来哺乳动物和鸟类的威胁， IUCN 将其列为濒危物种。","appearance":"成年黑额燕鸥体长约30厘米，重88至96克。前额至颈背黑色，背部和翅膀呈灰色，翼尖深灰，腹部淡灰色。尾羽浅灰，末端较暗，外侧主翼羽有暗色前缘和白色主轴。眼黑色，喙和脚亮橙色。繁殖季时，头部黑色延伸至喙部。非繁殖季，头部转为斑驳灰，眼周有黑色斑点，幼鸟也有相似特征。幼鸟头冠灰褐，杂以黑色，耳羽和眼上覆羽黑色；背部和翼覆羽棕色，边缘带淡色；胸腹灰，喉和尾下覆羽白；喙暗棕基部橙色，脚橙色。","call":"黑额燕鸥通常仅在繁殖季节发出声音，尤其是攻击入侵者时更为喧闹，俯冲并发出尖锐的叫声，常重复发出“kit”的叫声。","habits":"繁殖于湍急河流的砂石滩，也会在湖边筑巢。非繁殖季节，它们会分散到海岸线、湖泊和农田附近觅食。冬季，它们会在沿海港湾和河口栖息，有时不会离岸超过10公里。以小型鱼类、水生昆虫和陆地无脊椎动物为食，通过空中俯冲捕鱼或捕捉飞虫。","breeding":"繁殖期为10月至12月，偶尔延续至1月，晚产蛋可能是替代巢。成对或小群繁殖，巢距5至20米。巢建在岩石或灌木下的砾石凹陷处，难以发现。每窝产2枚蛋，孵化期约25天。雏鸟灰褐色至橄榄色，有暗斑，脸颊有黑斑，喉咙暗色，胸腹白，喙钝铬色带黑尖，脚橙色。雏鸟出生1至3天后离开巢穴，4周后羽毛丰满，至少两周后仍由成鸟喂养。","identification":"黑额燕鸥与其他燕鸥的区别在于其独特的黑色前额延伸至喙，以及亮橙色的喙和脚。繁殖季和非繁殖季的羽毛颜色变化明显，帮助区分季节性差异。","protection":"IUCN：EN（濒危）","distribution":"繁殖于新西兰南岛东部的河流床，冬季分散至斯图尔特岛沿海和北岛南部。偶尔访问北岛。","other":"黑额燕鸥的巢穴和雏鸟常受到本土猛禽和引进哺乳动物的捕食，如猫、鼬科动物和其他异域及本地捕食者。"},{"name":"须浮鸥","english_name":"Whiskered Tern","scientific_name":"Chlidonias hybrida","overview":"须浮鸥（英文名：Whiskered Tern，学名：Chlidonias hybrida），是鸻形目鸥科浮鸥属的鸟类。小型鸥科浮鸥属鸟类。繁殖期成鸟具有独特的深灰烟熏色身体与对比鲜明的白颊，如同宽大的白色‘胡须’。全球分布广泛，从欧洲、亚洲到非洲和澳大利亚均有其踪迹。","appearance":"须浮鸥体型中等偏小，翼展约64-70厘米，体重60-101克，喙较厚实，尾部略呈方形。繁殖期成鸟头部至颈背为黑色，形成明显的C形带，脸颊白色，上下体羽暗灰色。非繁殖期整体呈淡银灰色，幼鸟背部具黑色格状杂斑。雌鸟尺寸显著小于雄鸟。","call":"叫声沙哑而连续，特征性的‘krekk’声。","habits":"须浮鸥栖息于湿地、湖泊、河流等环境，尤其偏好低海拔地区的淡水水域。它们以小型鱼类、两栖动物、昆虫和甲壳类为食，捕食方式包括水面捕食而非典型的潜入水中。在澳大利亚干旱区内，仅在雨水丰沛年份繁殖。","breeding":"繁殖期在5月至6月间，于欧洲、11月至12月间在澳大利亚。集群筑巢于内陆湖泊或芦苇沼泽，巢由水生植物构成，漂浮于水面。每窝产卵2-3枚，孵化期约为18-20天，雏鸟在出生一天后即可游泳至植被中。雏鸟全身布满黑斑，额部黑色，胸部奶油色，喙黑色，腿粉色。","identification":"非繁殖期须浮鸥与白翅浮鸥的区别在于前者头顶黑色，腰部灰色，无黑色颊纹。雄鸟个体比雌鸟更大，且捕食的猎物相对更大。","protection":"IUCN：LC（无危）。全球估计有300,000至1,500,000只个体，总体数量波动。欧洲总繁殖群体约66,300-108,000对。","distribution":"繁殖于欧亚大陆南部、中部，非洲东部和南部，以及澳大利亚。冬季迁徙至非洲内陆、亚洲南部和澳大利亚。在西班牙的繁殖群体最大，数量在5000至8000对之间。","other":"须浮鸥面临的主要威胁包括栖息地丧失、季节性缺乏筑巢条件以及人类采集鸟蛋。在印度某些地区，大量采集鸟蛋导致种群下降。"},{"name":"白翅浮鸥","english_name":"White-winged Tern","scientific_name":"Chlidonias leucopterus","overview":"白翅浮鸥（英文名：White-winged Tern，学名：Chlidonias leucopterus），是鸻形目鸥科浮鸥属的鸟类。又称: 白翅黑海燕，小型水鸟，以其独特的黑白相间羽毛而著称。广泛分布于欧亚大陆的内陆淡水环境中，包括欧洲东部、俄罗斯乃至中国东北部。繁殖季节时，成鸟展现出醒目的黑白对比羽毛，而在非繁殖季节则呈现灰白相间的外观。主要栖息于淡水湖沼和河流附近。","appearance":"成年白翅浮鸥在繁殖期拥有鲜明的黑白对比羽毛，头部、颈部及肩胛区为黑色，与白色臀部、尾巴形成强烈对比。翅膀主要为白色，内翼部分为灰色，带有棕色尖端的覆羽。非繁殖期，大部分黑色部位被白色或淡灰色替代，仅保留少量黑色羽毛，下体为白色或淡灰色。幼鸟背部黑色，翅膀银灰色，与白色腰部形成鲜明对比，肩部羽毛具有黑色斑纹。喙红色偏黑，腿红亮至暗红。","call":"白翅浮鸥在繁殖期间最为嘈杂，会发出响亮的‘krek’、‘kerr’或‘kreek’声，当兴奋或受惊时尤为明显。叫声比黑浮鸥更加嘶哑和滑音，不如后者尖锐。","habits":"主要栖息于内陆的淡水湖泊、沼泽、稻田等环境，从北极森林到地中海均有分布，最高可达亚美尼亚的2000米。觅食时，它们不会像典型燕鸥那样潜水，而是缓慢飞行于水面，捕捉漂浮的食物和飞行中的昆虫。迁徙时，它们会经过多种生境，从内陆湖泊到岩石海岸、水库、泻湖和红树林沼泽。夜间常栖息于淹水树木的露出枝条或木桩上。","breeding":"繁殖期一般在4月至8月，主要集中在6月。它们在小型群体中繁殖，每群由3至100对组成，通常为20至40对，偶尔超过100对。巢筑于30至120厘米深的水面上，由浮游植被构成，巢间距广泛，约10至30米，偶尔近至2.5米。每窝产卵2至3枚，平均2.8枚，孵化期18至22天，雏鸟背部呈淡褐色，饰以黑色条纹，腹部颜色较浅，带有少量深色斑点，眼周有一淡色斑块，约20至25天后离巢。","identification":"非繁殖期的白翅浮鸥与黑浮鸥的区别在于，白翅浮鸥的白色颈环更完整，头顶黑色较少，杂斑较多，黑色耳覆羽将黑色头顶与浅色腰部隔开。在重叠分布区域，白翅浮鸥的幼鸟可通过背部的暗色与较亮的上翼和白色臀部的对比，以及肩部的黑色标记，与黑浮鸥区分开来。","protection":"IUCN：LC（无危）","distribution":"繁殖区覆盖欧洲内陆中南部、东部和伊拉克至俄罗斯东南部、中国东北部和西伯利亚中北部。非繁殖区延伸至非洲沿海和内陆北部和南部、撒哈拉沙漠、亚洲东南部、中国东部、菲律宾、印尼群岛、新几内亚沿海和澳大利亚。","other":"白翅浮鸥与黑浮鸥之间存在杂交现象，已在瑞典和荷兰有记录。"},{"name":"黑浮鸥","english_name":"Black Tern","scientific_name":"Chlidonias niger","overview":"黑浮鸥（英文名：Black Tern，学名：Chlidonias niger），是鸻形目鸥科浮鸥属的鸟类。小型水禽，额部、眼先白色，头顶及上体棕色。广泛分布于北美、欧亚大陆的淡水湿地，偏好有水生植物的内陆浅水湖泊。在中国极为罕见，属于国家二级保护动物。","appearance":"黑浮鸥体长23-28厘米，体重约62克，翼展57-65厘米。繁殖羽色时，头部、颈部和胸部黑色，背部和腹部较暗的石板灰色，翅膀和尾巴灰色，腹部和尾下覆羽白色，下翼灰色，喙和腿黑色。非繁殖羽色时，上体淡灰色，下体白色，头部白色，具深色中央冠和眼后黑色斑块，胸前有特征性的暗色斑。幼鸟似非繁殖羽色，但前额有棕色色调，背部和肩羽棕灰色，边缘淡黄色。","call":"高音的\"kik\"叫声，大群时声音震耳欲聋。","habits":"栖息于平原、山地、森林和荒漠中的湖泊、河流和沼泽地带，偏好有水生植物的内陆浅水湖泊，偶尔出现在海岸和沿岸沼泽地带。飞行轻快敏捷，常在水面低空飞翔，用向下倾斜的喙在水面啄食。主要以水生无脊椎动物、岸边昆虫和小鱼为食。","breeding":"繁殖于欧洲南部、黑海、里海、俄罗斯南部、亚洲中部，以及加拿大和美国北部等地。通常成群营巢，巢由芦苇叶和草茎构成，漂浮在水面的植物上。每窝产卵3枚，孵化期14-17天，由双亲轮流孵卵。","identification":"与白翅浮鸥和须浮鸥相区别，尤其在幼鸟和基本羽色时，通过体型较小、较暗的下体、灰色臀部和尾巴，以及胸前的诊断性暗斑来识别。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美、欧亚大陆的温带海洋内陆，从加拿大、美国到欧洲和亚洲中部。非繁殖季节迁至非洲西部和太平洋、加勒比墨西哥沿海至南美北部的海岸线和离岸水域。","other":"北美种群因栖息地丧失而显著减少，欧洲和非洲的迁徙路线上的湿地损失可能是主要原因。"},{"name":"巨嘴燕鸥","english_name":"Large-billed Tern","scientific_name":"Phaetusa simplex","overview":"巨嘴燕鸥（英文名：Large-billed Tern，学名：Phaetusa simplex），是鸻形目鸥科巨嘴燕鸥属的鸟类。体型较大，拥有醒目的黄色大喙。常见于南美洲东部河流和淡水湖泊，北至安第斯山脉以东，南至阿根廷中部。在繁殖季节以外，也会出现在海岸地带。","appearance":"体长38-42厘米，体重208-247克。特征显著，喙粗壮且长，呈鲜黄色，翅膀呈现独特的三色模式：黑色翼尖，淡色中间部分，灰色内翼。繁殖期头部黑色冠羽明显，上体中灰色，较多数燕鸥暗淡，次级飞羽和大覆羽白色，腿脚黄色。非繁殖期成鸟头部颜色较淡。幼鸟头部黑色较少，背部和翅膀具褐色斑点，喙色较暗淡。","call":"发出沙哑的‘kree’和‘kew’音调，常连续鸣叫。","habits":"栖息于宽阔的内陆河流和湖泊，繁殖于沙滩和沙洲，冬季迁徙至河流和海岸。常见于圭亚那沿岸全年，5月至8月繁殖季节数量减少。在南美东岸广泛分布，偶尔访问特立尼达岛，罕见记录于委内瑞拉、古巴、格兰纳达、阿鲁巴岛等地。","breeding":"繁殖期为5月至6月和10月至12月，阿根廷地区为8月至9月。单独或群居繁殖，每窝产卵2-3枚，平均2.3枚。巢通常无特殊材料，筑于沙洲。生产力高，每巢平均成功育雏1.66只。在秘鲁，68%的巢穴成功繁殖。","identification":"其显著的黄色大喙和独特的翅膀图案使其容易识别，与同类物种区分明显。","protection":"IUCN：LC（无危）","distribution":"广泛分布于南美洲东部河流和湖泊，从安第斯山脉以东至阿根廷中北部。偶尔出现在海岸地带，记录于特立尼达岛、委内瑞拉、古巴、格兰纳达、阿鲁巴岛等地。","other":"已知会掠夺同类的食物，捕食昆虫时会在泥滩上空飞翔或跟随耕作捕捉昆虫。"},{"name":"印加燕鸥","english_name":"Inca Tern","scientific_name":"Larosterna inca","overview":"印加燕鸥（英文名：Inca Tern，学名：Larosterna inca），是鸻形目鸥科印加燕鸥属的鸟类。属于鸥科中的独特成员。分布于南美洲，主要在秘鲁沿海北部至智利中部的Humboldt Current区域，以其独特的头部装饰和暗灰色的羽毛著称。","appearance":"体型中等，长度39至42厘米，重约180至210克。全身呈深石板灰，喉部和翼下覆羽颜色较浅。最显著的特征是白色条纹从嘴角延伸至颈部，形成丝滑的长羽毛。翅膀边缘和四根外侧初级飞羽边缘为白色。虹膜褐色，喙和腿呈深红色，基部有黄色裸露区域。幼鸟起初为紫棕色，逐渐变为成鸟的棕灰色，喙和腿为暗角质色，随成长转为红色。","call":"在繁殖地最为活跃，发出粗糙的咯咯声和类似小猫的喵喵叫声。","habits":"栖息于岩石海岸、海港和码头，偶尔出现在沙滩和河口。主要以小型鳀鱼（Engraulis ringens）为食，也捕食浮游甲壳类动物和食腐。会跟随捕鱼船和海洋哺乳动物，如海狮，利用它们搅动的水域寻找食物。飞行时有快速拍打翅膀的特征。","breeding":"繁殖期不固定，一般在4月至7月和10月至12月间发现蛋，8月有繁殖行为的记录。通常在岩石峭壁裂缝、岛屿上的洞穴、沙丘或人工构造中筑巢，如建筑和码头下的平台。一窝产2枚卵，有时仅1枚，孵化期未知，幼鸟约四周后离巢，至少一个月内仍依赖成鸟喂养。","identification":"其独特的外观使其易于识别，尤其是长而丝滑的白色颈饰和鲜艳的红腿红喙。与其他燕鸥相比，飞行姿态更为颤动。","protection":"IUCN：NT（近危）","distribution":"南美：秘鲁沿海北部至智利中部，主要繁殖区位于秘鲁中部海岸的鸟粪岛，如Chinchas、Pescadores和Asia岛。","other":"历史上曾被认为数量庞大，但现在数量已大幅减少，受El Niño事件影响显著。"},{"name":"智利贼鸥","english_name":"Chilean Skua","scientific_name":"Stercorarius chilensis","overview":"智利贼鸥（英文名：Chilean Skua，学名：Stercorarius chilensis），是鸻形目贼鸥科中贼鸥属的鸟类。大型掠食性海鸟，主要在南美洲的阿根廷和智利繁殖，非繁殖季节时活动范围可延伸至巴西和秘鲁。其独特的外观特征为暗色帽状头部与肉桂色喉部和面部形成鲜明对比，已知与福克兰贼鸥存在杂交现象。","appearance":"智利贼鸥背部、侧腹和脸颊呈深色，腹部统一为浅色。成年鸟的翅膀下方具特色性的肉桂色，但某些个体的颜色较为暗淡。所有成年鸟具有显著的暗色帽状头部和明显的金色条纹脸颈。它们拥有黑色腿脚，棕色眼睛，小而带暗尖的蓝灰色喙，翼展可达130至138厘米。幼鸟比成鸟颜色更鲜艳，无明显条纹，且头部深色突出，缺乏成鸟的胸带。","call":"在繁殖地，智利贼鸥发出一系列10至12个短促鼻音般的吠声。叫声中还包括短促的喉音咕噜声。","habits":"智利贼鸥栖息于南美洲沿海地带，从中央秘鲁到阿根廷北部，冬季活动范围扩展至巴西热带沿海水域。它们偏好沙滩、漂浮巨藻和淡水溪流旁的栖息环境。它们会掠夺其他海鸟的食物，甚至捕食小型海鸟，如鹱类，以及成为海鸥垃圾场的常客。","breeding":"繁殖期始于11月，持续至次年2月至3月。它们以高密度集群方式繁殖，类似大型海鸥，与其它贼鸥种类不同。在智利海岸的岛屿上，选择有淡水溪流穿过的沙滩作为领地，成鸟在这些地方沐浴，雏鸟则利用搁浅的巨藻堆作为庇护所。巢穴通常铺有枯草，每窝产卵2枚，偶尔仅一枚；孵化期为28至32天。雏鸟有均匀的浅粉色灰褐色绒毛，蓝灰色腿脚。","identification":"智利贼鸥与福克兰贼鸥相比，飞行时显得更为修长紧凑，具有独特的红色色调和翅膀上的白色新月图案。","protection":"IUCN：LC（无危）","distribution":"繁殖于智利沿海中南部和阿根廷东南部至合恩角，非繁殖期分布于秘鲁南部至巴西中部的海岸线。"},{"name":"南极贼鸥","english_name":"South Polar Skua","scientific_name":"Stercorarius maccormicki","appearance":"南极贼鸥成鸟体长50-55厘米，体重900-1600克，翼展130-140厘米，存在两种色型：淡色型的个体头部和体羽呈淡金色至烟灰色，与深棕色的翅膀、背部和尾巴形成鲜明对比；深色型个体则全身暗橄榄棕色，翅膀和背部为类似色调的赭色，显得更为统一，容易与大贼鸥混淆。颈上的淡黄色绒毛在淡色型个体中更为明显。随着年龄增长，鸟儿逐渐变淡，成年个体的羽毛在繁殖季节会褪色。淡色型个体在罗斯海区域较为常见，而深色型在南极半岛占主导。在所有区域，雄鸟伴侣的颜色几乎总是比它们较大的配偶更深。","call":"在繁殖地活跃发声，主要鸣叫为一连串快速的短促粗哑吠声，包含短促鸭子般的呱呱叫声，群体发出时听起来像嘈杂的喋喋不休，以及拉长的嘶哑‘hyeheheheh’声。","habits":"南极贼鸥栖息于相对无雪的南极海岸地带，主要在海上活动，尤其是繁殖期间。它们通常沿海岸线分布，但在无雪的山区形成小规模的内陆群落。作为跨赤道迁徙者，它们在三月离开繁殖地，十月返回，北上至阿拉斯加、格陵兰和印度洋，表现出顺时针的环迁模式。冬季饮食主要由鱼构成，尤其是南极银鱼，以及其它海鸟的成鸟、蛋和幼鸟，腐肉、海豹胎盘和磷虾。","breeding":"繁殖始于十一月，松散集群，高度领地意识。巢穴简单，通常不铺设。每窝通常产两枚蛋，但经验不足的个体可能仅产一枚；孵化期28-31天；雏鸟出生1-2天后离巢，覆盖均匀的浅灰褐色绒毛；约36-45天后离巢。年长的雏鸟通常杀死较年轻的同胞，繁殖成功率通常较低。性成熟在6岁以上，成鸟存活率90-95%。","identification":"与北方的北极贼鸥、蓬马林贼鸥和长尾贼鸥相比，南极贼鸥体型更大，胸部宽阔，白翼斑明显，即使远观也很容易识别。与近亲大贼鸥的鉴别更为复杂，需注意南极大贼鸥的冷棕色羽毛和蓝色喙基。与南方的其他大型贼鸥种类区分也具挑战性。","protection":"IUCN：LC（无危）","distribution":"繁殖区集中在南极沿海，包括罗斯海区域和南极半岛周边岛屿。非繁殖季节分布广泛，北至日本、韩国水域（太平洋）、美国东海岸（大西洋）和墨西哥西北部（东太平洋）、非洲西北部（北大西洋）。在中国大陆地区，南极贼鸥偶尔可见于沿海水域。","other":"长期研究表明，南极贼鸥数量和繁殖成功率在某些地区出现大规模波动，可能与鱼类资源短缺有关。"},{"name":"棕贼鸥","english_name":"Brown Skua","scientific_name":"Stercorarius antarcticus","overview":"棕贼鸥（英文名：Brown Skua，学名：Stercorarius antarcticus），是鸻形目贼鸥科中贼鸥属的鸟类。亦被称为南极贼鸥、亚南极贼鸥、南方贼鸥或毛利语中的hākoakoa。作为贼鸥科中最重的物种之一，其体型可与大型海鸥媲美，主要在南极和亚南极区域繁殖，非繁殖季节则向北迁徙。其分类复杂，涉及多个亚种，包括Falkland贼鸥、Tristan贼鸥和亚南极贼鸥，且与南极贼鸥和智利贼鸥存在杂交现象。","appearance":"棕贼鸥体长52至64厘米，翼展可达126至160厘米，体重在1.2到2.18千克之间，是贼鸥中最大的种类。羽毛颜色从深棕色到浅棕色带斑点，变异较大。喙相对较大，身体健壮。头部缺乏明显帽状特征，与北贼鸥和智利贼鸥相异。所有亚种的幼鸟颜色更深，更加均匀，胸部羽毛呈栗色，白色翼斑不明显。","call":"在繁殖地较为鸣叫活跃，发出快速连续的8至15声粗哑的吠叫声。面对入侵者时会发出粗糙沙哑的'ghraaaaa'叫声。","habits":"栖息于海洋环境，偏好亚南极岛屿，以海鸟巢穴和企鹅群落为邻。繁殖季节结束后，广泛分布于南部海域。以掠夺为主，食物包括鱼、企鹅幼鸟和其他海鸟，小型哺乳动物，蛋和腐肉。部分个体全年居住于特定区域，依赖稳定的海鸟猎物。","breeding":"繁殖始于10月至11月，集群繁殖，领域性强。巢通常位于远离人类干扰的岛屿上，由干草简单铺设。每窝产卵两枚，孵化期28至32天，雏鸟出生后1至2天离开巢穴，约40至50天后离巢飞翔。繁殖成功率受食物供应影响。","identification":"与北贼鸥和智利贼鸥相比，头部缺乏明显的帽状外观，翼下覆羽较暗。与南极贼鸥相比，色调更冷，喙较小。","protection":"IUCN：LC（无危）。全球估计有13,000至14,000对，分布于福克兰群岛、阿根廷、特里斯坦达库尼亚群岛、乔治岛、马夸里岛等地。指名亚种在过去五年（2004-2009）内数量锐减47%，可能与红腿巨隼的竞争有关。","distribution":"主要分布于南极和亚南极海域，从阿根廷南部海岸、福克兰群岛到新西兰区域，包括特里斯坦达库尼亚群岛、南乔治亚岛、马夸里岛、克罗泽群岛等地。","other":"已知能够识别个别的人类个体，显示出较高的认知能力。在南极长期居住的人类，如东正教神职人员，曾报告与棕贼鸥建立了特殊联系，观察到它们展现出玩耍或看似恶作剧的行为。"},{"name":"北贼鸥","english_name":"Great Skua","scientific_name":"Stercorarius skua","appearance":"北贼鸥体长50-58厘米，翼展125-140厘米。成年个体呈灰褐色条纹，头戴黑色帽，而幼鸟则为温暖的棕色，腹部无条纹。拥有短而钝的尾巴，飞行强劲有力，翅膀上显眼的白色斑块在飞行中尤其引人注目。","call":"其叫声主要为一系列短促的咆哮声，例如“piEh..piEh..piEh..piE..piEh”。还包括低沉的类似鸥鸣的“gUk”，更长的“grAAoo”，以及在攻击入侵者时发出的鼻音调“gyAheheh”。","habits":"北贼鸥栖息于岛屿，通常避开人类频繁出没的地区，偏好有植被覆盖的平地。它们在迁徙期间和冬季主要生活在海上，但在风大时可能在海岸附近被观察到。冬季时，它们倾向于跟随渔船，以渔获弃置物为食。","breeding":"繁殖期始于五月，群居但高度领地性。巢穴通常由干草铺垫。一般产两枚蛋，孵化期28-32天；雏鸟出生1-2天后离开巢穴，50天左右离巢。平均八岁达到性成熟，成鸟生存率高达90%。","identification":"与北极贼鸥、中贼鸥和长尾贼鸥相比，北贼鸥的鲱鸥大小、宽阔的胸膛和翅膀上的白色斑点使其易于识别，即使在远处也很明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于冰岛、法罗群岛、苏格兰、挪威、斯瓦尔巴群岛和俄罗斯西北部至新地岛。冬季则广泛分布于北大西洋海域，北至纽芬兰的Grand Banks，南至伊比利亚半岛北部，西非西部和西地中海。","other":"由于沙鳗资源减少，北贼鸥在设得兰群岛的繁殖成功率下降，数量有所减少。渔业废弃物构成了夏季饮食的一半以上，因此捕鱼实践的变化可能对其数量产生重大影响。"},{"name":"中贼鸥","english_name":"Pomarine Jaeger","scientific_name":"Stercorarius pomarinus","overview":"中贼鸥（英文名：Pomarine Jaeger，学名：Stercorarius pomarinus），是鸻形目贼鸥科中贼鸥属的鸟类。是贼鸥科中体型最大、胸部条纹最明显的种类。繁殖于北极苔原，非繁殖期则在海上度过。成鸟独特的特征是拥有细长的杓状中央尾羽。该鸟种依赖单一猎物——棕色田鼠（Lemmus trimucronatus）或其相似种繁殖成功，仅在田鼠数量达到高峰时繁殖，且繁殖周期约每三至四年一次。中贼鸥在全球的分布广泛，被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》。","appearance":"中贼鸥体型庞大，翼展宽广，具有一对强有力的大翅膀。成鸟在繁殖期有显著的特征：上体黑褐色，头部黑色斑块向下延伸至喙部下方，外侧飞羽的上下有大片白色羽轴。幼鸟体色变化较大，但通常上体有条纹，下体有明显的黑白条纹。成鸟的喙较其他贼鸥粗厚。","call":"中贼鸥发出多种刺耳的叽叽喳喳声，还有一些类似‘which-yew’的叫声。","habits":"中贼鸥繁殖于北极苔原地带，靠近海岸的河流与湖泊。非繁殖期主要栖息于开阔的海洋和近海岸水域。迁徙期间可见于大内陆河流与湖泊。飞行时直线前进，双翅频繁轻拍，但在抢夺其他鸟类食物时，飞行迅速且灵活，展现高超的飞行技巧。","breeding":"中贼鸥的繁殖期为6-7月，巢筑于苔原地上的浅坑，内铺干苔藓、地衣、枯草。每窝产卵2枚，卵呈橄榄褐色，具黑褐色斑点。雌雄轮流孵卵。","identification":"中贼鸥与短尾贼鸥最为相似，但中贼鸥体型更大，翅膀更宽，喙更粗。成鸟中央尾羽明显较长且扭曲，幼鸟的羽色变化较多，但通常有明显的黑白条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北极苔原，包括格陵兰西南部、斯瓦尔巴群岛、俄罗斯北极岛屿、阿拉斯加北部和加拿大北极地区。非繁殖期分布于全球温带至热带海域。","other":"中贼鸥的繁殖依赖于特定的环境条件，特别是棕色田鼠的数量，这使得它们的繁殖行为具有周期性和局部性。"},{"name":"短尾贼鸥","english_name":"Parasitic Jaeger","scientific_name":"Stercorarius parasiticus","appearance":"短尾贼鸥体型纤细，介于三种贼鸥中大小居中，成鸟繁殖期有长而尖的尾巴，但不如长尾贼鸥的长。羽色变异大，从全黑褐至浅色型，腹白，颈侧黄。幼鸟变化多样，通常是暖褐色，翅膀有肉桂色条纹。翼下覆羽和尾下覆羽的条纹比中贼鸥淡。喙相对较长而纤细。雄鸟体重约380-420克，雌鸟约460-510克。","call":"典型叫声为鼻音的喵喵声，连续重复几声。警戒时发出较短的声音。","habits":"繁殖于北极苔原，高海拔和亚北极地带，包括格陵兰、冰岛、苏格兰北部、斯堪的纳维亚沿海、巴伦支海、俄罗斯北部至西伯利亚东北部和勘察加半岛、阿留申群岛、白令海岛屿、阿拉斯加西部和西南部、加拿大北极地区（除最北端的高北极岛屿）至巴芬岛和加拿大东海岸。迁徙期间会出现在高生产力的亚热带至热带沿海水域，遍及非洲西岸、南非、中东、波斯湾、阿拉伯海东岸、印度洋北部、澳大利亚和新西兰、中南美洲部分地区。","breeding":"筑巢于干燥苔原、高地和岛屿。每窝产橄榄棕色蛋可达四枚。繁殖季节食物来源包括啮齿类、昆虫、鸟蛋、雏鸟和小型鸟类。冬季和迁徙期间，主要通过掠夺其他鸟类（尤其是鸥类和燕鸥）获取食物。","identification":"与长尾贼鸥和中贼鸥相比，短尾贼鸥体型更饱满，翼稍短，外观不如燕鸥。幼鸟辨识难度增加，色调通常更温暖，呈棕色而非灰色。区别于长尾贼鸥，短尾贼鸥翼上有更多白色轴线（通常4-6根），但少于中贼鸥。喙相对长而纤细。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极地区，包括格陵兰、冰岛、苏格兰北部、斯堪的纳维亚沿海、巴伦支海、俄罗斯北部至西伯利亚东北部和勘察加半岛、阿留申群岛、白令海岛屿、阿拉斯加西部和西南部、加拿大北极地区至巴芬岛和加拿大东海岸。非繁殖期广泛分布于亚热带至热带沿海水域，遍及非洲西岸、南非、中东、波斯湾、阿拉伯海东岸、印度洋北部、澳大利亚和新西兰、中南美洲部分地区。","other":"在冰岛，由于2000年代初期数量急剧下降，2018年被列为区域性的濒危物种。"},{"name":"长尾贼鸥","english_name":"Long-tailed Jaeger","scientific_name":"Stercorarius longicaudus","overview":"长尾贼鸥（英文名：Long-tailed Jaeger，学名：Stercorarius longicaudus），是鸻形目贼鸥科中贼鸥属的鸟类。是最小的贼鸥种类，体长约48-53厘米，拥有纤细的海鸥般身姿。其繁殖于北极苔原，其余时间在海上度过。繁殖期成鸟的特征为极长且尖锐的尾巴，背部均匀呈褐色，与深色飞羽形成鲜明对比，顶冠局部黑色，颈部侧面带有淡黄色。亚成鸟翅膀上的鳞片状图案颇具魅力，颜色从深棕色到浅灰色不等。","appearance":"长尾贼鸥为中等体型（约50厘米）的深色海鸟，以其长长的中央尾羽著称。繁殖期成鸟拥有灰褐色背部，与深色翼羽形成对比，黑色顶冠有限，颈部两侧泛黄。幼鸟翅膀上呈现迷人的鳞片状图案，颜色从深棕到浅灰白不等。成鸟在所有年龄段都展现浮标般的、燕鸥似的飞行姿态。外侧两根飞羽上的白色羽轴是其显著特征之一，数量少于其他贼鸥。喙部较短且厚实。","call":"在繁殖地，长尾贼鸥发出的叫声为吠叫和咔哒声。非繁殖季节时，它们在开阔海域上空发出尖锐的‘kreeah’叫声。","habits":"长尾贼鸥栖息于北极苔原，夏季频繁出没于干燥的苔原，甚至荒地，低坡和山脊上。其饮食主要依赖于田鼠和鼠类，因此容易受这些小型哺乳动物数量波动的影响。迁徙时，它们主要在开阔海域活动，冬季南迁至南大西洋和太平洋。迁徙期间，它们会猎捕小型陆生猎物，表现出对人类的较少畏惧。","breeding":"长尾贼鸥在高北极苔原繁殖，主要分布在欧亚大陆和北美北部，包括俄罗斯、阿拉斯加和加拿大，以及整个北极圈周边。繁殖季节，它们在干燥的苔原或高地筑巢，产下两枚橄榄褐色斑点的蛋。迁徙期间，它们成为高度远洋鸟类，南迁至南半球。","identification":"长尾贼鸥与短尾贼鸥最为相似，区分要点在于长尾贼鸥的中央尾羽更长，体型更纤细，喙部较短且厚实，飞行姿态更为轻盈。此外，长尾贼鸥的背部颜色较为灰色，而非短尾贼鸥的褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于北极苔原，包括格陵兰西北和东南、北极北欧至俄罗斯东北部和堪察加半岛（远东俄罗斯）。非繁殖季节，它们广泛分布于南大西洋和南太平洋，包括非洲西南部和东南部、马达加斯加南部、澳大利亚南部、秘鲁、智利和阿根廷中部东部的近岸亚南极水域。","other":"长尾贼鸥在迁徙途中，有时会在耕作的田野或高尔夫球场猎捕小型猎物，对人类相对无所畏惧。"},{"name":"黑头海雀","english_name":"Little Auk","scientific_name":"Alle alle","overview":"黑头海雀（英文名：Little Auk，学名：Alle alle），是鸻形目海雀科侏海雀属的鸟类。是海雀科中体型最小且数量最多的物种，广泛分布在北大西洋高北极地区，尤其是格陵兰岛。小型、紧凑的黑白色水鸟，具有高能量需求，在繁殖季节尤为显著。黑头海雀主要以浮游甲壳类动物为食，是唯一一种以浮游动物为主要食物的北大西洋海鸟。","appearance":"黑头海雀是一种小型鸟类，长度约19-21厘米，翼展34-38厘米，体重介于130到200克之间。其身体短小而圆胖，喙短而粗，尾巴圆形且黑色。繁殖季节，头部、颈部、背部和翅膀均为黑色，腹部为白色，非繁殖季节时，下颌和喉咙变为白色，耳后有一白色斑点。幼鸟上体颜色较暗淡，喉部和上胸带有褐色调，眼上方的白点较小。","call":"在繁殖地，黑头海雀会发出一系列的啾啾声和咯咯声，但在海上通常保持沉默。","habits":"黑头海雀在高北极地区的岩石岛屿上繁殖，筑巢于岩缝或大石下，冬季则向南迁徙至北大西洋北部海域。它们通过快速拍打短小的翅膀在水中游泳捕食，主要食物是浮游甲壳类动物，偶尔也会吃小鱼和无脊椎动物。","breeding":"黑头海雀在岩石缝隙中筑巢，每窝仅产一枚淡蓝绿色的蛋。双亲共同孵蛋，孵化期约为一个月。幼鸟出生时体重仅21克，无法自我调节体温，经过大约五天的孵化后能够独立调节体温，26-29天后离巢飞翔。","identification":"黑头海雀比其他海雀科鸟类小，拥有更圆胖的身体和短粗的喙。与之最相似的是北太平洋最小的小海雀，但黑头海雀具有更为鲜明的黑白羽色模式。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大东北至西北部的高北极海岸线，俄罗斯，偶尔在白令海峡繁殖。非繁殖期分布于南部墨西哥湾流至美国北卡罗来纳州，至英国北部和北海。","other":"历史上，黑头海雀是格陵兰、巴芬岛和拉布拉多因纽特人的食物来源之一，尤其是在食物短缺的冬季。"},{"name":"厚嘴崖海鸦","english_name":"Thick-billed Murre","scientific_name":"Uria lomvia","overview":"厚嘴崖海鸦（英文名：Thick-billed Murre，学名：Uria lomvia），是鸻形目海雀科海鸦属的鸟类。适应极地环境的大型海鸟。在夏季，广泛分布于北极海域的大陆架水域，冬季则向南迁移，常见于冰层边缘的开阔水域。厚嘴崖海鸦是北极海域夏季生物量最大的海鸟之一，常在陡峭的悬崖上密集筑巢，形成数量可达百万的庞大繁殖群体。在太平洋和大西洋的分布有所重叠，但在大西洋，与亲缘物种崖海鸦的重叠较少。厚嘴崖海鸦是深潜高手，能潜入水下超过100米，甚至有时达到200米，持续时间超过3分钟。","appearance":"成年厚嘴崖海鸦体型健壮，体长40-48厘米，翼展64-81厘米，体重介于736-1481克之间，头部、颈部、背部和翅膀呈深黑色，腹部为白色。喙长而尖，冬季下面部变为白色。它们具有小而圆的黑色尾巴。在繁殖季节，喙的上部有一条明显的白色条纹，与崖海鸦相比，喙更粗短，头部和背部颜色更深。幼鸟的喙比成鸟小，上喙的白色条纹常常不明显。","call":"在繁殖季节，厚嘴崖海鸦会发出一系列刺耳的咯咯声，但在海上飞行时保持沉默。","habits":"厚嘴崖海鸦全年大部分时间都在海上度过，偏好水温低于8℃的海域，仅在繁殖季节聚集在悬崖上。它们在冰层边缘和开阔水域觅食，主要以鱼类、鱿鱼、甲壳类动物和虾为食，潜水深度可达150米，最长潜水时间为4分钟。","breeding":"厚嘴崖海鸦在狭窄的岩石峭壁上形成密集的繁殖群落，每对每年产一枚蛋。幼鸟在18-25天后离开巢穴，跳入水中，由雄鸟亲鸟单独照顾约8周，期间雄鸟继续喂养幼鸟。","identification":"与崖海鸦相比，厚嘴崖海鸦的喙更粗短，头部和背部颜色更深，冬季下面部变为白色。喙上部的白色条纹是其显著特征之一。","protection":"IUCN：LC（无危）","distribution":"繁殖于北半球极地和亚极地地区的海岸线，包括北极圈内的高北极和低北极（局部温带）海岸。非繁殖季节分布于南部，直至纽约沿海。","other":"厚嘴崖海鸦有两种亚种：较小的lomvia，分布在东加拿大至西俄罗斯；较大的arra，分布在东俄罗斯至西加拿大。"},{"name":"崖海鸦","english_name":"Common Murre","scientific_name":"Uria aalge","overview":"崖海鸦（英文名：Common Murre，学名：Uria aalge），是鸻形目海雀科海鸦属的鸟类。体型较大的海雀科海鸦属鸟类，分布于亚北极到温带海洋，主要在北美的亚北极地区至温带海洋海岸线北部繁殖，具有黑白色调的羽毛，头部在繁殖季节全黑，非繁殖季节脸部呈现白色并有一条沿眼后方弯曲的暗线。","appearance":"崖海鸦体长38-46厘米，翼展61-73厘米，体重范围广泛，从945克到1,044克不等。繁殖季节时，其头、背和翅膀呈黑色，腹部白色，喙尖而呈暗色，尾部圆润且暗色。非繁殖季节，脸部白色，有一条沿眼后方延伸的暗色线。亚成鸟和成鸟基本一致，但成鸟在每年的12月至次年2月经历预替换换羽。","call":"崖海鸦发出柔和的咕噜声等多种叫声。","habits":"崖海鸦主要栖息于岛屿、岩岸、悬崖和海堆石上，具有海洋性生活习性，以鱼类、甲壳动物和其他海洋无脊椎动物为食，通常潜水捕食，能在水下达到30-60米的深度，有时甚至可达180米。非繁殖期在海上活动，冬季休息于水面。","breeding":"崖海鸦在高密度的群体中繁殖，筑巢于裸露岩石上，不筑巢，单产一卵，由双亲轮流孵化约30天。孵化后20天左右，幼鸟离开巢穴前往大海，由雄鸟父母陪伴长达两个月，期间幼鸟学会潜水和觅食。","identification":"与厚嘴崖海鸦的区别在于喙更长、更细，身体和颈部更长更纤细，背部羽毛总体偏棕色，侧翼和下翼覆羽颜色更深，胸白与喉部的深棕色以直线或浅倒“U”形相接，而非厚嘴崖海鸦的锐角“V”形。","protection":"IUCN：LC（无危）","distribution":"繁殖区域包括北美和欧亚的亚北极至温带海洋海岸线北部。非繁殖季节向南迁移至弗吉尼亚州的Gulf Stream、伊比利亚半岛、日本北部和墨西哥下加利福尼亚州西北部。","other":"崖海鸦对人类的干扰敏感，主要来自攀岩和观鸟活动。油污事件对其冬季成鸟的死亡率有显著影响。"},{"name":"刀嘴海雀","english_name":"Razorbill","scientific_name":"Alca torda","overview":"刀嘴海雀（英文名：Razorbill，学名：Alca torda），是鸻形目海雀科刀嘴海雀属的鸟类。北极大西洋沿岸的群居海鸟，属于海雀科Alcidae中的唯一现存物种。与已灭绝的大海雀亲缘关系最近。体长37至39厘米，重505至890克，翼展63至68厘米。上部黑色，下部白色，头颈粗壮，具深而扁平的喙。雄鸟和雌鸟外观相似，但雌鸟平均略小。广泛分布在北极到北温带的北大西洋海岸，从格陵兰岛、冰岛、不列颠群岛到斯堪的纳维亚、法国西北部、俄罗斯白海，加拿大东北部至缅因湾。","appearance":"刀嘴海雀拥有黑白相间的羽毛，上部黑色，下部白色，头部有薄薄的白色线条从前眼延伸至喙根部。冬季时，喉咙和头部侧面变白，白色线条变得不那么明显。喙黑色，深而侧扁，末端钝圆，有几条垂直的沟槽，其中一条饰有断续的白色垂直线。体型健壮，平均重量介于505至890克之间，翼展63至68厘米，尾巴相对较长。","call":"描述缺失。","habits":"刀嘴海雀主要栖息在北极到北温带的北大西洋海岸的岛屿、岩岸和悬崖上。它们是完全迁徙的海洋鸟类，冬季会离开陆地，迁移到大西洋海域。它们以鱼、甲壳类、软体动物和浮游生物为食，通过潜水捕食，能在水下达到120米的深度。","breeding":"刀嘴海雀在岩石缝隙或靠近岩石的隐蔽地点筑巢，通常选择离海有一定距离的巢址，以减少天敌的威胁。雌雄鸟终生配对，每年产一枚卵，孵化期约35天，双亲轮流孵卵。幼鸟孵化后17至23天就会跟随雄鸟父母跳下悬崖，进入海洋。","identification":"与其它海雀科鸟类相比，刀嘴海雀具有更厚重的头部和更大的喙，喙形状不同且尾部更长。冬季，刀嘴海雀与崖海鸦和厚嘴崖海鸦的区别在于喙的形状、尾部的长度以及头部的白色部分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域集中在北极到北温带的北大西洋海岸，包括格陵兰、冰岛、不列颠群岛、斯堪的纳维亚、法国西北部、俄罗斯白海，加拿大东北部至缅因湾。非繁殖季节，它们迁移到美国卡罗来纳州外海北部，伊比利亚半岛以及西地中海。","other":"刀嘴海雀在20世纪早期因人类捕猎其蛋、肉和羽毛而导致数量大幅下降，1917年在美国受到《候鸟条约法案》的保护。现在面临的主要威胁包括繁殖地的破坏、油污事件和食物质量的恶化。"},{"name":"大海雀","english_name":"Great Auk","scientific_name":"Pinguinus impennis","overview":"大海雀（英文名：Great Auk，学名：Pinguinus impennis），是鸻形目海雀科大海雀属的鸟类，是海雀类中唯一不飞的物种。体型巨大，约75至85厘米高，重约5公斤，是生存至近代的最大型的海雀。外观略似企鹅，英语中以企鹅命名，实际与刀嘴海雀关系更近。繁殖于北美、欧亚大陆的北岸，非繁殖季节迁徙至美国东部和地中海西部、中部。","appearance":"大海雀体长约75-80厘米，重约5公斤。头部两侧、颏、喉和翅膀黑褐色。背部黑色，胸腹白色，有黑白保护色。喙大，黑色，具白色横向纹槽，适于捕食。夏季眼周有白色斑块，冬季变为灰线。脚趾黑色，蹼棕色。幼鸟喙纹不明显，颈上黑白混杂。体型粗壮，双翼退化，无法飞行，但能强力划水。","call":"大海雀的叫声包括低沉的咕哝声和嘶哑的尖叫。曾有报告称，被捕获的大海雀在焦虑时会发出咕噜声。其它叫声与刀嘴海雀相似，但音量更大，音调更深。","habits":"大海雀为水生鸟，善于潜水捕食，食物主要为12至20厘米长的鱼，偶尔捕食较大的鱼。它们集体活动，常聚集在海面上或潜入海中。繁殖季节外，很少在陆地上生活。天敌少，主要为大型海洋哺乳动物和猛禽。天生不怕人类，但由于无法飞行和行走缓慢，易受人类捕猎。","breeding":"每年产一枚蛋，不筑巢，直接产在地面上。孵化在6月进行，由双方轮流进行。蛋黄色带黑灰色斑点和条纹。雏鸟生长迅速，三周后即可离巢。","identification":"与刀嘴海雀相比，大海雀体型更大，无法飞行，喙部具有明显的白色横向纹槽。幼鸟的喙纹不明显，颈部黑白混杂。区别于其他海雀，大海雀在陆地上行走缓慢。","protection":"IUCN：EX（灭绝）","distribution":"繁殖于加拿大东部、格陵兰、冰岛、法罗群岛、不列颠群岛和丹麦的北岸。非繁殖季节迁徙至美国东部和地中海西部、中部。","other":"大海雀在1844年最后一只个体被杀死后宣告灭绝。其灭绝主要因人类过度捕猎，用于食物、羽毛、油脂和博物馆标本。"},{"name":"白翅斑海鸽","english_name":"Black Guillemot","scientific_name":"Cepphus grylle","overview":"白翅斑海鸽（英文名：Black Guillemot，学名：Cepphus grylle），是鸻形目海雀科海鸽属的鸟类。中型海鸟，广泛分布于北冰洋周边的北极和北大西洋沿岸，南至美国缅因州海岸，向东横跨北极圈边缘直至亚洲，又在阿拉斯加和育空地区的孤立群落中重现。夏季时，其黑羽与白色翼斑及鲜红的腿足成为独特标志。白翅斑海鸽偏好近岸水域而非开阔海洋，以鱼类和底栖无脊椎动物为食。繁殖时，通常选择岩石缝隙或崖壁洞穴筑巢。","appearance":"成鸟体长约30至32厘米，翼展约52至58厘米，体重在320至485克之间。繁殖季时，全身呈黑色，翼上具显著的白色斑块，下翼覆羽几乎纯白，腿足鲜红。冬羽则转为上体灰白相间，头颈及下体白色，翼尖保留黑色，翼上斑块依旧白色。喙黑色，幼鸟及非繁殖期个体头部、颈部及两侧带有灰色或棕色斑纹，翼上斑块有暗色羽尖，形成破碎的白色边框。","call":"繁殖季节发出类似高压口哨的叫声。","habits":"白翅斑海鸽栖息于岩石海岸、悬崖和岛屿，偏好近岸水域，尤其是潮间带和海冰边缘，以潜水方式捕食海底的鱼类和无脊椎动物。它们通常单独或成对活动，有时聚集于小群体中。","breeding":"繁殖期从晚冬到早春，白翅斑海鸽在远离涨潮线的岩石裂缝或巨石周围筑巢。巢穴可能位于岩石缝隙中，许多对不筑巢而直接在地面产卵。每对通常产两枚蛋，孵化期约为28至32天，双亲共同孵化。雏鸟出生时被黑色绒羽覆盖，由双亲照料直至30至40天后离巢独立。","identification":"白翅斑海鸽的白色翼斑在成鸟中明显，而幼鸟和非繁殖期成鸟头部、颈部和两侧有灰色或棕色羽毛，翼上的白色斑块有暗色羽尖。在太平洋区域，与海鸽相似，但可通过海鸽下翼覆羽的灰色调和翼上斑块上的宽黑色条纹加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极至北温带的北大西洋和北极海域沿岸，包括北美东岸至缅因州，向东北横跨北极圈到达亚洲，以及阿拉斯加北部和育空地区的孤立群落。冬季，部分高北极水域的种群向南方迁移，以适应无冰水域。","other":"白翅斑海鸽具有多种亚种，其中在北美繁殖的有两种：arcticus亚种分布在缅因州和加拿大东南部，而mandtii亚种则在阿拉斯加繁殖。"},{"name":"海鸽","english_name":"Pigeon Guillemot","scientific_name":"Cepphus columba","overview":"海鸽（英文名：Pigeon Guillemot，学名：Cepphus columba），是鸻形目海雀科海鸽属的鸟类。以黑白相间的羽毛和鲜红的腿脚著称，善于潜入海底觅食。繁殖季节中，海鸽主要栖息在北极圈附近的岩石海岸、悬崖及岛屿。","appearance":"海鸽身长30至35厘米，喙尖呈黑色，腿脚鲜红。繁殖季节时，其体羽呈现黑色，翼上有醒目的白色斑块。冬季时，下体全白，上体则为褐色并带有白色斑纹。雏鸟与成鸟在外形上有所不同，具有灰色橙色的腿脚，以及身体羽毛上的棕色条纹。","call":"海鸽发出多种叫声，包括明显的‘拱背哨音’，在此叫声中，尾巴略微抬起，翅膀微张，头部向后仰45-90°，随后迅速回复水平位置。此外，还有用于远距离宣告领地的‘颤音’。","habits":"海鸽主要在近岸海域活动，尤其偏好水深10到30米的环境，以海底的小鱼和无脊椎动物为食。它们在繁殖季节内，通常在距巢穴1公里内的水域觅食。海鸽是独居或小群体生活的潜水高手，能够下潜至45米深度捕食。","breeding":"海鸽的繁殖栖息地通常位于岩石海岸、悬崖或岛屿上。它们倾向于在靠近水源的岩石裂缝中筑巢，也会利用其他海鸟弃置的巢穴或旧炸弹壳作为巢址。每窝通常产一到两枚蛋，由双亲共同孵化。","identification":"海鸽与白翅斑海鸽相似，但体型略大，翼下羽毛为灰褐色，翼上的白色斑块被一道棕色楔形分割。冬季时，可通过上体的黑灰相间及白色的下体来区分。","protection":"IUCN：LC（无危）","distribution":"海鸽的繁殖范围覆盖欧亚大陆和北美的北极至温带海洋西北部至太平洋中东部北部coasts，具体包括Chukotka南部至堪察加半岛、Kuril和科曼多尔群岛（俄罗斯东部）、白令海和阿留申群岛、美国阿拉斯加州至美国加利福尼亚州中部。冬季时，它们主要分布在太平洋北部。","other":"海鸽的种群数量估计约为235,000只，最大的繁殖集中地在Farallon Islands, CA和Chukot Peninsula。尽管局部地区面临油污、网捕和哺乳动物捕食者的威胁，但由于广泛分布，整体种群的脆弱性降低。"},{"name":"白眶海鸽","english_name":"Spectacled Guillemot","scientific_name":"Cepphus carbo","appearance":"白眶海鸽体长约38厘米，体重约490克，翼展65.5至69厘米。是Cepphus属中最大的海鸽，体型丰满类似潜鸟，拥有长而厚实的黑色喙。繁殖期时，其外观独特，以黑色为主调，眼周有显著的白色环状斑纹，喙基部有小块白色区域，脚和腿呈红色。冬季时，头顶有灰色和白色的斑驳，下体主要为白色。幼鸟与非繁殖期成鸟相似，但下体有棕色的横纹。","call":"在繁殖季节期间相当活跃，发出一系列快速、高音、类似鸣禽的叫声，通常以较长的一声开头，之后是连续的‘peee-pipipipipipi’。","habits":"白眶海鸽栖息于近岸海域，繁殖于岩石海岸的悬崖或斜坡、石堆，或在捕食者无法到达的岛屿上的开放地带。冬季多在开阔海域和海岸活动，通常靠近繁殖地。其饮食主要以鱼为主，包括多种底栖鱼类、沙丁鱼、鲱鱼和少量无脊椎动物。","breeding":"繁殖行为了解较少，估计大多数鸟在4月至5月间返回繁殖地，筑巢活动可能从中到晚期五月开始，孵化期从6月中旬到7月初，幼鸟在8月的第二周前不会出现在海上。一窝通常产2枚蛋，有时仅1枚，孵化期平均约为28天，由双亲共同孵卵。幼鸟出生时体重约40克，半早熟，抚育期变化较大，但已知有一只幼鸟在33天后离巢。","identification":"白眶海鸽与其他Cepphus属物种的主要辨识点在于其独特的‘眼镜’状白色斑纹和较大的体型。","protection":"IUCN：LC（无危）。在日本南部边缘的分布范围内接近受威胁状态，被列为Vulnerable。1993年保守估计总繁殖群体约71,000至74,000对，其中89%在Sea of Okhotsk，余下在Sea of Japan。近年来，多个繁殖地点记录了明显的种群下降。","distribution":"繁殖区位于欧亚的温带海洋太平洋西部北部海岸，包括Sea of Okhotsk、堪察加半岛南部、库页岛、千岛群岛、北海道北部以及?ne Korean Pen。非繁殖期分布至日本中部和朝鲜半岛南部。","other":"白眶海鸽的种群数量正在减少，最近几年在多个地点记录到了显著的种群下降，尤其是在北海道周围的繁殖地，以及Teuri I和Furugelm I等地。"},{"name":"云石斑海雀","english_name":"Marbled Murrelet","scientific_name":"Brachyramphus marmoratus","overview":"云石斑海雀（英文名：Marbled Murrelet，学名：Brachyramphus marmoratus），是鸻形目海雀科斑海雀属的鸟类。小型海鸟，以其独特的树巢习性而闻名。这种海鸟在北美和亚洲的沿海老树林中筑巢，特别是在远离海岸的老生长青森林中。外观特点是暗棕色的上体，带有红褐色的边缘，以及锈色的背部羽毛和红色的肩羽。下体和头部两侧至眼睛上方以及颈部为淡色，呈斑驳的棕色。冬季时，成鸟上体为深褐色，带有蓝灰色边缘的背部羽毛和大部分白色的肩羽。翼长而窄，喙短而薄。","appearance":"云石斑海雀体型小巧，长度约24-25厘米，翼展约122-149毫米，成鸟体重介于188-269克之间，两性大小相同。翼型较长、较窄且尖，最长的初级飞羽长度略超过翼长的一半。飞行速度极快，可达158公里/小时。尾巴约占翼长的四分之一，由14根宽且圆的尾羽组成，尾羽长度相等。成鸟羽毛色彩在繁殖季节和冬季有显著差异，冬季上体颜色更深，带有蓝灰色边缘的背部羽毛和大部分白色的肩羽。","call":"云石斑海雀发出的是类似‘meer-meer-meer’的声音。","habits":"云石斑海雀主要栖息于沿海水域，有时会出现在大型内陆湖泊。它们以小鱼为主食，也会食用虾、甲壳类和软体动物。繁殖期为6月至7月，通常在海岛松树的枝杈上筑巢，巢由苔藓构成，高度约7米。每次产卵一枚，卵呈淡蓝绿色，有暗色斑点。","breeding":"云石斑海雀的繁殖期集中在6月至7月，它们在海岛松树的枝杈上营巢，巢由苔藓搭建，距离地面约7米。每窝产卵1枚，卵色为淡蓝绿色，带有暗色斑点，卵的尺寸约为62.5×41.2毫米。","identification":"与长嘴斑海雀相比，云石斑海雀的喙更短，体型略小，冬季羽毛的对比度不如长嘴斑海雀明显。繁殖期羽毛的白色部分具有灰黑色横斑，而长嘴斑海雀的喉咙部位为苍白白色，这是两者间的重要区别。","protection":"IUCN：EN（全球濒危）","distribution":"繁殖区域位于北美的太平洋沿岸，从阿留申群岛中部至美国加利福尼亚州中部，最远可达内陆100公里。非繁殖季节则分布至美国加利福尼亚州南部沿海。","other":"在中国，云石斑海雀为旅鸟，以往记录显示其分布于青岛和大连沿海，1984年5月18日曾在吉林地区的松花湖发现一只雌鸟个体。"}];
